INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (52, 'Making AI operational in constrained public sector environments', 'https://www.technologyreview.com/2026/04/16/1135216/making-ai-operational-in-constrained-public-sector-environments/', 'MIT Technology Review', 'https://www.technologyreview.com/feed/', 5, '{General}', 'Making AI operational in constrained public sector environments', '2026-04-16 13:00:00+00', '2026-04-17 06:34:33.89133+00', 'The AI boom has hit across industries, and public sector organizations are facing pressure to accelerate adoption. At the same time, government institutions face distinct constraints around security, governance, and operations that set them apart from their business counterparts. For this reason, purpose-built small language models (SLMs) offer a promising path to operationalize AI in&#8230;', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (53, 'Treating enterprise AI as an operating layer', 'https://www.technologyreview.com/2026/04/16/1135554/treating-enterprise-ai-as-an-operating-layer/', 'MIT Technology Review', 'https://www.technologyreview.com/feed/', 5, '{General}', 'Treating enterprise AI as an operating layer', '2026-04-16 13:00:00+00', '2026-04-17 06:34:35.694346+00', 'There’s a fault line running through enterprise AI, and it’s not the one getting the most attention. The public conversation still tracks foundation models and benchmarks—GPT versus Gemini, reasoning scores, and marginal capability gains. But in practice, the more durable advantage is structural: who owns the operating layer where intelligence is applied, governed, and improved.&#8230;', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (54, 'The Download: cyberscammers’ banking bypasses, and carbon removal troubles', 'https://www.technologyreview.com/2026/04/16/1136034/the-download-cyberscammers-banking-bypasses-microsoft-carbon-removal-troubles/', 'MIT Technology Review', 'https://www.technologyreview.com/feed/', 5, '{General}', 'The Download: cyberscammers’ banking bypasses, and carbon removal troubles', '2026-04-16 12:10:00+00', '2026-04-17 06:34:39.000099+00', 'This is today&#8217;s edition of The Download, our weekday newsletter that provides a daily dose of what&#8217;s going on in the world of technology. Cyberscammers are bypassing banks’ security with illicit tools sold on Telegram  Inside a money-laundering&#160;center&#160;in Cambodia, an employee opens a banking app on his phone. It asks for a photo linked to the&#8230;', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (55, 'Why having “humans in the loop” in an AI war is an illusion', 'https://www.technologyreview.com/2026/04/16/1136029/humans-in-the-loop-ai-war-illusion/', 'MIT Technology Review', 'https://www.technologyreview.com/feed/', 5, '{General}', 'Why having “humans in the loop” in an AI war is an illusion', '2026-04-16 12:00:00+00', '2026-04-17 06:34:44.206654+00', 'The availability of artificial intelligence for use in warfare is at the center of a legal battle between Anthropic and the Pentagon. This debate has become urgent, with AI playing a bigger role than ever before in the current conflict with Iran. AI is no longer just helping humans analyze intelligence. It is now an&#8230;', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (56, 'The noise we make is hurting animals. Can we learn to shut up?', 'https://www.technologyreview.com/2026/04/16/1135179/anthropogenic-noise-hurting-animals/', 'MIT Technology Review', 'https://www.technologyreview.com/feed/', 5, '{General}', 'The noise we make is hurting animals. Can we learn to shut up?', '2026-04-16 10:00:00+00', '2026-04-17 06:34:46.228+00', 'When the covid-19 pandemic started, Jennifer Phillips thought about the songs of the sparrows. They were easier to hear, because the world had suddenly become quieter. Car traffic plummeted as people sheltered at home and shifted to remote work. Air travel collapsed. Cities—normally filled with the honking, screeching, engine-gunning riot of transportation—became as silent as&#8230;', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (57, 'The quest to measure our relationship with nature', 'https://www.technologyreview.com/2026/04/16/1135245/measure-relationship-with-nature-index/', 'MIT Technology Review', 'https://www.technologyreview.com/feed/', 5, '{General}', 'The quest to measure our relationship with nature', '2026-04-16 10:00:00+00', '2026-04-17 06:34:49.231442+00', 'As a movement, environmentalism has been pretty misanthropic. Understandably so—we humans have done some destructive things to the ecosystems around us. In the 21st century, though, mainstream conservation is learning that humans can be a force for good. Foresters are turning to Indigenous burning practices to prevent wildfires. Biologists are realizing that flower-dotted meadows were&#8230;', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (83, 'If Hungary Can Do It', 'https://www.theatlantic.com/podcasts/2026/04/hungary-orban-magyar-election/686821/?utm_source=feed', 'The Atlantic', 'https://feeds.feedburner.com/TheAtlantic', 5, '{General}', 'If Hungary Can Do It', '2026-04-16 11:00:00+00', '2026-04-17 06:35:52.890326+00', 'Viktor Orbán offered a model for antidemocratic rule, one admired by Donald Trump and other world leaders. What does his stunning loss after 16 years in power mean?', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (58, 'Is carbon removal in trouble?', 'https://www.technologyreview.com/2026/04/16/1135928/carbon-removal-microsoft/', 'MIT Technology Review', 'https://www.technologyreview.com/feed/', 5, '{General}', 'Is carbon removal in trouble?', '2026-04-16 10:00:00+00', '2026-04-17 06:34:51.132025+00', 'Last week, news outlets reported that Microsoft was pausing carbon removal purchases. It was something of a bombshell. The thing is, Microsoft is the carbon removal market. The company has single-handedly purchased something like 80% of all contracted carbon removal. If you’re looking for someone to pay you to suck carbon dioxide out of the&#8230;', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (59, 'Acting ICE director Todd Lyons to leave agency', 'https://www.axios.com/2026/04/17/acting-ice-director-todd-lyons-resigns', 'Axios', 'https://api.axios.com/feed/', 5, '{General}', 'Acting ICE director Todd Lyons to leave agency', '2026-04-17 01:28:49+00', '2026-04-17 06:34:55.528375+00', '<p>Acting Immigration and Customs Enforcement director <a href="https://www.axios.com/2026/02/10/ice-2026-fifa-world-cup-lyons-trump" target="_blank">Todd Lyons</a> submitted his resignation on Thursday, Homeland Security Secretary Markwayne Mullin confirmed.</p><p><strong>Why it matters: </strong>Lyons has defended ICE''s conduct <a href="https://www.axios.com/2026/02/10/ice-border-patrol-lyons-scott-trump-house-panel" target="_blank">in Congress</a> and <a href="https://www.axios.com/2026/01/28/ice-director-trump-hearing-canceled-todd-lyons" target="_blank">the courtroom</a> as the agency faces scrutiny over President Trump''s mass deportation drive. </p><hr><ul><li>The scrutiny has been particularly focused on the fatal shootings of U.S. citizens<a href="https://www.axios.com/local/twin-cities/2026/01/07/ice-shooting-victim-identified-renee-nicole-good-minneapolis" target="_self"> Renee Good</a> and <a href="https://www.axios.com/2026/01/25/trump-officials-stick-terrorist-label-on-americans-killed-by-dhs" target="_self">Alex Pretti</a> in Minneapolis in January.</li></ul><p><strong>Driving the news: </strong>The ICE <a href="https://www.congress.gov/119/meeting/house/118240/witnesses/HHRG-119-AP15-Bio-LyonsT-20250514.pdf" target="_blank">veteran</a> said in a letter to Mullin that he''s resigning to take a job in the private sector, Fox News first <a href="https://www.foxnews.com/politics/acting-ice-director-todd-lyons-submits-resignation-letter-dhs-secretary-markwayne-mullin" target="_blank">reported</a>.</p><ul><li>He will remain in the role until May 31 so he can help with the transition process.</li></ul><p><strong>What they''re saying: "</strong>Director Lyons has been a great leader of ICE," Mullin said in an emailed statement.</p><ul><li>"Thanks to his leadership, American communities are safer."</li></ul><p><strong>Go deeper: </strong><a href="https://www.axios.com/2026/04/15/ice-deportations-us-immigration-trump-biden-2025" target="_blank">ICE deported 442k people in fiscal year 2025</a></p>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (60, 'Trump officials negotiating access to Anthropic''s Mythos despite blacklist', 'https://www.axios.com/2026/04/16/white-house-anthropic-ai-mythos-government-national-security', 'Axios', 'https://api.axios.com/feed/', 5, '{General}', 'Trump officials negotiating access to Anthropic''s Mythos despite blacklist', '2026-04-16 23:23:44+00', '2026-04-17 06:34:57.514746+00', '<p>The White House and <a href="https://www.axios.com/2026/04/16/anthropic-claude-power-user-complaints" target="_blank">Anthropic</a> are in active discussions about deploying the AI firm''s powerful new model, <a href="https://www.axios.com/2026/04/07/anthropic-mythos-preview-cybersecurity-risks" target="_blank">Mythos Preview</a>, within the federal government despite ongoing efforts to blacklist the company as a supply chain risk, sources familiar with the discussions tell Axios. </p><p><strong>Why it matters: </strong>Anthropic is in a bitter feud with <a href="https://www.axios.com/2026/03/26/anthropic-pentagon-ai-deal" target="_blank">the Pentagon</a>, but even U.S. officials who dislike the company concede that it''s building tools that could aid U.S. national security — or harm it, if they fall into the wrong hands.</p><hr><p><strong>Driving the news: </strong>Anthropic is only rolling out Mythos to <a href="https://www.axios.com/2026/04/07/anthropic-mythos-preview-cybersecurity-risks" target="_blank">a select group</a> of companies and organizations, rather than the general public, so they can assess its frightening cyber capabilities and harden their defenses.</p><ul><li>Some government agencies want to join that club, and the White House and Anthropic are discussing the terms under which that might be possible.</li><li>In response to queries from agencies as to whether they are able to use Mythos, the Office of Management and Budget sent out an email, first reported by Bloomberg, saying they were looking into the matter.</li><li>Two sources told Axios there are ongoing discussions with Anthropic and agencies may get access to Mythos in the coming weeks.</li></ul><p><strong>Friction point: </strong>That''s despite the fact that Anthropic is in <a href="https://www.axios.com/2026/04/08/anthropic-loses-bid-to-block-pentagon-blacklisting" target="_blank">ongoing litigation with the Pentagon</a>, which declared the company a "<a href="https://www.axios.com/2026/03/09/anthropic-sues-pentagon-supply-chain-risk-label" target="_blank">supply chain risk</a>" and ordered companies that work with the military to remove its software from those workflows.</p><ul><li>Anthropic is currently barred from Pentagon contracts but can do business with the rest of the government while the case continues.</li><li>"There''s progress with the White House. There''s not progress with [the Department of] War," a administration official said.</li><li>A second administration official said the government "has a responsibility to evaluate every model to see where the frontier of tech is," but accused Anthropic of using "fear tactics" by issuing warnings of how Mythos could supercharge hacking.</li><li>"They''re using this Mythos cyber weapon to find friendly ears in the government," the official said. "They''re succeeding."</li></ul><p><strong>What they''re saying: </strong>"All the intel agencies use Anthropic. Every agency except War wants to. That''s because Anthropic doesn''t want to kill people and War''s position is ''don''t tell us what the f*** to do.'' But if you''re the Department of Energy, you don''t give a f*** about that. You''re worried about the Chinese attacking the energy grid. So you want Anthropic," the first administration official said.</p><ul><li>Anthropic''s official position is that it will not allow its models to be used for mass surveillance or to develop fully autonomous weapons.</li><li>The Pentagon says that''s unduly restrictive because those definitions are nebulous and it needs assurances it can use AI systems for "all lawful purposes."</li><li>Most of those concerns don''t apply to non-military work.</li><li>Anthropic and the Pentagon both declined to comment.</li></ul><p><strong>Zoom in:</strong> Civilian agencies like the Departments of Energy and Treasury are responsible for safeguarding critical sectors like the electric grid and financial system.</p><ul><li>Accessing Mythos would help them determine where companies and local governments may be vulnerable to cyberattacks and how to help them prepare.</li></ul><p><strong>Between the lines: </strong>Key officials in the Trump administration see Anthropic and its leaders as woke doomsters, and some relished slapping on the "supply chain risk" designation.</p><ul><li>But some of those same officials, and many others, also see Anthropic''s tools as best-in-class when it comes to AI for national security purposes. </li><li>One Defense official told Axios at the height of the Pentagon-Anthropic feud that the only reason the talks were ongoing is "these guys are that good."</li></ul><p><strong>Go deeper: </strong><a href="https://www.axios.com/2026/03/26/anthropic-pentagon-ai-deal" target="_blank">How Anthropic''s Pentagon deal could get revived</a></p><p><em>Sam Sabin contributed reporting.</em></p>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (61, 'Scoop: Democrats eye new strategy after Iran war powers fail', 'https://www.axios.com/2026/04/16/iran-war-powers-trump-democrats-congress-house', 'Axios', 'https://api.axios.com/feed/', 5, '{General}', 'Scoop: Democrats eye new strategy after Iran war powers fail', '2026-04-16 22:03:04+00', '2026-04-17 06:34:59.976753+00', '<p>A group of House Democrats is discussing plans to force a vote on an <a href="https://www.axios.com/2026/04/16/trump-iran-war-powers-vote-fails-democrats" target="_blank">Iran war powers</a> every day until one finally passes or U.S. operations in the region end, Axios has learned.</p><p><strong>Why it matters: </strong>It''s the kind of <a href="https://www.axios.com/2025/07/03/hakeem-jeffries-speech-big-beautiful-bill-trump" target="_blank">showy flood-the-zone tactic</a> that the Democratic grassroots is constantly trying to get the party''s lawmakers to pursue in resisting the Trump administration.</p><hr><ul><li>It''s not clear if House Democratic leadership will get behind the tactic, but even some centrists aren''t immediately dismissing the proposal.</li><li>"I''d welcome it," Rep. Susie Lee (D-Nev.), who represents battleground-district members in leadership, told Axios.</li><li>"I''ve voted for it twice," said Rep. Jared Moskowitz (D-Fla.). "I''ll vote for it as many times as we need."</li></ul><p><strong>Driving the news: </strong>The idea was raised at a Congressional Progressive Caucus lunch Thursday, multiple sources familiar with the matter told Axios.</p><ul><li>One member floated introducing enough war powers resolutions to force a vote every day that the House is in session, which was positively received, the sources said.</li><li>It''s not a "finalized plan," one source told Axios on the condition of anonymity to share details of private conversations.</li><li>But members "were interested in it" and it is "more than just one person talking," the source said.</li></ul><p><strong>State of play: </strong>The lunch came just after House Democrats narrowly failed to advance a war powers resolution forced to a vote by House Foreign Affairs Committee ranking member Greg Meeks (D-N.Y.).</p><ul><li>The Thursday morning vote failed 213 to 214, with Rep. Jared Golden (D-Maine) siding with Republicans in voting against the measure and Rep. Thomas Massie (R-Ky.) voting with Democrats to move it forward.</li><li>Rep. Warren Davidson (R-Ohio), who supported the resolution last month, voted "present," while Reps. Lauren Boebert (R-Colo.), Nancy Mace (R-S.C.) and Tom Kean Jr. (R-N.J.) didn''t vote.</li></ul><p><strong>What we''re hearing: </strong>"A number of us are talking about [how] we need to get to a strategy where we''re introducing a war powers resolution pretty much every day, one Progressive Caucus member told Axios.</p><ul><li>The lawmaker noted that war powers resolutions take up to 18 days to ripen, saying this strategy would involve "constantly moving them to the line to get them to be able to come to the floor."</li><li>Though the votes may be continually unsuccessful, the lawmaker noted it would continue to put Republicans on the record on the war and its second- and third-order effects, such as rising gas prices.</li></ul>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (62, 'Trump announces 10-day ceasefire between Israel and Lebanon', 'https://www.axios.com/2026/04/16/lebanon-ceasefire-trump-aoun-israel-netanyahu', 'Axios', 'https://api.axios.com/feed/', 5, '{General}', 'Trump announces 10-day ceasefire between Israel and Lebanon', '2026-04-16 21:23:19+00', '2026-04-17 06:35:03.813301+00', '<p>President Trump announced that Israel and Lebanon agreed to a 10-day ceasefire, to begin on Thursday at 5pm ET. </p><p><strong>The big picture: </strong>The U.S. has been pressing for a ceasefire between Israel and Lebanon for several days, while working in parallel on a potential peace deal with Iran.</p><hr><p><strong>What he''s saying:</strong> "I just had excellent conversations with the Highly Respected President Joseph Aoun, of Lebanon, and Prime Minister Bibi Netanyahu, of Israel. These two Leaders have agreed that in order to achieve PEACE between their Countries, they will formally begin a 10 Day CEASEFIRE at 5 P.M. EST," Trump wrote on Truth Social.</p><ul><li>Trump said he would be inviting Aoun and Netanyahu to the White House "for the first meaningful talks between Israel and Lebanon since 1983."</li></ul><p><strong>Between the lines: </strong>The ceasefire plan is politically sensitive for Netanyahu, but it could help Trump reach a peace deal with <a href="https://www.axios.com/world/iran" target="_self">Iran</a>.</p><ul><li>While the two tracks are officially separate, Iran claims the ongoing Israeli attacks in Lebanon constitute a violation of the truce it agreed with the U.S.</li><li>The U.S. and Israel deny that the Iran ceasefire applies to Israel''s offensive against Iran-backed Hezbollah. Israel conducted a string of mass casualty strikes after the Iran truce was agreed.</li></ul><p><strong>In recent days, </strong>the Iranian regime continued to condition a second meeting with the U.S. and a deal to end the war on a ceasefire in Lebanon.</p><ul><li>While the Trump administration and Israel claim the Lebanon and Iran ceasefires are entirely separate, the sense of urgency from the White House over the last two days to get a ceasefire in Lebanon was driven by its efforts to reach a deal with Iran, a former U.S. official said.</li><li>The Iranian foreign ministry welcomed the ceasefire in Lebanon and claimed it was part of the Iran-U.S. ceasefire understandings.  </li></ul><p><strong>The intrigue:</strong> Trump made his announcement shortly after Netanyahu convened his security cabinet for an urgent conference call to discuss the ceasefire and vote on it.</p><ul><li>The ministers — who must approve any such decision — heard about Trump''s announcement several minutes into the call, before any serious discussion had started. </li><li>"Trump pushed this ceasefire through," a senior Israeli official said.</li><li>The security cabinet also met on Wednesday night to discuss Lebanon but no decision was reached on a ceasefire.</li></ul><p><strong>How it happened:</strong> Secretary of State Marco Rubio <a href="https://www.axios.com/2026/04/14/lebanon-israel-peace-talks-rubio" target="_self">hosted a rare meeting</a> between Israeli and Lebanese diplomats on Tuesday. The ceasefire was discussed in the meeting but no decisions were made. </p><ul><li>The Lebanese ambassador acknowledged in the meeting "that Hezbollah is a mutual problem for both Israel and Lebanon," a White House official said. </li><li>On Wednesday evening, after the Israeli cabinet meeting ended without a decision on a ceasefire, Trump spoke with Netanyahu on the phone and asked him for a ceasefire. </li><li>The White House official said Netanyahu agreed to a ceasefire "with certain terms."</li><li>After that call, Rubio called Aoun overnight on Wednesday, and got his commitment to the ceasefire, the White House official said.</li><li>Later on Wednesday night, Trump wrote on Truth Social that he was "trying to get a little breathing room between Israel and Lebanon." He added in his post that the leaders of Israel and Lebanon would speak on Thursday, though neither side had confirmed that.</li></ul><p><strong>Behind the scenes: </strong>The Lebanese government was caught off guard by Trump''s post. Lebanese officials said it was unlikely Aoun would agree at this stage to speak to Netanyahu. </p><ul><li>On Thursday morning, Rubio spoke with Aoun again and discussed the ceasefire. Aoun reportedly told Rubio that a call with Netanyahu would be premature and asked to speak to Trump directly, according to a source with knowledge. </li><li>Several hours later, Trump called Aoun to finalize the ceasefire deal. It was the first time Trump had spoken with the Lebanese president since he took office. </li><li>During the call, Trump invited Aoun for a joint meeting with Netanyahu at the White House. The Lebanese president was non-committal and said he would be happy to do it at some point in the future, according to a source with knowledge.</li><li>Trump called Netanyahu again right afterwards. Soon after that, Trump announced the ceasefire deal.</li></ul><p><strong>Zoom in: ﻿﻿</strong>As Trump and Rubio were making those calls, the State Department was working with the two governments to formulate a Memorandum of Understanding for the ceasefire, a White House official said.</p><ul><li>According to the agreement, the 10-day ceasefire is defined as an Israeli "gesture of goodwill" in order to launch negotiations on a peace agreement between Israel and Lebanon.</li><li>This 10-day ceasefire may be extended by mutual agreement "if progress is demonstrated in the negotiations and as Lebanon effectively demonstrates its ability to assert its sovereignty," the document reads.</li></ul><p><strong>According to the agreement</strong>, Israel preserves the right to take military action, even during the ceasefire, "in self-defense, at any time, against planned, imminent, or ongoing attacks."</p><ul><li>Israel commits not to take offensive military operations against Lebanese targets, including civilian, military, and other state targets.</li><li>The government of Lebanon committed to "take meaningful steps to prevent Hezbollah and all other rogue non-state armed groups" from carrying out any attacks against Israeli targets.</li><li>Netanyahu said Israel would not end its occupation of the 6-mile deep buffer zone in southern Lebanon. But he said Israel had "an opportunity to make a historic peace agreement with Lebanon."</li></ul><p><strong>The big picture: </strong>As part of the ceasefire agreement, the U.S. will facilitate direct negotiations between Israel and Lebanon on the demarcation of their land border, in order to conclude a comprehensive peace agreement.</p><ul><li>A joint statement published by the State Department claimed both countries agreed to "recognize each other''s sovereignty and territorial integrity, and establishing genuine security along their shared border, while preserving Israel''s inherent right to self-defense."</li><li>The two countries also recognize "the significant challenges faced by the Lebanese state from non-state armed groups" and "understand that those groups'' activities must be curtailed" and that only state bodies will be allowed to bear arms. </li><li>"Israel and Lebanon affirm that the two countries are not at war and commit to engaging in good-faith direct negotiations, with the objective of achieving a comprehensive agreement that ensures lasting security, stability, and peace between the two countries," the joint statement reads. </li><li>The Lebanese government didn''t confirm it had agreed to those terms. Some of them, including recognition of Israel, would demand a change to Lebanese laws.</li><li>The Lebanese government only acknowledged the terms of the ceasefire and the plan to hold direct peace talks with Israel.   </li></ul><p><strong>What''s next:</strong> "I have directed Vice President JD Vance and Secretary of State Rubio, together with the Chairman of the Joint Chiefs of Staff, Dan Razin'' Caine, to work with Israel and Lebanon to achieve a Lasting PEACE," Trump added in his post.</p><ul><li>Trump told reporters he might hold the meeting with Netanyahu and Aoun at the White House "in the next week or two."</li><li>A source close to Aoun said the Lebanese president is unlikely to agree to such a meeting as long as Israeli forces occupy parts of Lebanon.</li></ul><p><em>This is a developing story and has been updated throughout.</em></p>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (63, 'RFK Jr. faces barrage from Democrats in House hearings', 'https://www.axios.com/2026/04/16/rfk-jr-faces-barrage-from-democrats-in-house-hearings', 'Axios', 'https://api.axios.com/feed/', 5, '{General}', 'RFK Jr. faces barrage from Democrats in House hearings', '2026-04-16 21:00:17+00', '2026-04-17 06:35:05.515254+00', '<p>Health Secretary Robert F. <a href="https://www.axios.com/health/rfk-jr" target="_blank">Kennedy</a> Jr. faced tough questions on vaccine policy and deep staff cuts at federal health agencies in a pair of House hearings Thursday that marked his first appearance before Congress in more than six months.</p><p><strong>The big picture:</strong> Kennedy doubled down on some of his most controversial moves, but also gave some ground, acknowledging at one point that the measles vaccine could have saved the life of a child who died in an outbreak in Texas last year. </p><hr><p><strong>Driving the news</strong>: Democrats on the Ways and Means and Appropriations committees repeatedly pressed Kennedy on the surge in measles cases across the country and tried to tie them to his vaccine criticism.</p><ul><li>"The anti-vaccine rhetoric you ran on and the anti-vaccine actions you have taken over the last year clearly correlates with the dramatic increases," said Rep. Linda Sánchez (D-Calif.). </li><li>Kennedy shot back that she was repeating "misinformation," arguing there is a "global measles epidemic" and that the U.S. is faring better than Mexico and Canada.  </li><li> Still, he said "it''s possible, certainly," when Sánchez asked if the measles vaccine could have saved the life of the Texas child.</li><li>Asked later if the measles vaccine is safe and effective, Kennedy replied, "yes, it''s safe for most people."</li></ul><p><strong>Between the lines</strong>: Kennedy didn''t mention vaccines in his prepared remarks, instead touting less controversial moves on healthy foods and lowering drug prices. </p><ul><li>But pressed by Democrats, he defended some policy changes. </li><li>Rep. Judy Chu (D-Calif.) faulted the Centers for Disease Control for scrapping a recommendation that all newborns receive the Hepatitis B vaccine, saying it was an "incredibly harmful thing to our community."</li><li>"Parents can assess the risk themselves through informed consent," Kennedy said in response.  </li></ul><p><strong>The intrigue</strong>: Republicans were less confrontational, but Rep. Darin LaHood (R-Ill.) asked about reports of "mismanagement and bungled drug reviews" at the Food and Drug Administration, and whether they were chilling biomedical innovation. </p><ul><li>Kennedy defended the agency and Commissioner Marty Makary, arguing it is speeding up drug review times and meeting all its review deadlines. He suggested critics were captive to pharmaceutical interests.</li><li>"Everybody goes after him because the industry''s so powerful," he said of Makary. "They own Congress, they own the media and they can beat up Marty Makary because he''s trying to do change over there." </li><li>Pressed whether CDC would hire back certain employees placed on administrative leave, Kennedy deferred to the agency''s new leadership team that President Trump announced on Thursday.</li></ul><p><strong>Kennedy said</strong> <strong>his</strong> department is adding staff. After falling from 82,000 to 62,000 employees last year, it is now up to 72,000 and plans to bring on 12,000 more, he said. </p><ul><li>"We will have made up for all the employees that we lost," he added.</li></ul><p><strong>What we''re watching</strong>: There could be more friction ahead after Kennedy said he plans to overhaul and put new members on the U.S. Preventive Services Task Force, the expert panel that makes recommendations for services that insurers must cover fully under the Affordable Care Act.</p><p>   </p><p> </p>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (64, 'Trump nominates former deputy surgeon general to lead CDC', 'https://www.axios.com/2026/04/16/trump-cdc-director-nomination-schwartz', 'Axios', 'https://api.axios.com/feed/', 5, '{General}', 'Trump nominates former deputy surgeon general to lead CDC', '2026-04-16 20:43:44+00', '2026-04-17 06:35:07.181415+00', '<p>President Trump on Thursday nominated his former deputy surgeon general <a href="https://www.axios.com/2026/04/15/cdc-director-nominee-trump-schwartz" target="_blank">Erica Schwartz</a> for director of the Centers for Disease Control and Prevention and moved to fill several other top positions at the beleaguered agency.</p><p><strong>Why it matters: </strong>The CDC has been without a permanent political leader since Susan Monarez was fired in August after serving in the role for less than a month.</p><hr><ul><li>If confirmed, Schwartz would face a demoralized workforce that''s been racked by turnover. Some current and former employees <a href="https://www.axios.com/2025/08/20/hhs-workers-kennedy-violence-cdc" target="_blank">have blamed</a> Health Secretary Robert F. Kennedy Jr. for spreading misinformation and dismantling the public health infrastructure.</li></ul><p><strong>Driving the news:</strong> Trump called Schwartz "a STAR!" in a <a href="https://truthsocial.com/%40realDonaldTrump/posts/116416019325047452" target="_blank">Truth Social</a> post, adding she had the knowledge and experience to turnaround an agency he said was focused on mandates under the Biden administration.</p><ul><li>Trump also appointed Sean Slovenski, a former president of Walmart Health, as CDC deputy director and chief operating officer.</li><li>He additionally named Jennifer Shuford, the commissioner of the Texas Department of State Health Services, as deputy director and chief medical officer, and Sara Brenner, now FDA''s principal deputy commissioner, as senior counselor for public health to Kennedy.</li></ul><p><strong>Between the lines:</strong> The CDC director is subject to Senate confirmation, A nominee with a traditional public health background like Schwartz could fare better than Trump''s pick for surgeon general, Casey Means, whose nomination has stalled.</p><ul><li>Schwartz spent 24 years in the uniformed service, becoming a rear admiral of the Coast Guard, where she served as the chief medical officer.</li><li>She has an MD from Brown University and a law degree from the University of Maryland.</li><li>The White House in March postponed the planned selection of a permanent director, leaving acting head Jay Bhattacharya overseeing the agency.</li></ul>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (65, 'SCOTUS justices air disputes in rare public rifts', 'https://www.axios.com/2026/04/16/supreme-court-divisions-public-criticism-justices', 'Axios', 'https://api.axios.com/feed/', 5, '{General}', 'SCOTUS justices air disputes in rare public rifts', '2026-04-16 19:22:39+00', '2026-04-17 06:35:09.097661+00', '<p><a href="https://www.axios.com/2026/01/01/2026-trump-supreme-court-cases-tariffs" target="_blank">Supreme Court</a> justices are trading barbs over the court''s direction, breaking from their usually private and civil decorum.</p><p><strong>Why it matters:</strong> The recent remarks have offered a rare public display of the deep <a href="https://www.axios.com/2024/03/14/supreme-court-civility-amy-coney-barrett-sonia-sotomayor" target="_blank">ideological divides</a> within the most secretive branch of the U.S. government.</p><hr><ul><li>The fracture''s timing is extraordinary since "this is the time of year, traditionally, when the court is putting the finishing touches on its biggest, and these days, most divisive, rulings," Georgetown law professor Stephen Vladeck tells Axios. </li><li>The conservative-majority court still has to decide on landmark cases involving <a href="https://www.npr.org/2025/10/15/nx-s1-5575101/scotus-voting-rights-arguments" target="_blank">voting rights</a>, <a href="https://apnews.com/live/supreme-court-birthright-citizenship-updates" target="_blank">birthright citizenship</a> and <a href="https://www.yahoo.com/news/articles/trump-v-slaughter-explainer-143000114.html" target="_blank">executive power</a> of the president — all cases that could redefine American life for generations.</li></ul><p><strong>Catch up quick:</strong> Justices Clarence Thomas, Ketanji Brown Jackson and Sonia Sotomayor have all issued critiques in recent days, with Sotomayor also criticizing fellow Justice Brett Kavanaugh — though she didn''t mention him by name. </p><ul><li>Thomas <a href="https://www.youtube.com/watch?v=ddqLhcmZ8Uk" target="_blank">slammed</a> progressivism as an existential threat to America''s founding principles in a speech on Wednesday, adding that "cynicism, rejection, hostility and animus" grip America.</li></ul><p><strong>Sotomayor and Jackson</strong> separately <a href="https://apnews.com/article/supreme-court-jackson-criticism-conservatives-trump-rulings-976a16d91953f42426818add77c7e3f2" target="_blank">critiqued</a> the court''s conservative justices for issuing <a href="https://www.axios.com/2025/07/13/trump-supreme-court-shadow-emergency-docket" target="_blank">emergency orders</a> allowing roughly two dozen of President <a href="https://www.axios.com/politics-policy/donald-trump" target="_blank">Trump''s</a> policies to take effect after lower courts blocked them.</p><ul><li>Sotomayor''s <a href="https://www.nbcnews.com/politics/supreme-court/justice-sonia-sotomayor-apologizes-brett-kavanaugh-hurtful-remarks-rcna332066" target="_blank">remarks</a> on Kavanaugh''s upbringing stemmed from his written comments on an immigration case last year, where Kavanaugh argued that racial profiling is inconsequential for legal residents. She later apologized, calling her comments "hurtful."</li><li>Jackson also delivered pointed criticism of her colleagues during a <a href="https://law.yale.edu/yls-today/yale-law-school-videos/james-thomas-lecture-justice-ketanji-brown-jackson" target="_blank">speech</a> at Yale Law School on Monday, saying some justices were issuing "scratch-paper musings" with little explanation, leaving lower courts to interpret them. </li></ul><p><strong>Worth noting:</strong> Jackson and Kavanaugh already butted heads earlier this year with an exceptional <a href="https://apnews.com/article/supreme-court-kavanaugh-jackson-emergency-appeals-84fa9402f5b449316d2cd28bdda1d06b" target="_blank">sparring</a> match at a legal lecture.</p><p><strong>Between the lines: </strong>While mud-slinging has become normalized in Congress and the<strong> </strong>White House, the judiciary has traditionally kept its composure and its disagreements behind closed doors.</p><ul><li>Vladeck tells Axios that the justice''s public comments could indicate a fight unfolding inside the court over a case, and that the remarks — especially from Sotomayor and Jackson — likely stem from frustration about some of the court''s case conclusions, alongside the Trump administration''s repeated use of the emergency docket. </li><li>"It is not the first time that we''ve had this peek behind the curtain, but it certainly does seem to suggest that things behind the curtain aren''t going very well," he said.  </li></ul><p><strong>The bottom line: </strong>While it''s not unheard of for the justices to raise public concerns about court decisions, the number of them from multiple justices in such a short period of time is "something we should all pay attention to," Vladeck said. </p><p><strong>Go deeper:</strong> <a href="https://www.axios.com/2023/07/03/supreme-court-justices-political-ideology-chart" target="_blank">Supreme Court ideology continues to lean conservative, new data shows</a></p>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (66, 'Trump''s border wall lurches closer to schedule', 'https://www.axios.com/2026/04/16/trumps-border-wall-construction-mileage', 'Axios', 'https://api.axios.com/feed/', 5, '{General}', 'Trump''s border wall lurches closer to schedule', '2026-04-16 17:36:17+00', '2026-04-17 06:35:11.272938+00', '<p>The U.S. has built roughly 50 miles of <a href="https://www.axios.com/2026/02/03/noem-dhs-border-wall-construction-contracts" target="_blank">primary border wall</a> along the southern border, 5.5 miles of buoy barriers in the water and 13.2 miles of secondary barriers, Customs and Border Protection commissioner Rodney Scott told Congress on Thursday.</p><p><strong>Why it matters:</strong> The $46 billion project has been stalled by contracting issues and community <a href="https://www.axios.com/2026/04/09/trump-border-wall-big-bend-texas-mexico" target="_blank">resistance</a>. But Scott told Congress the effort is now "ahead of schedule and we''re below budget."</p><hr><p><strong>By the numbers: </strong>The agency anticipated that it could build about 10 miles of wall per week, according to an interview with the <a href="https://www.washingtonexaminer.com/news/investigations/4444838/dhs-officials-point-fingers-delay-border-wall-construction/?utm_source=chatgpt.com" target="_blank">Washington Examiner</a>.</p><ul><li>Scott''s figures show progress closer to about 3.5 miles constructed per week since early-February.</li><li>Scott did not share figures for the stretches of the southern border that will be covered by "detection technology."</li></ul><p><strong>The big picture: </strong>Trump''s signature construction project depended on a major cash infusion from Congress that didn''t reach the agency until last summer. </p><ul><li>It took months for the first contracts to be awarded, and the project met further delays because of additional reviews implemented by then-Secretary Kristi Noem for all spending over $100,000. </li><li>The contract oversight policy delayed about 200 miles of border wall earlier this year. </li><li>The project is also facing acute local pushback: Residents and elected officials in the Big Bend sector have fought hundreds of miles of planned wall through national and state parks. They are working to prevent construction on private property and archeologically important sites.</li></ul><p><strong>Between the lines:</strong> Scott also shared that he''s traveling to the border for the next five days for meetings, where local residents and elected officials have been skeptical about the wall construction. </p><ul><li>"So the [border crossing] numbers went down, and all of that happened without a single foot of border wall or even a buoy," Rep. Henry Cuellar (R-Texas) said in the hearing. "It was policy, repercussions at the border that helped and working with our partners."</li><li>"Now my communities are concerned about the construction and the potential flood risks, impact to drinking water and threats to public lands that we have."</li></ul><p><strong>The bottom line: </strong>Scott defended the construction by saying it was an investment in long-term security. </p><ul><li>"We have almost 11,000 Department of War personnel on the border helping us create a level of deterrence and that is not a sustainable model," Scott said. "Building the border wall is actually an investment that saves American tax payers money."</li></ul>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (84, 'A Pillar of the Economics Establishment Admits That It Was Wrong', 'https://www.theatlantic.com/ideas/2026/04/world-bank-industrial-policy/686820/?utm_source=feed', 'The Atlantic', 'https://feeds.feedburner.com/TheAtlantic', 5, '{General}', 'A Pillar of the Economics Establishment Admits That It Was Wrong', '2026-04-16 11:00:00+00', '2026-04-17 06:35:55.132831+00', 'In a new report, the World Bank thinks better of its old free-market absolutism.', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (85, 'History Is Running Backwards', 'https://www.theatlantic.com/magazine/2026/05/reactionary-traditionalism-worldview/686597/?utm_source=feed', 'The Atlantic', 'https://feeds.feedburner.com/TheAtlantic', 5, '{General}', 'History Is Running Backwards', '2026-04-16 11:00:00+00', '2026-04-17 06:35:56.893398+00', 'Why reactionaries are taking over the world', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (86, '‘No one knew I was in a different time zone’: The workers who travel, play tennis, and do chores on the clock', 'https://www.fastcompany.com/91528048/no-one-knew-i-was-in-a-different-time-zone-the-workers-who-travel-play-tennis-and-do-chores-on-the-clock', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5, '{General}', '‘No one knew I was in a different time zone’: The workers who travel, play tennis, and do chores on the clock', '2026-04-17 06:00:00+00', '2026-04-17 06:36:01.010834+00', '<p>Errands, Target runs, tennis games, and even flying to Europe—these are just some of the things employees have done while taking “<a href="https://www.standard.co.uk/news/uk/soft-off-day-viral-trend-tiktok-wfh-b1274083.html">soft off days</a>.” </p>
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (67, 'House hands Trump a win with failed Iran war powers vote', 'https://www.axios.com/2026/04/16/trump-iran-war-powers-vote-fails-democrats', 'Axios', 'https://api.axios.com/feed/', 5, '{General}', 'House hands Trump a win with failed Iran war powers vote', '2026-04-16 17:02:48+00', '2026-04-17 06:35:14.210416+00', '<p>House Democrats failed Thursday to pass a <a href="https://www.axios.com/2026/04/09/trump-iran-democrat-congress-war-powers-vote" target="_blank">war powers resolution</a> that would constrain President Trump''s ability to wage war with Iran.</p><p><strong>Why it matters: </strong>It is the <a href="https://www.axios.com/2026/04/09/trump-iran-democrat-congress-war-powers-vote" target="_blank">third</a> <a href="https://www.axios.com/2026/03/05/iran-house-democrats-republicans-war-powers" target="_blank">time</a> Democrats have tried and failed to pass an Iran war powers resolution, which some lawmakers fear will be seen as a green light to the Trump administration to keep ignoring Congress.</p><hr><ul><li>The measure, introduced and forced to a vote by House Foreign Affairs Committee ranking member Greg Meeks (D-N.Y.), failed 213 to 214.</li></ul><p><strong>What happened: </strong>Centrist Rep. Jared Golden (D-Maine) voted with Republicans against the measure, while libertarian-leaning Rep. Thomas Massie (R-Ky.) voted with Democrats to pass it.</p><ul><li>Rep. Warren Davidson (R-Ohio), who voted to pass an Iran war powers resolution last month, voted "present" on Thursday.</li><li>Reps. Juan Vargas (D-Calif.), Greg Landsman (D-Ohio) and Henry Cuellar (D-Texas), who voted against the measure last month, flipped and voted for it.</li></ul>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (68, 'Anthropic releases Claude Opus 4.7, concedes it trails unreleased Mythos', 'https://www.axios.com/2026/04/16/anthropic-claude-opus-model-mythos', 'Axios', 'https://api.axios.com/feed/', 5, '{General}', 'Anthropic releases Claude Opus 4.7, concedes it trails unreleased Mythos', '2026-04-16 16:17:52+00', '2026-04-17 06:35:17.347359+00', '<p><a href="https://www.axios.com/2026/04/13/anthropic-revenue-growth-ai" target="_blank">Anthropic</a> on Thursday released Claude Opus 4.7, a meaningful upgrade to its flagship AI model with better coding, sharper vision and a new ability to double-check its own work.</p><p><strong>Why it matters: </strong>Anthropic publicly conceded that the new Opus model does not match the performance of <a href="https://www.axios.com/2026/04/07/anthropic-mythos-preview-cybersecurity-risks" target="_blank">Mythos</a>, a highly advanced system that the company hasn''t released to the public due to safety concerns.</p><hr><ul><li>In a chart accompanying its <a href="https://x.com/claudeai/status/2044785261393977612?s=20" target="_blank">announcement</a>, Anthropic showed that Opus 4.7 beats Opus 4.6, ChatGPT 5.4, Google Gemini 3.1 Pro in a number of key benchmarks.</li><li>But Opus 4.7 still falls short of its Mythos Preview model, which has only been released to a handpicked group of tech and cybersecurity companies.</li></ul><p><strong>What they''re saying:</strong> "Opus 4.7 is a notable improvement on Opus 4.6 in advanced software engineering, with particular gains on the most difficult tasks," Anthropic said in a <a href="https://www.anthropic.com/news/claude-opus-4-7" target="_blank">blog post</a>. </p><ul><li>"Users report being able to hand off their hardest coding work—the kind that previously needed close supervision—to Opus 4.7 with confidence."</li><li>"The model also has substantially better vision: it can see images in greater resolution," it said. "It''s more tasteful and creative when completing professional tasks, producing higher-quality
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (69, 'Kennedy returns to Capitol Hill with clout diminished', 'https://www.axios.com/2026/04/16/rfk-faces-scrutiny-congress', 'Axios', 'https://api.axios.com/feed/', 5, '{General}', 'Kennedy returns to Capitol Hill with clout diminished', '2026-04-16 10:00:08+00', '2026-04-17 06:35:19.244279+00', '<p>Health Secretary Robert F. Kennedy Jr. will face Congress for the first time in more than six months on Thursday with his autonomy and political influence in a very different place. </p><p><strong>Why it matters:</strong> As the White House <a href="https://www.axios.com/2026/02/27/trump-maha-kennedy-vaccine-agenda" target="_blank">tries to reel in</a> his agenda, Kennedy is expected to face a gauntlet of questions about vaccines, autism and other hot-button issues at the first of seven hearings over this week and next.</p><hr><ul><li>It will be a test of how well Kennedy can stay on message as the Trump administration tries to pivot away from controversies and emphasize priorities like lowering drug prices. </li></ul><p><strong>Driving the news:</strong> Kennedy will appear before the House Ways and Means and Appropriations committees on Thursday before heading to Senate hearings next week.</p><ul><li>Democrats and some Republicans are eager to press him on controversial moves since he last testified before the Senate Finance Committee in September. </li><li>One likely topic is January''s dramatic overhaul of the childhood vaccine schedule that dialed back<strong> </strong>17<strong> </strong>recommended vaccinations to 11.</li><li>Kennedy also directed the Centers for Disease Control and Prevention to <a href="https://www.axios.com/2025/11/20/cdc-website-rfk-vaccines-autism" target="_blank">update its</a> website to suggest a widely debunked link between vaccines and autism. </li><li>His handpicked vaccine advisers also voted to drop the recommendation that all infants receive the hepatitis B vaccine at birth. </li></ul><p><strong>Between the lines:</strong> Kennedy and his "Make America Healthy Again" movement have experienced setbacks in court and within the administration since the last time he appeared on the Hill.</p><ul><li>A federal judge last month <a href="https://www.axios.com/2026/03/16/rfk-kennedy-cdc-vaccine-changes-judge" target="_blank">temporarily blocked</a> the childhood vaccine changes. </li><li>More broadly, the Trump administration has elevated senior adviser Chris Klomp to be Kennedy''s de facto chief of staff, overseeing key personnel moves and focusing on issues like drug prices. </li><li>Kennedy, meanwhile, has been making campaign-like appearances around the country touting less controversial policies like promoting healthy foods — avoiding mention of moves like <a href="https://www.axios.com/2025/08/05/mrna-vaccine-development-kennedy-funding" target="_blank">canceling funding</a> for development of new mRNA vaccines. </li></ul><p><strong>Kennedy''s opening remarks</strong> for Thursday morning''s hearing do not include the word "vaccine." Instead he will tout "historic wins" like drug pricing deals with 16 pharmaceutical companies and new dietary guidelines that "put real, whole food at the center of the American plate."</p><ul><li>"We are ending the era of federal policies that fueled this chronic disease epidemic," he will say.</li></ul><p><strong>Kennedy has lashed </strong>out at his critics during congressional hearings and could be drawn into new showdowns over vaccine policy. </p><ul><li>Sen. Ron Wyden of Oregon, the top Democrat on Senate Finance, said he''ll press Kennedy on what he characterized as a failure to live up to pledges made during his contentious confirmation hearings. </li><li>"He was going to be independent and he was going to look at these issues again and all the rest, and he basically just went out and did all his anti-vax stuff wherever he could," Wyden said. </li><li>Kennedy still has defenders among Republicans, who praise him for shaking up a federal bureaucracy they say became captive to health industries it regulates.</li></ul><p><strong>The intrigue:</strong> Senate health committee Chair Bill Cassidy (R-La.) will be closely watched, given his increasingly fraught relationship with Kennedy and the fact he faces a tough primary against a Trump-backed challenger next month.  </p><ul><li>"I''ve just got so much in my brain right now I''ll address that when I get to it," Cassidy said on Wednesday, declining to discuss what he''ll ask Kennedy.</li><li>Aside from vaccines, personnel upheaval and canceled grants for medical research are also ripe areas for questioning. </li></ul><p><strong>Sen. Shelley Moore Capito</strong> (R-W.Va.), chair of the Appropriations health subcommittee, said she plans to seek assurances that National Institutes of Health grants, funding for substance abuse and other expenditures the administration previously targeted are flowing.</p><ul><li>Top House appropriator Tom Cole (R-Okla.) is another NIH supporter who could press Kennedy on his designs for the agency.</li><li>Capito said she''ll also have questions about the beleaguered CDC, adding "There''s been a fair amount of uncertainty there."</li><li>The agency has been without a permanent director since last summer, though the administration <a href="https://www.axios.com/2026/04/15/cdc-director-nominee-trump-schwartz" target="_blank">could be</a> zeroing in on a pick. </li></ul><p><strong>What we''re watching:</strong> How many Republicans have grown impatient with Kennedy and view him as a political liability heading into the midterm elections.  </p>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (70, 'Anthropic''s AI downgrade stings power users', 'https://www.axios.com/2026/04/16/anthropic-claude-power-user-complaints', 'Axios', 'https://api.axios.com/feed/', 5, '{General}', 'Anthropic''s AI downgrade stings power users', '2026-04-16 09:00:06+00', '2026-04-17 06:35:21.479612+00', '<p>Anthropic users across online forums are raising the same complaint: Claude suddenly feels… bad.</p><p><strong>Why it matters:</strong> The backlash lands just as Anthropic is <a href="https://www.axios.com/2026/04/07/anthropic-mythos-preview-cybersecurity-risks" target="_blank">testing</a> a more powerful model, Mythos — raising questions about whether cutting-edge AI is becoming less accessible even as it gets more capable.</p><hr><p><strong>Driving the news:</strong> Over the past few weeks, users on X, GitHub and Reddit have been swapping anecdotes, benchmarks and prompts in an effort to pinpoint what changed and why.</p><ul><li>"Claude has regressed to the point it cannot be trusted to perform complex engineering," an AMD senior director wrote in a <a href="https://x.com/firstadopter/status/2043086033454031281?s=20" target="_blank">widely shared</a> post on GitHub.</li><li><a href="https://x.com/iruletheworldmo/status/2043332977136975994?s=46" target="_blank">Others</a> have posted <a href="https://x.com/bridgemindai/status/2043321284113670594?s=46" target="_blank">side-by-side</a> outputs and benchmarks they say show Claude generating answers that are <a href="https://x.com/Hesamation/status/2042979500103815306" target="_blank">less accurate </a>or <a href="https://x.com/clairevo/status/2041287600154288400" target="_blank">nuanced</a>. </li><li>Much of the speculation centers on whether Claude has been deliberately scaled back — what users are calling "<a href="https://x.com/ShanuMathew93/status/2042645545970213202" target="_blank">nerfed</a>" — either to control costs or to redirect scarce compute toward Mythos and other frontier efforts.</li></ul><p><strong>The other side:</strong> Anthropic says it adjusted the default level of reasoning in Claude Code, but denies the changes were tied to compute constraints or Mythos.</p><ul><li>When asked about the online complaints, Anthropic pointed Axios to a post on X from Boris Cherny, head of Claude Code <a href="https://x.com/bcherny/status/2029970236460691885?s=46" target="_blank">from March 6</a>.<strong> </strong></li><li>"You can change it anytime in the /model selector if you prefer low effort (faster) or high effort (more intelligence). The setting is sticky and will persist for your next session," Anthropic''s Boris Cherny <a href="https://x.com/bcherny/status/2029970236460691885?s=46" target="_blank">said</a> last month on X</li></ul><p><strong>Between the lines:</strong> Analyst Patrick Moorhead decided to <a href="https://x.com/PatrickMoorhead/status/2044074719888982319?s=20" target="_blank">ask Claude</a> to weigh in.</p><ul><li>"Anthropic made real configuration changes that objectively reduced default thinking depth across all surfaces including claude.ai, but the most extreme ''secret nerfing'' narrative overstates what happened," Claude said as part of its lengthy response.</li></ul><p><strong>Another theory</strong> is that users aren''t seeing decline so much as acclimating to what previously felt magical.</p><ul><li>Over time, expectations rise and flaws become more noticeable — a phenomenon <a href="https://x.com/daniel_mac8/status/2043676629617045811?s=20" target="_blank">known as habituation</a>. </li></ul><p><strong>Yes, but:</strong> Even if the change is explainable, the perception problem is real — especially for power users relying on consistent performance for coding and research workflows.</p><p><strong>The big picture:</strong> The fight over Claude''s "intelligence" points to a broader shift: access to top-tier AI is fragmenting.</p><ul><li>Advanced capabilities are increasingly gated behind higher-cost tiers, API usage or experimental programs.</li><li>Anthropic is also reportedly close to <a href="https://www.theinformation.com/briefings/exclusive-anthropic-preps-opus-4-7-model-ai-design-tool" target="_blank">upgrading</a> its high-end Opus model to version 4.7.</li></ul><p><strong>The increasing stratification</strong> could lead to a division between those who can afford to pay top dollar for the best models and those who can''t.</p><ul><li>Anthropic recently <a href="https://www.theinformation.com/articles/anthropic-changes-pricing-bill-firms-based-ai-use-amid-compute-crunch?ref=implicator.ai" target="_blank">moved</a> large enterprise customers to a fully usage-based (token) pricing model, tying intelligence more directly to spend.</li><li>It''s also reinforcing a <a href="https://www.axios.com/2026/04/13/ai-elite-vs-ai-skeptic-doomer" target="_blank">widening divide</a> between power users and dabblers around AI''s capabilities.</li></ul><p><strong>What we''re watching:</strong> Whether "default" AI experiences continue to get worse even as frontier systems get dramatically stronger.</p>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (71, 'Religious resurgence stirs Gen Z', 'https://www.axios.com/2026/04/16/gen-z-religion-poll-gallup', 'Axios', 'https://api.axios.com/feed/', 5, '{General}', 'Religious resurgence stirs Gen Z', '2026-04-16 09:00:05+00', '2026-04-17 06:35:23.412027+00', '<div>Data: Gallup; Chart: Axios Visuals</div><p>New polling shows an uptick in religious fervor among young men, even as overall U.S. levels remain near <a href="https://www.axios.com/2023/10/06/organized-religion-decline-agnostic-atheist-nonreligious" target="_blank">historic lows</a>.
