INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (77, 'What I Saw Inside the Kennedy Center', 'https://www.theatlantic.com/culture/2026/04/inside-kennedy-center-shutdown-drama/686801/?utm_source=feed', 'The Atlantic', 'https://feeds.feedburner.com/TheAtlantic', 5, '{General}', 'What I Saw Inside the Kennedy Center', '2026-04-16 17:34:54+00', '2026-04-17 06:35:37.698573+00', 'I spent 10 months working at the institution because I thought I could help protect it. What I observed there is far worse than the public knows.', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
