INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (82, 'If You Want a Better World, Act Like You Live in It', 'https://www.theatlantic.com/books/2026/04/henry-david-thoreau-great-american-dissident/686823/?utm_source=feed', 'The Atlantic', 'https://feeds.feedburner.com/TheAtlantic', 5, '{General}', 'If You Want a Better World, Act Like You Live in It', '2026-04-16 12:00:00+00', '2026-04-17 06:35:49.603874+00', 'We’ve had Henry David Thoreau the environmentalist, the libertarian, the life coach. To understand his influence, think of him first as a dissident.', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
