INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (89, 'IBM just settled a major anti-DEI case for $17 million', 'https://www.fastcompany.com/91528241/ibm-just-settled-a-major-anti-dei-case-for-17-million', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5, '{General}', 'IBM just settled a major anti-DEI case for $17 million', '2026-04-16 21:00:00+00', '2026-04-17 06:36:06.441066+00', '<p>In 2025—not long after Trump <a href="https://www.fastcompany.com/91267693/how-trump-is-gutting-dei-with-a-flurry-of-executive-orders">fired off executive orders</a> that targeted diversity, equity, and inclusion (DEI) programs in the workplace—the Justice Department <a href="https://www.justice.gov/opa/pr/justice-department-establishes-civil-rights-fraud-initiative">announced the Civil Rights Fraud Initiative.</a> Its purpose was to investigate companies and academic institutions that accepted money from the government, by invoking a federal law called the False Claims Act. This past week, IBM <a href="https://www.justice.gov/opa/pr/ibm-pays-17-million-resolve-allegations-discrimination-through-illegal-dei-practices">agreed to pay $17 million</a> over claims that its DEI programs allegedly violated the law—the first instance of an employer settling a case that the government brought under this initiative. </p>
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (90, 'Sustainability is maturing', 'https://www.fastcompany.com/91527698/sustainability-is-maturing', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5, '{General}', 'Sustainability is maturing', '2026-04-16 20:45:41+00', '2026-04-17 06:36:09.34591+00', '<p>In 2002, 45% of the world’s top 250 companies <a href="https://kpmg.com/xx/en/our-insights/esg/survey-of-sustainability-reporting-2022/global-trends.html">reported on sustainability</a>. Today, 96% do. Sustainability metrics that once differentiated companies have become the new baseline. This doesn’t mean sustainability has stalled. Rather, it has matured. As geopolitical and regulatory risks continue progressing, what it means to be a sustainable business is evolving.&nbsp;</p>
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (91, '2028 candidates will face a new kind of economic anger', 'https://www.fastcompany.com/91527561/2028-candidates-will-face-a-new-kind-of-economic-anger', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5, '{General}', '2028 candidates will face a new kind of economic anger', '2026-04-16 20:07:59+00', '2026-04-17 06:36:11.101332+00', '<p>Election after election, Democratic strategist James Carville’s&nbsp;<a href="https://politicaldictionary.com/words/its-the-economy-stupid/" target="_blank" rel="noreferrer noopener">maxim</a>, “It’s the economy, stupid!” has held true. But in&nbsp;coming&nbsp;political campaigns, candidates will&nbsp;encounter&nbsp;an especially virulent strain of economic anxiety—driven by <a href="https://www.fastcompany.com/section/artificial-intelligence" data-internallinksmanager029f6b8e52c="1" title="AI">artificial intelligence</a>—that is proliferating among lower-wage, working Americans.&nbsp;</p>
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (92, 'Trader Joe’s class action settlement: How to find out if you’re an eligible shopper and claim your money', 'https://www.fastcompany.com/91528211/trader-joes-class-action-settlement-how-to-find-out-if-youre-an-eligible-shopper-and-claim-your-money', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5, '{General}', 'Trader Joe’s class action settlement: How to find out if you’re an eligible shopper and claim your money', '2026-04-16 20:00:00+00', '2026-04-17 06:36:13.112511+00', '<p>Trader Joe’s is <a href="https://www.tj-factasettlement.com/">settling a class action lawsuit for more than $7 million</a>, after a complaint claimed that the grocery giant printed 10 digits—the first six and last four—of customers’ debit and credit cards on transaction receipts.</p>
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (93, 'Mamdani filmed his pied-á-terre tax video outside Ken Griffin’s $238 million penthouse. Social media loves him for it', 'https://www.fastcompany.com/91528066/pied-a-terre-tax-zohran-mamdani-filmed-video-outside-ken-griffin-penthouse-social-media-loves-him-for-it', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5, '{General}', 'Mamdani filmed his pied-á-terre tax video outside Ken Griffin’s $238 million penthouse. Social media loves him for it', '2026-04-16 19:30:00+00', '2026-04-17 06:36:15.510174+00', '<p>Tax Day isn’t normally a cause for celebration. The annual due date for filing taxes usually comes with headache-inducing financial stress and mountains of difficult-to-decipher paperwork. But this year, Tax Day apparently came with an unexpected upside for some New Yorkers, thanks to an announcement from New York City Mayor Zohran Mamdani.</p>
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (94, 'A U.S. state just banned big AI data centers. Here’s why it might not be the last', 'https://www.fastcompany.com/91528122/a-u-s-state-just-banned-big-ai-data-centers-heres-why-it-might-not-be-the-last', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5, '{General}', 'A U.S. state just banned big AI data centers. Here’s why it might not be the last', '2026-04-16 19:00:00+00', '2026-04-17 06:36:17.264859+00', '<p>As tech’s titans sprint to build a <a href="https://www.fastcompany.com/91525419/big-tech-talks-climate-change-less-ai-data-centers">sprawling web of data centers</a> to power the <a href="https://www.fastcompany.com/section/artificial-intelligence" data-internallinksmanager029f6b8e52c="1" title="AI">AI</a> boom, some cities and states are racing to stop them.</p>
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (95, 'From legacy processes to AI-native work', 'https://www.fastcompany.com/91528215/from-legacy-processes-to-ai-native-work', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5, '{General}', 'From legacy processes to AI-native work', '2026-04-16 18:26:17+00', '2026-04-17 06:36:19.175808+00', '<p>The challenges with <a href="https://www.fastcompany.com/section/artificial-intelligence" data-internallinksmanager029f6b8e52c="1" title="AI">AI</a> adoption have little to do with the technology itself. In the work environment, the hardest part is bringing together a new orchestration model that fully integrates AI tools while ensuring teams both adopt and master new behaviors to deliver tangible results.</p>
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (96, 'OpenAI shifts its focus to business users amid Anthropic pressure', 'https://www.fastcompany.com/91528145/openai-chatgpt-spud-sam-altman-anthropic-mythos', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5, '{General}', 'OpenAI shifts its focus to business users amid Anthropic pressure', '2026-04-16 18:13:12+00', '2026-04-17 06:36:20.941138+00', '<p>The same ChatGPT chatbot that gave <a href="https://www.fastcompany.com/section/openai">OpenAI</a>’s chief financial officer Sarah Friar a tilapia recipe for a recent Sunday night dinner at home is also now doing her most mundane tasks at work like summarizing her emails and Slack messages.</p>
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (97, 'A massive tariff refund program is launching. Here’s who actually gets the money', 'https://www.fastcompany.com/91528115/a-massive-refund-program-is-launching-heres-who-actually-gets-the-money', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5, '{General}', 'A massive tariff refund program is launching. Here’s who actually gets the money', '2026-04-16 18:00:00+00', '2026-04-17 06:36:23.864483+00', '<p>A tariff refund program will open next week following the invalidation of President Trump&#8217;s tariffs by the Supreme Court. But consumers shouldn&#8217;t get too excited—the program is aimed only at companies, not individuals. </p>
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (98, 'Why people can’t build wealth on wages alone, and what to do about it', 'https://www.fastcompany.com/91524585/why-people-cant-build-wealth-on-wages-alone-and-what-to-do-about-it', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5, '{General}', 'Why people can’t build wealth on wages alone, and what to do about it', '2026-04-16 17:57:22+00', '2026-04-17 06:36:26.127853+00', '<p>As Jennifer Harris, director of the Economy and Society Initiative at the William and Flora Hewlett Foundation, <a href="https://www.nytimes.com/2026/04/08/opinion/ai-wealth-inequality-jobs-investment.html?unlocked_article_code=1.ZVA.H2k0.zUpWOXIo6q40&amp;smid=url-share">has recently pointed out</a>, we are at a particularly fraught moment. Rising inequality means that fewer people have spending power, creating incentives that sharpen the affordability crisis for everybody else. But there are remedies that don’t require draconian taxes and are proven to work—at their core is ownership. </p>
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (99, 'Eldercare—the leadership crisis no one is talking about', 'https://www.fastcompany.com/91527449/eldercare-the-leadership-crisis-no-one-is-talking-about', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5, '{General}', 'Eldercare—the leadership crisis no one is talking about', '2026-04-16 17:30:46+00', '2026-04-17 06:36:28.041459+00', '<p>As founder, chair, and CEO of the Exceptional Women Alliance, I am privileged to engage with extraordinary female leaders across industries. This month, I spoke with Shari Hofer about a workforce issue hiding in plain sight: eldercare.</p>
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (100, 'Why workplaces need a gendered health approach', 'https://www.fastcompany.com/91527046/why-workplaces-need-a-gendered-health-approach', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5, '{General}', 'Why workplaces need a gendered health approach', '2026-04-16 17:20:07+00', '2026-04-17 06:36:31.293165+00', '<p>Over the past few years, words that once had no place in workplace conversations have slowly entered HR agendas: menstruation, endometriosis, perimenopause, menopause, breast cancer and—more slowly—male andropause or prostate cancer. These are not passing trends. They signal a deeper shift in how we understand work and the people who do it.</p>
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (101, 'Why AI is the ultimate accelerator for creativity', 'https://www.fastcompany.com/91521407/why-ai-is-the-ultimate-accelerator-for-creativity', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5, '{General}', 'Why AI is the ultimate accelerator for creativity', '2026-04-16 17:02:50+00', '2026-04-17 06:36:33.155637+00', '<p>Have you noticed that in the current discourse around <a href="https://www.fastcompany.com/section/artificial-intelligence" data-internallinksmanager029f6b8e52c="1" title="AI">artificial intelligence</a>, the narrative often slips into one of two extremes? There is either a techno-utopian dream of total automation or a dystopian nightmare where human agency is erased. But there are other options! As we navigate this inflection point in civilization, I invite you to consider a third path: pragmatic optimism.</p>
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (102, 'AI anxiety is turning volatile', 'https://www.fastcompany.com/91527261/ai-anxiety-is-turning-volatile', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5, '{General}', 'AI anxiety is turning volatile', '2026-04-16 16:00:00+00', '2026-04-17 06:36:36.293498+00', '<p id="h-"><em>Welcome to</em> <a href="https://www.fastcompany.com/section/artificial-intelligence">AI</a> Decoded<em>, </em>Fast Company<em>’s weekly newsletter that breaks down the most important news in the world of <a href="https://www.fastcompany.com/section/artificial-intelligence">AI</a>. You can sign</em> <em>up to receive this newsletter every week via email </em><a href="https://www.fastcompany.com/newsletters"><em>here</em></a><em>.</em>  </p>
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (103, 'Inside NTT Research’s push to commercialize deep tech', 'https://www.fastcompany.com/91527309/inside-ntt-researchs-push-to-commercialize-deep-tech', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5, '{General}', 'Inside NTT Research’s push to commercialize deep tech', '2026-04-16 15:41:02+00', '2026-04-17 06:36:39.844325+00', '<p>Since opening in Silicon Valley in 2019, NTT Research has operated as a long-horizon science lab, a dedicated arm of Japan’s telecommunications giant NTT Group, which invests <a href="https://group.ntt/en/ir/fin/highlight.html">more than $3 billion annually</a> in global R&amp;D. Now in its seventh year, the lab was built as a research subsidiary insulated from quarterly pressure and product roadmaps.</p>
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (104, 'Warren Buffett once said that success at the end of your life comes down to 1 word', 'https://www.fastcompany.com/91527165/warren-buffett-once-said-success-end-your-life-comes-down-1-word', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5, '{General}', 'Warren Buffett once said that success at the end of your life comes down to 1 word', '2026-04-16 15:13:57+00', '2026-04-17 06:36:41.77614+00', '<p><a href="https://www.inc.com/marcel-schwantes/warren-buffetts-top-hiring-rule-look-for-this-trait-first-or-nothing-else-matters/91225032">Warren Buffett</a>&nbsp;is seldom wrong, especially regarding investment and innovation. As most of us know, the&nbsp;<a href="https://www.inc.com/marcel-schwantes/warren-buffett-says-this-one-simple-everyday-habit-sets-successful-people-apart/91151818">Oracle of Omaha</a>&nbsp;<a href="https://www.fastcompany.com/91508751/warren-buffett-says-4-timeless-principles-create-lifelong-success-fulfillment-happiness">offers wisdom</a> that goes beyond industries, generations, and cultures.</p>
