INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (164, 'After a saga of broken promises, a European rover finally has a ride to Mars', 'https://arstechnica.com/space/2026/04/after-a-saga-of-broken-promises-a-european-rover-finally-has-a-ride-to-mars/', 'Ars Technica', 'https://feeds.arstechnica.com/arstechnica/index', 5, '{General}', 'After a saga of broken promises, a European rover finally has a ride to Mars', '2026-04-17 03:15:54+00', '2026-04-17 06:57:50.540404+00', 'Europe''s first Mars rover mission is now on its fourth rocket: SpaceX''s Falcon Heavy.', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (151, 'Netflix embraces vertical video with major mobile app update', 'https://www.theverge.com/streaming/913539/netflix-mobile-app-update-vertical-video', 'The Verge', 'https://www.theverge.com/rss/index.xml', 5, '{General}', 'Netflix embraces vertical video with major mobile app update', '2026-04-16 20:29:56+00', '2026-04-17 06:57:19.618273+00', 'Netflix announced on Thursday that it will be launching a redesigned mobile app, which will include a vertical video feed, at the end of April. "This redesign will better reflect our expanding entertainment offering and make it easier for members to engage how and when they want," the company said in its Q1 2026 earnings [&#8230;]', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (152, 'Netflix cofounder Reed Hastings is officially leaving the company', 'https://www.theverge.com/streaming/913201/netflix-reed-hastings-earnings-q1-2026', 'The Verge', 'https://www.theverge.com/rss/index.xml', 5, '{General}', 'Netflix cofounder Reed Hastings is officially leaving the company', '2026-04-16 20:23:00+00', '2026-04-17 06:57:21.260107+00', 'Netflix cofounder and chairman Reed Hastings plans to leave the company after nearly 30 years. The news comes as part of Netflix''s Q1 2026 earnings results released on Thursday, which says Hastings "will not stand for re-election to our Board when his current term expires at the Annual Meeting in June." After co-founding Netflix in [&#8230;]', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (153, 'Live Nation says it will fight monopoly suit loss', 'https://www.theverge.com/policy/913494/live-nation-ticketmaster-fight-state-monopoly-jury-verdict', 'The Verge', 'https://www.theverge.com/rss/index.xml', 5, '{General}', 'Live Nation says it will fight monopoly suit loss', '2026-04-16 19:02:12+00', '2026-04-17 06:57:23.34527+00', 'After a jury found that Live Nation-Ticketmaster violated antitrust law on several counts, the company warns in a blog post that the verdict "is not the last word on this matter." The company plans to renew a motion for the judge to issue a ruling against the states, claiming that they did not prove their [&#8230;]', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (154, 'Ozlo’s comfy Sleepbuds are nearly 30 percent off in the run-up to Mother’s Day', 'https://www.theverge.com/gadgets/913352/ozlo-sleepbuds-mothers-day-deal-sale', 'The Verge', 'https://www.theverge.com/rss/index.xml', 5, '{General}', 'Ozlo’s comfy Sleepbuds are nearly 30 percent off in the run-up to Mother’s Day', '2026-04-16 19:00:00+00', '2026-04-17 06:57:24.893536+00', 'If you’re struggling to get a full night of rest, a good pair of sleep earbuds can help you tune out unwanted distractions. The Ozlo Sleepbuds are one such option, and they’re currently available for $249 ($100 off) in the run-up to Mother’s Day at Amazon and Ozlo’s online storefront, which is easily the lowest [&#8230;]', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (155, 'Teenage Engineering might be getting into instrument amps next', 'https://www.theverge.com/gadgets/913396/teenage-engineering-ko-amp-35-leak', 'The Verge', 'https://www.theverge.com/rss/index.xml', 5, '{General}', 'Teenage Engineering might be getting into instrument amps next', '2026-04-16 18:57:16+00', '2026-04-17 06:57:27.356131+00', 'An unannounced Teenage Engineering device, the KO-Amp 35, can be found over at the FCC in a new filing. The label clearly marks it as a member of the mid-range EP family instruments, which currently includes the KO-II and its spinoffs, the Riddim and the Medieval. The name suggests that TE could be getting into [&#8230;]', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (156, 'The only way to fight deepfakes is by making deepfakes', 'https://www.theverge.com/report/913445/deepfake-detection-reality-defender-pindrop-ai', 'The Verge', 'https://www.theverge.com/rss/index.xml', 5, '{General}', 'The only way to fight deepfakes is by making deepfakes', '2026-04-16 18:45:00+00', '2026-04-17 06:57:29.181668+00', 'I was unsure if my parents would notice that the voice on the other end wasn''t mine - or that it was mine, sort of, but it wasn''t me. The voice said hello, asked my dad how he was doing, and asked again when he didn''t respond quickly enough. "What is that, Gaby?" He realized [&#8230;]', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (157, 'Casely has reannounced a power bank recall from 2025 following a fatality', 'https://www.theverge.com/tech/913177/casely-recall-power-pods-wireless-bank-lithium-ion-battery-fire-explosion-uscpsc', 'The Verge', 'https://www.theverge.com/rss/index.xml', 5, '{General}', 'Casely has reannounced a power bank recall from 2025 following a fatality', '2026-04-16 18:40:03+00', '2026-04-17 06:57:30.978012+00', 'Casely first recalled over 429,000 of its 5,000mAh Power Pods wireless power banks in April 2025 following 51 reports of their lithium-ion batteries "overheating, expanding or catching fire," resulting in six minor burn injuries. Both the company and the US Consumer Product Safety Commission (USCPSC) are reannouncing the same recall today following 28 additional reports [&#8230;]', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (158, 'Salesforce launches Headless 360 to turn its entire platform into infrastructure for AI agents', 'https://venturebeat.com/technology/salesforce-launches-headless-360-to-turn-its-entire-platform-into-infrastructure-for-ai-agents', 'VentureBeat', 'https://feeds.feedburner.com/venturebeat/SZYF', 5, '{General}', 'Salesforce launches Headless 360 to turn its entire platform into infrastructure for AI agents', '2026-04-16 21:00:00+00', '2026-04-17 06:57:33.064674+00', '<p><a href="https://www.salesforce.com/">Salesforce</a> on Wednesday unveiled the most ambitious architectural transformation in its 27-year history, introducing &quot;<a href="https://www.salesforce.com/news/stories/salesforce-headless-360-announcement/">Headless 360</a>&quot; — a sweeping initiative that exposes every capability in its platform as an API, MCP tool, or CLI command so AI agents can operate the entire system without ever opening a browser.</p><p>The announcement, made at the company&#x27;s annual <a href="https://www.salesforce.com/tdx/">TDX developer conference</a> in San Francisco, ships more than 100 new tools and skills immediately available to developers. It marks a decisive response to the existential question hanging over enterprise software: In a world where AI agents can reason, plan, and execute, does a company still need a CRM with a graphical interface?</p><p>Salesforce&#x27;s answer: No — and that&#x27;s exactly the point.</p><p>&quot;We made a decision two and a half years ago: Rebuild Salesforce for agents,&quot; the company said in its announcement. &quot;Instead of burying capabilities behind a UI, expose them so the entire platform will be programmable and accessible from anywhere.&quot;</p><p>The timing is anything but coincidental. Salesforce finds itself navigating one of the most turbulent periods in enterprise software history — a sector-wide sell-off that has pushed the iShares Expanded Tech-Software Sector ETF <a href="https://www.cnbc.com/2026/02/26/saas-software-saaspocalypse-sell-off-ai-openai-anthropic-oracle-salesforce.html">down roughly 28%</a> from its September peak. The fear driving the decline: that AI, particularly large language models from Anthropic, OpenAI, and others, could render traditional SaaS business models obsolete.</p><p><a href="https://www.salesforce.com/news/stories/author/jayesh-govindarajan/">Jayesh Govindarjan</a>, EVP of Salesforce and one of the key architects behind the Headless 360 initiative, described the announcement as rooted not in marketing theory but in hard-won lessons from deploying agents with thousands of enterprise customers.</p><p>&quot;The problem that emerged is the lifecycle of building an agentic system for every one of our customers on any stack, whether it&#x27;s ours or somebody else&#x27;s,&quot; Govindarjan told VentureBeat in an exclusive interview. &quot;The challenge that they face is very much the software development challenge. How do I build an agent? That&#x27;s only step one.&quot;</p><h2><b>More than 100 new tools give coding agents full access to the Salesforce platform for the first time</b></h2><p>Salesforce <a href="https://www.salesforce.com/news/stories/salesforce-headless-360-announcement/">Headless 360</a> rests on three pillars that collectively represent the company&#x27;s attempt to redefine what an enterprise platform looks like in the agentic era.</p><p>The first pillar — build any way you want — delivers more than <a href="https://www.salesforce.com/news/stories/salesforce-headless-360-announcement/">60 new MCP (Model Context Protocol) tools</a> and 30-plus preconfigured coding skills that give external coding agents like Claude Code, Cursor, Codex, and Windsurf complete, live access to a customer&#x27;s entire Salesforce org, including data, workflows, and business logic. Developers no longer need to work inside Salesforce&#x27;s own IDE. They can direct AI coding agents from any terminal to build, deploy, and manage Salesforce applications.</p><p><a href="https://www.salesforce.com/service/demos/agentforce-for-service/?d=701ed000003k9a6AAA&amp;nc=701ed000003kErPAAU&amp;utm_content=701ed000003k9a6AAA&amp;utm_source=google&amp;utm_medium=paid_search&amp;utm_campaign=21111797517&amp;utm_adgroup=176814593425&amp;utm_term=agentforce%20service&amp;utm_matchtype=p&amp;gclsrc=aw.ds&amp;gad_source=1&amp;gad_campaignid=21111797517&amp;gbraid=0AAAAAD4PnrM1AwwpMOV0LfYGfxuZJZgM5&amp;gclid=Cj0KCQjwkYLPBhC3ARIsAIyHi3TDuoIJARMmz2NKtFE82f0uXfC6X5_7sZU2PPxW7600JcFhVR6KWUYaApQCEALw_wcB">Agentforce Vibes 2.0</a>, the company&#x27;s own native development environment, now includes what it calls an &quot;open agent harness&quot; supporting both the <a href="https://code.claude.com/docs/en/agent-sdk/overview">Anthropic agent SDK</a> and the <a href="https://openai.com/index/the-next-evolution-of-the-agents-sdk/">OpenAI agents SDK</a>. As demonstrated during the keynote, developers can choose between Claude Code and OpenAI agents depending on the task, with the harness dynamically adjusting available capabilities based on the selected agent. The environment also adds multi-model support, including Claude Sonnet and GPT-5, along with full org awareness from the start.</p><p>A significant technical addition is <a href="https://developer.salesforce.com/blogs/2026/04/build-with-react-run-on-salesforce-introducing-salesforce-multi-framework">native React support on the Salesforce platform</a>. During the keynote demo, presenters built a fully functional partner service application using React — not Salesforce&#x27;s own Lightning framework — that connected to org metadata via GraphQL while inheriting all platform security primitives. This opens up dramatically more expressive front-end possibilities for developers who want complete control over the visual layer.</p><p>The second pillar — deploy on any surface — centers on the new <a href="https://www.salesforce.com/agentforce/resources/maximizing-roi-with-agentforce/?d=701ed00000pAMHLAA4&amp;nc=701ed00000pBB3kAAG&amp;utm_content=701ed00000pAMHLAA4&amp;utm_source=google&amp;utm_medium=paid_search&amp;utm_campaign=21746031327&amp;utm_adgroup=192654615024&amp;utm_term=agentforce&amp;utm_matchtype=p&amp;gclsrc=aw.ds&amp;gad_source=1&amp;gad_campaignid=21746031327&amp;gbraid=0AAAAAD4PnrNSAUHeAfP8_ATTlAQ25bVP6&amp;gclid=Cj0KCQjwkYLPBhC3ARIsAIyHi3RZbLYycHjrr645-ZO9PlbrmlQ03Q9m9-aHI51Zpxv2PkWQ7rRR_tgaAv0XEALw_wcB">Agentforce Experience Layer</a>, which separates what an agent does from how it appears, rendering rich interactive components natively across Slack, mobile apps, Microsoft Teams, ChatGPT, Claude, Gemini, and any client supporting MCP apps. During the keynote, presenters defined an experience once and deployed it across six different surfaces without writing surface-specific code. The philosophical shift is significant: rather than pulling customers into a Salesforce UI, enterprises push branded, interactive agent experiences into whatever workspace their customers already inhabit.</p><p>The third pillar — build agents you can trust at scale — introduces an entirely new suite of lifecycle management tools spanning testing, evaluation, experimentation, observation, and orchestration. <a href="https://developer.salesforce.com/docs/ai/agentforce/guide/agent-script.html">Agent Script</a>, the company&#x27;s new domain-specific language for defining agent behavior deterministically, is now generally available and open-sourced. A new <a href="https://help.salesforce.com/s/articleView?id=ai.agent_testing_center.htm&amp;language=en_US&amp;type=5">Testing Center </a>surfaces logic gaps and policy violations before deployment. Custom Scoring Evals let enterprises define what &quot;good&quot; looks like for their specific use case. And a new A/B Testing API enables running multiple agent versions against real traffic simultaneously.</p><h2><b>Why enterprise customers kept breaking their own AI agents — and how Salesforce redesigned its tooling in response</b></h2><p>Perhaps the most technically significant — and candid — portion of VentureBeat&#x27;s interview with Govindarjan addressed the fundamental engineering tension at the heart of enterprise AI: agents are probabilistic systems, but enterprises demand deterministic outcomes.</p><p>Govindarjan explained that early Agentforce customers, after getting agents into production through &quot;sheer hard work,&quot; discovered a painful reality. &quot;They were afraid to make changes to these agents, because the whole system was brittle,&quot; he said. &quot;You make one change and you don&#x27;t know whether it&#x27;s going to work 100% of the time. All the testing you did needs to be redone.&quot;</p><p>This brittleness problem drove the creation of <a href="https://developer.salesforce.com/docs/ai/agentforce/guide/agent-script.html">Agent Script</a>, which Govindarjan described as a programming language that &quot;brings together the determinism that&#x27;s in programming languages with the inherent flexibility in probabilistic systems that LLMs provide.&quot; The language functions as a single flat file — versionable, auditable — that defines a state machine governing how an agent behaves. Within that machine, enterprises specify which steps must follow explicit business logic and which can reason freely using LLM capabilities.</p><p>Salesforce <a href="https://github.com/salesforce/agentscript">open-sourced Agent Script</a> this week, and Govindarjan noted that Claude Code can already generate it natively because of its clean documentation. The approach stands in sharp contrast to the &quot;vibe coding&quot; movement gaining traction elsewhere in the industry. As the Wall Street Journal recently reported, <a href="https://www.wsj.com/cio-journal/meet-the-companies-vibe-coding-their-own-crms-263e500f">some companies are now attempting to vibe-code entire CRM replacements</a> — a trend Salesforce&#x27;s <a href="https://www.salesforce.com/news/stories/salesforce-headless-360-announcement/">Headless 360</a> directly addresses by making its own platform the most agent-friendly substrate available.</p><p>Govindarjan described the tooling as a product of Salesforce&#x27;s own internal practice. &quot;We needed these tools to make our customers successful. Then our FDEs needed them. We hardened them, and then we gave them to our customers,&quot; he told VentureBeat. In other words, Salesforce productized its own pain.</p><h2><b>Inside the two competing AI agent architectures Salesforce says every enterprise will need</b></h2><p>Govindarjan drew a revealing distinction between two fundamentally different agentic architectures emerging in the enterprise — one for customer-facing interactions and one he linked to what he called the &quot;<a href="https://venturebeat.com/technology/how-ralph-wiggum-went-from-the-simpsons-to-the-biggest-name-in-ai-right-now">Ralph Wiggum loop</a>.&quot;</p><p>Customer-facing agents — those deployed to interact with end customers for sales or service — demand tight deterministic control. &quot;Before customers are willing to put these agents in front of their customers, they want to make sure that it follows a certain paradigm — a certain brand set of rules,&quot; Govindarjan told VentureBeat. Agent Script encodes these as a static graph — a defined funnel of steps with LLM reasoning embedded within each step.</p><p>The &quot;<a href="https://venturebeat.com/technology/how-ralph-wiggum-went-from-the-simpsons-to-the-biggest-name-in-ai-right-now">Ralph Wiggum loop</a>,&quot; by contrast, represents the opposite end of the spectrum: a dynamic graph that unrolls at runtime, where the agent autonomously decides its next step based on what it learned in the previous step, killing dead-end paths and spawning new ones until the task is complete. This architecture, Govindarjan said, manifests primarily in employee-facing scenarios — developers using coding agents, salespeople running deep research loops, marketers generating campaign materials — where an expert human reviews the output before it ships.</p><p>&quot;Ralph Wiggum loops are great for employee-facing because employees are, in essence, experts at something,&quot; Govindarjan explained. &quot;Developers are experts at development, salespeople are experts at sales.&quot;</p><p>The critical technical insight: both architectures run on the same underlying platform and the same graph engine. &quot;This is a dynamic graph. This is a static graph,&quot; he said. &quot;It&#x27;s all a graph underneath.&quot; That unified runtime — spanning the spectrum from tightly controlled customer interactions to free-form autonomous loops — may be Salesforce&#x27;s most important technical bet, sparing enterprises from maintaining separate platforms for different agent modalities.</p><h2><b>Salesforce hedges its bets on MCP while opening its ecosystem to every major AI model and tool</b></h2><p>Salesforce&#x27;s embrace of openness at TDX was striking. The platform now integrates with <a href="https://openai.com/">OpenAI</a>, <a href="https://www.anthropic.com/">Anthropic</a>, <a href="https://gemini.google.com/app">Google Gemini</a>, <a href="https://www.llama.com/">Meta&#x27;s LLaMA</a>, and <a href="https://mistral.ai/models">Mistral AI</a> models. The open agent harness supports third-party agent SDKs. MCP tools work from any coding environment. And the new <a href="https://www.salesforce.com/agentforce/agentexchange/">AgentExchange marketplace</a> unifies 10,000 Salesforce apps, 2,600-plus Slack apps, and 1,000-plus Agentforce agents, tools, and MCP servers from partners including Google, Docusign, and Notion, backed by a new $50 million AgentExchange Builders Initiative.</p><p>Yet Govindarjan offered a surprisingly candid assessment of MCP itself — the protocol Anthropic created that has become a de facto standard for agent-tool communication.</p><p>&quot;To be very honest, not at all sure&quot; that MCP will remain the standard, he told VentureBeat. &quot;When MCP first came along as a protocol, a lot of us engineers felt that it was a wrapper on top of a really well-written CLI — which now it is. A lot of people are saying that maybe CLI is just as good, if not better.&quot;</p><p>His approach: pragmatic flexibility. &quot;We&#x27;re not wedded to one or the other. We just use the best, and often we will offer all three. We offer an API, we offer a CLI, we offer an MCP.&quot; This hedging explains the &quot;Headless 360&quot; naming itself — rather than betting on a single protocol, Salesforce exposes every capability across all three access patterns, insulating itself against protocol shifts.</p><p><a href="https://engine.com/">Engine</a>, the B2B travel management company featured prominently in the keynote demos, offered a real-world proof point for the open ecosystem approach. The company built its customer service agent, Ava, in 12 days using Agentforce and now handles 50% of customer cases autonomously. Engine runs five agents across customer-facing and employee-facing functions, with Data 360 at the heart of its infrastructure and Slack as its primary workspace. &quot;CSAT goes up, costs to deliver go down. Customers are happier. We&#x27;re getting them answers faster. What&#x27;s the trade off? There&#x27;s no trade off,&quot; an Engine executive said during the keynote.</p><p>Underpinning all of it is a shift in how Salesforce gets paid. The company is moving from per-seat licensing to consumption-based pricing for Agentforce — a transition Govindarjan described as &quot;a business model change and innovation for us.&quot; It&#x27;s a tacit acknowledgment that when agents, not humans, are doing the work, charging per user no longer makes sense.</p><h2><b>Salesforce isn&#x27;t defending the old model — it&#x27;s dismantling it and betting the company on what comes next</b></h2><p>Govindarjan framed the company&#x27;s evolution in architectural terms. Salesforce has organized its platform around four layers: a system of context (<a href="https://www.salesforce.com/data/demos/data-cloud/?d=7013y000002ExkzAAC&amp;nc=7013y000002EyXSAA0&amp;utm_content=7013y000002ExkzAAC&amp;utm_source=google&amp;utm_medium=paid_search&amp;utm_campaign=21134104451&amp;utm_adgroup=161913224524&amp;utm_term=salesforce%20data&amp;utm_matchtype=p&amp;gclsrc=aw.ds&amp;gad_source=1&amp;gad_campaignid=21134104451&amp;gbraid=0AAAAAD4PnrPnIjyiB0fbGAiHNB3eJEWN9&amp;gclid=Cj0KCQjwkYLPBhC3ARIsAIyHi3SevPZf6by7PpC2t5_zf3xvZWC841GkpB7PH7VBbn0QSSFAX-66eqMaAkbQEALw_wcB">Data 360</a>), a system of work (<a href="https://www.salesforce.com/products/what-is-customer-360/">Customer 360 apps</a>), a system of agency (<a href="https://www.salesforce.com/agentforce/resources/maximizing-roi-with-agentforce/?d=701ed00000pAMHNAA4&amp;nc=701ed00000pBB3mAAG&amp;utm_content=701ed00000pAMHNAA4&amp;utm_source=google&amp;utm_medium=paid_search&amp;utm_campaign=21746031327&amp;utm_adgroup=167932510533&amp;utm_term=agentforce&amp;utm_matchtype=e&amp;gclsrc=aw.ds&amp;gad_source=1&amp;gad_campaignid=21746031327&amp;gbraid=0AAAAAD4PnrNSAUHeAfP8_ATTlAQ25bVP6&amp;gclid=Cj0KCQjwkYLPBhC3ARIsAIyHi3R73LzLcCGps4kW0OwZ2C1RCUNiz9Tt0bp8U83p82IGLB1DqTHfKK0aAjykEALw_wcB">Agentforce</a>), and a system of engagement (Slack and other surfaces). Headless 360 opens every layer via programmable endpoints.</p><p>&quot;What you saw today, what we&#x27;re doing now, is we&#x27;re opening up every single layer, right, with MCP tools, so we can go build the agentic experiences that are needed,&quot; Govindarjan told VentureBeat. &quot;I think you&#x27;re seeing a company transforming itself.&quot;</p><p>Whether that transformation succeeds will depend on execution across thousands of customer deployments, the staying power of MCP and related protocols, and the fundamental question of whether incumbent enterprise platforms can move fast enough to remain relevant when AI agents can increasingly build new systems from scratch. The software sector&#x27;s bear market, the financial pressures bearing down on the entire industry, and the breathtaking pace of LLM improvement all conspire to make this one of the highest-stakes bets in enterprise technology.</p><p>But there is an irony embedded in Salesforce&#x27;s predicament that <a href="https://www.salesforce.com/news/stories/salesforce-headless-360-announcement/">Headless 360</a> makes explicit. The very AI capabilities that threaten to displace traditional software are the same capabilities that Salesforce now harnesses to rebuild itself. Every coding agent that could theoretically replace a CRM is now, through Headless 360, a coding agent that builds on top of one. The company is not arguing that agents won&#x27;t change the game. It&#x27;s arguing that decades of accumulated enterprise data, workflows, trust layers, and institutional logic give it something no coding agent can generate from a blank prompt.</p><p>As <a href="http://google.com/search?q=mad+money+marc+benioff&amp;oq=mad+money+marc+benioff&amp;gs_lcrp=EgZjaHJvbWUyBggAEEUYOTIGCAEQRRg80gEINDE3MWowajeoAgCwAgA&amp;sourceid=chrome&amp;ie=UTF-8">Benioff declared on CNBC&#x27;s Mad Money</a> in March: &quot;The software industry is still alive, well and growing.&quot; Headless 360 is his company&#x27;s most forceful attempt to prove him right — by tearing down the walls of the very platform that made Salesforce famous and inviting every agent in the world to walk through the front door.</p><p>Parker Harris, Salesforce&#x27;s co-founder, captured the bet most succinctly in a question he posed last month: &quot;Why should you ever log into Salesforce again?&quot;</p><p>If Headless 360 works as designed, the answer is: You shouldn&#x27;t have to. And that, Salesforce is wagering, is precisely what will keep you paying for it.
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (159, 'Are we getting what we paid for? How to turn AI momentum into measurable value', 'https://venturebeat.com/infrastructure/are-we-getting-what-we-paid-for-how-to-turn-ai-momentum-into-measurable-value', 'VentureBeat', 'https://feeds.feedburner.com/venturebeat/SZYF', 5, '{General}', 'Are we getting what we paid for? How to turn AI momentum into measurable value', '2026-04-16 19:55:13+00', '2026-04-17 06:57:36.831353+00', '<p>Enterprise AI is entering a new phase — one where the central question is no longer what can be built, but how to make the most of our AI investment.</p><p>At VentureBeat’s latest AI Impact Tour session, Brian Gracely, director of portfolio strategy at Red Hat, described the operational reality inside large organizations: AI sprawl, rising inference costs, and limited visibility into what those investments are actually returning.</p><p>It’s the “Day 2” moment — when pilots give way to production, and cost, governance, and sustainability become harder than building the system in the first place.</p><p>&quot;We&#x27;ve seen customers who say, &#x27;I have 50,000 licenses of Copilot. I don&#x27;t really know what people are getting out of that. But I do know that I&#x27;m paying for the most expensive computing in the world, because it&#x27;s GPUs,&#x27;&quot; Gracely said. &quot;&#x27;How am I going to get that under control?&#x27;&quot;</p><h2>Why enterprise AI costs are now a board-level problem</h2><p>For much of the past two years, cost was not the primary concern for organizations evaluating generative AI. The experimental phase gave teams cover to spend freely, and the promise of productivity gains justified aggressive investment, but that dynamic is shifting as enterprises enter their second and third budget cycles with AI. The focus has moved from &quot;can we build something?&quot; to &quot;are we getting what we paid for?&quot;</p><p>Enterprises that made large, early bets on managed AI services are conducting hard reviews of whether those investments are delivering measurable value. The issue isn’t just that GPU computing is expensive. It is that many organizations lack the instrumentation to connect spending to outcomes, making it nearly impossible to justify renewals or scale responsibly.</p><h2>The strategic shift from token consumer to token producer</h2><p>The dominant AI procurement model of the past few years has been straightforward: pay a vendor per token, per seat, or per API call, and let someone else manage the infrastructure. That model made sense as a starting point but is increasingly being questioned by organizations with enough experience to compare alternatives.</p><p>Enterprises that have been through one AI cycle are starting to rethink that model.</p><p>&quot;Instead of being purely a token consumer, how can I start being a token generator?&quot; Gracely said. &quot;Are there use cases and workloads that make sense for me to own more? It may mean operating GPUs. It may mean renting GPUs. And then asking, &#x27;Does that workload need the greatest state-of-the-art model? Are there more capable open models or smaller models that fit?&#x27;&quot;</p><p>The decision is not binary. The right answer depends on the workload, the organization, and the risk tolerance involved, but the math is getting more complicated as the number of capable open models, from DeepSeek to models now available through cloud marketplaces, grows. Now enterprises actually have real alternatives to the handful of providers that dominated the landscape two years ago.</p><h2>Falling AI costs and rising usage create a paradox for enterprise budgets</h2><p>Some enterprise leaders argue that locking into infrastructure investments now could mean significantly overpaying in the long run, pointing to the statement from Anthropic CEO Dario Amodei that AI inference costs are declining roughly 60% per year. </p><p>The emergence of open-source models such as DeepSeek and others has meaningfully expanded the strategic options available to enterprises that are willing to invest in the underlying infrastructure in the last three years.</p><p>But while costs per token are falling, usage is accelerating at a pace that more than offsets efficiency gains. It&#x27;s a version of Jevons Paradox, the economic principle that improvements in resource efficiency tend to increase total consumption rather than reduce it, as lower cost enables broader adoption. </p><p>For enterprise budget planners, this means declining unit costs do not translate into declining total bills. An organization that triples its AI usage while costs fall by half still ends up spending more than it did before. The consideration becomes which workloads genuinely require the most capable and most expensive models, and which can be handled just fine by smaller, cheaper alternatives.</p><h2>The business case for investing in AI infrastructure flexibility</h2><p>The prescription isn&#x27;t to slow down AI investment, but to build with flexibility being top of mind. The organizations that will win aren&#x27;t necessarily the ones that move fastest or spend the most; they&#x27;re the ones building infrastructure and operating models capable of absorbing the next unexpected development.</p><p>&quot;The more you can build some abstractions and give yourself some flexibility, the more you can experiment without running up costs, but also without jeopardizing your business. Those are as important as asking whether you&#x27;re doing everything best practice right now,&quot; Gracely explained.</p><p>But despite how entrenched AI discussions have become in enterprise planning cycles, the practical experience most organizations have is still measured in years, not decades. </p><p>&quot;It feels like we&#x27;ve been doing this forever. We&#x27;ve been doing this for three years,&quot; Gracely added. &quot;It&#x27;s early and it&#x27;s moving really fast. You don&#x27;t know what&#x27;s coming next. But the characteristics of what&#x27;s coming next — you should have some sense of what that looks like.”</p><p>For enterprise leaders still calibrating their AI investment strategies, that may be the most actionable takeaway: the goal is not to optimize for today&#x27;s cost structure, but to build the organizational and technical flexibility to adapt when, not if, it changes again.</p>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (160, 'OpenAI debuts GPT-Rosalind, a new limited access model for life sciences, and broader Codex plugin on Github', 'https://venturebeat.com/technology/openai-debuts-gpt-rosalind-a-new-limited-access-model-for-life-sciences-and-broader-codex-plugin-on-github', 'VentureBeat', 'https://feeds.feedburner.com/venturebeat/SZYF', 5, '{General}', 'OpenAI debuts GPT-Rosalind, a new limited access model for life sciences, and broader Codex plugin on Github', '2026-04-16 19:02:45+00', '2026-04-17 06:57:39.186245+00', '<p>The journey from a laboratory hypothesis to a pharmacy shelf is one of the most grueling marathons in modern industry, typically spanning 10 to 15 years and billions of dollars in investment. </p><p>Progress is often stymied not just by the inherent mysteries of biology, but by the &quot;fragmented and difficult to scale&quot; workflows that force researchers to manually pivot between the actual experimental design equipment, software, and databases.</p><p>But OpenAI is releasing a new specialized model <b>GPT-Rosalind</b> specifically to speed up this process and make it more efficient, easier, and ideally, more productive. Named after the pioneering chemist Rosalind Franklin, whose work was vital to the discovery of DNA’s structure (and was often overlooked for her male colleagues James Watson and Francis Crick), this new frontier reasoning model is purpose-built to act as a specialized intelligence layer for life sciences research.</p><p>By shifting AI’s role from a general-purpose assistant to a domain-specific &quot;reasoning&quot; partner, OpenAI is signaling a long-term commitment to biological and chemical discovery. </p><h2><b>What GPT-Rosalind offers</b></h2><p>GPT-Rosalind isn&#x27;t just about faster text generation; it is designed to synthesize evidence, generate biological hypotheses, and plan experiments—tasks that have traditionally required years of expert human synthesis.</p><p>At its core, GPT-Rosalind is the first in a new series of models optimized for scientific workflows. While previous iterations of GPT excelled at general language tasks, this model is fine-tuned for deeper understanding across genomics, protein engineering, and chemistry.</p><p>To validate its capabilities, OpenAI tested the model against several industry benchmarks. On BixBench, a metric for real-world bioinformatics and data analysis, GPT-Rosalind achieved leading performance among models with published scores. </p><p>In more granular testing via LABBench2, the model outperformed GPT-5.4 on six out of eleven tasks, with the most significant gains appearing in CloningQA—a task requiring the end-to-end design of reagents for molecular cloning protocols.</p><p>The model’s most striking performance signal came from a partnership with Dyno Therapeutics. In an evaluation using unpublished, &quot;uncontaminated&quot; RNA sequences, GPT-Rosalind was tasked with sequence-to-function prediction and generation. </p><p>When evaluated directly in the Codex environment, the model’s submissions ranked above the 95th percentile of human experts on prediction tasks and reached the 84th percentile for sequence generation.</p><p> This level of expertise suggests the model can serve as a high-level collaborator capable of identifying &quot;expert-relevant patterns&quot; that generalist models often overlook.</p><h2><b>The new lab workflow</b></h2><p>OpenAI is not just releasing a model; it is launching an ecosystem designed to integrate with the tools scientists already use. Central to this is a new <b>Life Sciences research plugin for Codex, available on GitHub.</b></p><p>Scientific research is famously siloed. A single project might require a researcher to consult a protein structure database, search through 20 years of clinical literature, and then use a separate tool for sequence manipulation. The new plugin acts as an &quot;orchestration layer,&quot; providing a unified starting point for these multi-step questions.</p><ul><li><p><b>Skill Set</b>: The package includes modular skills for biochemistry, human genetics, functional genomics, and clinical evidence.</p></li><li><p><b>Connectivity</b>: It connects models to over <b>50 public multi-omics databases</b> and literature sources.</p></li><li><p><b>Efficiency</b>: This approach targets &quot;long-horizon, tool-heavy scientific workflows,&quot; allowing researchers to automate repeatable tasks like protein structure lookups and sequence searches.</p></li></ul><h2><b>Limited and gated access</b></h2><p>Given the potential power of a model capable of redesigning biological structures, OpenAI is eschewing a broad &quot;open-source&quot; or general public release in favor of a Trusted Access program.</p><p>The model is launching as a research preview specifically for qualified Enterprise customers in the United States. This restricted deployment is built on three core principles: beneficial use, strong governance, and controlled access. </p><p>Organizations requesting access must undergo a qualification and safety review to ensure they are conducting legitimate research with a clear public benefit.</p><p>Unlike general-use models, GPT-Rosalind was developed with heightened enterprise-grade security controls. For the end-user, this means:</p><ul><li><p><b>Restricted Access</b>: Usage is limited to approved users within secure, well-managed environments.</p></li><li><p><b>Governance</b>: Participating organizations must maintain strict misuse-prevention controls and agree to specific life sciences research preview terms.</p></li><li><p><b>Cost</b>: During the preview phase, the model will not consume existing credits or tokens, allowing researchers to experiment without immediate budgetary constraints (subject to abuse guardrails).</p></li></ul><h2><b>Warm reception from initial industry partners</b></h2><p>The announcement garnered significant buy-in from OpenAI parnters across the pharmaceutical and technology sectors. </p><p>Sean Bruich, SVP of AI and Data at Amgen, noted that the collaboration allows the company to apply advanced tools in ways that could &quot;accelerate how we deliver medicines to patients&quot;.The impact is also being felt in the specialized tech infrastructure that supports labs:</p><ul><li><p><b>NVIDIA</b>: Kimberly Powell, VP of Healthcare and Life Sciences, described the convergence of domain reasoning and accelerated computing as a way to &quot;compress years of traditional R&amp;D into immediate, actionable scientific insights&quot;.</p></li><li><p><b>Moderna</b>: CEO Stéphane Bancel highlighted the model&#x27;s ability to &quot;reason across complex biological evidence&quot; to help teams translate insights into experimental workflows.</p></li><li><p><b>The Allen Institute</b>: CTO Andy Hickl emphasized that GPT-Rosalind stands out for making manual steps—like finding and aligning data—more &quot;consistent and repeatable in an agentic workflow&quot;.</p></li></ul><p>This builds on tangible results OpenAI has already seen in the field, such as its collaboration with Ginkgo Bioworks, where AI models helped achieve a 40% reduction in protein production costs.</p><h2><b>What&#x27;s next for Rosalind and OpenAI in life sciences?</b></h2><p>OpenAI’s mission with GPT-Rosalind is to narrow the gap between a &quot;promising scientific idea&quot; and the actual &quot;evidence, experiments, and decisions&quot; required for medical progress. </p><p>By partnering with institutions like Los Alamos National Laboratory to explore AI-guided catalyst design and biological structure modification, the company is positioning GPT-Rosalind as more than a tool—it is meant to be a &quot;capable partner in discovery&quot;.</p><p>As the life sciences field becomes increasingly data-dense, the move toward specialized &quot;reasoning&quot; models like Rosalind may become the standard for navigating the &quot;vast search spaces&quot; of biology and chemistry.</p>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (161, 'OpenAI drastically updates Codex desktop app to use all other apps on your computer, generate images, preview webpages', 'https://venturebeat.com/technology/openai-drastically-updates-codex-desktop-app-to-use-all-other-apps-on-your-computer-generate-images-preview-webpages', 'VentureBeat', 'https://feeds.feedburner.com/venturebeat/SZYF', 5, '{General}', 'OpenAI drastically updates Codex desktop app to use all other apps on your computer, generate images, preview webpages', '2026-04-16 18:36:52+00', '2026-04-17 06:57:41.989841+00', '<p>Confirming it has reached 3 million weekly developers, <a href="https://openai.com/index/codex-for-almost-everything/">OpenAI is massively updating its Codex developer environment</a> via its Mac and Windows desktop apps today to bring it closer to the “Super App” the company has confirmed it is pursuing.</p><p>Before today, Codex was primarily an environment for using OpenAI’s underlying language models to write, edit, debug and ship software as directed by the user. </p><p>Now, Codex will be able to access all of the other apps on your computer, surface relevant information from within them to you when asked or proactively, take actions as directed in said applications, and, in the case of Mac users, even do so while you continue manually using your computer simultaneously to your agents working in the background.</p><div></div><p>Andrew Ambrosino, an OpenAI technical staffer on the Codex team, described the change plainly in an embargoed press briefing I attended virtually yesterday: “Codex can actually click on apps, launch apps, and type into apps. This works with any apps on your machine.” </p><p>Codex on desktop is further getting its own built-in web browser, allowing users to preview their front-end development, and a directly integrated pipeline to OpenAI’s powerful AI image generation model gpt-image-1.5, allowing users to generate imagery for their projects — everything from websites to presentations to full playable PC games with hundreds of assets — all in the same style.</p><p>As Thibault &quot;Tibo&quot; Sottiaux, Head of Codex at OpenAI, said during the briefing: “It’s not just about the growth. It is putting a very capable agent in the hands of builders, and now we’re seeing that we’re able to expand and do a lot more work entirely across your computer&quot;</p><p>Asked why OpenAI was pursuing all this in Codex, not its more recognizable flagship app, ChatGPT, Sottiaux told VentureBeat: “Codex is our most powerful agent.It already worked on your computer, and so we’re expanding the capabilities there. It felt very natural. We will make it make sense at some point.&quot;</p><p>The update comes as rival Anthropic has previously courted similar use cases with the launch of its <a href="https://venturebeat.com/orchestration/anthropic-says-claude-code-transformed-programming-now-claude-cowork-is">Claude Cowork</a> and redesigned <a href="https://venturebeat.com/orchestration/we-tested-anthropics-redesigned-claude-code-desktop-app-and-routines-heres-what-enterprises-should-know">Claude Code desktop app views</a>, all available within the Claude desktop app for Mac and Windows. But Claude does not allow for simultaneous background app cursor usage from the desktop app across all of a user&#x27;s apps like Codex does.</p><h2><b>Multiple agentic computer use workflows in the background on macOS</b></h2><p>The most significant technological leap in this release is &quot;Computer Use,&quot; limited for now to macOS users.</p><p>This feature allows Codex to break out of the traditional chatbot container to &quot;see, click, and type&quot; across all applications on a machine.</p><p>Crucially, this happens in the background. &quot;It can use apps on your computer in the background, as opposed to taking over your entire computer,&quot; explained Caffrey Lynch of OpenAI’s developer product communications. </p><p>This enables &quot;multi-agent&quot; workflows where Codex might be testing a frontend change or triaging a JIRA ticket while the developer continues working in a different application.</p><p>For Windows users, the core Codex desktop app remains available and supported — as does pulling information in from those apps to surface to the user in Codex  — though it lacks the cursor-level background interaction available on Mac at launch.</p><h2><b>A one-stop shop for end-to-end software development</b></h2><p>Beyond operating the OS, OpenAI is doubling down on the &quot;Software Development Lifecycle&quot; (SDLC). The Codex app now functions more like a unified workspace, supporting everything from GitHub PR reviews to managing remote infrastructure.</p><p>&quot;The simplest way to think about this release is teaching Codex and the app to work across a much larger surface area,&quot; said Andrew Ambrosino, lead of Codex app development. This surface area now includes:</p><ul><li><p><b>Integrated Browser</b>: An in-app browser allows developers to iterate on frontend designs by commenting directly on DOM elements, providing precise instructions for the agent to follow.</p></li><li><p><b>Visual Primitives</b>: By integrating gpt-image-1.5, Codex can now generate and iterate on images for mockups and game assets directly within the development workflow.</p></li><li><p><b>Expanded Sidebar</b>: The app now includes rich previews for non-code files such as PDFs, spreadsheets, and slide decks, alongside a summary pane to track agent plans and sources.</p></li><li><p><b>Terminal &amp; SSH</b>: The update adds support for multiple terminal tabs and an alpha feature for connecting to remote devboxes via SSH.</p></li></ul><p>To connect these disparate tasks, OpenAI is releasing more than 90 new plugins. These connectors—including CircleCI, GitLab, and Microsoft Suite—allow the agent to gather context and take action across the entire toolchain a developer uses daily.</p><p>In a demo video shown off during the briefing, OpenAI presented an example showing the user typing into the Codex prompt entry field, “Can you check Slack, Gmail, Google Calendar, and Notion and tell me what needs my attention?” showing how Codex can now scan across multiple apps and gather information from them all in single prompt, and surface what matters most to the user.</p><p>“You can @ mention them if you want Codex to use a specific app, or if not, Codex can discover which apps to use,” Ambrosino said.</p><h2><b>The ‘heartbeat’ of productivity</b></h2><p>One of the more subtle but powerful shifts is the introduction of persistent agency. Through &quot;Heartbeat Automations,&quot; Codex can now schedule future work for itself and &quot;wake up&quot; to continue long-term tasks. </p><p>This allows teams to set up agents that monitor Slack channels or Notion docs and proactively update documentation or landing PRs.</p><p>This is supported by a new &quot;Memory&quot; feature, currently in preview. Memory allows Codex to remember personal preferences, previous corrections, and gathered information, reducing the need for extensive custom instructions in every new session.</p><p>&quot;As you use Codex, Codex also becomes better at being proactive,&quot; noted Sottiaux.</p><p>This proactivity manifests in a &quot;daily brief&quot; style feature where the app suggests how to start the day by identifying open Google Doc comments or relevant Slack context.</p><p>It&#x27;s similar in spirit and practice to the new <a href="https://venturebeat.com/orchestration/we-tested-anthropics-redesigned-claude-code-desktop-app-and-routines-heres-what-enterprises-should-know">&quot;Routines&quot; feature launched by Anthropic for its Claude Code product</a> earlier this week.</p><h2><b>Licensing, pricing, and availability</b></h2><p>OpenAI has recently transitioned toward a more flexible pricing model for teams, including a $100 plan and pay-as-you-go options to accommodate the increased usage of autonomous agents. For individual users, these updates are rolling out today to those signed in to the Codex desktop app with ChatGPT.</p><p>While the <b>Codex desktop app is available on both macOS and Windows</b>, the rollout of specific features is tiered:</p><ul><li><p><b>Background Computer Use</b>: macOS only at launch.</p></li><li><p><b>Personalization (Memory/Suggestions)</b>: Coming soon for Enterprise, Edu, EU, and UK users.</p></li><li><p><b>Core Software Development Life Cycle Updates</b>: Available to all desktop app users starting today.</p></li></ul><h2><b>The vision: from developer tool to Super App for all</b></h2><p>When asked if these features represent the foundation of an AI &quot;Super App,&quot; Sottiaux confirmed the strategy: &quot;We’re building the Super App in the open and evolving it out of the Codex app&quot;.</p><p>The goal is to address the reality that developers spend a majority of their time on coordination and context-gathering rather than writing code. </p><p>By bringing Codex closer to the operating system and the broader ecosystem of developer tools, OpenAI is positioning it as the central nervous system for modern software development.</p><p>&quot;Our mission is to ensure that AGI benefits all of humanity,&quot; the company stated in its official announcement. &quot;That means narrowing the gap between what people can imagine and what they can actually build&quot;.</p>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (162, 'Anthropic releases Claude Opus 4.7, narrowly retaking lead for most powerful generally available LLM', 'https://venturebeat.com/technology/anthropic-releases-claude-opus-4-7-narrowly-retaking-lead-for-most-powerful-generally-available-llm', 'VentureBeat', 'https://feeds.feedburner.com/venturebeat/SZYF', 5, '{General}', 'Anthropic releases Claude Opus 4.7, narrowly retaking lead for most powerful generally available LLM', '2026-04-16 16:17:00+00', '2026-04-17 06:57:45.922604+00', '<p>Anthropic is publicly releasing its most powerful large language model yet,<a href="https://www.anthropic.com/news/claude-opus-4-7"> Claude Opus 4.7</a>, today — as it continues to keep an<a href="https://venturebeat.com/technology/anthropic-says-its-most-powerful-ai-cyber-model-is-too-dangerous-to-release"> even more powerful successor, Mythos,</a> restricted to a small number of external enterprise partners for <a href="https://venturebeat.com/security/mythos-detection-ceiling-security-teams-new-playbook">cybersecurity testing and patching vulnerabilities</a> in the software said enterprises use (which Mythos exposed rapidly).</p><p>The big headlines are that Opus 4.7 exceeds its most direct rivals — OpenAI&#x27;s GPT-5.4, <a href="https://venturebeat.com/technology/openai-launches-gpt-5-4-with-native-computer-use-mode-financial-plugins-for">released in early March 2026</a>, scarcely more than a month ago; and <a href="https://venturebeat.com/technology/google-launches-gemini-3-1-pro-retaking-ai-crown-with-2x-reasoning">Google&#x27;s latest flagship model Gemini 3.1 Pro from February</a> — on key benchmarks including agentic coding, scaled tool-use, agentic computer use, and financial analysis. </p><p>But also, it&#x27;s notable how tight the race is getting: on directly comparable benchmarks, Opus 4.7 only leads GPT-5.4 by 7-4.</p><p>It currently leads the market on the GDPVal-AA knowledge work evaluation with an Elo score of 1753, surpassing both GPT-5.4 (1674) and Gemini 3.1 Pro (1314). </p><p>Yet, the model does not represent a &quot;clean sweep&quot; across all categories. </p><p>Competitors like GPT-5.4 and Gemini 3.1 Pro still hold the lead in specific domains such as agentic search, where GPT-5.4 scores 89.3% compared to Opus 4.7’s 79.3%, as well as in multilingual Q&amp;A and raw terminal-based coding. </p><p>This positioning defines Opus 4.7 not as a unilateral victor in all AI tasks, but as a specialized powerhouse optimized for the reliability and long-horizon autonomy required by the burgeoning agentic economy.</p><p>Claude Opus 4.7 is available today across all major cloud platforms, including Amazon Bedrock, Google Cloud’s Vertex AI, and Microsoft Foundry, with <a href="https://platform.claude.com/docs/en/about-claude/models/overview">API pricing held steady at $5/$25 per million tokens</a>.</p><h2><b>Improvement in hard sciences and agentic workflows</b></h2><p>Claude Opus 4.7 is a direct evolution of the Opus 4.6 architecture, but its performance delta is most visible in the &quot;hard&quot; sciences of agentic workflows: software engineering and complex document reasoning. </p><p>At its core, the model has been re-tuned to exhibit what Anthropic describes as &quot;rigor&quot;. This isn&#x27;t just marketing parlance; it refers to the model’s new ability to devise its own verification steps before reporting a task as complete. </p><p>For example, in internal tests, the model was observed building a Rust-based text-to-speech engine from scratch and then independently feeding its own generated audio through a separate speech recognizer to verify the output against a Python reference. </p><p>This level of autonomous self-correction is designed to reduce the &quot;hallucination loops&quot; that often plague earlier iterations of agentic software.</p><p>The most significant architectural upgrade is the move to high-resolution multimodal support. Opus 4.7 can now process images up to 2,576 pixels on their longest edge—roughly 3.75 megapixels. </p><p>This represents a three-fold increase in resolution compared to previous iterations. For developers building &quot;computer-use&quot; agents that must navigate dense, high-DPI interfaces or for analysts extracting data from intricate technical diagrams, this change effectively removes the &quot;blurry vision&quot; ceiling that previously limited autonomous navigation. </p><p>This visual acuity is reflected in benchmarks from XBOW, where the model jumped from a 54.5% success rate in visual-acuity tests to 98.5%.</p><p>On the benchmark front, Opus 4.7 has claimed the top spot in several critical categories:</p><ul><li><p><b>Knowledge Work (GDPVal-AA):</b> It achieved an Elo score of 1753, notably outperforming GPT-5.4 (1674) and Gemini 3.1 Pro (1314).</p></li><li><p><b>Agentic Coding (SWE-bench Pro):</b> The model resolved 64.3% of tasks, compared to 53.4% for its predecessor.</p></li><li><p><b>Graduate-Level Reasoning (GPQA Diamond):</b> It reached 94.2%, maintaining parity with the industry&#x27;s most advanced models while improving on its internal consistency.</p></li><li><p><b>Visual Reasoning (arXiv Reasoning):</b> With tools, the model scored 91.0%, a meaningful jump from the 84.7% seen in Opus 4.6.</p></li></ul><p>Crucially, Anthropic warns that this increased precision requires a shift in how users approach prompting. Opus 4.7 follows instructions literally. While older models might &quot;read between the lines&quot; and interpret ambiguous prompts loosely, Opus 4.7 executes the exact text provided. This means that legacy prompt libraries may require re-tuning to avoid unexpected results caused by the model’s strict adherence to the letter of the request.</p><h2><b>Controlling the &#x27;thinking&#x27; budget</b></h2><p>The &quot;agentic&quot; nature of Opus 4.7—its tendency to pause, plan, and verify—comes with a trade-off in token consumption and latency. </p><p>To address this, Anthropic is introducing a new &quot;effort&quot; parameter. Users can now select an xhigh (extra high) effort level, positioned between high and max, allowing for more granular control over the depth of reasoning the model applies to a specific problem. </p><p>Internal data shows that while max effort yields the highest scores (approaching 75% on coding tasks), the xhigh setting provides a compelling sweet spot between performance and token expenditure.</p><p>To manage the costs associated with these more &quot;thoughtful&quot; runs, the Claude API is introducing &quot;task budgets&quot; in public beta. This allows developers to set a hard ceiling on token spend for autonomous agents, ensuring that a long-running debugging session doesn&#x27;t result in an unexpected bill. </p><p>These product changes signal a maturing market where AI is no longer a novelty but a production line item that requires fiscal and operational guardrails. </p><p>Furthermore, Opus 4.7 utilizes an updated tokenizer that improves text processing efficiency, though<b> it can increase the token count of certain inputs by 1.0–1.35x.</b></p><p>Within the Claude Code environment, the update brings a new <code>/ultrareview </code>command. Unlike standard code reviews that look for syntax errors, <code>/ultrareview</code> is designed to simulate a senior human reviewer, flagging subtle design flaws and logic gaps. </p><p>Additionally, &quot;auto mode&quot;—a setting where Claude can make autonomous decisions without constant permission prompts—has been extended to Max plan users.</p><h2><b>Licensing, safety, and the &quot;cyber&quot; divide</b></h2><p>Anthropic continues to walk a narrow line regarding cybersecurity. The recent announcement of the aforementioend cybersecurity partnership around Mythos with external industry partners —<a href="https://venturebeat.com/technology/anthropic-says-its-most-powerful-ai-cyber-model-is-too-dangerous-to-release"> known as &quot;Project Glasswing&quot; </a>— highlighted the dual-use risks of high-capability models. </p><p>Consequently, while the flagship Mythos Preview model remains restricted, Opus 4.7 serves as the testbed for new automated safeguards. The model includes systems designed to detect and block requests that suggest high-risk cyberattacks, such as automated vulnerability exploitation.</p><p>To bridge the gap for the security industry, Anthropic is launching the Cyber Verification Program. This allows legitimate professionals—vulnerability researchers, penetration testers, and red-teamers—to apply for access to use Opus 4.7’s capabilities for defensive purposes. </p><p>This &quot;verified user&quot; model suggests a future where the most capable AI features are not universally available, but gated behind professional credentials and compliance frameworks. </p><p>In cybersecurity vulnerability reproduction (CyberGym), Opus 4.7 maintains a 73.1% success rate, trailing Mythos Preview&#x27;s 83.1% but leading GPT-5.4&#x27;s 66.3%.</p><h2><b>Initial reactions from industry partners reveal quantifiable improvements in production enterprise workflows</b></h2><p>Early testimonials from enterprise customers shared by Anthropic indicate there has been a tangible shift in model perception of Opus 4.7 from 4.6, going from &quot;impressed by the tech&quot; to &quot;relying on the output&quot;.</p><p>Clarence Huang, VP of Technology at Intuit, noted that the model’s ability to &quot;catch its own logical faults during the planning phase&quot; is a game-changer for velocity. </p><p>This sentiment was echoed by Replit President Michele Catasta, who stated that the model achieved higher quality at a lower cost for tasks like log analysis and bug hunting, adding, &quot;It really feels like a better coworker&quot;.</p><p>Other specific reactions included:</p><ul><li><p><b>Cognition (Devin):</b> CEO Scott Wu reported that Opus 4.7 can work coherently &quot;for hours&quot; and pushes through difficult problems that previously caused models to stall.</p></li><li><p><b>Notion:</b> Sarah Sachs, AI Lead, highlighted a 14% improvement in multi-step workflows and a 66% reduction in tool-calling errors, making the agent feel like a &quot;true teammate&quot;.</p></li><li><p><b>Factory Droids:</b> Leo Tchourakov observed that the model carries work through to validation steps rather than &quot;stopping halfway,&quot; a common complaint with previous frontier models.</p></li><li><p><b>Harvey:</b> Niko Grupen, Head of Applied Research, noted the model&#x27;s 90.9% score on BigLaw Bench, highlighting its &quot;noticeably smarter handling of ambiguous document editing tasks&quot;.</p></li></ul><p>Perhaps the most telling reaction came from Aj Orbach, CEO of a dashboard-building firm, who remarked on the model’s &quot;design taste,&quot; noting that its choices for data-rich interfaces were of a quality he would &quot;actually ship&quot;.</p><h2><b>Should enterprises immediately upgrade to Opus 4.7?</b></h2><p>For enterprise leaders, Claude Opus 4.7 represents a shift from generative AI as a &quot;creative assistant&quot; to a &quot;reliable operative.&quot; </p><p>But importantly, <b>it is not a &quot;clean win&quot; for every use case. </b></p><p>Instead, it is a decisive upgrade for teams building autonomous agents or complex software systems. The primary value proposition is the model&#x27;s new capability for self-verification and rigor; it no longer just generates an answer but creates internal tests to verify that the answer is correct before responding. This reliability makes it a superior choice for long-horizon engineering tasks where the cost of human supervision is the primary bottleneck.</p><p>However,<b> an immediate, wholesale migration from Opus 4.6 requires caution</b>. The model&#x27;s increased literalism in instruction following means that prompts engineered to be &quot;loose&quot; or conversational with previous versions may now produce unexpected or overly rigid results. </p><p>Furthermore, enterprises must prepare for a significant increase in operational costs. Opus 4.7 uses an updated tokenizer that can increase input token counts by 1.0–1.35x, and its tendency to &quot;think harder&quot; at high effort levels results in higher output token consumption. </p><p>For <b>legacy applications where prompts are fragile and margins are thin, a phased rollout with significant re-tuning is recommended.</b></p><h2><b>Where it puts Anthropic in the AI race</b></h2><p>This release arrives at a paradoxical moment for Anthropic. Financially, the company is an undisputed juggernaut, with <a href="https://techcrunch.com/2026/04/15/anthropic-shrugs-off-vc-funding-offers-valuing-it-at-800b-for-now/">venture capital firms reportedly extending investment offers at a staggering $800 billion</a> valuation—more than double its $380 billion Series G valuation from February 2026. </p><p>This momentum is fueled by explosive growth, with the company’s annual run-rate revenue skyrocketing to $30 billion in April 2026, driven largely by enterprise adoption and the success of Claude Code.</p><p>Yet, this commercial success is being contested by intense regulatory and technical friction. <a href="https://venturebeat.com/technology/anthropic-vs-the-pentagon-what-enterprises-should-do">Anthropic is currently embroiled in a high-stakes legal battle with the U.S. Department of War (DoW)</a>, which recently labeled the company a &quot;supply chain risk&quot; after Anthropic refused to allow its models to be used for mass surveillance or fully autonomous lethal weapons. </p><p>While a San Francisco judge initially blocked the designation, a <a href="https://www.axios.com/2026/04/08/anthropic-loses-bid-to-block-pentagon-blacklisting">federal appeals panel recently denied Anthropic’s bid to stay the blacklisting</a>, leaving the company excluded from lucrative defense contracts during an active military conflict.</p><p>Simultaneously, Anthropic is fending off a growing rebellion from its most loyal power users. Despite the company&#x27;s &quot;market leader&quot; status, <a href="https://venturebeat.com/technology/is-anthropic-nerfing-claude-users-increasingly-report-performance">developers have flooded GitHub and X with accusations of &quot;AI shrinkflation,&quot;</a> claiming that the preceding Opus 4.6 model and Claude Code product have been quietly degraded. </p><p>Users report that recent versions are more prone to exploration loops, memory loss, and ignored instructions, leading some to describe the newly released Claude Code desktop app as &quot;unpolished&quot; and unbefitting a firm with a near-trillion-dollar valuation. Opus 4.7 is Anthropic&#x27;s attempt to silence these critics by proving that &quot;deep thinking&quot; can be paired with the rigorous execution that its enterprise clients now demand.</p><p>Ultimately, Opus 4.7 is a model defined by its discipline. In a market where models are often incentivized to be &quot;helpful&quot; to a fault—sometimes hallucinating answers to please the user—Opus 4.7 marks a return to rigor. By allowing users to control effort, set budgets, and verify outputs, Anthropic is moving closer to the goal of a truly autonomous digital labor force. For the engineering teams at Replit, Notion, and beyond, the shift from &quot;watching the AI work&quot; to &quot;managing the AI&#x27;s results&quot; has officially begun.</p>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (163, 'AI lowered the cost of building software. Enterprise governance hasn’t caught up', 'https://venturebeat.com/infrastructure/ai-lowered-the-cost-of-building-software-enterprise-governance-hasnt-caught', 'VentureBeat', 'https://feeds.feedburner.com/venturebeat/SZYF', 5, '{General}', 'AI lowered the cost of building software. Enterprise governance hasn’t caught up', '2026-04-16 07:00:00+00', '2026-04-17 06:57:48.812374+00', '<p><i>Presented by Retool </i></p><hr/><p>The logic used to be: buying software is cheaper, faster, and safer for most use cases. Building was reserved for companies with large engineering teams, deep pockets, and problems so specific that no vendor could address them. But now, the cost to code a piece of software has dropped to zero. </p><p>Anyone can build their own software now, but enterprise and governance models have yet to catch up. Retool’s <a href="http://retool.com/blog/ai-build-vs-buy-report-2026">2026 Build vs. Buy Shift Report</a>, based on a survey of 817 builders, traces exactly how this shift is playing out.</p><h2>The cost curve changed; SaaS pricing didn’t</h2><p>Two years ago, a custom internal tool might have taken an engineering team weeks or months and cost six figures. Today, an operations lead with the right platform can have a working prototype in a day or two. This structural shift is driven by AI-assisted development and the maturation of enterprise app-building platforms.</p><p>Meanwhile, SaaS pricing hasn’t adjusted, still charging per-seat for generic software that requires customization and integration costs on top. When the cost of building drops by an order of magnitude but the cost of buying stays flat, the math changes for every company, not just the ones with large engineering teams.</p><p>The data reflects this. Retool’s report found that 35% of teams have already replaced at least one SaaS tool with a custom build, and 78% plan to build more custom tooling in 2026.</p><h2>Workflow automations and admin tools are among SaaS tools at risk</h2><p>The shift isn’t happening uniformly. The top SaaS tools respondents have replaced or considered replacing include workflow automations (35%) and internal admin tools (33%), followed by BI tools (29%) and CRMs (25%).</p><p>A purchased workflow automation tool has to serve thousands of customers, so it optimizes for the average case — and the average case is nobody’s <i>actual</i> case. Every company’s internal workflows are different. They reflect org structure, compliance requirements, data systems, and business logic unique to that organization. </p><p>Internal admin tools carry the same problem: they’re inherently company-specific. These categories were always the most awkward fit for off-the-shelf software, and there’s now an affordable, accessible alternative (MIT’s <a href="https://mlq.ai/media/quarterly_decks/v0.1_State_of_AI_in_Business_2025_Report.pdf">State of AI in Business</a> reported $2-10 million in savings annually for customer service and document processing tasks).</p><p>The replacement pattern tends to be additive rather than wholesale (nobody is just ripping out Salesforce). They’re replacing the specific pieces that never quite fit: an approval flow that required three workarounds, the dashboard that couldn’t connect to their actual data … but those narrow replacements add up. Once a team builds one tool that works better than what they bought, the default question shifts from “What should we buy?” to “Can we build this?”</p><h2>Builders go around IT, signaling broader procurement challenges</h2><p>The clearest evidence that procurement processes haven’t kept up with building capability is the scale of shadow IT now occurring inside enterprises. Retool’s report found that 60% of builders have created tools, workflows, or automations outside of IT oversight in the past year — and 25% report doing so frequently.</p><p>Even experienced, high-judgment people choose speed over process. Two-thirds of total survey respondents (64%) are senior managers and above. Existing procurement cycles weren’t designed for a world where building software takes days rather than months. When people love to quote the <a href="https://fortune.com/2025/08/18/mit-report-95-percent-generative-ai-pilots-at-companies-failing-cfo/">95% generative AI pilot failure rate</a> they’re not accounting for the <a href="https://venturebeat.com/ai/mit-report-misunderstood-shadow-ai-economy-booms-while-headlines-cry-failure">robust grassroots adoption happening under executives’ noses</a>.</p><p>Shadow IT at this scale is a demand signal. The people closest to the problems are telling organizations that the existing process can’t can&#x27;t keep up — 31% of those going around IT do so simply because they can build faster than IT can provision tools. So, suppression isn’t a productive response. The challenge is that the tools being built in the shadows are also the ones most likely to stall before they become useful.</p><p>A vibe-coded prototype running on sample data is impressive. A production tool connected to your actual Salesforce instance, with role-based access and a security review, is <i>useful</i>. The report found that 51% of builders have shipped production software currently in use by their teams, and among those, about half report saving six or more hours per week. </p><p>When building happens in an ungoverned environment, organizations get neither outcome reliably. Someone connects an AI-powered tool to production data with no audit trail, no access controls, and no owner. Multiply that by dozens of builders across an organization, and you have an expanding security surface that IT doesn’t even know exists.<sup>[1]</sup> </p><p>The teams whose homebuilt solutions reach production tend to have three things the others don’t: connectivity to real data sources, a security and permissions model they trust, and a review process for what gets deployed. Channeling builder energy into governed environments, where speed and security aren’t in conflict, is how organizations avoid shadow IT becoming a liability.</p><h2>Governance will define the next era of SaaS</h2><p>The build vs. buy shift is already underway. The more important question now is who controls the environment where that building happens.</p><p>Ungoverned building invites security risks <i>and</i> makes the ROI case difficult to close. You can’t measure time saved by tools IT doesn’t know exist, or are only run in one individual’s workflow. You can’t enforce access controls on a prototype that someone connected to production data last Tuesday. And those aren’t hypothetical risks: in <a href="https://www.deloitte.com/us/en/what-we-do/capabilities/applied-artificial-intelligence/content/state-of-ai-in-the-enterprise.html">Deloitte’s 2026 State of AI in the Enterprise survey of 3,200+ leaders</a>, data privacy and security ranked as the top AI concern at 73%, with governance capabilities close behind at 46%. The 35% of organizations with no AI productivity metrics are missing more than just a dashboard. They’re missing the accountability infrastructure that justifies building over buying in the first place.</p><p>The organizations that treat governed environments as a prerequisite for building at scale will be the ones that can actually prove it’s working. The ones that don’t will find out when something breaks.</p><p><i>For a closer look at the data, including how enterprises are approaching AI-assisted building, read the full </i><a href="https://retool.com/blog/ai-build-vs-buy-report-2026"><i>2026 Build vs. Buy Shift Report</i></a><i>.</i></p><p><i><sup>[1]</sup></i><i> The cost of which can be steep: </i><a href="https://www.ibm.com/reports/data-breach"><i>IBM’s 2025 Cost of Data Breach Report</i></a><i> found that AI-associated cases cost organizations more than $650,000 per breach.</i></p><hr/><p><i>David Hsu is CEO at Retool.</i></p><hr/><p><i>Sponsored articles are content produced by a company that is either paying for the post or has a business relationship with VentureBeat, and they’re always clearly marked. For more information, contact </i><a href="mailto:sales@venturebeat.com"><i><u>sales@venturebeat.com</u></i></a><i>.</i></p>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (165, 'Lucasfilm drops The Mandalorian and Grogu final trailer at CinemaCon', 'https://arstechnica.com/culture/2026/04/lucasfilm-drops-mandalorian-and-grogu-final-trailer-at-cinemacon/', 'Ars Technica', 'https://feeds.arstechnica.com/arstechnica/index', 5, '{General}', 'Lucasfilm drops The Mandalorian and Grogu final trailer at CinemaCon', '2026-04-16 23:20:33+00', '2026-04-17 06:57:51.969159+00', '"The old protect the young, and then the young protect the old."', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
