INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (234, 'South African politician Julius Malema given five-year jail term for gun offence', 'https://www.theguardian.com/world/2026/apr/16/south-africa-julius-malema-jail-term-rifle', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{General}', 'South African politician Julius Malema given five-year jail term for gun offence', '2026-04-16 12:37:49+00', '2026-04-17 07:00:20.836518+00', '<p>Leader of leftwing Economic Freedom Fighters was convicted last year for firing rifle in the air at 2018 rally</p><p>The South African leftwing politician <a href="https://www.theguardian.com/world/julius-malema">Julius Malema</a> has been sentenced to five years in prison for firing a rifle in the air at a political rally in 2018.</p><p>Lawyers for the leader of the Economic Freedom Fighters, South Africa’s fourth largest political party, immediately appealed, and Malema will remain free while the appeal proceedings are under way.<strong> </strong></p> <a href="https://www.theguardian.com/world/2026/apr/16/south-africa-julius-malema-jail-term-rifle">Continue reading...</a>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (235, 'Pedro Pascal v Pedro Piscal: actor in legal battle with Chilean spirit brand', 'https://www.theguardian.com/world/2026/apr/16/pedro-pascal-pedro-piscal-actor-spirit-brand-legal-battle-chile', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{General}', 'Pedro Pascal v Pedro Piscal: actor in legal battle with Chilean spirit brand', '2026-04-16 11:33:33+00', '2026-04-17 07:00:23.069079+00', '<p>Pedro Piscal pisco is latest Chilean brand to resemble a Hollywood name – and others have fought off the lawsuits</p><p>The actor <a href="https://www.theguardian.com/culture/pedro-pascal">Pedro Pascal</a> is waging a legal battle against a Chilean pisco merchant who has chosen a cheeky name for his brand of the country’s national spirit: Pedro Piscal.</p><p>David Herrera registered the brand name with a Chilean commercial regulator in 2023 and began selling his pisco in off-licences and restaurants.</p> <a href="https://www.theguardian.com/world/2026/apr/16/pedro-pascal-pedro-piscal-actor-spirit-brand-legal-battle-chile">Continue reading...</a>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (236, '‘How do I end a call?’: the elderly Japanese people determined to master smartphones', 'https://www.theguardian.com/technology/2026/apr/17/japanese-over-70s-mobile-master-smartphones', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{General}', '‘How do I end a call?’: the elderly Japanese people determined to master smartphones', '2026-04-17 04:00:20+00', '2026-04-17 07:00:25.1486+00', '<p>Elderly people take advantage of courses on how to navigate mobile devices and avoid ‘analogue isolation’</p><p>It’s not only young people whose gaze is fixed on tiny screens. But for these users in Tokyo, clicking and scrolling is anything but second nature.</p><p>“I can’t deal with all of the apps that jump out at me,” says one. “How do I know if I’ve definitely ended a call?” asks another.</p> <a href="https://www.theguardian.com/technology/2026/apr/17/japanese-over-70s-mobile-master-smartphones">Continue reading...</a>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (237, 'Australia news live: two men charged after allegedly stealing 1,000 litres of diesel; Hume highway closed in both directions after multi-vehicle crash', 'https://www.theguardian.com/australia-news/live/2026/apr/17/anthony-albanese-richard-marles-geelong-refinery-fire-fuel-supply-crisis-prices-labor-coalition-political-reactions-ntwnfb', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{General}', 'Australia news live: two men charged after allegedly stealing 1,000 litres of diesel; Hume highway closed in both directions after multi-vehicle crash', '2026-04-17 06:54:45+00', '2026-04-17 07:00:26.961577+00', '<p>Follow updates live</p><ul><li><p>Get our <a href="https://www.theguardian.com/email-newsletters?CMP=cvau_sfl">breaking news email</a>, <a href="https://app.adjust.com/w4u7jx3">free app</a> or <a href="https://www.theguardian.com/australia-news/series/full-story?CMP=cvau_sfl">daily news podcast</a></p></li></ul><p><strong>Australia secures extra fertilizer and 100m extra litres of fuel, PM says</strong></p><p>Albanese has also provided an update on Australia’s talks with its allies in Asia to shore up imports of fuel and other goods affected by the effective closure of the Strait of Hormuz.</p><p>The advice that we have received today is that 80% of diesel production is continuing, 80% of aviation fuel is continuing, ongoing.</p><p>It has been slowed down just slightly because of the circumstances which are there, but 60% of petrol production [is] proceeding today as well.</p> <a href="https://www.theguardian.com/australia-news/live/2026/apr/17/anthony-albanese-richard-marles-geelong-refinery-fire-fuel-supply-crisis-prices-labor-coalition-political-reactions-ntwnfb">Continue reading...</a>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (243, 'Woman stranded in Dusseldorf after return UK flight blocked over Home Office admin error', 'https://www.theguardian.com/politics/2026/apr/17/woman-dusseldorf-uk-home-office-return-flight-blocked', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{General}', 'Woman stranded in Dusseldorf after return UK flight blocked over Home Office admin error', '2026-04-17 06:00:22+00', '2026-04-17 07:00:44.580219+00', '<p>Liza Tobay, who lives in UK, was told her settled status had been ‘red flagged’ after trying to make a connecting flight from Munich to Edinburgh</p><p>A German woman has been separated from her two-year-old daughter in Edinburgh after a Home Office mistake left her stranded in Dusseldorf earlier this week.</p><p>Liza Tobay, who has lived in the UK for 15 years, had taken her oldest child, a six-year-old boy, to visit his grandfather and some other relatives over Easter when confronted with what she said appeared to be “a serious administrative error”.</p> <a href="https://www.theguardian.com/politics/2026/apr/17/woman-dusseldorf-uk-home-office-return-flight-blocked">Continue reading...</a>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (238, 'Ben Roberts-Smith granted bail after being charged with five counts of war crime murder', 'https://www.theguardian.com/australia-news/2026/apr/17/ben-roberts-smith-brs-bail-decision-war-crimes-trial-ntwnfb', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{General}', 'Ben Roberts-Smith granted bail after being charged with five counts of war crime murder', '2026-04-17 03:43:55+00', '2026-04-17 07:00:30.810239+00', '<p>Former SAS corporal to be released from Silverwater prison ahead of potential trial on charges relating to alleged killing of civilians in Afghanistan</p><ul><li><p><a href="https://www.theguardian.com/australia-news/live/2026/apr/17/anthony-albanese-richard-marles-geelong-refinery-fire-fuel-supply-crisis-prices-labor-coalition-political-reactions-ntwnfb">Follow our Australia news live blog for latest updates</a></p></li><li><p>Get our <a href="https://www.theguardian.com/email-newsletters?CMP=cvau_sfl">breaking news email</a>, <a href="https://app.adjust.com/w4u7jx3">free app</a> or <a href="https://www.theguardian.com/australia-news/series/full-story?CMP=cvau_sfl">daily news podcast</a></p></li></ul><p>Ben Roberts-Smith has been granted bail under strict conditions while he awaits a potential trial on alleged war crimes.</p><p>The Victoria Cross recipient, once Australia’s most lionised soldier, faces five charges of war crime murder over allegations he killed unarmed civilians during his service with the Australian SAS in Afghanistan.</p> <a href="https://www.theguardian.com/australia-news/2026/apr/17/ben-roberts-smith-brs-bail-decision-war-crimes-trial-ntwnfb">Continue reading...</a>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (239, 'Australia fuel watch tracker: check current petrol and diesel prices, service station outages and shipments – in charts', 'https://www.theguardian.com/australia-news/2026/apr/16/fuel-prices-tracker-watch-petrol-diesel-australia-shortage-reserves', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{General}', 'Australia fuel watch tracker: check current petrol and diesel prices, service station outages and shipments – in charts', '2026-04-17 03:18:45+00', '2026-04-17 07:00:32.74028+00', '<p>How much fuel does Australia have left today, and when could we run out? Track how much petrol and diesel prices have risen near you in Sydney, Melbourne and across the country.</p><ul><li><p>Get our <a href="https://www.theguardian.com/email-newsletters?CMP=cvau_sfl">breaking news email</a>, <a href="https://app.adjust.com/w4u7jx3">free app</a> or <a href="https://www.theguardian.com/australia-news/series/full-story?CMP=cvau_sfl">daily news podcast</a></p></li></ul><p>The federal government has <a href="https://www.theguardian.com/australia-news/2026/mar/13/australia-to-release-nearly-20-of-fuel-stockpile-as-bowen-insists-country-nowhere-near-running-out">released</a> fuel reserves, cut fuel excise taxes and rolled out a <a href="https://www.theguardian.com/australia-news/2026/mar/30/fuel-crisis-australia-government-measures-excise-explained-petrol-prices-cheaper">national fuel security plan</a> as Australia battles a fuel crisis.</p><p>While we know there have been outages and price increases, it can be difficult to get a full picture of what is happening – this is partly due to the thousands of independent businesses and different governments involved. We have brought together the latest data on prices, outages and oil tanker deliveries.</p> <a href="https://www.theguardian.com/australia-news/2026/apr/16/fuel-prices-tracker-watch-petrol-diesel-australia-shortage-reserves">Continue reading...</a>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (240, '‘Parent’s worst nightmare’: Sydney childcare worker faces 137 child abuse charges relating to multiple centres', 'https://www.theguardian.com/australia-news/2026/apr/17/sydney-childcare-worker-child-abuse-charges-multiple-centres-ntwnfb', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{General}', '‘Parent’s worst nightmare’: Sydney childcare worker faces 137 child abuse charges relating to multiple centres', '2026-04-17 03:17:43+00', '2026-04-17 07:00:34.428734+00', '<p>Man initially charged in July but Australian federal police uncovered dozens more alleged offences after reviewing files on his devices</p><ul><li><p><a href="https://www.theguardian.com/australia-news/live/2026/apr/17/anthony-albanese-richard-marles-geelong-refinery-fire-fuel-supply-crisis-prices-labor-coalition-political-reactions-ntwnfb">Follow our Australia news live blog for latest updates</a></p></li><li><p>Get our <a href="https://www.theguardian.com/email-newsletters?CMP=cvau_sfl">breaking news email</a>, <a href="https://app.adjust.com/w4u7jx3">free app</a> or <a href="https://www.theguardian.com/australia-news/series/full-story?CMP=cvau_sfl">daily news podcast</a></p></li></ul><p>A former childcare employee accused of abusing children in his care has been hit with another 129 charges after investigators say they identified more victims.</p><p>The man, aged in his 30s, was initially charged with eight counts of online child abuse material offences in July 2025 after years of alleged offending.</p> <a href="https://www.theguardian.com/australia-news/2026/apr/17/sydney-childcare-worker-child-abuse-charges-multiple-centres-ntwnfb">Continue reading...</a>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (241, 'Fuel prices fall despite Geelong refinery blaze as Albanese says facility production has slipped by 40%', 'https://www.theguardian.com/australia-news/2026/apr/17/albanese-no-fuel-restrictions-geelong-refinery-fire', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{General}', 'Fuel prices fall despite Geelong refinery blaze as Albanese says facility production has slipped by 40%', '2026-04-17 02:50:10+00', '2026-04-17 07:00:40.805863+00', '<p>Prime minister says Corio refinery fire will not push Australia into stage 3 restrictions, despite reduced production of petrol, diesel and aviation fuel</p><ul><li><p><a href="https://www.theguardian.com/australia-news/live/2026/apr/17/anthony-albanese-richard-marles-geelong-refinery-fire-fuel-supply-crisis-prices-labor-coalition-political-reactions-ntwnfb">Follow our Australia news live blog for latest updates</a></p></li><li><p><a href="https://www.theguardian.com/australia-news/2026/apr/16/fuel-prices-tracker-watch-petrol-diesel-australia-shortage-reserves">Track Australia’s fuel prices, service station outages and shipments in charts</a></p></li><li><p>Get our <a href="https://www.theguardian.com/email-newsletters?CMP=cvau_sfl">breaking news email</a>, <a href="https://app.adjust.com/w4u7jx3">free app</a> or <a href="https://www.theguardian.com/australia-news/series/full-story?CMP=cvau_sfl">daily news podcast</a></p></li></ul><p>Anthony Albanese says petrol production has fallen 40% at one of Australia’s two remaining oil refineries but the <a href="https://www.theguardian.com/australia-news/2026/apr/16/geelongs-refinery-fire-may-be-out-but-questions-over-what-it-means-for-our-fuel-crisis-are-still-raging">damage caused by fire</a> at the Geelong facility will not lead to fuel restrictions.</p><p>Petrol prices have fallen below $2.10 a litre and diesel below $3 a litre in most cities, as a price spike predicted to follow the refinery shutdown failed to materialise on Friday.</p> <a href="https://www.theguardian.com/australia-news/2026/apr/17/albanese-no-fuel-restrictions-geelong-refinery-fire">Continue reading...</a>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (242, 'US tech firms successfully lobbied EU to keep datacentre emissions secret', 'https://www.theguardian.com/technology/2026/apr/17/microsoft-us-tech-firms-lobbied-eu-secrecy-rules-datacentre-emissions', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{General}', 'US tech firms successfully lobbied EU to keep datacentre emissions secret', '2026-04-17 06:00:24+00', '2026-04-17 07:00:42.785903+00', '<p>Legally questionable confidentiality clause adopted almost word for word from demands of Microsoft and trade groups</p><p>Microsoft and other US tech companies successfully lobbied the EU to hide the environmental toll of their datacentres, an investigation has found, with demands to block a database of green metrics from public view written almost word for word into EU rules.</p><p>The secrecy provision, which the European Commission added to its proposal almost verbatim after industry lobbying in 2024, hinders scrutiny of the pollution that individual datacentres emit. It leaves researchers with just national-level summaries of their energy footprints.</p> <a href="https://www.theguardian.com/technology/2026/apr/17/microsoft-us-tech-firms-lobbied-eu-secrecy-rules-datacentre-emissions">Continue reading...</a>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (244, 'Ukraine war briefing: €90bn EU loan for Ukraine to be released in second quarter', 'https://www.theguardian.com/world/2026/apr/17/ukraine-war-briefing-90bn-eu-loan-russia', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{General}', 'Ukraine war briefing: €90bn EU loan for Ukraine to be released in second quarter', '2026-04-17 00:19:33+00', '2026-04-17 07:00:46.55516+00', '<p>EU economy commissioner says Iran war is feeding Russia’s war machine; Trump condemns massive strikes on Ukraine. What we know on day 1,513</p><p><strong>The EU expects to start releasing a new €90bn loan to Ukraine in the second quarter, the bloc’s economy chief told AFP on Thursday.</strong> The EU’s economy commissioner, Valdis Dombrovskis, was speaking on the sidelines of the International Monetary Fund and World Bank’s spring meetings, which brought finance ministers, central bankers and other leaders to Washington. “Our support for Ukraine, also continued pressure and sanctions against aggressor Russia was very much part of the agenda,” Dombrovskis said. He warned that Moscow was “emerging as a winner from this war in Iran, because it provides windfall profits to feed Russia’s war machine”.</p><p><strong>Russia hammered civilian areas across Ukraine with drones and missiles on Thursday, <a href="https://www.theguardian.com/world/2026/apr/16/russia-attack-ukraine-drones-missiles-kyiv-odesa-volodymyr-zelenskyy">killing at least 17 people</a></strong><a href="https://www.theguardian.com/world/2026/apr/16/russia-attack-ukraine-drones-missiles-kyiv-odesa-volodymyr-zelenskyy"> </a>and wounding more than 100 others in the worst aerial attack in weeks, Ukrainian authorities said. Nearly 700 drones and dozens of ballistic and cruise missiles were used, as Ukrainian officials said vital stocks of advanced interceptors were running low.</p><p><strong>Donald Trump on Thursday condemned a massive Russian drone and missile attack across Ukraine that ripped</strong> through apartment buildings in the capital, Kyiv. Asked by reporters at the White House for his reaction to the barrage, Trump said: “I think it’s terrible.”</p><p><strong>It is not in the interest of the US that Russia is the winner of the Iran war, the German vice chancellor, Lars Klingbeil, said on Thursday in Washington.</strong> “It’s not in our interest and it cannot be in the interest of the United States,” he said in a joint statement with the finance ministers of Ukraine and Norway on the sidelines of the IMF spring meetings. Klingbeil said the Russian economy was growing thanks to the Middle East conflict and the country was profitting from the energy situation. As the conflict in the Middle East dominated the gathering of finance officials at the IMF in Washington, the ministers of Norway, Germany and Ukraine spoke about not forgetting to support Ukraine in its defence against Russia. “All the meetings here are about the question of what’s happening with the war in Iran, and I think it’s really important we show solidarity with our friends in Ukraine,” Klingbeil said.</p><p><strong>The heads of the EU and Nato on Thursday discussed efforts to bolster Europe’s arms production, as Donald Trump threw doubt on Washington’s commitment to the transatlantic alliance.</strong> “We need to invest more, to produce more and to do both faster,” the European Commission’s president, Ursula von der Leyen, posted online after meeting Nato’s chief, Mark Rutte. European nations are scrambling to bolster their militaries in the face of Russia’s war on Ukraine and pressure from Trump.</p> <a href="https://www.theguardian.com/world/2026/apr/17/ukraine-war-briefing-90bn-eu-loan-russia">Continue reading...</a>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (245, 'Armed robbers hold 25 people hostage at Naples bank before fleeing through hole in floor', 'https://www.theguardian.com/world/2026/apr/16/armed-robbers-hostages-naples-bank-flee-hole-floor-sewers', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{General}', 'Armed robbers hold 25 people hostage at Naples bank before fleeing through hole in floor', '2026-04-16 18:08:46+00', '2026-04-17 07:00:48.260048+00', '<p>Thieves believed to have escaped into sewers after holding staff and customers in Crédit Agricole branch for two hours</p><p>Armed robbers held 25 people hostage at a bank in Naples for two hours on Thursday, before fleeing through a tunnel.</p><p>The three thieves entered a branch of Crédit Agricole in the southern Italian city at about 11.30am, taking hostage staff and customers, who were freed by police a couple of hours later.</p> <a href="https://www.theguardian.com/world/2026/apr/16/armed-robbers-hostages-naples-bank-flee-hole-floor-sewers">Continue reading...</a>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (246, 'Orbán’s defeat threatens to halt Hungarian support of populist right', 'https://www.theguardian.com/politics/2026/apr/16/viktor-orban-defeat-halt-hungarian-support-populist-right', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{General}', 'Orbán’s defeat threatens to halt Hungarian support of populist right', '2026-04-16 17:52:55+00', '2026-04-17 07:00:50.000904+00', '<p>Individuals such as Matt Goodwin and Lord Frost benefited from largesse of self-styled ‘illiberal democracy’</p><ul><li><p><a href="https://www.theguardian.com/politics/live/2026/apr/16/iran-economy-food-fuel-local-elections-covid-latest-news-updates">UK politics live – latest updates</a></p></li></ul><p>The last 16 years of Viktor Orbán’s rule have been kind to a number of British political figures – from the Tory peer David Frost to Reform UK’s Matt Goodwin and James Orr.</p><p>All benefited from largesse extended by the self-styled “illiberal democracy” established by the Hungarian leader’s ruling Fidesz party, which took a particular liking for those on the harder right of British conservatism.</p> <a href="https://www.theguardian.com/politics/2026/apr/16/viktor-orban-defeat-halt-hungarian-support-populist-right">Continue reading...</a>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (247, 'Middle East crisis live: UN chief calls for Israel-Lebanon ceasefire to be ‘fully’ respected as it comes into effect', 'https://www.theguardian.com/world/live/2026/apr/17/middle-east-crisis-live-news-israel-lebanon-ceasefire-iran-war-us-latest-updates', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{General}', 'Middle East crisis live: UN chief calls for Israel-Lebanon ceasefire to be ‘fully’ respected as it comes into effect', '2026-04-17 06:27:00+00', '2026-04-17 07:00:56.812953+00', '<p>António Guterres welcomes truce and says through spokesperson he hopes halt in fighting will ‘pave the way for negotiations’</p><p>In case you’re just joining us, here are the latest developments in the Middle East to bring you up to speed. It’s 9am in Beirut and Jerusalem, 9.30am in Tehran and 2am in Washington DC.</p><p><strong>A 10-day ceasefire between Israel and Lebanon has come into effect</strong>, pausing fighting between Israel and Hezbollah that has killed more than 2,100 Lebanese people and displaced more than 2.1 million. The agreement was announced earlier by Donald Trump, who said he had spoken with Israeli prime minister Benjamin Netanyahu and Lebanese president Joseph Aoun, and invited both leaders “for meaningful talks” at the White House. Both leaders welcomed the agreement.</p><p><strong>Israel and Hezbollah both maintained their right to defend themselves</strong> if the truce is broken – here’s <a href="https://www.theguardian.com/world/2026/apr/16/trump-announces-10-day-ceasefire-in-lebanon-after-excellent-conversations">our full report</a>.</p><p><strong>Netanyahu called the ceasefire a “historic” opportunity for peace but refused to withdraw his troops from southern Lebanon during the pause in fighting.</strong> “We are remaining in Lebanon in an expanded security zone,” he said, due to the “danger of an invasion” and to prevent fire into Israel. “That is where we are, and we are not leaving.”</p><p><strong>UN chief António Guterres welcomed the ceasefire</strong>, which took effect at midnight on Thursday (2100 GMT) in Lebanon, and urged “all actors” to fully respect it. He hoped the halt in fighting would “pave the way for negotiations”.</p><p><strong>The Lebanese army warned people displaced from southern Lebanon about returning home</strong> because of intermittent shelling that was reported after the ceasefire came into effect.</p><p><strong>The Israeli military warned residents of southern Lebanon not to return south of the Litani River </strong>despite the truce.</p><p><strong>Iran’s foreign ministry spokesperson <a href="https://www.theguardian.com/world/live/2026/apr/16/middle-east-crisis-live-iran-war-news-us-trump-ceasefire-deal-lebanon-israel-oil-sanctions-latest-updates?CMP=share_btn_url&amp;page=with%3Ablock-69e14d0d8f089afd5295602d#block-69e14d0d8f089afd5295602d">welcomed the ceasefire</a> </strong>and stressed it was already part of the original Iran-US agreement brokered by Pakistan.</p><p><strong>Israel and Hezbollah continued to exchange fire</strong> in the hours before the truce took effect.</p> <a href="https://www.theguardian.com/world/live/2026/apr/17/middle-east-crisis-live-news-israel-lebanon-ceasefire-iran-war-us-latest-updates">Continue reading...</a>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (248, 'Gunfire reported in Beirut as truce comes into effect – as it happened', 'https://www.theguardian.com/world/live/2026/apr/16/middle-east-crisis-live-iran-war-news-us-trump-ceasefire-deal-lebanon-israel-oil-sanctions-latest-updates', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{General}', 'Gunfire reported in Beirut as truce comes into effect – as it happened', '2026-04-17 03:18:11+00', '2026-04-17 07:00:58.990499+00', '<p>This blog is now closed. Our live coverage <a href="https://www.theguardian.com/world/live/2026/apr/17/middle-east-crisis-live-news-israel-lebanon-ceasefire-iran-war-us-latest-updates">continues here</a></p><p>Iran has stopped all petrochemical exports to prioritise domestic supply and prevent shortages of raw materials, Reuters reported.</p><p>The state-owned National Petrochemical Company ordered firms to suspend exports until further notice.</p> <a href="https://www.theguardian.com/world/live/2026/apr/16/middle-east-crisis-live-iran-war-news-us-trump-ceasefire-deal-lebanon-israel-oil-sanctions-latest-updates">Continue reading...</a>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (249, 'Israel escalates attacks on medics in Lebanon with deadly ‘quadruple tap’', 'https://www.theguardian.com/world/2026/apr/16/israel-escalates-attacks-on-medics-in-lebanon-with-deadly-quadruple-tap', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{General}', 'Israel escalates attacks on medics in Lebanon with deadly ‘quadruple tap’', '2026-04-16 17:12:32+00', '2026-04-17 07:01:00.881122+00', '<p>Lebanese health ministry says killing of 91 healthcare workers shows ‘total disregard’ for international law</p><ul><li><p><a href="https://www.theguardian.com/world/live/2026/apr/16/middle-east-crisis-live-iran-war-news-us-trump-ceasefire-deal-lebanon-israel-oil-sanctions-latest-updates">Middle East crisis – live updates</a></p></li></ul><p>When they received the call to respond to an Israeli airstrike in the city of Mayfadoun, in southern Lebanon, most of the paramedics held back, having previously seen colleagues killed by double-tap attacks targeting rescuers. But the medics from the Islamic Health Association (IHA) rushed to the scene.</p><p>By the time the other emergency workers arrived at the site, they found the IHA medics had indeed been caught in a second strike. They started evacuating their wounded colleagues, only for their ambulances to be hit in two further attacks.</p> <a href="https://www.theguardian.com/world/2026/apr/16/israel-escalates-attacks-on-medics-in-lebanon-with-deadly-quadruple-tap">Continue reading...</a>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (250, 'Hegseth says US is ‘locked and loaded’ to finish job of destroying Iran energy grid', 'https://www.theguardian.com/us-news/2026/apr/16/pete-hegseth-iran-energy-infrastructure', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{General}', 'Hegseth says US is ‘locked and loaded’ to finish job of destroying Iran energy grid', '2026-04-16 14:19:51+00', '2026-04-17 07:01:02.64801+00', '<p>US defense secretary says Iran’s energy infrastructure is ‘not destroyed yet’ while also lambasting the media</p><p>Iran’s energy infrastructure is “not destroyed yet” and the US is “locked and loaded” to finish the job, Pete Hegseth, the defense secretary, said on Thursday as he called many of the press corps gathered the moral equivalent of the Pharisees who conspired to destroy Jesus Christ.</p><p>Hegseth’s comments from the Pentagon podium came as a naval blockade of Iranian ports began this week and he called on Tehran to accept a nuclear deal or face consequences for its remaining infrastructure, power generation and energy industry.</p> <a href="https://www.theguardian.com/us-news/2026/apr/16/pete-hegseth-iran-energy-infrastructure">Continue reading...</a>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (260, 'Pepsi says price cuts and wellness push are bringing back customers — and the stock surges', 'https://www.marketwatch.com/story/pepsi-says-price-cuts-and-wellness-push-are-bringing-back-customers-and-the-stock-surges-e6e5ea05?mod=mw_rss_topstories', 'MarketWatch', 'https://feeds.marketwatch.com/marketwatch/topstories/', 5, '{General}', 'Pepsi says price cuts and wellness push are bringing back customers — and the stock surges', '2026-04-16 23:33:00+00', '2026-04-17 07:01:34.067966+00', 'PepsiCo shares rallied Thursday after the beverage and snack giant indicated that new products and recent price cuts had brought back wary customers, while noting that it hadn’t taken much of a hit yet from the Iran war.', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (251, '‘A dollar or two increase is devastating’: US consumers on toll of rising gas prices', 'https://www.theguardian.com/us-news/2026/apr/16/us-readers-rising-gas-prices-iran-trump', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{General}', '‘A dollar or two increase is devastating’: US consumers on toll of rising gas prices', '2026-04-16 11:00:57+00', '2026-04-17 07:01:06.683384+00', '<p>Guardian readers describe how their lives have been upended by cost hikes stemming from Trump’s Iran war</p><p>With the US and Israel’s war on Iran now in its seventh week, with a <a href="https://www.theguardian.com/world/2026/apr/08/middle-east-ceasefire-doubt-israel-lebanon-iran-oil-tankers">fragile ceasefire</a> in place since earlier this month, Americans are continuing to feel the effects at the pump as <a href="https://www.theguardian.com/business/2026/mar/31/us-average-fuel-prices-iran-war">global fuel prices</a> <a href="https://www.theguardian.com/world/2026/apr/06/defense-contractors-oil-companies-profit-iran-war">rise</a>.</p><p>For several readers who spoke to the Guardian, the impact has <a href="https://www.theguardian.com/world/2026/mar/29/americans-struggling-rising-costs-iran-war">forced difficult trade-offs</a> – from accessing essential medicines and groceries to facing the brink of homelessness amid an already <a href="https://www.theguardian.com/us-news/2026/apr/05/prices-iran-war-gas-flights-economy">rising cost of living</a>.</p> <a href="https://www.theguardian.com/us-news/2026/apr/16/us-readers-rising-gas-prices-iran-trump">Continue reading...</a>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (252, 'Minister defends Starmer amid Mandelson revelations, saying vetting decision ‘utterly unacceptable’ – UK politics live', 'https://www.theguardian.com/politics/live/2026/apr/17/peter-mandelson-keir-starmer-olly-robbins-vetting-foreign-office-latest-news-updates', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{General}', 'Minister defends Starmer amid Mandelson revelations, saying vetting decision ‘utterly unacceptable’ – UK politics live', '2026-04-17 06:50:16+00', '2026-04-17 07:01:11.547027+00', '<p>Darren Jones says he has ordered an urgent review into news that the Foreign Office ignored security vetting advice</p><p>Sir Ed Davey, the leader of the Liberal Democrats, is among voices calling for the PM to go.</p><p>He has said even if the prime minister’s explanation - that he was unaware of the Foreign Office’s decision to overrule Mandelson’s failed vetting until this week – is “true”, he should still resign.</p><p>I don’t think the prime minister can get out of his responsibility by sacking Olly Robbins - the buck has to stop with Mr Starmer.</p><p>I think frankly it’s inconceivable on such a sensitive matter the permeant secretary at the Foreign Office wouldn’t have referred to ministers on this.</p><p>Let’s imagine they are telling the truth and they did only just learn about this on Tuesday what does that say about the Governmenet and how they operate?</p><p>It means people around the prime minister were hiding critical information from him and he took this decision without meeting Mandelson, without knowing about his failed security but knowing about Mandelson’s reputation.</p><p>It’s hard to believe it was inadvertent, it stretches credibility, but even if that is a true story it shows there was total negligence and incompetence at the top of his government...</p><p>The PM held the Conservatives to account when he was in opposition when Boris Johnson was clearly lying over partygate and Keir Starmer called for all the accountability and called for Boris Johnson to go... but I’m afraid now he he has to take his own medicine. All the evidence suggests he has to go.</p><p>It is utterly unacceptable, not just in the individual case of Peter Mandelson and respect of the Prime Minister’s fury at the Foreign Office for not having taught him this information, but the very fact that their processes were in place that allow for that to happen in the first place.</p><p>That’s why in my role in the Cabinet Office, immediately last night, I suspended the rights for these organisations to make these judgments.</p><p>As soon as I found out last night that the Foreign Office and a small number of other organisations have the right to ignore the recommendation… I immediately suspended those rights and ordered an urgent audit.</p> <a href="https://www.theguardian.com/politics/live/2026/apr/17/peter-mandelson-keir-starmer-olly-robbins-vetting-foreign-office-latest-news-updates">Continue reading...</a>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (253, 'More than 15m oysters to be released in the North Sea for UK rewilding project', 'https://www.theguardian.com/environment/2026/apr/17/more-than-15m-oysters-to-be-released-in-the-north-sea-for-uk-rewilding-project', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{General}', 'More than 15m oysters to be released in the North Sea for UK rewilding project', '2026-04-17 06:00:23+00', '2026-04-17 07:01:13.470962+00', '<p>Exclusive: Experts say scheme will help repair damaged marine ecosystems while sequestering large amounts of carbon</p><p>More than 15m juvenile oysters are to be released into the North Sea in one of the biggest rewilding projects in UK waters.</p><p>The scheme, which will use a unique rearing process, hopes to re-establish a huge oyster bed around Orkney that experts say will create a “trophic cascade” of climate and ecological benefits.</p> <a href="https://www.theguardian.com/environment/2026/apr/17/more-than-15m-oysters-to-be-released-in-the-north-sea-for-uk-rewilding-project">Continue reading...</a>', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
