INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (341, 'Odd Lots: Planet Money Explains the World (Podcast)', 'https://www.bloomberg.com/news/audio/2026-04-17/odd-lots-planet-money-explains-the-world-podcast', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 3.5, '{Economy}', 'Podcast episode overview discussing economic explanations for consumer complaints (housing, food, childcare, AI). Descriptive content without new strategic signal or institutional insight.', '2026-04-17 08:00:00+00', '2026-04-17 08:32:43.222727+00', 'There are a lot of things to be annoyed about in modern life. The high cost of food and housing and childcare. Dating apps that don’t seem to work. The fear of AI replacing you at your job. These are all common complaints and concerns, and each of them can be traced to a specific economic phenomenon or market structure issue. Once you start thinking about the world in this way, you can’t unsee it. In this episode, we speak with Planet Money co-host Mary Childs, and contributor to the podcast, Al', 'pending', 'Strategic Foresight', 'Joe Weisenthal, Tracy Alloway', NULL, 'news', false, false, 5, NULL);
