INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (349, 'Trump-Linked Investors Want to Pour $1.8 Billion Into Bosnia', 'https://www.bloomberg.com/news/articles/2026-04-17/trump-linked-investors-want-to-pour-1-8-billion-into-bosnia', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 4.5, '{Geopolitics}', 'Trump-linked figures pursuing $1.8B infrastructure investment in Bosnia signals potential shift in U.S. geopolitical engagement patterns, but lacks clarity on systemic market or governance implications for senior leaders.', '2026-04-17 07:16:10+00', '2026-04-17 08:32:43.242342+00', 'Two figures who worked on President Donald Trump’s attempt to overturn the results of the 2020 election are pursuing a major infrastructure project in Bosnia.', 'pending', 'Strategic Foresight', 'Jasmina Kuzmanovic', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (350, 'JPMorgan, UBS See Little Stock Upside Left in Europe This Year', 'https://www.bloomberg.com/news/articles/2026-04-17/jpmorgan-ubs-see-little-stock-upside-left-in-europe-this-year', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 5.5, '{Finance,Economy}', 'European equity strategists signal earnings downgrades ahead, suggesting limited stock upside—a capital allocation signal for leaders managing global portfolios and economic exposure.', '2026-04-17 07:15:13+00', '2026-04-17 08:32:43.244335+00', 'Looming downgrades to over-optimistic earnings expectations mean European stocks will struggle to rise further this year, according to strategists surveyed by Bloomberg.', 'pending', 'Strategic Foresight', 'Michael Msika', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (351, 'Insight with Haslinda Amin 4/18/2026', 'https://www.bloomberg.com/news/videos/2026-04-17/insight-with-haslinda-amin-4-18-2026-video', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 2.5, '{}', 'Generic program description with no substantive content. Lacks specific guest, topic, or strategic signal.', '2026-04-17 07:11:48+00', '2026-04-17 08:32:43.246357+00', 'Insight with Haslinda Amin, a daily news program featuring in-depth, high-profile interviews and analysis to give viewers the complete picture on the stories that matter. The show features prominent leaders spanning the worlds of business, finance, politics and culture. (Source: Bloomberg)', 'pending', 'N/A', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (352, 'This new Google Pixel phone is exclusive to Japan', 'https://www.fastcompany.com/91525366/google-pixel-10a-phone-exclusive-japan', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 2.2, '{Technology}', 'Google launches a Japan-exclusive Pixel phone variant. A product customization with no systemic market implications for senior leaders.', '2026-04-17 08:00:00+00', '2026-04-17 08:32:43.248641+00', 'Despite Google ’s status as one of the true giants of U.S. tech, it’s never quite been able to make its Pixel phones a mainstream success. Last year, for instance, the company enjoyed record U.S. sales in September after the launch of the Pixel 10 line, according to Counterpoint Research. But despite achieving 28% year-on-year growth, the Pixel still only accounted for 6.1% of the $600-and-up smartphone market in the U.S., which is dominated by Apple. There is one market, however, where Google has managed to turn the Pixel into a big hit, and surprisingly, it’s in a country that was one of the last to adopt its search engine. The entry-level Pixel 8A and 9A have been some of the best-selling phones in Japan in recent years, and this seems to have prompted Google to pull out all the stops for the latest iteration. {"blockType":"mv-promo-block","data":{"imageDesktopUrl":"https:\/\/images.fastcompany.com\/image\/upload\/f_webp,q_auto,c_fit\/wp-cms-2\/2025\/12\/multicore.png","imageMobileUrl":"https:\/\/images.fastcompany.com\/image\/upload\/f_webp,q_auto,c_fit\/wp-cms-2\/2025\/12\/multicore-mobile.png","eyebrow":"","headline":"\u003Cstrong\u003E\u003Cstrong\u003ESubscribe to Multicore\u003C\/strong\u003E\u003C\/strong\u003E","dek":"Multicore is about technology hardware and design. It\u0027s written from Tokyo by Sam Byford. To learn more visit \u003Ca href=\u0022https:\/\/www.multicore.blog\/\u0022\u003Emulticore.blog\u003C\/a\u003E","subhed":"","description":"","ctaText":"SIGN UP","ctaUrl":"https:\/\/www.multicore.blog\/","theme":{"bg":"#f5f5f5","text":"#000000","eyebrow":"#9aa2aa","subhed":"#ffffff","buttonBg":"#000000","buttonHoverBg":"#3b3f46","buttonText":"#ffffff"},"imageDesktopId":91454027,"imageMobileId":91454030,"shareable":false,"slug":"","wpCssClasses":""}} Announced this week, the Pixel 10A is getting a design-forward variant that’s exclusive to Japan. Google calls the color “ Isai Blue ,” and it was developed in partnership with the Japanese creative company Heralbony, based in the city of Morioka in Iwate Prefecture. “Isai” is a term that refers to “unique brilliance,” and the shade of blue used is intended to represent the symbolic color for autism. Earlier this month, Heralbony launched a campaign called the Beyond Blue Project to tie into World Autism Day on April 2. The connection there is that Heralbony collaborates with artists who have disabilities and helps integrate their creative work into lifestyle products. The Isai Blue Pixel 10A, for example, features exclusive wallpapers by artists including Midori Kudo, Kaoru Iga, and Shigaku Mizukami, and the Pixel software dynamically adjusts its app icons and color schemes in response. The Japan-exclusive Pixel 10A comes in specialized packaging with artwork from Kudo. It also includes a limited bumper-style case to highlight the device’s color, and a set of included stickers by artist Nozomi Fujita. It will be available in a single 256-gigabyte configuration for 94,900 yen ($596). ', 'pending', 'Strategic Foresight', 'Sam Byford', NULL, 'news', false, false, 5, NULL);
