INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (366, 'Weather tracker: hail covers parts of Tunisia and Algeria like snow', 'https://www.theguardian.com/environment/2026/apr/17/weather-tracker-hail-covers-parts-of-tunisia-and-algeria-like-snow', 'The Guardian', 'https://www.theguardian.com/world/rss', 2.5, '{"Environmental Health"}', 'Severe Mediterranean thunderstorms produced unusual hail accumulation in North Africa. While a notable weather event, lacks systemic implications for organizational strategy or leadership decision-making.', '2026-04-17 07:49:39+00', '2026-04-17 08:32:43.284326+00', 'Accumulations of up to 3cm deep reported as severe thunderstorms also bring heavy downpours to central Italy Severe thunderstorms have affected the Mediterranean this week. On Monday, a surface low-pressure system in the Mediterranean in conjunction with an upper air cut-off low, led to thunderstorms over north Africa. Their intensity was aided by the hot precursor conditions. Algeria and Tunisia were notably affected by the thunderstorms, with some hail accumulation layers as a result. When so much hail forms, it starts to lay down sheets of hail, covering the ground like snow. Hail accumulations of up to 3cm were reported in Oum Ladjoul and Hammam Sokhna in Algeria, and there were hailstones of up to 3cm in diameter in Makthar, Tunisia. Thunderstorms continued in the region through the following day, with further hail accumulations, notably in Ouled Bousmir, Tunisia, where there was a layer about 2cm deep. Continue reading...', 'pending', 'Strategic Foresight', 'Faye Hulton for MetDesk', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (367, 'Albanese’s visits to key allies have borne early fruits of fuel and fertiliser but ‘resilience’ is on the budget agenda', 'https://www.theguardian.com/world/2026/apr/17/albaneses-visits-to-key-allies-have-borne-early-fruits-of-fuel-and-fertiliser-but-resilience-is-on-the-budget-agenda', 'The Guardian', 'https://www.theguardian.com/world/rss', 5.5, '{Geopolitics,Policy}', 'Australian PM''s diplomatic engagement on energy security reveals growing systemic vulnerability to global supply shocks—a pattern senior leaders must recognize in their own supply chain resilience strategies.', '2026-04-17 07:45:51+00', '2026-04-17 08:32:43.286527+00', 'The prime minister has weathered the crises – for now – and there is a growing recognition that Australia is too vulnerable to world events Follow our Australia news live blog for latest updates Get our breaking news email , free app or daily news podcast Anthony Albanese’s fuel diplomacy tour of Asia has already started paying dividends, but the real test could still be to come. After last week’s rush to Singapore and pulling forward a planned visit, the prime minister dashed back to Australia from Malaysia on Thursday, to survey the damage at one of the nation’s only remaining fuel refineries. The hastily arranged trips, were to show a leader on the job; to demonstrate Albanese’s attention to the fuel crisis. Continue reading...', 'pending', 'Strategic Foresight', 'Josh Butler', NULL, 'news', false, false, 5, NULL);
