INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (380, 'Boeing is hiring 100 to 140 factory workers a week to boost production', 'https://qz.com/boeing-factory-hiring-production-increase-041626', 'Quartz', 'https://qz.com/feed', 4.2, '{Strategy}', 'Boeing''s accelerated hiring signals production recovery post-MAX grounding, but lacks systemic implications for senior leaders unless tied to supply chain, labor cost, or competitive positioning shifts.', '2026-04-16 13:50:42+00', '2026-04-17 08:32:43.316634+00', 'The hiring pace is the highest since 2024, as Boeing adds staff for a new 737 MAX production line and replaces retiring workers', 'pending', 'Strategic Foresight', 'Colleen Cabili', NULL, 'news', false, false, 5, NULL);
