INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (382, 'Planet Money Turned Everyday Annoyances Into an Economics Book', 'https://www.bloomberg.com/news/videos/2026-04-17/planet-money-turned-annoyances-into-an-economics-book-video', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 3.5, '{Economy}', 'Popular economics podcast publishes book connecting everyday frustrations to economic principles. Interesting for general audiences but lacks systemic insight or strategic signal for senior leaders.', '2026-04-17 08:10:28+00', '2026-04-17 08:37:27.297675+00', 'There are a lot of things to be annoyed about in modern life. The high cost of food and housing and childcare. Dating apps that don''t seem to work. The fear of AI replacing you at your job. These are all common complaints and concerns, and each of them can be traced to a specific economic phenomenon or market structure issue. Once you start thinking about the world in this way, you can''t unsee it. In this episode, we speak with Planet Money co-host Mary Childs, and contributor to the podcast, Alex Mayassi. They''ve just written a book called Planet Money: A Guide to the Economic Forces That Shape Your Life. We discuss how one of Tracy''s childhood memories was a reflection of the commodity trap, what Baumol''s cost disease tells us about daycare, and why -- despite all these frustrations -- there are still many reasons to be optimistic about economic progress. (Source: Bloomberg)', 'pending', 'Strategic Foresight', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (401, 'Trump ditches deportation showmanship', 'https://www.axios.com/2026/04/17/trump-memes-noem-deportations-immigration', 'Axios', 'https://api.axios.com/feed/', 5.2, '{}', 'Trump ditches deportation showmanship', '2026-04-17 09:00:08+00', '2026-04-17 09:52:57.593061+00', 'The Trump administration is discarding its shock-and-awe publicity tactics on immigration after mass deportations were met with mass backlash. Why it matters: The White House has become allergic to the edgy memes , embedded camera crews and cosplaying officials that dominated former Homeland Security Secretary Kristi Noem''s tenure. A former DHS official said "cooler heads have prevailed" in the White House and are re-calibrating the messaging, naming chief of staff Susie Wiles and her deputy James Blair as among the cooler heads. But other White House staffers, such as deputy chief of staff Stephen Miller, have pushed DHS into some of the confrontations that tanked public opinion, as Axios has previously reported. "Everything I''ve done, I''ve done at the direction of the president and Stephen," Noem told a person who relayed her remarks to Axios back in November. Between the lines : "There was a priority on people seeing the enforcement actions," the former agency official told Axios about the aggressive tactics of 2025. "Some of the law enforcement actions you see, even if they''re hardened criminals, it can be hard optics. They can be hard to stomach when you''re seeing really physical altercations," the former official said. "You have the base that is demanding this action, and you need to get them out for the midterms. And if they''re not seeing it, to them, it''s not happening." Flashback: Noem, dressed as an ICE agent, spent parts of last year trailing agents making arrests around the country. The Trump administration said it wanted to emphasize "the visuals." For about nine months, Border Patrol official Greg Bovino was plucked from the El Centro sector to lead interior enforcement in cities with often violent tactics and rabid social media promotion. Last May, Miller told reporters that Trump was elected in large part to "deport the illegals" and "remove the people from this country that we don''t want here." Soon after, federal agents swarmed Los Angeles. That''s changed this year: Today, the administration realizes its polling numbers have plummeted on immigration enforcement and Miller has been less present in media appearances on the issue, although he''s still firmly entrenched in his role. New DHS Secretary Markwayne Mullin''s first press stop (in business attire) was to promote FEMA''s efforts in North Carolina. Bovino''s social media accounts were deleted and Trump called in White House Border Czar Tom Homan to become more involved with ICE''s operations. The latest: Homan said he''s actively working on plans to change ICE''s social media presence, in an interview with America First Legal''s podcast. "I think that''s gonna be important because we can''t lose the faith in American people," Homan said, adding it was needed to combat fake news. What they''re saying: "Nobody is changing the Administration''s immigration enforcement agenda," White House spokesperson Abigail Jackson said in a statement. "Thanks to President Trump''s strong immigration enfo', 'pending', 'Multiple', 'Brittany Gibson', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (402, 'Why work still sucks for women', 'https://www.fastcompany.com/91526746/why-work-still-sucks-for-women', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5.2, '{}', 'Why work still sucks for women', '2026-04-17 09:30:00+00', '2026-04-17 09:52:57.595768+00', 'Work sucks for women. Not all women, but far too many. There’s the gender pay gap, where full-time working women earn 81 cents for every dollar men earn , according to the most recent data from the Census Bureau. There’s the glass ceiling that prevents women from leadership advancement, as evidenced by the fact that only 37% of leadership positions in the U.S. are held by women despite representing 47% of the workforce . Let us not forget the disproportionate harassment at work that women experience compared to men, the gender sidelining , and the exclusion from the “boys’ club.” And if that’s not enough, there’s the additional unpaid domestic work that women are expected to do outside of the office—cooking, cleaning, and child rearing—that’s often overlooked and undervalued. That’s assuming they haven’t been displaced out of the workforce altogether, like the more than 300,000 African American women who lost employment in 2025 alone, despite being the most academically educated population in the country . Yes, women have it bad when it comes to work, and that ain’t good. Yet these realities still persist. I say that as someone who has benefited from the injustices women have suffered at work and, for far too long, I’ve been far too quiet about it. Perhaps it’s because earlier in my career I wasn’t as aware as I should have been that they existed. Or maybe it’s because I, too, have to wrestle with the challenges of marginalization as a Black man in America, so I perceived my hands as being “too full” to fight for someone else’s equality while I’m busy fighting for my own. Or maybe I didn’t care as much because it wasn’t happening to me. Honestly, I’m not sure which one it was or if it was a combination of them all. Whatever the case, as the Reverend Dr. Martin Luther King once espoused, “Injustice anywhere is a threat to justice everywhere.” And that’s exactly why we brought Stacy London on the From the Culture podcast to illuminate these wrongs and help shed light on how to make them right. {"blockType":"mv-promo-block","data":{"imageDesktopUrl":"https:\/\/images.fastcompany.com\/image\/upload\/f_webp,q_auto,c_fit\/wp-cms-2\/2026\/01\/studio_16-9.jpg","imageMobileUrl":"https:\/\/images.fastcompany.com\/image\/upload\/f_webp,q_auto,c_fit\/wp-cms-2\/2026\/01\/studio_square_thumbnail.jpg","eyebrow":"","headline":"FROM THE CULTURE","dek":"FROM THE CULTURE is a podcast that explores the inner workings of organizational culture that enable companies to thrive, teams to win, and brands to succeed. If culture eats strategy for breakfast, then this is the most important conversation in business that you aren’t having.","subhed":"","description":"","ctaText":"Listen","ctaUrl":"https:\/\/open.spotify.com\/show\/7mYFUlY2MBMuGz6FMk2P1n?si=ed44030ee854439c\u0026nd=1\u0026dlsi=5b16af49c2a24eb5","theme":{"bg":"#2b2d30","text":"#ffffff","eyebrow":"#9aa2aa","subhed":"#ffffff","buttonBg":"#3b3f46","buttonHoverBg":"#3b3f46","buttonText":"#ffffff"},"imageDesktopId":', 'pending', 'Multiple', 'Marcus Collins', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (403, 'The stigma around AI in journalism may be easing, but trust is still fragile', 'https://www.fastcompany.com/91525420/the-stigma-around-ai-in-journalism-may-be-easing-but-trust-is-still-fragile', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5.2, '{}', 'The stigma around AI in journalism may be easing, but trust is still fragile', '2026-04-17 09:00:00+00', '2026-04-17 09:52:57.597975+00', 'I tend to write about AI from the perspective of the bleeding edge, looking at how journalists and media companies are using the technology to change the way they work , reach new audiences , and transform their organizations . But the reality is that there&#8217;s a stigma around using artificial intelligence in the journalism community. In conversations I have with working reporters and editors, there&#8217;s clearly still a lot of reluctance, if not outright disdain, for using AI in almost any part of their work. Looking at recent coverage of journalists using AI, however, you might think some of that disdain is going away. The Wall Street Journal recently profiled how Fortune business editor Nick Lichtenberg uses AI to turbocharge his output, sometimes writing as many as seven stories in a single day. The same day, Wired highlighted how several prominent reporters—including independents like Alex Heath and Taylor Lorenz as well as The New York Times ’ Kevin Roose—use AI in various editorial tasks, sometimes in the writing itself. With all this, it feels as if a kind of dam has burst, and I don&#8217;t think it&#8217;s a coincidence that it&#8217;s happening at the same time Claude Cowork —which brings incredibly powerful agentic AI to everyone—has transformed the AI landscape. (An interesting aside buried in all this coverage of journalists&#8217; use of AI is that it appears Claude is rapidly becoming what the Mac became among media pros: the platform of choice for creatives who &#8220;know better.&#8221;) {"blockType":"mv-promo-block","data":{"imageDesktopUrl":"https:\/\/images.fastcompany.com\/image\/upload\/f_webp,q_auto,c_fit\/wp-cms-2\/2025\/03\/media-copilot.png","imageMobileUrl":"https:\/\/images.fastcompany.com\/image\/upload\/f_webp,q_auto,c_fit\/wp-cms-2\/2025\/03\/fe289316-bc4f-44ef-96bf-148b3d8578c1_1440x1440.png","eyebrow":"","headline":"\u003Cstrong\u003ESubscribe to The Media Copilot\u003C\/strong\u003E","dek":"Want more about how AI is changing media? Never miss an update from Pete Pachal by signing up for The Media Copilot. To learn more visit \u003Ca href=\u0022https:\/\/mediacopilot.substack.com\/\u0022\u003Emediacopilot.substack.com\u003C\/a\u003E","subhed":"","description":"","ctaText":"SIGN UP","ctaUrl":"https:\/\/mediacopilot.substack.com\/","theme":{"bg":"#f5f5f5","text":"#000000","eyebrow":"#9aa2aa","subhed":"#ffffff","buttonBg":"#000000","buttonHoverBg":"#3b3f46","buttonText":"#ffffff"},"imageDesktopId":91453847,"imageMobileId":91453848,"shareable":false,"slug":"","wpCssClasses":""}} A cautionary tale in copy and paste However, if the relationship between journalists and AI has been warming up, it got splashed in the face with a cold bucket of water last week when The New York Times severed ties with a freelance writer who had submitted a book review that was at least partially AI-written. The review by Alex Preston , published in early January, included passages that were nearly identical to Christobel Kent&#8217;s', 'pending', 'Multiple', 'Pete Pachal', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (404, 'Spoofed Tankers Are Flooding the Strait of Hormuz. These Analysts Are Tracking Them', 'https://www.wired.com/story/spoofed-tankers-strait-of-hormuz/', 'Wired', 'https://www.wired.com/feed/rss', 5.2, '{}', 'Spoofed Tankers Are Flooding the Strait of Hormuz. These Analysts Are Tracking Them', '2026-04-17 09:30:00+00', '2026-04-17 09:52:57.59985+00', 'Marine insurers and oil traders want to know what’s going on in one of the world’s most critical waterways. As the volume of disappearing ships in the area increases, analysts are getting creative.', 'pending', 'Multiple', 'Aarian Marshall', NULL, 'news', false, false, 5, NULL);
