INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (373, 'Why Women Leaders Are Ditching the Old Workplace Rulebook—and Winning Because of It', 'https://www.inc.com/fast-company-2/women-leaders-old-workplace-rulebook-winning/91331896', 'Inc. Magazine', 'https://www.inc.com/rss', 6.2, '{Leadership,Culture}', 'Female executives rejecting traditional management norms demonstrate measurable gains in retention and performance—signaling a leadership model shift that reshapes organizational effectiveness.', '2026-04-16 12:34:43+00', '2026-04-17 08:32:43.300477+00', 'Forging a new model leads to happier work lives and a better bottom line.', 'selected', 'System Vitality', 'Fast Company', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (368, 'Finance leaders warn over Mythos as UK banks prepare to use powerful Anthropic AI tool', 'https://www.theguardian.com/technology/2026/apr/17/finance-leaders-warn-over-claude-mythos-as-uk-banks-prepare-to-use-powerful-anthropic-ai-tool', 'The Guardian', 'https://www.theguardian.com/world/rss', 7.5, '{AI,Policy}', 'Major AI model expansion into financial services raises systemic risk questions: senior finance leaders flagging safety concerns as Anthropic deploys Claude to UK banks with limited public oversight.', '2026-04-17 08:17:58+00', '2026-04-17 08:32:43.288759+00', 'Release of new Claude model, so far limited to US firms, will expand to British institutions in coming days British banks will be given access in the next week to a powerful AI tool that was deemed too dangerous to be released to the public, as a series of senior finance figures warned over its impact. Anthropic, which has so far limited the release of the new model to a small clutch of primarily US businesses, including Amazon, Apple and Microsoft, said it would expand that to UK financial institutions. Continue reading...', 'selected', 'Strategic Foresight', 'Kalyeena Makortoff Banking correspondent', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (372, 'Amazon’s Secret Weapon Isn’t Technology. It’s Writing', 'https://www.inc.com/carmine-gallo/amazons-secret-weapon-isnt-technology-its-writing/91330477', 'Inc. Magazine', 'https://www.inc.com/rss', 7.2, '{Leadership,Culture}', 'Amazon''s institutional discipline around written communication—not slides—shapes decision-making quality and organizational culture at scale. A rare insight into how operational norms embed strategic thinking.', '2026-04-16 13:00:00+00', '2026-04-17 08:32:43.298211+00', 'If your explanation needs slides, it’s already too complicated.', 'selected', 'System Vitality', 'Carmine Gallo', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (344, 'Goldman Sachs Says Market Recovery Hinges on ''Rates Relief''', 'https://www.bloomberg.com/news/videos/2026-04-17/goldman-says-market-recovery-hinges-on-rates-relief-video', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 6.5, '{Economy,Finance}', 'Goldman''s head of asset allocation signals that equity rally sustainability depends on Fed rate cuts. Leaders must monitor central bank trajectory as a critical variable for capital deployment and financial planning.', '2026-04-17 07:36:34+00', '2026-04-17 08:32:43.229431+00', 'Christian Mueller-Glissmann, head of asset allocation research at Goldman Sachs, discusses the equities rally, the impact of US-Iran de-escalation on sentiment, and whether the markets recovery is sustainable. "I think we need central banks to shift back to a bit to where we were before," Mueller-Glissmann tells Bloomberg Television. "We need the rates relief to come in." (Source: Bloomberg)', 'selected', 'Strategic Foresight', NULL, NULL, 'news', false, true, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (378, 'Charles Schwab is launching direct bitcoin and ethereum trading', 'https://qz.com/charles-schwab-direct-bitcoin-ethereum-trading-041626', 'Quartz', 'https://qz.com/feed', 6.2, '{Finance,Technology}', 'A $11T asset manager''s entry into direct crypto trading signals institutional normalization of digital assets and shifts competitive dynamics in wealth management—leaders must assess crypto''s role in client strategy and competitive positioning.', '2026-04-16 15:20:32+00', '2026-04-17 08:32:43.312645+00', 'The brokerage, which manages more than $11 trillion in client assets, will charge a 0.75% fee per crypto trade', 'selected', 'Strategic Foresight', 'Colleen Cabili', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (385, 'Why Jeff Bezos’ Tax Rate Is Lower Than Yours', 'https://www.nytimes.com/2026/04/17/opinion/ezra-klein-podcast-ray-madoff.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 4.7, '{Policy,"Civic Stewardship"}', 'Tax policy explainer using Bezos case study to illustrate systemic inequities in capital gains treatment and wealth accumulation.', '2026-04-17 09:05:03+00', '2026-04-17 09:52:57.544057+00', 'The tax expert Ray Madoff explains why the American tax system is broken, and how to make it fairer.', 'pending', 'Civic Stewardship — legitimacy of institutional tax fairness and policy reform', 'Ezra Klein and Rollin Hu', NULL, 'news', false, false, 8.5, 'Argues that progressive taxation is structurally inadequate and allows high-net-worth individuals to exploit legal loopholes.');
