INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (392, 'South African Unions to Sign 3-Year Eskom Wage Deal for 7% Raise', 'https://www.bloomberg.com/news/articles/2026-04-17/south-african-unions-to-sign-3-year-eskom-wage-deal-for-7-raise', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 5.2, '{}', 'South African Unions to Sign 3-Year Eskom Wage Deal for 7% Raise', '2026-04-17 09:05:17+00', '2026-04-17 09:52:57.57297+00', 'South African labor unions will sign a three-year wage deal with state-owned power utility Eskom Holdings SOC Ltd. for above-inflation increases on Friday, according to two of the groups.', 'pending', 'Multiple', 'Paul Burkhardt', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (393, 'German Carriers Want to Tap Strategic Fuel Reserves, NATO Supply', 'https://www.bloomberg.com/news/articles/2026-04-17/german-carriers-want-to-tap-strategic-fuel-reserves-nato-supply', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 4.7, '{Geopolitics,Economy}', 'German carriers request access to strategic kerosene reserves and NATO supply chains to prevent summer flight disruptions amid Middle East tensions.', '2026-04-17 09:00:00+00', '2026-04-17 09:52:57.575073+00', 'German airlines are urging the government to take emergency steps such as releasing strategic kerosene reserves to avoid flight cuts before the peak summer season as Mideast tensions remain high.', 'pending', 'Strategic Foresight (weak signal on energy supply chain vulnerability and geopolitical cascades to commercial operations)', 'Sonja Wind', NULL, 'news', false, false, 8.5, 'German airlines seek emergency government intervention to release strategic fuel reserves amid geopolitical supply concerns.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (394, 'Markets Await Clarity on Iran Talks', 'https://www.bloomberg.com/news/videos/2026-04-17/markets-await-clarity-on-iran-talks-video', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 5.2, '{}', 'Markets Await Clarity on Iran Talks', '2026-04-17 08:57:49+00', '2026-04-17 09:52:57.576903+00', 'Traders are waiting for further details of a potential peace deal between Iran and the US ahead of the weekend at the end of a febrile week. Meanwhile there''s little room for disappointment as companies start to feel the impact of the war. (Source: Bloomberg)', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (397, 'Trump: Iran Deal ''Looking Good'' & Israel-Lebanon Ceasefire | Daybreak Europe 4/17/2026', 'https://www.bloomberg.com/news/videos/2026-04-17/daybreak-europe-4-17-2026-video', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 5.2, '{}', 'Trump: Iran Deal ''Looking Good'' & Israel-Lebanon Ceasefire | Daybreak Europe 4/17/2026', '2026-04-17 08:35:15+00', '2026-04-17 09:52:57.584187+00', 'Bloomberg Daybreak Europe is your essential morning viewing to stay ahead. US President Donald Trump says the US and Iran could agree to a permanent ceasefire “pretty soon” and talks may resume this weekend. The president also plans to invite Israel and Lebanon to the White House for discussions as their 10-day truce kicks off today. Meanwhile, Bloomberg understands that some European and Gulf Arab leaders think a US-Iran peace deal will take six months to finalise. Keir Starmer faces renewed calls to quit after revelations that his US envoy Peter Mandelson was granted security clearance despite objections from vetting officials. Bloomberg understands the UK prime minister fired the foreign office’s top civil servant, Olly Robbins, over the incident. Today''s guest: Aneeka Gupta, Director of Macroeconomic Research at Wisdomtree. (Source: Bloomberg)', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (398, 'Ambani’s Jio Platforms Is Said to Plan Filing for IPO Next Month', 'https://www.bloomberg.com/news/articles/2026-04-17/ambani-s-jio-platforms-is-said-to-plan-filing-for-ipo-next-month', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 4.7, '{Finance,Strategy}', 'Reliance Industries subsidiary Jio Platforms expected to file IPO paperwork in May, incorporating full-year earnings data.', '2026-04-17 08:06:57+00', '2026-04-17 09:52:57.58622+00', 'Reliance Industries Ltd. is likely to file draft paperwork for the initial public offering of Jio Platforms Ltd. in May, incorporating earnings for the full fiscal year, according to people familiar with the matter.', 'pending', 'Tangential to Strategic Foresight (market capital formation); no clear implications for system vitality or civic stewardship.', 'Baiju Kalesh, Rajesh Mascarenhas, Sanjai P R', NULL, 'news', false, false, 7.5, 'Reports on Jio Platforms'' expected IPO filing timeline based on unnamed sources familiar with the matter.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (399, 'The nation’s cartoonists on the week in politics', 'https://www.politico.com/gallery/2026/04/17/the-nations-cartoonists-on-the-week-in-politics-00878255', 'Politico', 'https://rss.politico.com/politics-news.xml', 2.7, '{}', 'Weekly curated collection of political cartoons from U.S. cartoonists reflecting on current events.', '2026-04-17 09:00:00+00', '2026-04-17 09:52:57.588227+00', 'Every week political cartoonists throughout the country and across the political spectrum apply their ink-stained skills to capture the foibles, memes, hypocrisies and other head-slapping events in the world of politics. The fruits of these labors are hundreds of cartoons that entertain and enrage readers of all political stripes. Here''s an offering of the best of this week''s crop, picked fresh off the Toonosphere. Edited by Matt Wuerker.', 'pending', 'None', 'By POLITICO Staff', NULL, 'news', false, false, 7.5, 'Reports on weekly political cartoons without taking an editorial position.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (400, 'Scoop: Anthropic to have peace talks at White House', 'https://www.axios.com/2026/04/17/anthropic-trump-administration-mythos', 'Axios', 'https://api.axios.com/feed/', 5.2, '{}', 'Scoop: Anthropic to have peace talks at White House', '2026-04-17 09:41:50+00', '2026-04-17 09:52:57.590181+00', 'Anthropic CEO Dario Amodei is scheduled to walk into the West Wing on Friday for a meeting with White House chief of staff Susie Wiles — a breakthrough in his effort to resolve the company''s bitter AI fight with the Pentagon. Why it matters: The Trump administration recognizes the power of Anthropic''s new Claude model, Mythos , and its highly sophisticated — and potentially dangerous — ability to breach cybersecurity defenses . "It would be grossly irresponsible for the U.S. government to deprive itself of the technological leaps that the new model presents," a source close to negotiations told us. "It would be a gift to China." Reminder: Anthropic is suing the Pentagon for blacklisting the company after Amodei refused to allow his AI to be used without restrictions. Some parts of the U.S. intelligence community , plus the Cybersecurity and Infrastructure Security Agency (CISA, part of Homeland Security), are testing Mythos. Treasury and others want it. Behind the scenes: After Anthropic took the administration to court, negotiations with the Pentagon chilled. But Anthropic has hired key Trumpworld consultants — so expect a deal. Friday''s meeting is designed to pave the way. Flashback: This is the second time Amodei has held a high-stakes meeting with a top Trump official this year. In late February, Defense Secretary Pete Hegseth gave Amodei until the end of the week to accept the Pentagon''s terms, or else. Anthropic didn''t. Since then, the Pentagon and Anthropic have been locked in a legal and political feud. Some in the administration think the fight is growing counterproductive. 💡 If you''re a CEO or on a CEO''s team: Apply here for free admission to Jim''s new Axios C-Suite weekly newsletter. Go deeper : Trump officials negotiating access to Anthropic''s Mythos despite blacklist.', 'pending', 'Multiple', 'Jim VandeHei', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (395, 'Wall Street Turns Gloomy on the Dollar as Haven Demand Fades', 'https://www.bloomberg.com/news/articles/2026-04-17/wall-street-turns-gloomy-on-the-dollar-as-haven-demand-fades', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 6.5, '{Geopolitics,Finance}', 'Major banks signal end of dollar''s geopolitical risk premium as US-Iran tensions ease, triggering portfolio reallocation toward risk assets.', '2026-04-17 00:00:00+00', '2026-04-17 09:52:57.580148+00', 'Deutsche Bank AG and Wells Fargo & Co. are among banks declaring the dollar’s war-driven haven rally is likely over as the fragile ceasefire between the US and Iran prompts investors to seek riskier assets.', 'selected', 'Strategic Foresight — weak signal on geopolitical volatility shifts and their market consequences; Finance — currency/capital flow implications', 'Carter Johnson, Anya Andrianova', NULL, 'news', false, false, 9.5, 'Claims that geopolitical de-escalation is shifting capital allocation away from safe-haven currencies toward riskier assets.');
