INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (413, '‘Popesplaining’ Vance out of depth in row over whether Iran is a just war', 'https://www.theguardian.com/world/2026/apr/17/pope-jd-vance-row-iran-just-war', 'The Guardian', 'https://www.theguardian.com/world/rss', 5.2, '{}', '‘Popesplaining’ Vance out of depth in row over whether Iran is a just war', '2026-04-17 09:00:25+00', '2026-04-17 09:52:57.618384+00', 'Trump administration has riled head of Catholic church over use of theology to justify conflict in Iran The contrast in experience between the two men disagreeing over war and theology was striking. On the one side was Pope Leo XIV, the first North American to head the Catholic church and the first cleric from the Augustinian order, who this week visited the modern Algerian city where Saint Augustine once lived. For Leo, who wrote his doctoral thesis on Augustine’s ideas, it was the culmination of a lifelong intellectual interest. Continue reading...', 'pending', 'Multiple', 'Peter Beaumont Senior international correspondent', NULL, 'news', false, false, 5, NULL);
