INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (427, 'Are Markets Moving Past Iran War Shock? | The China Show 4/17/2026', 'https://www.bloomberg.com/news/videos/2026-04-17/the-china-show-4-17-2026-video', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 5.2, '{}', 'Are Markets Moving Past Iran War Shock? | The China Show 4/17/2026', '2026-04-17 09:18:32+00', '2026-04-17 10:00:25.87935+00', '“Bloomberg: The China Show” is your definitive source for news and analysis on the world''s second-biggest economy. From politics and policy to tech and trends, David Ingles and Yvonne Man give global investors unique insight, delivering in-depth discussions with the newsmakers who matter. (Source: Bloomberg)', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (428, 'Richard Desmond loses £1.3bn damages battle over national lottery licence', 'https://www.theguardian.com/uk-news/2026/apr/17/richard-desmond-loses-damages-battle-with-gambling-commission-ending-national-lottery-dispute', 'The Guardian', 'https://www.theguardian.com/world/rss', 5.2, '{}', 'Richard Desmond loses £1.3bn damages battle over national lottery licence', '2026-04-17 09:47:42+00', '2026-04-17 10:00:26.111466+00', 'Firms owned by media tycoon launched action against Gambling Commission in 2022 after Allwyn won franchise The media tycoon Richard Desmond has lost his claim for up to £1.3bn in damages from the Gambling Commission , ending a bitter dispute over the regulator’s decision not to award him the 10-year licence to run the national lottery. Companies owned by the former proprietor of the Daily Express and Channel 5 launched action against the regulator in 2022, starting a tortuous legal process in which Desmond’s costs were estimated to have reached £55m by May last year. Continue reading...', 'pending', 'Multiple', 'Rob Davies', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (429, 'Lebanon’s Cease-Fire Buys Time, Not a Way Out', 'https://www.nytimes.com/2026/04/17/world/middleeast/lebanon-israel-ceasefire-hezbollah.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 5.7, '{Geopolitics,Strategy}', 'Lebanon secures Israel ceasefire through high-risk negotiations, but underlying institutional fragility and competing power centers suggest the pause masks deeper state-level dysfunction with potential spillover effects on regional stability and Western strategic interests.', '2026-04-17 10:10:32+00', '2026-04-17 10:26:25.662101+00', 'The country’s leaders secured a truce through risky talks with Israel, but the government now finds itself caught between competing pressures.', 'pending', 'Strategic Foresight (geopolitical volatility, weak signals of state failure); Civic Stewardship (legitimacy of institutions, regional stability)', 'Euan Ward', NULL, 'news', false, false, 9.5, 'RGI partially agrees: the article correctly identifies that ceasefires are tactical pauses rather than strategic resolutions, but underestimates how state fragility in the Levant creates systemic risk for global business continuity and investor confidence in emerging markets. Senior leaders must recognize that institutional instability in critical geopolitical nodes—particularly those affecting energy, trade routes, and regional financial systems—now require explicit scenario planning in capital allocation and supply chain resilience strategies.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (430, 'Lebanon Cease-Fire Leaves Netanyahu in an Uncomfortable Spot', 'https://www.nytimes.com/2026/04/17/world/middleeast/lebanon-cease-fire-leaves-netanyahu.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 6.7, '{Geopolitics,Policy}', 'Netanyahu accepts Lebanon cease-fire despite domestic pressure, signaling potential subordination of Israeli security calculus to Trump administration preferences—reshaping regional stability dynamics and U.S. alliance credibility.', '2026-04-17 08:58:11+00', '2026-04-17 10:26:25.665381+00', 'Most Israelis wanted the fight against Hezbollah to continue. But Prime Minister Benjamin Netanyahu’s critics say he is showing that he cannot, or will not, stand up to President Trump.', 'pending', 'Strategic Foresight (geopolitical volatility, alliance realignment, weak signals in U.S. foreign policy under Trump); Civic Stewardship (institutional legitimacy of Western security commitments, democratic consensus fracture in Israel)', 'David M. Halbfinger', NULL, 'news', false, false, 8.5, 'RGI partially agrees: The article correctly identifies a significant geopolitical inflection point—U.S.-Israel alignment under Trump is reshaping Middle East strategy—but frames it primarily through domestic Israeli politics rather than systemic implications for global security architecture and corporate/institutional risk. Senior leaders must understand that U.S. foreign policy unpredictability under Trump directly affects supply chains, regional stability, and institutional legitimacy calculations for firms operating across the Middle East and allied economies.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (431, 'What to Know About the Israel-Lebanon Cease-Fire, and R.F.K. Jr.’s Shifting Tone on Vaccines', 'https://www.nytimes.com/2026/04/17/podcasts/the-headlines/israel-lebanon-cease-fire-rfk-jr-vaccines-heelys.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 4.7, '{Geopolitics}', 'NYT news roundup combining Israel-Lebanon ceasefire coverage with R.F.K. Jr. vaccine commentary and a Friday quiz.', '2026-04-17 10:00:09+00', '2026-04-17 10:26:25.667946+00', 'Plus, the Friday news quiz.', 'pending', 'Geopolitics has tangential relevance to Civic Stewardship; vaccine policy touches on institutional legitimacy, but this aggregation format lacks strategic depth for executive decision-making.', 'Tracy Mumford, Will Jarvis, Margaret Kadifa, Ian Stewart, Christina Goldbaum and Ash Wu', NULL, 'news', false, false, 8.5, 'RGI notes this item falls outside the core strategic lens — limited implications for senior leadership.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (432, 'She Made Sure Her Baby Was Born an American. Then Federal Agents Separated Them.', 'https://www.nytimes.com/2026/04/17/us/politics/ice-cbp-birth-pregnancy-detention.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 5.2, '{}', 'She Made Sure Her Baby Was Born an American. Then Federal Agents Separated Them.', '2026-04-17 09:01:09+00', '2026-04-17 10:26:25.670453+00', 'Diana Acosta Verde, who came into the United States illegally when she was six months pregnant, had to leave her baby at a hospital while she returned to a detention center.', 'pending', 'Multiple', 'Caroline Kitchener, Charo Henríquez and Hamed Aleaziz', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (433, 'Texas Restaurant Owners Call for Work Permits as Immigration Crackdown Strains Industry', 'https://www.nytimes.com/2026/04/17/us/texas-restaurants-immigration-work-permits.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 6.7, '{Policy,"Future of Work","Civic Stewardship"}', 'Texas restaurant operators, facing acute labor shortages from immigration enforcement, are forming cross-partisan coalitions to lobby for legal work pathways—signaling both sector-level operational strain and the emergence of business-led policy reform.', '2026-04-17 09:00:57+00', '2026-04-17 10:26:25.673785+00', 'Restaurant operators say labor shortages, rising costs and worker fear have prompted an unusual alliance of industry and political leaders in Texas to call for legal pathways to hire immigrants.', 'pending', '{"System Vitality: organizational response to external labor constraints and workforce sustainability","Civic Stewardship: private sector mobilizing to reshape immigration policy and assert legitimacy in regulatory debates"}', 'Jesus Jiménez', NULL, 'news', false, false, 9.5, 'RGI partially agrees: the article correctly identifies systemic labor market dysfunction and organizational adaptation, but frames this primarily as an immigration policy issue rather than the deeper leadership challenge of workforce resilience and organizational legitimacy during regulatory volatility. Senior leaders must recognize that labor scarcity forcing unlikely coalitions signals a fundamental mismatch between workforce availability and operational model sustainability—requiring either business model redesign or proactive policy participation.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (434, 'The 27-Year-Old Diplomat Waging Trump’s Cultural War With Europe', 'https://www.nytimes.com/2026/04/17/world/europe/trump-samson-europe.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 5.2, '{}', 'The 27-Year-Old Diplomat Waging Trump’s Cultural War With Europe', '2026-04-17 09:07:36+00', '2026-04-17 10:26:25.676009+00', 'Five years out of college, Samuel Samson has driven the Trump administration’s push to upend America’s postwar relationship with Europe.', 'pending', 'Multiple', 'Michael D. Shear, Catherine Porter, Jane Bradley and Christopher F. Schuetze', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (435, 'Trump Tries to Stop Drug Smuggling From South America. Drug Smugglers Invent New Tactics.', 'https://www.nytimes.com/2026/04/17/world/americas/trump-drug-trafficking-south-america-brazil.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 6.7, '{Geopolitics,Policy,Governance}', 'U.S. authorities deploy advanced tech (drones, AI, troops) to interdict cocaine smuggling from South America, but criminal organizations rapidly evolve countermeasures, moving record volumes. Signals systemic mismatch between enforcement capacity and adaptive criminal networks.', '2026-04-17 09:00:12+00', '2026-04-17 10:26:25.678675+00', 'Authorities are using drones, troops and A.I. to crack down on cocaine smuggling. But gangs are finding new ways to move record amounts of drugs across the world.', 'pending', 'Civic Stewardship (institutional legitimacy, policy effectiveness, cross-border governance) + Strategic Foresight (adversarial adaptation, weak signals in illicit networks)', 'Ana Ionova, Max Bearak and Federico Rios', NULL, 'news', false, false, 9.5, 'RGI partially agrees: the article correctly identifies adversarial adaptation in illicit supply chains, but frames this as a law-enforcement cat-and-mouse game rather than a systemic governance failure affecting institutional legitimacy and cross-border policy coordination. Senior leaders must recognize that drug trafficking networks now operate as sophisticated adaptive systems requiring whole-of-society response—not enforcement-only approaches—and this directly challenges corporate supply chain security, community safety mandates, and government credibility in border management.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (436, 'The case for fixing everything', 'https://www.technologyreview.com/2026/04/17/1135408/book-review-stewart-brand-fixing-everything-maintenance/', 'MIT Technology Review', 'https://www.technologyreview.com/feed/', 6.7, '{Strategy,Governance}', 'Stewart Brand''s new book ''Maintenance: Of Everything'' argues that maintenance is foundational to civilizational health, a claim with implications for how organizations prioritize durability over growth.', '2026-04-17 10:00:00+00', '2026-04-17 10:26:25.681301+00', 'The handsome new book Maintenance: Of Everything, Part One, by the tech industry legend Stewart Brand, promises to be the first in a series offering “a comprehensive overview of the civilizational importance of maintenance.” One of Brand’s several biographers described him as a mainstay of both counterculture and cyberculture, and with Maintenance, Brand wants us&#8230;', 'pending', 'System Vitality (organizational durability, long-term health); Civic Stewardship (institutional infrastructure and resilience)', 'Lee Vinsel', NULL, 'news', false, false, 7.5, 'RGI partially agrees: Brand''s thesis that maintenance is civilizationally critical aligns with System Vitality (organizational durability, infrastructure health) and Civic Stewardship (institutional legitimacy), but the article reads as book promotion rather than strategic signal about *why* maintenance culture is failing in institutions or markets. Leaders should audit whether their organizations treat maintenance as strategic capital or cost-center liability—misclassification directly degrades institutional resilience.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (437, 'How robots learn: A brief, contemporary history', 'https://www.technologyreview.com/2026/04/17/1135416/how-robots-learn-brief-contemporary-history/', 'MIT Technology Review', 'https://www.technologyreview.com/feed/', 4.7, '{Technology,Innovation}', 'MIT Technology Review surveys the history of robot learning, contrasting early sci-fi ambitions with practical industrial outcomes. Frames the evolution from aspiration (humanoid robots) to market reality (specialized machines).', '2026-04-17 10:00:00+00', '2026-04-17 10:26:25.684052+00', 'Roboticists used to dream big but build small. They’d hope to match or exceed the extraordinary complexity of the human body, and then they’d spend their career refining robotic arms for auto plants. Aim for C-3P0; end up with the Roomba.&#160; The real ambition for many of these researchers was the robot of science fiction—one&#8230;', 'pending', 'Tangential to Strategic Foresight — describes technological evolution rather than forward-looking disruption signals or leadership implications.', 'James O''Donnell', NULL, 'news', false, false, 8.5, 'RGI notes this item falls outside the core strategic lens — limited implications for senior leadership.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (438, 'They bought property in the metaverse. Then it collapsed', 'https://www.fastcompany.com/91526201/metaverse-property-sunk-cost', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5.2, '{}', 'They bought property in the metaverse. Then it collapsed', '2026-04-17 10:06:00+00', '2026-04-17 10:26:25.687324+00', 'Five years ago, tech angel investor Chris Adamo and a few friends jumped on a burgeoning trend in the digital asset world: they used a virtual real estate broker to buy 23 parcels of property in a metaverse called The Sandbox. He doesn’t remember exactly how much he spent, but it was around $200,000 for the whole group. The real estate, to be clear, consisted of pixelated parcels in “hip,” “trendy” virtual “neighborhoods,” an asset that crypto bros and Web3 enthusiasts like Adamo saw as the future of tech and digital investment. At one point, it ballooned tenfold in value. Adamo was far from alone. Across the four major metaverse platforms, property sales topped $500 million in 2021. It wasn’t just niche investors making that call. Perhaps most famously, Mark Zuckerberg bet big on the metaverse. He called it “the successor to the mobile internet.” Convinced that one billion people would eventually use it, he poured $80 billion into the effort and, in one of the most visible signals of that bet, renamed Facebook as Meta. Adamo and his cohort bought into that vision. &#8220;When metaverse worlds and NFTs started, our friend group wanted to begin learning and playing in the proverbial sandbox,&#8221; Adamo says. “Since we all had already owned so many NFTs, as an experience to learn that realm, land ownership seemed like the next logical trial by fire.&#8221; But big promises to investors gave way to weak financial performance and low user counts, and many metaverse companies have struggled in recent years. The Verge reported in 2023 that Decentraland’s billion-dollar metaverse had as few as 38 active users on a given day. Animoca Brands, which owns The Sandbox, cut 50% of its staff and closed all offices worldwide last year. Perhaps most damningly, Mark Zuckerberg announced last month that Meta would effectively shut down Horizon Worlds in June. All of its employees were laid off and the metaverse budget cut by 30% as the company pivoted toward wearables like its viral AI and AR glasses . As for Adamo, he tells Fast Company that the money his group put into Sandbox real estate has effectively been written off as a sunk cost, one he has accepted won’t yield returns anytime soon. They tried to sell and take the loss, but there was “no one to buy them,” he says. For now, they’re holding on, partly in the hope that the assets might rebound, partly, as Adamo jokes, as a kind of historical artifact. &#8220;Going into it, we knew that it was going to either be a complete wash (too early) or a big outcome if it took off,&#8221; he says via Instagram direct message. &#8220;Sadly, the tech and adoption was just too slow and lost steam as COVID ended and people got back to real-world activities.&#8221; How the metaverse real estate economy works The metaverse house-hunting process largely mirrors the real-world one. Land can be bought at auction or at a fixed price. Once a buyer secures a parcel, they pay in crypto and receive the keys as a non-fungible token', 'pending', 'Multiple', 'Steffi Cao', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (439, 'Australia scrambles to secure energy as war on Iran fuels uncertainty', 'https://www.aljazeera.com/features/2026/4/17/australia-scrambles-to-secure-energy-as-war-on-iran-fuels-uncertainty?traffic_source=rss', 'Al Jazeera English', 'https://www.aljazeera.com/xml/rss/all.xml', 6.4, '{Geopolitics,Economy,Policy}', 'Australia faces energy supply volatility amid Iran tensions, exposing structural reliance on imported oil and raising questions about energy security as both economic and geopolitical vulnerability.', '2026-04-17 10:09:09+00', '2026-04-17 10:26:25.690075+00', 'Heavily dependent on imported oil, Australia looks for quick fixes from regional diplomacy to free train rides.', 'pending', 'Strategic Foresight (weak signal on resource dependency in volatile regions); Civic Stewardship (energy policy, institutional response)', NULL, NULL, 'news', false, false, 7.2, 'RGI partially agrees: Australia''s energy vulnerability is real and structurally significant, but the article conflates acute geopolitical risk with long-term energy strategy without distinguishing between them. Senior leaders must recognize that energy security is now a core geopolitical asset—not a logistics problem—and that regional dependencies create asymmetric exposure to state actors.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (440, 'Trump’s pardons are costing shooting survivors millions', 'https://www.theguardian.com/us-news/2026/apr/17/trump-pardons-cost-shooting-survivors-millions', 'The Guardian', 'https://www.theguardian.com/world/rss', 5.2, '{}', 'Trump’s pardons are costing shooting survivors millions', '2026-04-17 10:00:27+00', '2026-04-17 10:26:25.692509+00', 'A Trace analysis found that revenue from fining white-collar criminals is drying up – due to presidential pardons This story was originally published by the Trace, a non-profit newsroom covering gun violence in America. Sign up for its newsletters here. Since his return to office last year, Donald Trump has pardoned dozens of white-collar criminals. He’s also forgiven their fines, penalties and restitution, to the tune of billions . Some of that revenue was supposed to go to a fund to help victims of violent crime – and the organizations that serve them are feeling the pinch. Continue reading...', 'pending', 'Multiple', 'Jennifer Mascia for the Trace', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (442, '9 Successful Entrepreneurs on How to Turn a Side Hustle Into a Real Business', 'https://www.inc.com/jaime-catmull/successful-entrepreneurs-grow-side-hustle-real-business/91331177', 'Inc. Magazine', 'https://www.inc.com/rss', 5.2, '{}', '9 Successful Entrepreneurs on How to Turn a Side Hustle Into a Real Business', '2026-04-17 10:00:00+00', '2026-04-17 10:26:25.697484+00', 'Building successful businesses is not about luck or timing. It’s about identifying real demand and building systems that foster significant growth.', 'pending', 'Multiple', 'Jaime Catmull', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (369, 'Foreign Office’s top civil servant Olly Robbins forced out over Mandelson vetting row', 'https://www.theguardian.com/uk-news/2026/apr/16/foreign-offices-top-civil-servant-olly-robbins-leaves-post-in-mandelson-vetting-row', 'The Guardian', 'https://www.theguardian.com/world/rss', 7.5, '{Governance,Policy}', 'UK PM loses confidence in top civil servant over vetting override decision—signals institutional tension between political leadership and civil service independence on security accountability.', '2026-04-17 07:59:54+00', '2026-04-17 08:32:43.29178+00', 'Keir Starmer understood to have lost confidence in official over decision to override security vetting failure Mandelson failed vetting but Foreign Office overruled decision Sir Olly Robbins, the UK Foreign Office’s top civil servant, has been forced out of his post after the decision to fail Peter Mandelson during his security vetting was overruled by his department. Robbins was the Foreign Office’s most senior official in late January 2025 when the decision was made, paving the way for Mandelson to become the US ambassador. Continue reading...', 'selected', 'System Vitality', 'Pippa Crerar Political editor', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (396, 'HKEX Plans to Cut Trade Settlement to One Day From End of 2027', 'https://www.bloomberg.com/news/articles/2026-04-17/hkex-plans-to-cut-trade-settlement-to-one-day-from-end-of-2027', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 6.7, '{Finance,Technology,Geopolitics}', 'Hong Kong stock exchange moving to T+1 settlement by end of 2027, aligning with global market infrastructure modernization but raising operational complexity for Western investors.', '2026-04-17 08:46:58+00', '2026-04-17 09:52:57.582185+00', 'Hong Kong’s stock exchange operator is planning to halve the time it takes to settle stock trades, matching a global push toward shorter settlement windows despite concerns over the operational hurdles for Western investors.', 'selected', 'Strategic Foresight — market infrastructure transition; Finance — settlement system modernization', 'Kiuyan Wong', NULL, 'news', false, false, 9.5, 'Reports on HKEX''s plan to accelerate trade settlement cycles to align with global standards, noting implementation challenges for international market participants.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (412, 'Ben Roberts-Smith’s comrades say he ordered them to execute unarmed civilians, court documents show', 'https://www.theguardian.com/australia-news/2026/apr/17/ben-roberts-smiths-comrades-say-he-ordered-them-to-execute-unarmed-civilians-court-documents-show-ntwnfb', 'The Guardian', 'https://www.theguardian.com/world/rss', 6.7, '{Governance,Policy}', 'Australian war crimes prosecution alleges Victoria Cross recipient Ben Roberts-Smith ordered execution of unarmed detainees in Afghanistan, with court documents showing systematic evidence planting and control failures.', '2026-04-17 09:34:41+00', '2026-04-17 09:52:57.615938+00', 'Former SAS corporal allegedly placed man on his knees and ordered fellow soldier to shoot him, according to statement of facts Australian soldiers have told prosecutors they executed unarmed civilians at the orders of Ben Roberts-Smith or in complicity with him, according to a statement of facts tendered to the New South Wales local court. Roberts-Smith, a Victoria Cross recipient and once one of Australia’s most lionised soldiers, faces five charges of the war crime of murder, allegedly committed while he served in the Australian SAS in Afghanistan. Each victim was unarmed and present in a location where Roberts-Smith could reasonably have suspected insurgents to be located; Each offence was committed in a situation where there was no active engagements with enemy forces and the Australian Defence Force was in control of the environment; Evidence was planted or falsely associated with each deceased to enhance reporting that each of the killings were within the lawful rules of engagement; Each deceased was handcuffed, detained for a period, and questioned prior to their execution; None of the deceased was killed in a situation where the Australian Defence Force did not have effective control of the battlespace. Continue reading...', 'selected', 'System Vitality (institutional accountability, trust in defense institutions); Civic Stewardship (legitimacy of state power, rule of law)', 'Ben Doherty and Penry Buckley', NULL, 'news', false, false, 9.5, 'Reports on court allegations that decorated SAS officer ordered execution of unarmed detainees, raising questions about military accountability and rules of engagement.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (338, 'Gold Heads for Fourth Weekly Gain on Optimism for US-Iran Truce', 'https://www.bloomberg.com/news/articles/2026-04-16/gold-steadies-after-trump-expresses-optimism-on-us-iran-truce', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 6.5, '{Geopolitics,Economy}', 'Trump signals potential US-Iran ceasefire, reducing geopolitical risk premium in commodities and inflation expectations—a material shift in market conditions leaders must monitor for capital allocation and supply chain planning.', '2026-04-16 22:19:47+00', '2026-04-17 08:32:43.215301+00', 'Gold headed for a fourth weekly gain after President Donald Trump expressed optimism that the US and Iran could agree a permanent ceasefire to end the war that’s upended markets and heightened inflation fears.', 'selected', 'Strategic Foresight', 'Yihui Xie', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (339, 'ECB Must Be ‘Vigilant’ Without Rushing Rate Hikes, Muller Says', 'https://www.bloomberg.com/news/articles/2026-04-17/ecb-must-be-vigilant-without-rushing-rate-hikes-muller-says', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 6.5, '{Economy,Policy}', 'ECB official signals cautious inflation monitoring amid geopolitical risk, suggesting monetary policy will remain data-dependent rather than reactive—critical for leaders managing currency, capital, and operational exposure to eurozone.', '2026-04-17 08:10:44+00', '2026-04-17 08:32:43.217662+00', 'The European Central Bank needs to stay “vigilant“ to potential inflation risks from the Iran war but mustn’t act in haste, Governing Council member Madis Muller said.', 'selected', 'Strategic Foresight', 'Mark Schroers, Jana Randow', NULL, 'news', false, true, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (359, 'Iran war’s big winners: Wall Street, weapons firms, AI and green energy', 'https://www.aljazeera.com/news/2026/4/17/iran-wars-big-winners-wall-street-weapons-firms-ai-and-green-energy?traffic_source=rss', 'Al Jazeera English', 'https://www.aljazeera.com/xml/rss/all.xml', 7.2, '{Geopolitics,Economy,AI}', 'Geopolitical escalation creates bifurcated market conditions: macro headwinds offset by concentrated gains in defense, AI, and energy sectors. Leaders must navigate divergent industry exposure and volatility.', '2026-04-17 07:42:37+00', '2026-04-17 08:32:43.264277+00', 'The global economic outlook for 2026 looks grim if the Iran war continues, but some industries are booming.', 'selected', 'Strategic Foresight', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (441, 'Oil prices dropping after Trump says Iran war should end ‘pretty soon’', 'https://www.marketwatch.com/story/oil-prices-dropping-after-trump-says-iran-war-should-end-pretty-soon-da53676a?mod=mw_rss_topstories', 'MarketWatch', 'https://feeds.marketwatch.com/marketwatch/topstories/', 7.4, '{Geopolitics,Economy}', 'Trump signals potential near-term Iran conflict resolution, triggering crude price decline. Market-moving geopolitical signal with direct implications for energy costs, supply chain stability, and capital allocation across energy-intensive sectors.', '2026-04-17 10:06:00+00', '2026-04-17 10:26:25.694979+00', 'West Texas Intermediate and Brent crude fell after U.S. President Donald Trump said it’s looking ‘very good’ that a truce will be made', 'selected', 'Strategic Foresight (geopolitical volatility, market transitions, weak signals); Economy (commodity pricing, energy markets)', 'Nora Redmond', NULL, 'news', false, true, 8.2, 'RGI partially agrees: Trump''s geopolitical signaling on Iran conflict resolution is strategically material, but the article conflates commodity price movement with policy certainty—markets react to rhetoric, not outcomes. Senior leaders must distinguish between negotiation signals and actual geopolitical de-escalation; energy volatility remains a structural risk until agreements are formalized and verified.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (443, 'Lebanon Cease-Fire Leaves Netanyahu in an Uncomfortable Spot', 'https://www.nytimes.com/2026/04/17/world/middleeast/lebanon-cease-fire-netanyahu-israel.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 6.7, '{Geopolitics,"Global Politics"}', 'Netanyahu agrees to Lebanon cease-fire despite domestic pressure for continued military action, signaling Trump administration''s decisive influence over Israeli foreign policy and regional conflict trajectory.', '2026-04-17 08:58:11+00', '2026-04-17 10:40:06.569494+00', 'Most Israelis wanted the fight against Hezbollah to continue. But Prime Minister Benjamin Netanyahu’s critics say he is showing that he cannot, or will not, stand up to President Trump.', 'pending', '{"Strategic Foresight","Civic Stewardship"}', 'David M. Halbfinger', NULL, 'news', false, false, 8.5, 'RGI partially agrees: the article correctly identifies a significant geopolitical inflection point—U.S.-Israel alignment under Trump reshaping Middle East conflict dynamics—but frames it primarily through domestic Israeli political narrative rather than systemic implications for global security architecture and corporate/institutional strategy. Senior leaders must recognize that U.S. executive preference now materially constrains regional military escalation, reducing geopolitical risk premiums in energy, defense, and Middle East operations—a structural shift requiring portfolio and exposure recalibration.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (444, 'World Leaders Turn to China’s Xi as Iran War Drags On', 'https://www.bloomberg.com/news/videos/2026-04-17/world-leaders-turn-to-china-s-xi-as-iran-war-drags-on-video', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 7.7, '{Geopolitics,"Global Politics"}', 'Xi Jinping signals willingness to mediate US-Iran tensions as world leaders seek China as arbiter of regional stability, marking a structural shift in how global power brokers navigate Middle East conflict.', '2026-04-17 10:29:47+00', '2026-04-17 10:40:06.67404+00', '"The international order is crumbling into disarray," says Chinese leader Xi Jinping. After peace talks between the US and Iran floundered, world leaders are rushing to meet with Xi, signaling growing expectations for China to be a credible force for peace. (Source: Bloomberg)', 'pending', 'Strategic Foresight (weak signal of multipolarity acceleration and US relative influence erosion); Civic Stewardship (legitimacy and role of major powers in international order).', NULL, NULL, 'news', false, true, 8.5, 'RGI partially agrees: the article correctly identifies a significant geopolitical shift in how major powers are repositioning around China as a potential mediator, but conflates diplomatic positioning with actual capability or willingness to resolve regional conflict. The signal is real; the interpretation of China''s motivations and leverage requires deeper scrutiny.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (445, 'The Shocking Secrets of Madison Square Garden''s Surveillance Machine', 'https://www.wired.com/story/madison-square-garden-jim-dolan-surveillance-machine/', 'Wired', 'https://www.wired.com/feed/rss', 5.2, '{}', 'The Shocking Secrets of Madison Square Garden''s Surveillance Machine', '2026-04-17 10:00:00+00', '2026-04-17 10:40:06.677025+00', 'Famously vengeful Knicks owner Jim Dolan has long spied on people at his iconic arenas. WIRED goes deep inside the operation that allegedly tracked a trans woman, lawyers, protesters, and more.', 'pending', 'Multiple', 'Noah Shachtman, Robert Silverman', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (446, 'Mandelson Failed Security Vetting…Who Knew What, When?', 'https://www.bbc.co.uk/sounds/play/p0nd41j7?at_medium=RSS&at_campaign=rss', 'BBC News', 'http://feeds.bbci.co.uk/news/rss.xml', 5, '{}', 'Mandelson Failed Security Vetting…Who Knew What, When?', '2026-04-16 19:40:00+00', '2026-04-17 10:40:06.680156+00', 'Starmer did not know Mandelson failed vetting, government says', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (447, 'I’ve Been Debunking AI Myths For 16 Years—the Truth Is Still the Truth', 'https://www.inc.com/joe-procopio/ive-been-debunking-ai-myths-for-16-years-the-truth-is-still-the-truth/91332338', 'Inc. Magazine', 'https://www.inc.com/rss', 5.2, '{}', 'I’ve Been Debunking AI Myths For 16 Years—the Truth Is Still the Truth', '2026-04-17 10:00:00+00', '2026-04-17 10:40:06.6834+00', 'The AI lies are only getting louder and sillier.', 'pending', 'Multiple', 'Joe Procopio', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (448, 'Supreme Court Sides With Oil Companies in Louisiana Coastal Lawsuits', 'https://www.nytimes.com/2026/04/17/us/politics/supreme-court-oil-louisiana.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 7.7, '{"Policy & Regulation","Climate & Environmental Health"}', 'Supreme Court ruling allows oil companies to move Louisiana coastal environmental suits from state to federal courts, reducing litigation pressure and weakening state-level environmental accountability mechanisms.', '2026-04-17 15:18:06+00', '2026-04-17 15:40:06.029374+00', 'The companies had asked the justices to clear the way to move environmental lawsuits out of state courts, to friendlier federal venues.', 'pending', '{"Civic Stewardship","Strategic Foresight"}', 'Abbie VanSickle', NULL, 'news', false, false, 9.5, 'RGI partially agrees: the ruling materially affects corporate litigation risk and state regulatory authority, but the decision itself is procedural rather than substantive on climate/environmental policy. Senior leaders must now anticipate that state-court environmental litigation—a key vector for forcing corporate accountability on coastal risk—has become significantly harder to weaponize, reshaping how boards evaluate climate liability and community trust in coastal regions.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (449, 'A Family Feud at an Oregon Winery Turns to Vinegar Over A.I. Slop', 'https://www.nytimes.com/2026/04/17/us/oregon-winery-ai-legal-fight.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 5.2, '{}', 'A Family Feud at an Oregon Winery Turns to Vinegar Over A.I. Slop', '2026-04-17 14:44:43+00', '2026-04-17 15:40:06.111103+00', 'She wanted to pry her late mother’s vineyard from two of her brothers. Instead, her lawyers were fined nearly $110,000 for citing bogus case law generated by artificial intelligence.', 'pending', 'Multiple', 'Evan Gorelick and Anna Griffin', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (450, 'Help for Medicare Advantage Patients Who Lose Doctors Is Shelved, for Now', 'https://www.nytimes.com/2026/04/16/business/medicare-advantage-enrollment-networks.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 5.5, '{"Policy & Regulation",Macroeconomics}', 'Widespread provider exits from Medicare Advantage plans leave seniors facing care disruption and cost escalation; federal relief measures stalled, exposing governance gaps in private health market.', '2026-04-16 19:52:11+00', '2026-04-17 15:40:06.125268+00', 'Nationwide, hospitals and other providers are leaving private Medicare Advantage plans, putting thousands of seniors at risk of higher costs and of losing trusted doctors.', 'pending', 'System Vitality (organizational trust, institutional health) + Civic Stewardship (corporate responsibility, legitimacy of firms managing public benefit programs)', 'Susan Jaffe', NULL, 'news', false, false, 9.5, 'RGI partially agrees: the article correctly identifies a structural market problem (provider-payer misalignment in Medicare Advantage) that affects institutional legitimacy and senior access, but frames it primarily as a consumer protection issue rather than a systemic governance failure requiring executive-level strategic response. Senior leaders must recognize that Medicare Advantage plan design failures create downstream reputational and regulatory risk for both insurers and provider networks, signaling broader questions about private sector stewardship of public health infrastructure.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (451, 'The Race for Space Energy Dominance', 'https://www.bloomberg.com/news/videos/2026-04-17/the-race-for-space-energy-dominance-video', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 7.7, '{Geopolitics,"Policy & Regulation","Energy & Oil"}', 'CEO of nuclear-space startup Oklo argues US must accelerate space nuclear development to compete with Russia and China; Bloomberg explores policy tailwinds and strategic implications.', '2026-04-17 15:23:53+00', '2026-04-17 15:40:06.130233+00', 'Nuclear energy is heading to space, and fast. Oklo CEO Jake DeWitte joined Bloomberg Open Interest to explain why nuclear power is the only viable solution for lunar bases and deep space missions, how US policy is accelerating development, and why falling behind rivals like Russia and China could shape the future of space dominance. (Source: Bloomberg)', 'pending', '{"Strategic Foresight — long-range technology transition and geopolitical capability race","Civic Stewardship — US policy positioning and institutional competitive posture"}', NULL, NULL, 'news', false, true, 8.5, 'RGI partially agrees: nuclear energy in space addresses genuine technical requirements for deep-space missions, but the framing of ''space energy dominance'' as a primary geopolitical battleground overstates current strategic urgency relative to terrestrial AI, supply-chain resilience, and near-term fiscal policy. Leaders should monitor space-based energy infrastructure as an emerging capability differentiator within 10-15 years, not as an immediate competitive pressure.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (452, 'Airfare Prices Won’t Drop Soon: Brian Kelly', 'https://www.bloomberg.com/news/videos/2026-04-17/airfare-prices-won-t-drop-soon-brian-kelly-video', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 5.2, '{}', 'Airfare Prices Won’t Drop Soon: Brian Kelly', '2026-04-17 15:16:18+00', '2026-04-17 15:40:06.133307+00', 'Airlines are hiking prices, cutting perks, and travelers still can’t get enough. Points Guy Founder Brian Kelly joins Bloomberg Open Interest to break down why airfare isn’t dropping anytime soon, how airlines are quietly stripping value from tickets, and why massive demand is keeping the entire system afloat despite rising costs and frustrations. (Source: Bloomberg)', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (453, 'The Private Credit Industry Is Growing Up. That’s Rarely a Painless Process', 'https://www.bloomberg.com/news/newsletters/2026-04-17/private-credit-is-growing-larger-but-what-about-bank-exposures', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 6.7, '{"Finance & Markets","Policy & Regulation"}', 'Bloomberg examines private credit industry expansion and maturation challenges, including governance and regulatory pressures as the sector scales beyond $1T+. Article signals potential inflection point in capital markets structure.', '2026-04-17 15:10:17+00', '2026-04-17 15:40:06.136767+00', 'Also: Who’s actually buying Cybertrucks?', 'pending', '{"System Vitality","Strategic Foresight"}', 'Christine Dobby', NULL, 'news', false, false, 8.5, 'RGI partially agrees: private credit growth reflects legitimate systemic shifts in capital allocation away from traditional banking, but the article''s framing of ''growing pains'' obscures deeper questions about opacity, systemic risk concentration, and regulatory arbitrage that matter for institutional leaders. Senior leaders managing institutional capital or board-level fiduciaries must understand that private credit expansion creates both opportunity and concentration risk — regulators will eventually demand transparency frameworks, which will reshape deal economics and governance expectations.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (454, 'Emerging Currencies Erase War Losses as Traders Bet on Peace', 'https://www.bloomberg.com/news/articles/2026-04-17/emerging-currencies-erase-war-losses-as-traders-bet-on-peace', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 4.7, '{Geopolitics,"Finance & Markets"}', 'Emerging-market currency indices have recovered war-related losses following de-escalation signals in the US-Iran conflict and reopening of the Strait of Hormuz.', '2026-04-17 15:10:16+00', '2026-04-17 15:40:06.139533+00', 'A key gauge of emerging-market currencies has fully recovered its losses from the start of the US-Iran war, driven by optimism that the conflict is de-escalating after Iran reopened the Strait of Hormuz.', 'pending', 'Tangential to Strategic Foresight (geopolitical de-escalation signal) but insufficient systemic or leadership implication to warrant high score.', 'Maria Elena Vizcaino, Leda Alvim', NULL, 'news', false, false, 8.5, 'RGI notes this item falls outside the core strategic lens — limited implications for senior leadership.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (456, 'What''s Next for Reed Hastings?', 'https://www.bloomberg.com/news/videos/2026-04-17/what-s-next-for-reed-hastings-video', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 4.7, '{"Finance & Markets"}', 'Bloomberg analyzes Netflix stock reaction to Reed Hastings'' departure announcement, attributing volatility to weak guidance and a $20B spending surge rather than leadership transition alone.', '2026-04-17 15:07:23+00', '2026-04-17 15:40:06.146861+00', 'Netflix stock is taking a hit, but just how much can be attributed to Reed Hastings'' exit Sarah Hunt of Alpine Woods and Geetha Ranganathan of Bloomberg Intelligence break down why investors are reacting to weak guidance and a massive $20B spending surge. (Source: Bloomberg)', 'pending', 'Tangentially touches Strategic Foresight (media/entertainment market signals) but lacks systemic implications for organizational leadership or governance.', NULL, NULL, 'news', false, false, 8.5, 'RGI notes this item falls outside the core strategic lens — limited implications for senior leadership.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (457, 'Canada Stocks Recover Losses From Iran Conflict as Strait Opens', 'https://www.bloomberg.com/news/articles/2026-04-17/canada-stocks-recover-losses-from-iran-conflict-as-strait-opens', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 6.7, '{Geopolitics,"Finance & Markets"}', 'Canadian equity markets reversed Middle East conflict losses after Iran signaled commercial shipping access to the Strait of Hormuz, suggesting potential de-escalation in regional tensions with implications for commodity prices and supply chain stability.', '2026-04-17 14:59:31+00', '2026-04-17 15:40:06.150328+00', 'Canadian stocks jumped Friday and reversed all of their losses since the war in the Middle East began after Iran said the Strait of Hormuz is open to commercial ships, fueling hopes the conflict may be nearing an end.', 'pending', 'Strategic Foresight (weak signal monitoring of geopolitical volatility and market transitions); Finance & Markets (equity market response to geopolitical risk pricing)', 'Stephanie Hughes', NULL, 'news', false, false, 9.5, 'RGI partially agrees: the article correctly identifies market-level implications of geopolitical de-escalation, but treats a single day''s recovery as strategic signal when systemic assessment requires sustained pattern evidence. Senior leaders must distinguish between tactical market volatility and durable geopolitical shifts—one day of strait reopening does not constitute a strategic inflection point without sustained stability indicators.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (458, 'Bitcoin Climbs to Two-Month High Amid Middle East Deal Optimism', 'https://www.bloomberg.com/news/articles/2026-04-17/bitcoin-climbs-to-two-month-high-amid-middle-east-deal-optimism', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 4.7, '{"Finance & Markets",Geopolitics}', 'Bitcoin price movement attributed to Middle East diplomatic optimism; Bloomberg reports on asset price fluctuation tied to geopolitical sentiment.', '2026-04-17 14:55:14+00', '2026-04-17 15:40:06.153506+00', 'Bitcoin climbed to the highest level since early February after a flurry of comments from the US and Iran sparked optimism that the conflict in the Middle East may be heading toward a resolution.', 'pending', 'Tangentially touches Strategic Foresight (geopolitical signal) but article is primarily a commodity price update without systemic market or leadership implications.', 'David Pan', NULL, 'news', false, false, 9.5, 'RGI notes this item falls outside the core strategic lens — limited implications for senior leadership.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (459, 'Ariel’s Rogers on Investing in Women’s Sports', 'https://www.bloomberg.com/news/videos/2026-04-16/ariel-s-rogers-on-women-s-sports-and-orphan-stocks-video', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 4.5, '{"Business & Strategy"}', 'John Rogers (Ariel Investments) discusses the firm''s entry into women''s sports investing and comments on US-Iran geopolitical tensions. A mixed-signal piece: the women''s sports investment is sectoral/portfolio news; geopolitical commentary lacks substantive analysis.', '2026-04-16 20:25:01+00', '2026-04-17 15:40:06.156606+00', 'Ariel Investments has been expanding its private markets platform and has jumped into the world of investing in women’s sports. Company Chair and co-CEO John Rogers speaks on “Bloomberg The Close” about the decision and also weighs in on the political implications of the difficult economic reality caused by the US-Iran war. (Corrects to reflect Project Level is under the Ariel Investments umbrella and not Ariel Alternatives.)', 'pending', 'Tangential to System Vitality (investment in underrepresented sectors); weak signal on Civic Stewardship (corporate capital allocation trends). No material governance, leadership, or systemic implication.', NULL, NULL, 'news', false, false, 8.5, 'RGI notes this item falls outside the core strategic lens — limited implications for senior leadership.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (460, 'Venezuela Bonds Rally as IMF Resumes Formal Contact with Caracas', 'https://www.bloomberg.com/news/articles/2026-04-17/venezuela-bonds-rally-as-imf-resumes-formal-contact-with-caracas', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 6.7, '{Geopolitics,"Finance & Markets"}', 'Venezuela''s sovereign bonds rally following IMF''s decision to restore formal engagement with Caracas, signaling potential shift in international financial and diplomatic posture toward the nation''s economic crisis.', '2026-04-17 14:43:19+00', '2026-04-17 15:40:06.159865+00', 'Venezuela’s dollar bonds are rallying on Friday as the International Monetary Fund’s decision to resume contact with authorities in Caracas lifts investor sentiment toward the nation’s defaulted debt.', 'pending', '{"Strategic Foresight","Civic Stewardship"}', 'Nicolle Yapur', NULL, 'news', false, false, 8.5, 'RGI partially agrees: The IMF''s resumption of formal contact with Venezuela signals potential policy normalization, but a single diplomatic gesture does not constitute a systemic economic or governance inflection point without evidence of structural reform or debt restructuring agreements. Senior leaders should monitor whether this diplomatic thaw translates into concrete institutional reforms or remains symbolic positioning ahead of potential negotiations.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (464, 'Treasuries Rally as Oil Tumbles on Mideast Peace Deal Optimism', 'https://www.bloomberg.com/news/articles/2026-04-17/treasuries-rally-as-oil-tumbles-on-mideast-peace-deal-optimism', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 5.7, '{Geopolitics,"Finance & Markets"}', 'Treasury yields and oil prices moved sharply on speculation of a Middle East peace breakthrough, suggesting markets are repricing geopolitical risk downward—but without confirmed diplomatic milestones.', '2026-04-17 13:58:31+00', '2026-04-17 15:40:06.17167+00', 'Treasuries jumped, sending yields to their lowest levels in a month, as oil prices tumbled on optimism a Middle East peace deal is within reach.', 'pending', 'Strategic Foresight (weak signal detection on geopolitical volatility); Finance & Markets (systemic asset price correlation)', 'Michael MacKenzie, Ye Xie', NULL, 'news', false, false, 9.5, 'RGI partially agrees: the article correctly signals market-level sensitivity to geopolitical risk repricing, but conflates short-term tactical moves with strategic inflection points—a single day''s treasury/oil correlation lacks staying power without clarity on underlying peace deal substance or timeline. Senior leaders must distinguish between market noise and durable geopolitical shifts: premature optimism on Mideast resolution has repeatedly proven false, and portfolio hedging decisions should rest on verified diplomatic progress, not sentiment swings.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (465, 'Intel Shares Soar to Highest Since 2000 on Turnaround Optimism', 'https://www.bloomberg.com/news/articles/2026-04-17/intel-shares-soar-to-highest-since-2000-on-turnaround-optimism', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 4.7, '{"Finance & Markets"}', 'Intel stock reaches 24-year high on turnaround momentum, but article provides no substantive signal about market shifts, competitive dynamics, or systemic implications.', '2026-04-17 13:46:49+00', '2026-04-17 15:40:06.174968+00', 'Intel Corp. shares leaped to their highest intraday level since the dot-com era on Friday as optimism that the chipmaker’s turnaround plan is working continues to grow.', 'pending', 'None of the three core disciplines (Strategic Foresight, System Vitality, Civic Stewardship) are materially engaged. This is a routine equity price movement without strategic context.', 'Ryan Vlastelica', NULL, 'news', false, false, 9.5, 'RGI notes this item falls outside the core strategic lens — limited implications for senior leadership.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (466, 'France and Greece to Renew Defense Pact and Broaden Cooperation', 'https://www.bloomberg.com/news/articles/2026-04-17/france-and-greece-to-renew-defense-pact-and-broaden-cooperation', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 6.7, '{Geopolitics,"Policy & Regulation"}', 'France and Greece formalize defense pact renewal, signaling European nations are building bilateral security partnerships amid geopolitical volatility. Strategic implication: bilateral pacts may accelerate defense spending but risk duplicating NATO capabilities.', '2026-04-17 13:45:19+00', '2026-04-17 15:40:06.177522+00', 'France and Greece are set to renew their defense pact next week as the European nations seek to further shore up their deterrence strategy.', 'pending', 'Strategic Foresight (geopolitical volatility, alliance architecture shifts)', 'Sotiris Nikas, Ania Nussbaum', NULL, 'news', false, false, 8.5, 'RGI partially agrees: France-Greece defense alignment reflects rational geopolitical hedging against Russian aggression and Turkish assertiveness, but the article lacks strategic depth on how this reshapes NATO architecture or European defense spending trajectories. Senior leaders should monitor whether bilateral defense pacts fragment EU collective security strategy or strengthen NATO''s southeastern flank—this distinction determines defense investment and supply chain resilience for European firms.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (478, 'What San Francisco’s AI billboards say about the state of the industry', 'https://www.fastcompany.com/91528348/what-san-franciscos-ai-billboards-say-about-the-state-of-the-industry', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5.4, '{"AI & Artificial Intelligence","Business & Strategy"}', 'Fast Company analyzes San Francisco billboards to argue that AI industry marketing prioritizes speed and capability over safety and governance—reflecting a market-driven orientation toward enterprise adoption over systemic risk mitigation.', '2026-04-17 14:47:54+00', '2026-04-17 15:40:06.223562+00', 'Here in San Francisco, we live in a bubble, and we know it. While much of the rest of the country sees the city through the lens of Fox News cameramen searching out homeless encampments, we actually live in a very beautiful, very wealthy, and, currently, very AI -obsessed place. Traditionally, the billboards along 101 through Silicon Valley have offered a glimpse into the collective mind of the tech industry. These days, a big chunk of that industry, including most of the major AI labs, is based here in San Francisco, and the billboards have followed. The San Francisco Chronicle recently did the legwork to catalog literally all of the billboards in the city and found that fully half now advertise AI apps, platforms, and infrastructure. The words and imagery they use reveal something about how the AI industry sees itself and the world around it. A billboard advertising an artificial intelligence company is posted on September 16, 2025 in San Francisco, California. As AI companies open offices in San Francisco, billboards advertising AI companies are appearing throughout the city and along Interstate 80. [Photo: Justin Sullivan/Getty Images] You are here The advertisements do collectively smack of young companies in a young industry. But they also depict an AI industry that is well past its experimental stage. The billboards around town, for the most part, advertise real apps that do non-trivial things, and products that solve real, sometimes niche problems that hinder the meaningful deployment of AI in business settings. No space for safety Even though AI safety, alignment with human values and goals, and governance remain hotly debated issues, almost none of the outdoor advertising mentions those subjects. The go-to-market teams at AI companies may believe billboards are no place for nuanced policy debates. The ads seem aimed at chief information officers or VP-level decision-makers trying to gain a competitive edge by using AI for more business tasks. That audience is likely more interested in agentic features, reliability, and scalability. Only one billboard, from Okta, mentioned downside risk. Its billboard reads: &#8220;Build and secure AI agents from day one. Okta secures AI.&#8221; What Okta is actually selling is identity and access management for AI agents—that is, the authentication and permissions systems that keep agents from seeing things they shouldn’t. On the other hand, trust will be a huge issue as AI models and agents proliferate within businesses. Leaders and workers will have to build trust in these systems over time, and that trust depends on AI consistently getting things right while being entrusted with increasingly valuable work. If an AI system leaks sensitive information, for example, trust could vanish, and the tool itself would quickly lose value. ‘Stop hiring humans’ Another elephant in the room is job replacement, yet none of the billboards acknowledge it. In one case, they lean into it. Artisan AI, which sells AI “wo', 'pending', 'System Vitality (institutional trust and governance), Strategic Foresight (AI industry maturation signals)', 'Mark Sullivan', NULL, 'news', false, false, 6.2, 'RGI partially agrees: the article correctly identifies that AI industry messaging avoids safety/governance discourse, but conflates billboard advertising strategy (B2B sales tactic) with actual industry priorities—which is incomplete. Senior leaders should recognize that enterprise AI adoption will increasingly hinge on trust infrastructure and governance frameworks, not just performance metrics, making safety a competitive differentiator rather than a marketing liability.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (467, 'Aluminum Drops After Iran Says Strait of Hormuz Is Fully Open', 'https://www.bloomberg.com/news/articles/2026-04-17/aluminum-drops-after-iran-says-strait-of-hormuz-is-fully-open', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 6.7, '{Geopolitics,"Finance & Markets"}', 'Iran''s announcement that the Strait of Hormuz is open triggered aluminum price declines, signaling market relief from shipping risk premium. The move affects Middle Eastern metal exporters and reflects shifting regional tensions.', '2026-04-17 13:44:42+00', '2026-04-17 15:40:06.181447+00', 'Aluminum prices sank in London after Iran said the Strait of Hormuz was open for cargoes to transit, a move that would allow the metal to be exported out of key producers Bahrain, Saudi Arabia and the United Arab Emirates.', 'pending', 'Strategic Foresight (geopolitical volatility and market signal transmission); System Vitality (organizational resilience planning for supply chain disruption)', 'Archie Hunter', NULL, 'news', false, false, 9.5, 'RGI partially agrees: the article correctly identifies a geopolitical-to-market transmission mechanism (Iranian sanctions rhetoric → shipping risk premium → commodity pricing), but conflates tactical shipping reassurance with strategic resolution of the Iran sanctions regime. Forward implication: Senior leaders in energy, metals, and defense sectors must model multiple Strait closure scenarios as tail-risk contingencies, as rhetorical openness does not eliminate structural geopolitical volatility or sanctions enforcement.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (469, 'US Natural Gas Futures Waver on Plunging Oil Price, Lower Output', 'https://www.bloomberg.com/news/articles/2026-04-17/us-natural-gas-futures-waver-on-plunging-oil-price-lower-output', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 4.7, '{"Energy & Oil"}', 'Intraday volatility in US natural gas futures driven by geopolitical chatter about the Strait of Hormuz and correlated energy product trading, with minimal fundamental supply/demand impact.', '2026-04-17 13:42:27+00', '2026-04-17 15:40:06.187226+00', 'US natural gas futures fluctuated between slight gains and losses, paring an earlier rise as Iran’s foreign minister said the Strait of Hormuz was “completely open.” The news sent oil prices plunging, triggering immediate financial outflows from baskets of energy products that include the US gas contract. The tandem price move happened despite near-term supply and demand for US gas remaining fundamentally unaffected by such geopolitical developments.', 'pending', 'None — this is commodity market microstructure reporting without systemic leadership implications.', 'Julian Hast', NULL, 'news', false, false, 9.5, 'RGI notes this item falls outside the core strategic lens — limited implications for senior leadership.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (472, 'House GOP rebellion derails FISA renewal', 'https://www.axios.com/2026/04/17/house-republicans-pass-fisa-extension', 'Axios', 'https://api.axios.com/feed/', 7.3, '{"Policy & Regulation","Global Politics"}', 'House GOP rebellion forces two-week FISA extension instead of long-term renewal, exposing Speaker Johnson''s diminished ability to enforce party discipline on national security—a signal of institutional fragmentation affecting governance capacity.', '2026-04-17 11:49:50+00', '2026-04-17 15:40:06.202023+00', 'The House voted overnight to extend Section 702 of the Foreign Intelligence Surveillance Act for two weeks after a bloc of 20 Republicans derailed a longer-term renewal. Why it matters: The revolt is a significant setback for House Speaker Mike Johnson (R-La.) and the White House, who both pushed for a clean long-term extension of the surveillance authority. The House agreed by unanimous consent to extend FISA until April 30 after a group of Republicans blocked attempts to pass five-year and 18-month renewals of the program. The short-term patch was a last-resort option for GOP leadership, who couldn''t muscle the longer extension despite an aggressive whip effort. The program is set to lapse Monday. Driving the news: Johnson was trying to pass a five-year extension of the national security tool with reforms after postponing an initial vote Wednesday. The deal that came after days of intense negotiations included warrant requirements, and other measures aimed at addressing privacy concerns. But a broad coalition of Republicans voted down the rule, preventing the bill from advancing and forcing leadership to pivot. Opposition came from both conservatives and Republicans who favored a clean extension. What''s next : The measure now heads to the Senate with little time to spare before the program expires. • GOP leaders are hoping to use the next two weeks to hammer out a deal.', 'pending', '{"System Vitality","Civic Stewardship"}', 'Kate Santaliz', NULL, 'news', false, false, 8.2, 'RGI partially agrees: the article correctly identifies institutional dysfunction and leadership erosion, but undersells the deeper signal—this reflects broader fracturing of executive authority and institutional trust that extends far beyond FISA mechanics. Senior leaders must anticipate that even bipartisan national security priorities now face fragmentation risk, signaling structural weakness in institutional consensus-building at scale.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (474, 'The Scapegoat Scam', 'https://www.theatlantic.com/ideas/2026/04/hungary-orban-loss/686832/?utm_source=feed', 'The Atlantic', 'https://feeds.feedburner.com/TheAtlantic', 6.3, '{"Global Politics","Civic Stewardship"}', 'The Atlantic reports on Hungary''s electorate rejecting scapegoating tactics previously deployed by Prime Minister Viktor Orbán, suggesting potential limits to authoritarian populism in mature democracies.', '2026-04-17 11:00:00+00', '2026-04-17 15:40:06.211249+00', 'Hungarians stopped falling for an authoritarian’s trick.', 'pending', '{"strategicForesight":"Moderate — signals weakness in a previously successful authoritarian playbook, but article lacks clarity on whether this reflects durable institutional change or tactical electoral shifts.","systemVitality":"Moderate — demonstrates voter skepticism toward divisive leadership narratives, relevant to understanding organizational culture vulnerability to scapegoating.","civicStewardship":"High — directly examines institutional resistance to authoritarian governance tactics and democratic legitimacy."}', 'Adam Serwer', NULL, 'news', false, false, 7.2, 'RGI partially agrees: Hungary''s rejection of scapegoating signals institutional resilience against authoritarian capture, but the article lacks concrete evidence of systemic governance reform or durable institutional change. Senior leaders should recognize that civic resistance to divisive leadership narratives requires sustained institutional countermeasures—messaging alone does not prevent democratic erosion.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (475, 'Polymarket and Kalshi are up against a united Congress as D.C. steps up scrutiny of prediction markets', 'https://www.fastcompany.com/91528586/polymarket-kalshi-up-against-united-congress-dc-steps-up-scrutiny-prediction-markets', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 7.4, '{"Policy & Regulation","Finance & Markets"}', 'Congress is moving with unusual bipartisan speed to regulate prediction markets like Polymarket and Kalshi, driven by market integrity concerns, insider trading risks, and high-profile cases (betting on military operations). The CFTC faces mounting pressure to implement guardrails, with White House and presidential candidates now engaged—signaling prediction markets may face structural regulatory constraints within 12-18 months.', '2026-04-17 15:10:13+00', '2026-04-17 15:40:06.214572+00', 'As the United States was preparing a daring mission to rescue an airman whose fighter jet was shot down by Iran, there was money to be made. Users on Polymarket , the world&#8217;s largest prediction market, could place bets on when the airman would be rescued. When Rep. Seth Moulton, D-Mass., shared a screenshot of the activity on social media, an April 3 rescue was trading at 15% compared with 63% who were betting on April 4. After Moulton posted the screenshot and blasted this &#8220;dystopian death market,&#8221; Polymarket stopped the betting, saying the market &#8220;does not meet our integrity standards.&#8221; A former Marine who served four tours in Iraq, Moulton said he was &#8220;absolutely not satisfied with Polymarket&#8217;s response&#8221; and blamed the site for being &#8220;completely unwilling to self-regulate when it comes to betting on the lives of our service members.&#8221; &#8220;This is war profiteering and Congress needs to step in and stop it,&#8221; he said. A confrontation is brewing in Washington over prediction markets, the online exchanges that allow users to bet on the outcome of everything from a baseball game to when Jesus Christ will return. In a highly polarized Congress, the need to guard against the prediction markets being used for insider trading has become rare common ground. Members of both parties pressed the leader of a typically low-profile regulatory agency on the issue during a hearing on Thursday. The market debate is also drawing in the White House, potential presidential candidates and state leaders. &#8220;It&#8217;s a national conversation about what it means to have market integrity,&#8221; said Kristin Johnson, a former commissioner at the Commodity Futures Trading Commission, which regulates prediction markets in the U.S. In a capital that was slow to respond to the perils of tobacco, opioids and social media, the push to put guardrails on prediction markets has been uncommonly swift. The markets, which include Polymarket and its chief rival Kalshi, have been criticized for everything from undermining the integrity of sports to contributing to an online betting addiction crisis among young men. Polymarket has come under particular scrutiny as a venue for offshore trades that are beyond the reach of U.S. regulators. Donald Trump Jr., the president&#8217;s son, is on Polymarket&#8217;s advisory board and is a paid adviser for Kalshi. 1789 Capital, the venture capital firm where Trump Jr. is a partner, has invested in Polymarket. Well-timed trades catch Washington&#8217;s attention The Associated Press reported this month that a group of new accounts on Polymarket made highly specific, well-timed bets on whether the U.S. and Iran would reach a ceasefire on April 7, resulting in hundreds of thousands of dollars in profits for these new customers. On the same day the report was published, the White House warned staff against using private information to trade on prediction markets. Earlier this ye', 'pending', 'Strategic Foresight (emerging regulatory inflection point affecting fintech markets) + Civic Stewardship (market integrity, insider trading, legitimacy of new financial instruments in democratic systems)', 'Associated Press', NULL, 'news', false, false, 7.2, 'RGI partially agrees: prediction markets create genuine market integrity and insider trading risks that warrant regulatory attention, but the framing conflates separate issues (war-betting ethics, offshore opacity, addiction) that require distinct policy responses. Senior leaders must prepare for bifurcated regulatory outcomes—stricter CFTC oversight of political/geopolitical markets while consumer-protection rules lag, creating compliance complexity and market fragmentation.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (476, 'Anthropic launches a design tool to take on all the other design tools', 'https://www.fastcompany.com/91528198/anthropic-claude-design-ai-design-tool', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5.4, '{"AI & Artificial Intelligence","Technology & Digital Innovation"}', 'Anthropic launches Claude Design, an AI-powered design tool integrated with its Claude Opus 4.7 model, joining competitors like Figma, Canva, and Adobe in AI-native design. The tool enables rapid prototyping and design iteration through conversational prompts and collaborative editing, available to Claude Pro/Max/Team/Enterprise subscribers.', '2026-04-17 15:00:00+00', '2026-04-17 15:40:06.217701+00', 'Anthropic Labs just announced a new product for its flagship AI model called Claude Design. According to Anthropic, the new tool “lets you collaborate with Claude to create polished visual work like designs, prototypes, slides, one-pagers, and more.” The company is billing the tool as a way for non-designers to mock up visuals, and a way for designers to quickly test out a range of initial prototypes. It’s powered by Claude’s most recent new model, Opus 4.7 , which is trained to handle difficult coding prompts and complex, long-running tasks. Claude Design is available starting today to Claude Pro, Max, Team, and Enterprise Subscribers.&nbsp; [Image: Anthropic] Anthropic joins a growing number of companies developing their own AI-based design tools, including Figma, Canva, Adobe Express , and Google’s Stitch . As each of these companies expands its AI capabilities, the segmentation between their capabilities is becoming less and less pronounced: Canva is an AI company with design tools , Figma is a UX company running on AI , and, now, Claude is a powerful chatbot with a design and UX assistant.&nbsp; [Image: Anthropic] How Claude Design works Claude Design functions like an ultra-intelligent middle man between designers and product engineers.&nbsp; To use the tool, users start with a text prompt, as well as supplementary materials they want to use for reference, like a codebase, images, or documents. For example, a user might type, “Prototype a serene mobile meditation app. It should have calming typography, subtle nature-inspired colors, and a clean layout.” [Image: Anthropic] From there, Claude Design will produce a first draft. The tool’s UX is designed to make editing intuitive: an inline comment box facilitates specific tweaks, like, in this case, adding a dark mode toggle; custom sliders automatically spawn for small adjustments, such as color and type size; and users can also make direct edits on the draft themselves. It’s clearly designed to feel iterative and collaborative; like bouncing ideas off of a very fast colleague. This same workflow applies whether a user is making an app, a webpage, a powerpoint, or a social media post. Bigger teams can bring Claude Design into the loop on their company’s needs by uploading a codebase and design files. Claude will then digest that information and create a design system that uses the appropriate colors, typography, and components automatically. Once a design is complete, it can be shared as an internal URL within an organization, saved as a folder, or exported to Canva, PDF, PPTX, or standalone HTML files.&nbsp; Claude Design offers a one-stop shop for design consultation on app prototypes, web UX, and marketing assets, and it feels like an encapsulation of where the industry is headed. In the AI design space, the biggest players aren’t specializing—they’re becoming jacks of all trades.', 'pending', 'Strategic Foresight (minor): Signals capability convergence—large AI models absorbing domain-specific tools. System Vitality (minor): Potential implications for designer workflow, skill requirements, organizational design teams.', 'Grace Snelling', NULL, 'news', false, false, 7.2, 'RGI partially agrees: Anthropic''s Claude Design represents meaningful AI capability expansion, but the article conflates product feature parity with genuine strategic differentiation—the real signal is whether Claude''s reasoning model creates durable competitive advantage in design workflows, not tool proliferation. Senior leaders should monitor whether AI design tools reduce designer scarcity (System Vitality impact) or simply commoditize design labor without raising output quality.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (477, 'New data: Associate degrees, community college on the rise as students ditch traditional 4-year bachelor’s', 'https://www.fastcompany.com/91528204/associate-degree-community-college-rising-as-students-ditch-traditional-4-year-bachelors-degrees-new-data', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 6.4, '{"Future of Work","Policy & Regulation"}', 'National Student Clearinghouse data shows 18-20-year-olds now represent the largest cohort of first-time associate degree earners; 79% of new bachelor''s graduates with prior credentials came via the community college pathway. Cost differential ($21K vs. $65K annually) and federal workforce grant expansion are driving the transition.', '2026-04-17 15:00:00+00', '2026-04-17 15:40:06.220632+00', 'A new report from the National Student Clearinghouse Research Center (NSCRC) shows that more students are seeking out an associate degree first over a four-year bachelor’s degree. Surpassing those aged 21 to 24 for the first time, students aged 18 to 20 represent the largest share of first time associate degree earners in the 2024-25 academic year. That academic year, of the 2 million students who earned a bachelor’s degree, 532,464 of them had a prior postsecondary credential—either a certificate, associate or bachelor’s/masters degree. And of those, 419,766 students completed the bachelor’s degree pathway from an associate degree, accounting for the largest percent (78.8%). Clearly, choosing to receive a two-year degree before moving on to complete a bachelor’s is an accessible and popular way to a postsecondary education—and the trend seems likely to continue. According to an earlier report by the NSCRC, community college enrollment saw a 3% increase in fall 2025, which drove overall growth in undergraduate enrollment. Meanwhile, private 4-year colleges saw a declines of 1.6% at nonprofit institutions, and 2% at for-profit institutions. Why the trend? The cost of college is a glaring factor, which could contribute to the appeal of community college. For the 2025-26 academic year, CollegeBoard reported the average budget for full-time students at a public two-year institution ranged from $21,320, while the budget for a private nonprofit four-year institution ranged from $65,470. The federal government has also been ramping up funding for community colleges, aimed at supporting and prioritizing students in the labor market. The Department of Labor has issued five rounds of Strengthening Community Colleges Training Grants , part of a program that began in 2020. The grants aim to address skill development needs to employers, support workers in gaining such skills to reach employment, and help students overcome career barriers to find quality jobs. And this February, the U.S. Department of Labor announced a sixth round of grant funding , including $65 million to support community colleges in training opportunities through Workforce Pell Grants.', 'pending', 'System Vitality (workforce pipeline integrity, talent access, institutional health) and Civic Stewardship (federal labor policy, equitable credential pathways, employer-education alignment)', 'Sage Swaby', NULL, 'news', false, true, 8.2, 'RGI partially agrees: the data accurately reflects a real structural shift in postsecondary pathways driven by cost arbitrage and labor-market alignment, but the article underemphasizes the systemic implications for workforce pipeline design and institutional legitimacy. Senior leaders must recognize that the two-year-then-bachelor model is now a primary talent acquisition pathway, requiring fundamentally different employer partnership strategies and credential signaling than traditional four-year degree recruitment.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (479, 'At roundtable on AI, members of Congress express angst and fears of ‘destruction’', 'https://www.fastcompany.com/91528592/at-roundtable-ai-members-congress-express-angst-fears-destruction', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 6.4, '{"AI & Artificial Intelligence","Policy & Regulation"}', 'House Oversight subcommittee holds AI roundtable; lawmakers express existential fears about data security, deepfakes, military systems, and energy impact, but produce no concrete policy direction.', '2026-04-17 14:44:51+00', '2026-04-17 15:40:06.227362+00', 'A congressional subcommittee on Thursday held a roundtable discussion on the potential of artificial intelligence , which took a turn toward the existential as each lawmaker aired their anxieties about the rapidly evolving technology . Rep. James Walkinshaw, D-Va., expressed alarm that federal workers may be using AI chatbots to handle sensitive government data. Rep. William Timmons, R-S.C., asked whether it should be illegal for AI systems to use someone&#8217;s likeness to create pornographic images. Rep. John McGuire, R-Va., expressed concerns that AI systems could deny U.S. military forces from taking lethal actions due to a model&#8217;s conclusion for &#8220;moral&#8221; behavior. And Rep. Yassamin Ansari, D-Ariz., raised concerns about the Trump administration&#8217;s use of AI in the war with Iran , the technology&#8217;s intensive energy usage and its potential effects on the climate. While members of Congress elsewhere debated other major topics — the scope of the federal government&#8217;s surveillance powers, the war with Iran and funding the Department of Homeland Security — the House Oversight Committee&#8217;s subcommittee roundtable on &#8220;Artificial Intelligence and American Power&#8221; brought executives of AI firms, academics and those implementing AI at major companies together with lawmakers. Thursday&#8217;s discussion comes as leaders on Capitol Hill grapple with the dizzying pace of global developments in which technology plays a central role. But the conversation quickly considered the potential for artificial intelligence to dwarf every other challenge facing the country. &#8220;People in our districts across this country are going to start feeling impacts very soon, and if we don&#8217;t start thinking properly and aggressively and proactively about the challenges that AI creates, I fear that we&#8217;re going to have a revolution on our hands,&#8221; said Rep. Dave Min, D-Calif. The subcommittee&#8217;s ranking Democrat, Rep. Maxwell Frost of Florida, also expressed optimism about AI&#8217;s ability to cure diseases and boost the economy. But Frost, currently the youngest member of Congress, worried that the technology would outpace lawmakers and pose potentially disastrous consequences if not addressed early on . &#8220;I don&#8217;t have faith in this institution to actually put the common sense guardrails in place. And then we fast forward ten years, and the house is on fire,&#8221; said Frost. &#8220;That won&#8217;t be good for anybody, whether it&#8217;s the industry or working families and people, or this institution itself.&#8221; Rep. Eric Burlison, R-Mo., kicked off the meeting with praise for the industry and marveled at how one panelist&#8217;s company used AI to automate and fast-track manufacturing in the firm&#8217;s factories. &#8220;It&#8217;s truly like the closest thing to Star Trek I&#8217;ve ever seen,&#8221; Burlison said. He later inquired about what congressional districts should do to attra', 'pending', '{"Strategic Foresight","Civic Stewardship"}', 'Associated Press', NULL, 'news', false, false, 7.2, 'RGI partially agrees: Congressional anxiety about AI governance reflects legitimate systemic risks (data security, deepfakes, military autonomy, energy/climate), but the roundtable format captures sentiment rather than strategic policy signal—no concrete regulatory frameworks or enforcement mechanisms emerged. Senior leaders must recognize that legislative gridlock on AI governance creates a vacuum where corporate self-regulation and geopolitical competition will determine AI deployment standards, not democratic process.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (480, 'Dozens of nations are gathering for plans to reopen the Strait of Hormuz. The U.S. isn’t one of them', 'https://www.fastcompany.com/91528597/dozens-nations-gathering-plans-reopen-strait-hormuz-u-s-isnt-one-them', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 7.4, '{Geopolitics,"Energy & Oil","Supply Chains & Trade"}', 'France and U.K. leading international coalition to reopen Strait of Hormuz without U.S. participation, signaling fracture in Western alignment on Middle East energy security and reshaping global supply-chain risk architecture.', '2026-04-17 12:58:05+00', '2026-04-17 15:40:06.230785+00', 'The leaders of France and the U.K. gathered dozens of countries — but not the United States — on Friday to push forward plans to reopen the Strait of Hormuz , a key oil route choked off by the U.S.-Israeli war on Iran . The Paris meeting is part of attempts by sidelined nations to ease the impact of a conflict they didn&#8217;t start and haven&#8217;t joined, but that has sent the global economy reeling. After the war started on Feb. 28, Iran effectively shut the narrow strait though which a fifth of the world&#8217;s oil usually passes. The U.S. is not part of the planning for what has been branded the Strait of Hormuz Maritime Freedom of Navigation Initiative. In a post on X ahead of Friday&#8217;s conference, French President Emmanuel Macron said the mission to provide security for shipping through the strait would be &#8220;strictly defensive,&#8221; limited to non-belligerent countries and deployed &#8220;when security conditions allow.&#8221; British Prime Minister Keir Starmer, facing political troubles at home, was greeted by Macron in the courtyard of the Elysee presidential palace on Friday afternoon. Macron and Starmer have spearheaded international efforts to increase diplomatic and economic pressure on Iran, which Starmer has accused of &#8220;holding the world&#8217;s economy to ransom.&#8221; U.S. President Donald Trump&#8217;s announcement of a retaliatory American blockade of Iranian ports has raised the economic jeopardy even higher. &#8220;The unconditional and immediate reopening of the Strait is a global responsibility, and we need to act to get global energy and trade flowing freely again,&#8221; Starmer said before the meeting. Military planning underway France and Britain also have led military planning meetings, in an echo of the &#8220;coalition of the willing&#8221; assembled to provide security for Ukraine in the event of a ceasefire in that war. French military spokesman Col. Guillaume Vernet said Thursday that the mission is still &#8220;in construction.&#8221; Macron&#8217;s office said participants will contribute &#8220;each according to its capabilities,&#8221; stressing options to ensure safe passage through the strait will depend on the security situation after a lasting ceasefire. &#8220;What matters is that ship operators have all the means at their disposal to be sure their vessels will not be hit if they pass through the strait. That may require intelligence, mine-clearing capabilities, military escorts, communication procedures with coastal states, etc.,&#8221; an official said, speaking on condition of anonymity in line with the French presidency&#8217;s customary practices. Sidharth Kaushal, a research fellow in sea power at the Royal United Services Institute think tank, said mine-clearing and creating a warning system for maritime threats were more likely roles for the coalition than warships escorting commercial tankers though the strait. &#8220;You need huge numbers of vessels for that sort of thing,', 'pending', '{"Strategic Foresight","Civic Stewardship"}', 'Associated Press', NULL, 'news', false, true, 7.2, 'RGI partially agrees: the article correctly identifies a critical geopolitical realignment—U.S. absence from Strait of Hormuz security coordination signals strategic decoupling from traditional European allies on Middle East energy security—but underestimates the deeper systemic risk: fragmented maritime security architecture increases volatility exposure for global supply chains and energy markets. Senior leaders must prepare for a multi-polarity energy security model where U.S. commitments to critical chokepoints are no longer assumed, requiring portfolio diversification and supply-chain redundancy investments immediately.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (481, 'Netflix stock faces a punishing day as Reed Hastings departs. Don’t blame his exit on WBD, bosses say', 'https://www.fastcompany.com/91528606/netflix-stock-punished-reed-hastings-departs-blame-wbd', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 5.3, '{"Finance & Markets","Leadership & Organizations"}', 'Netflix reported strong Q1 2026 earnings (revenue $12.25B, EPS $1.23 vs. expectations) but issued below-consensus Q2 guidance ($12.57B vs. $12.63B expected), triggering stock decline. Cofounder Reed Hastings announced June departure. Market spooked by leadership transition + forward deceleration signal despite solid current results.', '2026-04-17 12:21:00+00', '2026-04-17 15:40:06.233856+00', 'Shares of Netflix Inc. (Nasdaq: NFLX) are getting battered this morning, one day after the company reported its Q1 2026 financial results—the first since the streaming giant abandoned its plans to acquire Warner Bros. Discovery (WBD) in February. In addition to its quarterly earnings, Netflix also announced a bombshell: its cofounder and current chairman, Reed Hastings, will be exiting the company this June. The departure of Hastings, who has been the de facto face of the company since its inception, has left many investors wondering about Netflix&#8217;s future. Here’s what you need to know. What’s happened? On Thursday, Netflix announced its Q1 2026 financial results. And for all intents and purposes, the results were pretty good. For the quarter, Netflix reported $12.25 billion in revenue, representing a 16.2% growth from the same quarter a year earlier. It also announced a diluted earnings per share (EPS) of $1.23, which was significantly higher than its EPS of 66 cents in the quarter a year earlier. As noted by CNBC, Netflix’s Q1 revenue of $12.25 billion surpassed LSEG analysts’ expectations of $12.18 billion. That’s something investors always cheer. The company’s EPS of $1.23 also massively surpassed the 76 cents that analysts expected. However, the massive surge in Netflix’s Q1 EPS was primarily due to a one-time payment the company received after it declined to make a counteroffer in February to Paramount Skydance’s bid for Warner Bros. Discovery—which many had assumed Netflix would acquire. As part of the deal&#8217;s collapse, Netflix received a $2.8 billion termination fee from WBD, which helped drive its surging EPS in Q1. Still, there’s no denying that Netflix captured impressive revenue growth in Q1. So then, why is the stock crashing today? 2 factors are spooking Netflix investors today There are two leading factors that are contributing to Netflix’s declining stock price this morning.&nbsp; The first involves Netflix’s guidance for its current Q2. While Netflix reported impressive revenue growth in Q1, it issued Q2 revenue guidance of $12.57 billion. As noted by Proactive Investors, this is below the $12.63 billion in revenue that analysts had expected for Q2. However, it’s worth pointing out that Netflix maintains its previous full fiscal 2026 guidance of $50.7 billion to $51.7 billion, which the company says represents 12%-14% year-over-year growth. Still, investors sometimes think in the short term, and when a quarterly guidance misses expectations, it can trigger a sell-off in the stock. But lackluster Q2 guidance isn’t the only thing spooking investors. The other, more significant issue is the news about Netflix cofounder and current chairman, Reed Hastings. Reed Hastings announces departure from Netflix In addition to reporting its Q1 results yesterday, Netflix also announced a bombshell: its cofounder and current chairman, Reed Hastings, will shortly depart the company. Hastings, who has served as the chairman of Netflix s', 'pending', 'System Vitality (leadership transition risk; founder-dependent organizational culture); Finance & Markets (earnings miss on guidance; investor confidence)', 'Michael Grothaus', NULL, 'news', false, false, 6.2, 'RGI partially agrees: Netflix''s Q1 beat on revenue and earnings is strategically sound, but the stock decline reflects legitimate concerns about leadership continuity and forward guidance miss—not operational failure. Senior leaders must recognize that founder transitions combined with cautious forward guidance create governance credibility gaps that markets punish regardless of current financial performance.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (482, 'America’s gambling rehab crisis', 'https://www.fastcompany.com/91527303/americas-gambling-rehab-crisis', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 6.3, '{"Policy & Regulation","Leadership & Organizations"}', 'Fast Company reports on explosive growth in sports betting addiction since 2018 legalization, with 20 million Americans now at-risk; sportsbooks deploy algorithmic nudges, live-betting mechanics, and reload bonuses designed to exploit compulsion, creating systemic public health crisis and looming regulatory backlash.', '2026-04-17 11:00:00+00', '2026-04-17 15:40:06.236491+00', 'It&#8217;s sometime after midnight on a Monday morning when Zach unlocks his phone and starts scrolling for something to bet on. He&#8217;s 26, tucked into his childhood bed at his parents&#8217; house in Washington, D.C. He moved back in after a stint in Las Vegas that didn&#8217;t go as planned. The NFL is done for the night. The NBA&#8217;s late games have wrapped. Mainstream sports are fast asleep. In FanDuel&#8217;s live betting tab, he finds a women&#8217;s tennis tournament streaming from somewhere in Southeast Asia. Two unranked, unknown teenagers, one boasting a 0–1 career record. Empty arena, no ball boys. Between points, the players jog to the fence to retrieve the ball themselves. He puts money on it. &#8220;I wasn&#8217;t thinking what a normal person would think,&#8221; says Zach, who asked to be identified only by his first name. &#8220;I was on autopilot.&#8221; Fourteen months earlier, in the fall of 2023, Zach downloaded FanDuel for the first time and went on the best run of his gambling life—eleven bets, eleven wins, a two-week stretch in which everything he touched turned to money. He won a couple of thousand dollars, he says. He was on a heater. He spent the next year-plus chasing that same kind of luck, that same feeling. He never found it. Multiply Zach by twenty million, and you get a sense of what&#8217;s become a gambling epidemic. Since the Supreme Court struck down the federal ban on sports betting in 2018, Americans have legally wagered more than $650 billion on sports. Nearly half of American men between 18 and 49 now carry an active sportsbook account on their phone. The apps pump out bonuses to keep users betting. Promotional credits, &#8220;no sweat&#8221; bets refunded as credits if the &#8220;no sweat&#8221; bet is lost, and boosted odds on popular games. Ninety percent of legal sports bets in the U.S. are now placed on phones. More than half are live bets, placed while games are in progress. When a user goes quiet, they get a push notification; when they lose big, a reload bonus appears. &#8220;They make you feel like you&#8217;re getting free money,&#8221; Zach says. &#8220;Then the free money&#8217;s gone, and you&#8217;re using your own. By then, you&#8217;re already hooked.&#8221; The National Council on Problem Gambling estimates as many as 20 million Americans have a serious gambling problem or are at risk of developing one—a figure that has grown 30 percent since legalization. What hasn&#8217;t grown is the number of options to help gambling addicts. The federal government spends $3.6 billion a year treating people struggling with alcohol and drugs, while those addicted to the 24-hour casino in their pocket are largely left to fend for themselves. The desperation loop Rick Benson has heard some version of Zach&#8217;s story hundreds of times. Benson, 70, is the founder of Algamus Recovery Centers in Goodyear, Arizona—the oldest dedicated gambling addiction treatment program in the United States, and one ', 'pending', 'System Vitality (institutional behavior, trust erosion, predatory design); Civic Stewardship (corporate responsibility, legitimacy of firms, policy reform necessity)', 'Paul Mueller', NULL, 'news', false, false, 7.2, 'RGI partially agrees: the article correctly identifies a systemic addiction crisis and predatory app design practices, but frames this primarily as a social/health issue rather than interrogating the institutional legitimacy question—why have corporations and regulators allowed algorithmic manipulation of vulnerable populations to scale unchecked, and what does this signal about civic stewardship breakdown? Senior leaders must recognize that sportsbook platforms have weaponized behavioral psychology at scale, creating reputational and regulatory risk for the entire sector—remediation will require governance reform, not voluntary compliance.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (483, 'Republican Mutiny Sinks Trump''s Push to Extend Warrantless Surveillance', 'https://www.wired.com/story/republican-mutiny-sinks-trumps-push-to-extend-warrantless-surveillance/', 'Wired', 'https://www.wired.com/feed/rss', 7.7, '{"Policy & Regulation","Global Politics"}', 'Republican House members blocked White House effort to extend Section 702 warrantless surveillance authority, signaling weakening executive control over intelligence apparatus and creating uncertainty for corporate/institutional data governance frameworks dependent on current surveillance infrastructure.', '2026-04-17 14:07:02+00', '2026-04-17 15:40:06.240034+00', 'A post-midnight revolt in the House sank the White House''s efforts to extend Section 702—a spy program the FBI has used to look into members of Congress, protesters, and political donors.', 'pending', '{"Civic Stewardship","System Vitality"}', 'Dell Cameron', NULL, 'news', false, false, 8.5, 'RGI partially agrees: the article correctly identifies a significant governance breakdown (intraparty defection on national security authority), but frames it primarily through partisan political theater rather than the systemic implications for executive power, institutional checks, and corporate/civic data vulnerability. The concrete forward implication: senior leaders must reassess assumptions about executive surveillance authority stability—regulatory and operational frameworks built on Section 702 continuity face material uncertainty, and organizations handling sensitive stakeholder data should stress-test compliance architectures against sudden legal shifts.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (508, 'How developed vetting works - and what happens when someone fails it', 'https://www.bbc.com/news/articles/cj0n5700nrpo?at_medium=RSS&at_campaign=rss', 'BBC News', 'http://feeds.bbci.co.uk/news/rss.xml', 4.6, '{"Policy & Regulation"}', 'BBC examines how US security clearance vetting processes function and explores a case where an ambassador received clearance despite flagged concerns during background checks.', '2026-04-17 12:20:04+00', '2026-04-17 15:40:06.308026+00', 'The former US ambassador was given a security clearance despite concerns being raised during checks.', 'pending', 'Tangential to Civic Stewardship (institutional legitimacy/governance). The piece is procedurally descriptive rather than strategically significant.', NULL, NULL, 'news', false, false, 8.5, 'RGI notes this item falls outside the core strategic lens — limited implications for senior leadership.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (484, 'With US spy laws set to expire, lawmakers are split over protecting Americans from warrantless surveillance', 'https://techcrunch.com/2026/04/17/with-us-spy-laws-set-to-expire-lawmakers-are-split-over-protecting-americans-from-warrantless-surveillance/', 'TechCrunch', 'https://techcrunch.com/feed/', 7.7, '{"Policy & Regulation","Global Politics"}', 'U.S. surveillance law Section 702 faces April expiration amid divided congressional response to decades of warrantless monitoring abuses; reauthorization outcome will signal whether democratic institutions can constrain executive surveillance power or whether warrantless collection becomes normalized.', '2026-04-17 14:00:00+00', '2026-04-17 15:40:06.243064+00', 'Some lawmakers are calling for widespread reforms following years of surveillance scandals and abuses across successive U.S. administrations. But even if the spy law known as Section 702 expires in April, the government''s spy powers will not automatically lapse.', 'pending', 'Civic Stewardship (institutional legitimacy, democratic accountability, corporate responsibility in relation to government power asymmetries)', 'Zack Whittaker', NULL, 'news', false, false, 7.5, 'RGI partially agrees: Section 702 expiration represents a genuine governance inflection point with material implications for institutional legitimacy and executive power, but the article understates the systemic stakes—this is fundamentally about whether democratic oversight constrains surveillance state expansion, not merely a procedural reform debate. Senior leaders must recognize that Section 702 reauthorization signals either strengthened institutional accountability or normalized warrantless intelligence collection; the former protects civic trust, the latter erodes it.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (485, 'Netflix plans to add a vertical video feed, use AI for recommendations', 'https://techcrunch.com/2026/04/17/netflix-plans-to-add-a-vertical-video-feed-use-ai-for-recommendations/', 'TechCrunch', 'https://techcrunch.com/feed/', 4.7, '{"Technology & Digital Innovation","AI & Artificial Intelligence"}', 'Netflix announces plans to launch a TikTok-style vertical video feed and expand AI use for content recommendations and creation.', '2026-04-17 13:17:18+00', '2026-04-17 15:40:06.245682+00', 'Netflix is going to launch a TikTok-like vertical video feed within its apps this month, and plans to use AI broadly for content creation and recommendations.', 'pending', 'Tangential to System Vitality (user engagement/platform design) and Strategic Foresight (AI application in media), but lacks systemic or governance-level significance.', 'Ivan Mehta', NULL, 'news', false, false, 6.5, 'RGI notes this item falls outside the core strategic lens — limited implications for senior leadership.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (486, 'SaySo is a new short-form video app that aims to restore users’ trust in news', 'https://techcrunch.com/2026/04/17/sayso-is-a-new-short-form-video-app-that-aims-to-restore-users-trust-in-news/', 'TechCrunch', 'https://techcrunch.com/feed/', 5.2, '{}', 'SaySo is a new short-form video app that aims to restore users’ trust in news', '2026-04-17 13:00:00+00', '2026-04-17 15:40:06.248778+00', 'Users are fed up with misinformation and AI slop cluttering their feeds. SaySo is a new short-form video app that delivers news from vetted creators and journalists.', 'pending', 'Multiple', 'Lauren Forristal', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (487, 'Loop raises $95M to build supply chain AI that predicts disruptions', 'https://techcrunch.com/2026/04/17/loop-raises-95m-to-build-supply-chain-ai-that-predicts-disruptions/', 'TechCrunch', 'https://techcrunch.com/feed/', 5.2, '{}', 'Loop raises $95M to build supply chain AI that predicts disruptions', '2026-04-17 13:00:00+00', '2026-04-17 15:40:06.252284+00', 'The San Francisco startup closed a Series C funding round led by Antonio Gracias'' firm Valor, which is a major backer of xAI.', 'pending', 'Multiple', 'Sean O''Kane', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (488, 'The South Korean president is doing quote-post diplomacy', 'https://www.theverge.com/policy/913587/south-korea-lee-jae-myung-israel', 'The Verge', 'https://www.theverge.com/rss/index.xml', 5.2, '{}', 'The South Korean president is doing quote-post diplomacy', '2026-04-17 14:00:00+00', '2026-04-17 15:40:06.25477+00', '"This is no different from Comfort Women or the Holocaust," wrote South Korean President Lee Jae-myung on X last week, quoting a post with a video of Israeli Defense Forces soldiers throwing a body off a rooftop in Gaza. The president''s post kicked off an internet firestorm for a thousand different reasons, not least because [&#8230;]', 'pending', 'Multiple', 'Sarah Jeong', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (489, 'The creative software industry has declared war on Adobe', 'https://www.theverge.com/tech/913765/adobe-rivals-free-creative-software-app-updates', 'The Verge', 'https://www.theverge.com/rss/index.xml', 6.4, '{"Business & Strategy","Technology & Digital Innovation"}', 'The Verge reports mounting competitive pressure on Adobe from rivals exploiting customer dissatisfaction with subscription pricing and generative AI integration choices. The article frames emerging challengers as capitalizing on Adobe''s strategic missteps in a historically consolidated market.', '2026-04-17 12:51:16+00', '2026-04-17 15:40:06.257171+00', 'All empires eventually fall, and it seems the creative software industry has collectively decided that Adobe''s time has come. The Creative Cloud provider''s suite of design tools have been considered the industry standard for decades - despite unpopular decisions to fully embrace generative AI and abandon software licenses in favor of expensive, complicated subscriptions. Pricing [&#8230;]', 'pending', 'System Vitality (organizational trust erosion) + Strategic Foresight (market transition signals in software monetization)', 'Jess Weatherbed', NULL, 'news', false, false, 7.2, 'RGI partially agrees: Adobe''s dominance faces genuine competitive pressure from pricing backlash and AI strategy missteps, but "declared war" overstates coordination—this reflects fragmented market opportunism rather than systemic industry realignment. Senior leaders must recognize that subscription model fatigue and AI skepticism among creative professionals signal vulnerability in high-switching-cost markets, requiring Adobe and competitors to rebuild trust through transparency on pricing and AI governance.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (490, 'A giant cell tower is going to space this weekend', 'https://www.theverge.com/tech/913752/blue-origin-reusable-rocket-test-ast-sapcemobile', 'The Verge', 'https://www.theverge.com/rss/index.xml', 5.1, '{}', 'A giant cell tower is going to space this weekend', '2026-04-17 11:25:37+00', '2026-04-17 15:40:06.259468+00', 'This weekend''s scheduled Blue Origin rocket launch is rather momentous. Success would signal an end to SpaceX''s monopoly on reusable orbital launch vehicles, and set up a three-way race to make that "No Service" indicator on your phone disappear forever. On Sunday morning, Jeff Bezos'' massive New Glenn rocket is scheduled to launch with the [&#8230;]', 'pending', 'Multiple', 'Thomas Ricker', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (509, 'What is Claude Mythos and what risks does it pose?', 'https://www.bbc.com/news/articles/crk1py1jgzko?at_medium=RSS&at_campaign=rss', 'BBC News', 'http://feeds.bbci.co.uk/news/rss.xml', 6.7, '{"AI & Artificial Intelligence","Policy & Regulation"}', 'BBC reports on Anthropic''s Claude AI capabilities in hacking and cybersecurity, raising financial sector concerns about AI-enabled cyber threats and institutional preparedness.', '2026-04-17 13:41:01+00', '2026-04-17 15:40:06.311077+00', 'The company''s claim the AI tool can outperform humans at some hacking and cyber-security tasks has sparked fears in the financial world.', 'pending', '{"Strategic Foresight","System Vitality"}', NULL, NULL, 'news', false, false, 7.5, 'RGI partially agrees: the article correctly identifies AI capability escalation as a legitimate risk signal for institutional cyber resilience, but conflates speculative ''mythos'' framing with concrete threat assessment—blurring hype from operational risk. Senior leaders must immediately audit AI-dependent infrastructure vulnerabilities and establish governance protocols for adversarial AI capabilities, regardless of vendor marketing claims.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (491, 'Anthropic just launched Claude Design, an AI tool that turns prompts into prototypes and challenges Figma', 'https://venturebeat.com/technology/anthropic-just-launched-claude-design-an-ai-tool-that-turns-prompts-into-prototypes-and-challenges-figma', 'VentureBeat', 'https://feeds.feedburner.com/venturebeat/SZYF', 6.4, '{"AI & Artificial Intelligence","Technology & Digital Innovation"}', 'Anthropic launches Claude Design, an AI tool converting text prompts into visual prototypes, marking the company''s move from foundation model provider into the full-stack application layer. The release, powered by Claude Opus 4.7, targets design and prototyping workflows historically dominated by Figma, Adobe, and Canva.', '2026-04-17 15:00:00+00', '2026-04-17 15:40:06.262468+00', 'Anthropic today launched Claude Design , a new product from its Anthropic Labs division that allows users to create polished visual work — designs, interactive prototypes, slide decks, one-pagers, and marketing collateral — through conversational prompts and fine-grained editing controls. The release, available immediately in research preview to all paid Claude subscribers , is the company&#x27;s most aggressive expansion beyond its core language model business and into the application layer that has historically belonged to companies like Figma , Adobe , and Canva . Claude Design is powered by Claude Opus 4.7, Anthropic&#x27;s most capable generally available vision model, which the company also released today. Anthropic says it is rolling access out gradually throughout the day to Claude Pro, Max, Team, and Enterprise subscribers. The simultaneous launches mark a watershed for Anthropic, whose ambitions now visibly extend from foundation model provider to full-stack product company — one that wants to own the arc from a rough idea to a shipped product. The timing is also significant: Anthropic hit roughly $20 billion in annualized revenue in early March 2026, according to Bloomberg, up from $9 billion at the end of 2025 — and surpassed $30 billion by early April 2026. The company is in early talks with Goldman Sachs, JPMorgan, and Morgan Stanley about a potential IPO that could come as early as October 2026. How Claude Design turns a text prompt into a working prototype The product follows a workflow that Anthropic has designed to feel like a natural creative conversation. Users describe what they need, and Claude generates a first version. From there, refinement happens through a combination of channels: chat-based conversation, inline comments on specific elements, direct text editing, and custom adjustment sliders that Claude itself generates to let users tweak spacing, color, and layout in real time. During onboarding, Claude reads a team&#x27;s codebase and design files and builds a design system — colors, typography, and components — that it automatically applies to every subsequent project. Teams can refine the system over time and maintain more than one. The import surface is broad: users can start from a text prompt, upload images and documents in various formats, or point Claude at their codebase. A web capture tool grabs elements directly from a live website so prototypes look like the real product. What distinguishes Claude Design from the wave of AI design experiments that have proliferated in the past year is the handoff mechanism. When a design is ready to build, Claude packages everything into a handoff bundle that can be passed to Claude Code with a single instruction. That creates a closed loop — exploration to prototype to production code — all within Anthropic&#x27;s ecosystem. The export options acknowledge that not everyone&#x27;s next step is Claude Code: users can also share designs as an internal URL within their organi', 'pending', 'Strategic Foresight (primary): signals AI capability expansion into creative application layers and competitive repositioning within the design/productivity stack. Indirect relevance to System Vitality (future of work implications for design teams and creative workflows).', 'michael.nunez@venturebeat.com (Michael Nuñez)', NULL, 'news', false, false, 7.2, 'RGI partially agrees: Anthropic''s expansion into design tooling signals genuine AI capability advancement, but the article overstates the competitive threat to Figma—design is a crowded, incumbency-heavy layer where tooling lock-in and workflow integration matter more than model capability alone. Leaders must recognize this as a real capability inflection, not a market disruption signal.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (492, 'Should my enterprise AI agent do that? NanoClaw and Vercel launch easier agentic policy setting and approval dialogs across 15 messaging apps', 'https://venturebeat.com/orchestration/should-my-enterprise-ai-agent-do-that-nanoclaw-and-vercel-launch-easier-agentic-policy-setting-and-approval-dialogs-across-15-messaging-apps', 'VentureBeat', 'https://feeds.feedburner.com/venturebeat/SZYF', 6.4, '{"AI & Artificial Intelligence","Policy & Regulation"}', 'NanoClaw 2.0 and Vercel launch infrastructure-level approval system for AI agents, shifting security enforcement from the agent layer to isolated containers with human sign-off gates. Targets high-consequence actions (DevOps, finance) via native messaging app workflows.', '2026-04-17 14:06:00+00', '2026-04-17 15:40:06.26562+00', 'For the past year, early adopters of autonomous AI agents have been forced to play a murky game of chance: keep the agent in a useless sandbox or give it the keys to the kingdom and hope it doesn&#x27;t hallucinate a catastrophic "delete all" command. To unlock the true utility of an agent—scheduling meetings, triaging emails, or managing cloud infrastructure—users have had to grant these models raw API keys and broad permissions, raising the risk of their systems being disrupted by an accidental agent mistake. That tradeoff ends today. The creators of the open source sandboxed NanoClaw agent framework — now known under their new private startup named NanoCo — have announced a landmark partnership with Vercel and OneCLI to introduce a standardized, infrastructure-level approval system. By integrating Vercel’s Chat SDK and OneCLI’s open source credentials vault, NanoClaw 2.0 ensures that no sensitive action occurs without explicit human consent, delivered natively through the messaging apps where users already live. The specific use cases that stand to benefit most are those involving high-consequence "write" actions. That is, in DevOps, an agent could propose a cloud infrastructure change that only goes live once a senior engineer taps "Approve" in Slack. For finance teams, an agent could prepare batch payments or invoice triaging, with the final disbursement requiring a human signature via a WhatsApp card. Technology: security by isolation The fundamental shift in NanoClaw 2.0 is the move away from "application-level" security to "infrastructure-level" enforcement. In traditional agent frameworks, the model itself is often responsible for asking for permission—a flow that Gavriel Cohen, co-founder of NanoCo, describes as inherently flawed. "The agent could potentially be malicious or compromised," Cohen noted in a recent interview. "If the agent is generating the UI for the approval request, it could trick you by swapping the &#x27;Accept&#x27; and &#x27;Reject&#x27; buttons." NanoClaw solves this by running agents in strictly isolated Docker or Apple Containers. The agent never sees a real API key; instead, it uses "placeholder" keys. When the agent attempts an outbound request, the request is intercepted by the OneCLI Rust Gateway. The gateway checks a set of user-defined policies (e.g., "Read-only access is okay, but sending an email requires approval"). If the action is sensitive, the gateway pauses the request and triggers a notification to the user. Only after the user approves does the gateway inject the real, encrypted credential and allow the request to reach the service. Product: bringing the &#x27;human&#x27; into the loop While security is the engine, Vercel’s Chat SDK is the dashboard. Integrating with different messaging platforms is notoriously difficult because every app—Slack, Teams, WhatsApp, Telegram—uses different APIs for interactive elements like buttons and cards. By leveraging Vercel’s unified SDK, NanoClaw can now deploy', 'pending', 'System Vitality (organizational control, human-AI decision boundaries, institutional trust in automation) + Strategic Foresight (governance architecture for AI acceleration)', 'carl.franzen@venturebeat.com (Carl Franzen)', NULL, 'news', false, false, 7.2, 'RGI partially agrees: NanoClaw 2.0 addresses a genuine governance gap in agentic AI deployment—moving security from application to infrastructure level is architecturally sound—but the article conflates a tactical tooling improvement with a systemic solution to the deeper problem of AI agent trustworthiness and organizational control. Senior leaders must recognize that approval dialogs and sandboxing are necessary hygiene, not sufficiency; the critical strategic question remains how to build organizational decision-making frameworks that can operate at AI agent velocity without abdicating human accountability.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (493, 'Recent advances push Big Tech closer to the Q-Day danger zone', 'https://arstechnica.com/security/2026/04/while-some-big-tech-players-accelerate-pqc-readiness-others-stay-the-course/', 'Ars Technica', 'https://feeds.arstechnica.com/arstechnica/index', 7.3, '{"AI & Artificial Intelligence","Policy & Regulation"}', 'Advances in quantum computing capabilities are narrowing the timeline to ''Q-Day'' — when adversaries can decrypt current cryptographic systems — forcing enterprises and governments to accelerate migration to post-quantum encryption standards.', '2026-04-17 11:00:50+00', '2026-04-17 15:40:06.268205+00', 'Here''s which players are winning the race to transition to post-quantum crypto.', 'pending', '{"Strategic Foresight","System Vitality"}', 'Dan Goodin', NULL, 'news', false, false, 7.2, 'RGI partially agrees: the article correctly identifies quantum computing as a systemic security threat requiring cryptographic transition, but frames it primarily as a technical race rather than an urgent governance and organizational readiness crisis that demands immediate institutional action. Senior leaders must treat post-quantum cryptography migration as a critical infrastructure priority equivalent to Y2K — not as a technology competition scorecard, but as a mandatory organizational resilience initiative with board-level accountability and 3-5 year implementation timelines.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (494, 'The Scapegoat Scam', 'https://www.theatlantic.com/ideas/2026/04/hungary-orban-loss/686832/?utm_source=feed', 'The Atlantic', 'https://www.theatlantic.com/feed/all/', 6.6, '{"Global Politics","Leadership & Organizations"}', 'The Atlantic reports on how Hungarian society has grown resistant to authoritarian scapegoating tactics, suggesting limits to populist blame-deflection strategies in democratic contexts.', '2026-04-17 11:00:00+00', '2026-04-17 15:40:06.270532+00', 'Hungarians stopped falling for an authoritarian’s trick.', 'pending', '{"strategicForesight":"Moderate—pattern recognition on political communication tactics and democratic resilience, but limited geopolitical or market-level signal","systemVitality":"High—directly addresses how leadership narratives shape institutional trust and organizational culture; scapegoating is a trust-destruction mechanism","civicStewardship":"High—examines legitimacy crisis and the breakdown of populist governance narratives; relevant to corporate leaders navigating polarized civic environments"}', 'Adam Serwer', NULL, 'news', false, false, 7.5, 'RGI partially agrees: the article identifies a real governance pattern—how authoritarian leaders use scapegoating to deflect accountability—but frames it as a Hungarian anomaly rather than a systemic leadership vulnerability affecting democracies globally. Senior leaders must recognize that scapegoating erodes institutional trust and creates brittle governance; organizations that normalize blame-shifting externally will face internal culture collapse.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (495, 'Can Pakistan secure Iran-US nuclear compromise, as Trump says deal ‘close’?', 'https://www.aljazeera.com/news/2026/4/17/can-pakistan-secure-iran-us-nuclear-compromise-as-trump-says-deal?traffic_source=rss', 'Al Jazeera English', 'https://www.aljazeera.com/xml/rss/all.xml', 7.4, '{Geopolitics,"Policy & Regulation"}', 'Pakistan positions itself as diplomatic broker in US-Iran nuclear negotiations as Trump signals deal proximity; development carries implications for Middle East stability, energy markets, and regional power realignment.', '2026-04-17 14:54:34+00', '2026-04-17 15:40:06.273385+00', 'Pakistan&#039;s civilian and army leaders shuttle between key capitals as Trump says he may visit Islamabad to sign a deal.', 'pending', 'Strategic Foresight (geopolitical volatility, long-range pattern recognition); Civic Stewardship (institutional legitimacy of diplomacy)', NULL, NULL, 'news', false, true, 7.2, 'RGI partially agrees: The article correctly identifies Pakistan as a potential diplomatic intermediary in US-Iran nuclear negotiations, but overstates Trump''s stated proximity to a deal without substantiating the ''close'' claim with direct quotes or corroborated sources. Senior leaders must prepare for the strategic instability that accompanies nuclear diplomacy in volatile regions—Pakistan''s leverage position creates both opportunity and systemic risk for global energy markets and geopolitical alignment.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (529, 'Walmart is remodeling more than 650 U.S. stores and opening 20 new ones this year', 'https://qz.com/walmart-store-remodels-new-openings-041726', 'Quartz', 'https://qz.com/feed', 5.1, '{}', 'Walmart is remodeling more than 650 U.S. stores and opening 20 new ones this year', '2026-04-17 12:10:43+00', '2026-04-17 15:40:06.367228+00', 'The retailer''s remodel push includes wider aisles, updated pharmacies, and expanded pickup and delivery capabilities', 'pending', 'Multiple', 'Cris Tolomia', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (496, 'The three clocks of the Iran war', 'https://www.aljazeera.com/opinions/2026/4/17/the-three-clocks-of-the-iran-war?traffic_source=rss', 'Al Jazeera English', 'https://www.aljazeera.com/xml/rss/all.xml', 7.4, '{Geopolitics,"Wars & Crisis"}', 'Analysis of how Trump''s electoral calendar, Iran''s strategic patience, and Netanyahu''s political durability create three incompatible timeframes for conflict resolution in the Middle East, amplifying risks of prolonged instability.', '2026-04-17 13:20:56+00', '2026-04-17 15:40:06.276021+00', 'Trump is racing against the midterms, Iran is betting on endurance, and Netanyahu needs a war with no end.', 'pending', 'Strategic Foresight (geopolitical volatility, weak signal pattern recognition on actor incentive misalignment); Civic Stewardship (legitimacy of state actors and regional institutions under stress)', NULL, NULL, 'news', false, false, 6.2, 'RGI partially agrees: the article correctly identifies divergent temporal incentive structures among three key actors, a critical geopolitical signal—but the framing conflates analytical observation with interpretive claim about Netanyahu''s motivations, which exceeds the evidence presented. Senior leaders must recognize that misaligned time horizons between state actors create structural instability in conflict resolution and increase risk of escalation cycles that disrupt global markets and supply chains.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (497, 'How the Lebanon ceasefire is viewed in Israel', 'https://www.aljazeera.com/video/newsfeed/2026/4/17/how-the-lebanon-ceasefire-is-viewed-in-israel?traffic_source=rss', 'Al Jazeera English', 'https://www.aljazeera.com/xml/rss/all.xml', 5.4, '{Geopolitics,"Wars & Crisis"}', 'Al Jazeera reports on Israeli public and media reactions to a Lebanon ceasefire, capturing domestic political sentiment but without analysis of durability, regional power realignment, or implications for global markets and security.', '2026-04-17 13:19:16+00', '2026-04-17 15:40:06.278427+00', 'Al Jazeera’s Tony Cheng describes how people and the press in Israel are reacting to the ceasefire with Lebanon.', 'pending', 'Strategic Foresight (weak signal on regional stability); Civic Stewardship (minimal)', NULL, NULL, 'news', false, false, 7.2, 'RGI partially agrees: the article captures important regional sentiment on a geopolitical inflection point, but lacks depth on systemic implications for global business, security architecture, or institutional strategy. Senior leaders need to understand ceasefire durability and downstream effects on Middle East stability and energy markets — this reporting provides tactical sentiment, not strategic signal.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (498, 'Macron and Starmer host allies for summit on Hormuz maritime security', 'https://www.aljazeera.com/news/2026/4/17/macron-and-starmer-host-allies-for-summit-on-hormuz-maritime-security?traffic_source=rss', 'Al Jazeera English', 'https://www.aljazeera.com/xml/rss/all.xml', 6.4, '{Geopolitics,"Supply Chains & Trade"}', 'France and UK convene allied powers to establish independent maritime security force in the Strait of Hormuz without US participation, signaling European autonomy attempts but revealing institutional fragmentation in global energy security governance.', '2026-04-17 12:45:32+00', '2026-04-17 15:40:06.281074+00', 'US not part of France- and UK-led talks on a post-war Hormuz maritime force, but Europe&#039;s role remains limited.', 'pending', '{"Strategic Foresight","Civic Stewardship"}', NULL, NULL, 'news', false, false, 7.2, 'RGI partially agrees: the article correctly identifies a significant geopolitical realignment—Europe attempting autonomous security capability in a critical chokepoint—but undersells the strategic signal by not analyzing implications for US-Europe defense decoupling or energy market stability. Senior leaders must prepare for a multipolar maritime security architecture where European institutional leadership may fragment allied response protocols in the Strait of Hormuz, creating both supply-chain vulnerability and NATO coordination risk.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (499, 'Can Hungary wean itself off Russian energy, as its new leader has promised?', 'https://www.aljazeera.com/news/2026/4/17/can-hungary-wean-itself-off-russian-energy-as-its-new-leader-has-promised?traffic_source=rss', 'Al Jazeera English', 'https://www.aljazeera.com/xml/rss/all.xml', 6.3, '{Geopolitics,"Energy & Oil","Policy & Regulation"}', 'Hungarian political transition presents energy pivot away from Russian dependency; implications for European energy security, NATO alignment, and corporate energy strategy in Central Europe.', '2026-04-17 12:36:11+00', '2026-04-17 15:40:06.284312+00', 'Magyar’s pitch to Hungarian voters was to turn away from some of Orban’s policies, including Russian energy imports.', 'pending', 'Strategic Foresight (geopolitical volatility, energy market transition); Civic Stewardship (institutional legitimacy, democratic transitions affecting regional stability)', NULL, NULL, 'news', false, false, 7.2, 'RGI partially agrees: Hungary''s energy diversification from Russia is strategically significant for European security and NATO cohesion, but the article lacks primary signals from Magyar or energy officials on concrete timelines and feasibility. Senior leaders must recognize that Central European energy realignment directly affects supply chain resilience, geopolitical leverage, and corporate operations across the EU.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (500, 'The Iran war has exposed the limits of neutrality', 'https://www.aljazeera.com/opinions/2026/4/17/the-iran-war-has-exposed-the-limits-of-neutrality?traffic_source=rss', 'Al Jazeera English', 'https://www.aljazeera.com/xml/rss/all.xml', 7.3, '{Geopolitics,"Global Politics"}', 'Al Jazeera analysis examining how Iran conflict pressures allies and energy markets, forcing strategic actors to abandon equivocation on regional positioning and alliance commitments.', '2026-04-17 12:23:19+00', '2026-04-17 15:40:06.286897+00', 'From Gulf energy shocks to divisions among allies, the conflict has made strategic ambiguity harder to sustain.', 'pending', 'Strategic Foresight (geopolitical volatility, system-level pressure on institutional positioning); Civic Stewardship (firm legitimacy and stakeholder demands for explicit geopolitical positioning)', NULL, NULL, 'news', false, false, 7.2, 'RGI partially agrees: the article correctly identifies that geopolitical volatility is forcing institutional actors to abandon strategic ambiguity, but conflates tactical alliance pressure with systemic erosion of neutrality doctrine—missing the deeper signal that multipolarity is restructuring how firms and states navigate competing stakeholder demands. Senior leaders must recognize that ''neutrality'' as a business positioning strategy is now a liability; stakeholders (investors, employees, markets) will demand explicit stance-taking on geopolitical exposure, forcing boards to integrate Iran/Gulf risk into core governance frameworks rather than treating it as external noise.');
