INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (504, 'How two ceasefires and opening of Hormuz could boost Iran talks', 'https://www.bbc.com/news/articles/c0mjynzvw94o?at_medium=RSS&at_campaign=rss', 'BBC News', 'http://feeds.bbci.co.uk/news/rss.xml', 6.7, '{Geopolitics,"Supply Chains & Trade"}', 'BBC reports potential momentum in Iran nuclear/sanctions negotiations tied to ceasefire conditions in Gaza and Syria, plus reopening of Strait of Hormuz shipping lane. Assesses whether diplomatic progress can prevent regional conflict recurrence.', '2026-04-17 15:22:08+00', '2026-04-17 15:40:06.297133+00', 'Some kind of diplomatic progress is now under way, but is it enough to prevent a return to war?', 'pending', '{"Strategic Foresight","Civic Stewardship"}', NULL, NULL, 'news', false, false, 8.5, 'RGI partially agrees: the article correctly identifies that ceasefire conditions and Hormuz corridor access create negotiating leverage, but oversimplifies the structural geopolitical constraints (US sanctions architecture, regional proxy networks, internal Iranian factions) that historically derail Iran talks. Senior leaders managing energy security, supply chain exposure to Middle East volatility, or Iran-adjacent investments must model worst-case escalation scenarios alongside diplomatic optimism.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (506, 'Some Iran-linked ships have crossed US blockade, data suggests', 'https://www.bbc.com/news/articles/ckge7138l2go?at_medium=RSS&at_campaign=rss', 'BBC News', 'http://feeds.bbci.co.uk/news/rss.xml', 7.7, '{Geopolitics,"Supply Chains & Trade"}', 'Ship-tracking data indicates at least four Iran-linked vessels have crossed a US blockade line in the Gulf of Oman, suggesting potential weakening of US economic sanctions enforcement in a critical global trade corridor.', '2026-04-17 14:36:54+00', '2026-04-17 15:40:06.302911+00', 'At least four vessels tracked from Iranian ports appear to have crossed a US blockade line in the Gulf of Oman, analysis of ship-tracking data suggests.', 'pending', '{"Strategic Foresight — geopolitical volatility and weak signals of shifting US enforcement capacity in contested waters","System Vitality — implications for corporate supply chain risk assessment and institutional confidence in US sanctions credibility"}', NULL, NULL, 'news', false, false, 8.5, 'RGI partially agrees: the article documents a tactically significant geopolitical development (blockade breach), but lacks primary signal from US or Iranian leadership on strategic intent or policy response, limiting systemic implications. Senior leaders must recognize that maritime sanctions enforcement is eroding in real-time, signaling either US capacity constraints or deliberate strategic recalibration in the Middle East.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (507, 'Ceasefire with Israel brings respite to Lebanon, but obstacles to peace remain', 'https://www.bbc.com/news/articles/crm10w4ynj1o?at_medium=RSS&at_campaign=rss', 'BBC News', 'http://feeds.bbci.co.uk/news/rss.xml', 4.7, '{Geopolitics}', 'BBC reports on Israel-Lebanon ceasefire implementation and risks to durability, focusing on immediate humanitarian relief and structural obstacles to lasting peace.', '2026-04-17 14:31:51+00', '2026-04-17 15:40:06.305748+00', 'The halt to weeks of fighting is being celebrated in Lebanon, but it will be difficult to ensure it lasts.', 'pending', 'Tangential to Civic Stewardship (institutional legitimacy, policy reform) but primarily conflict coverage without systemic implications for organizational leadership or governance models.', NULL, NULL, 'news', false, false, 9.5, 'RGI notes this item falls outside the core strategic lens — limited implications for senior leadership.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (510, 'NSW should think twice before banning ‘globalise the intifada’ after court struck down anti-protest law, legal expert says', 'https://www.theguardian.com/australia-news/2026/apr/18/nsw-should-think-twice-before-banning-globalise-the-intifada-after-court-struck-down-anti-protest-law-legal-expert-says-ntwnfb', 'The Guardian', 'https://www.theguardian.com/world/rss', 6.7, '{"Policy & Regulation","Global Politics"}', 'NSW Supreme Court struck down anti-protest law, limiting government power to restrict marches and speech. Constitutional experts warn against banning specific protest phrases, signaling broader tension between security governance and democratic freedoms.', '2026-04-17 15:00:49+00', '2026-04-17 15:40:06.313553+00', 'Another lawyer says ruling ‘puts brakes on the Minns government’s ability to use executive power to minimise people’s rights to protest’ Get our breaking news email , free app or daily news podcast The Minns government should think twice before imposing an outright ban on the phrase “globalise the intifada” in the wake of a landmark finding that could limit attempts to control speech and protests, a leading constitutional expert has said. New South Wales’ highest court ruled in favour of the Palestine Action Group and Blak Caucas on Thursday, striking down an anti-protest law introduced after the Bondi beach terror attack that gave police the power to restrict marches, including the anti-Herzog rally in February . Continue reading...', 'pending', 'Civic Stewardship', 'Jordyn Beazley', NULL, 'news', false, false, 8.5, 'RGI partially agrees: the court ruling does signal meaningful constraints on executive power to restrict protest—a genuine governance issue—but the specific application (a single Australian state law) lacks systemic or global leadership implications. Senior leaders should monitor how democracies balance security powers against speech rights, as precedent-setting court rulings on protest restrictions will reshape institutional risk management around civic assembly.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (511, 'US Live Nation and Ticketmaster verdict triggers calls for Australian investigation into ticketing rules', 'https://www.theguardian.com/australia-news/2026/apr/18/us-live-nation-and-ticketmaster-verdict-triggers-calls-for-australian-investigation-into-ticketing-rules', 'The Guardian', 'https://www.theguardian.com/world/rss', 7.7, '{"Policy & Regulation","Business & Strategy"}', 'US federal court finds Live Nation/Ticketmaster liable for systematic monopoly extraction ($595M annually); Australian regulators now examining local ticketing market concentration and fee transparency.', '2026-04-17 15:00:47+00', '2026-04-17 15:40:06.316712+00', 'One insider estimates Australians pay A$10 in fees per ticket, with fans bearing the burden of monopolised music tour schedules and inflated artist values Get our breaking news email , free app or daily news podcast Australia is being urged to improve ticketing transparency after a US federal court found Live Nation Entertainment had a harmful monopoly over big concert venues. This week, a New York jury found the global entertainment giant and its subsidiary Ticketmaster liable for systematically stifling competition to extract excessive profits from concertgoers. The jury identified a baseline overcharge of US$1.72 for every ticket sold by Live Nation since 2010 – totalling an additional US$595m in 2025 alone. Continue reading...', 'pending', 'Civic Stewardship (legitimacy of concentrated corporate power in consumer markets; regulatory reform signals); Strategic Foresight (geopolitical regulatory coordination on antitrust; market transition in live entertainment sector)', 'Kelly Burke', NULL, 'news', false, false, 8.5, 'RGI partially agrees: the US antitrust verdict signals genuine market concentration risk, but the article conflates US monopoly findings with unproven Australian market structure without addressing whether comparable harms exist locally. Senior leaders in live entertainment, venues, and artist management should immediately audit pricing opacity and competitive constraints in their markets, as regulatory scrutiny of ticketing monopolies will likely spread across OECD jurisdictions within 18 months.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (512, 'More than half of Britons support rejoining EU 10 years on from Brexit vote', 'https://www.theguardian.com/politics/2026/apr/17/half-britons-support-rejoining-eu-10-years-brexit-vote', 'The Guardian', 'https://www.theguardian.com/world/rss', 5.2, '{}', 'More than half of Britons support rejoining EU 10 years on from Brexit vote', '2026-04-17 13:27:21+00', '2026-04-17 15:40:06.319674+00', 'Experts say Labour’s ‘halfway house’ approach risks losing support from progressives and ‘red wall’ voters UK politics live – latest updates Support for rejoining the EU rather than simply rejoining the single market is growing among British voters, with more than 80% of Labour, Liberal Democrat and Green party supporters favouring this option, according to research mapping voter attitudes 10 years after the Brexit referendum. Labour’s “muted” approach to the issue means it risks losing support among progressive voters and in “red wall” constituencies, experts have said as part of research by Best for Britain. Continue reading...', 'pending', 'Multiple', 'Lisa O’Carroll', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (513, 'EU officials arrive in Hungary for high-stakes talks with Magyar’s government', 'https://www.theguardian.com/world/2026/apr/17/eu-officials-hungary-talks-peter-magyar-government', 'The Guardian', 'https://www.theguardian.com/world/rss', 7.6, '{Geopolitics,"Global Politics"}', 'Viktor Orbán concedes electoral defeat after 16 years in power; EU officials engage incoming Hungarian government weeks before transition. Signals potential resolution of EU-Hungary judicial independence disputes and sanctions framework.', '2026-04-17 11:21:50+00', '2026-04-17 15:40:06.322179+00', 'Departing PM Viktor Orbán admits ‘political era has ended’ as EU says ‘clock is ticking’ to resolve important issues EU officials have arrived in Budapest for high-stakes talks aimed at reshaping the bloc’s strained relationship with Hungary, weeks before the new government takes office, as the country’s departing prime minister, Viktor Orbán, admitted a “political era has ended” and suggested he would stay on as leader of his party in his first interview since the election. Speaking to the pro-government outlet Patrióta, Orbán described Sunday’s election as an “emotional rollercoaster” after the opposition Tisza party won a landslide victory , bringing an end to his 16 years in power. Continue reading...', 'pending', '{"Strategic Foresight","Civic Stewardship"}', 'Ashifa Kassam European community affairs correspondent', NULL, 'news', false, true, 9.5, 'RGI partially agrees: the article correctly identifies a major institutional transition with systemic EU implications, but undersells the geopolitical significance of Hungary''s shift away from Orbán''s anti-EU posture—this is a foundational realignment of EU governance dynamics, not merely a bilateral negotiation. Senior leaders across Europe and in Washington must recognize this as a structural reset of EU cohesion and Budapest''s role in the bloc''s stability, requiring immediate strategic repositioning on sanctions, judicial reform, and energy policy.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (514, 'Senate passes short-term extension of surveillance law – US politics live', 'https://www.theguardian.com/us-news/live/2026/apr/17/house-congress-republicans-trump-administration-us-politics-news-live', 'The Guardian', 'https://www.theguardian.com/world/rss', 5.7, '{"Policy & Regulation","Global Politics"}', 'Senate passes 10-day extension of surveillance law by voice vote after House blocked longer-term extensions; Trump nominates Erica Schwartz (former deputy surgeon general) to lead CDC pending Senate confirmation; Iran announces Strait fully open.', '2026-04-17 15:21:29+00', '2026-04-17 15:40:06.32482+00', 'Senators pass 10-day extension by voice vote after House defeated attempts for five-year and 18-month extensions on Thursday night Sign up for the Breaking News US email In more CDC news, Donald Trump has selected Erica Schwartz to lead the troubled health agency, bringing to an end a months-long search for a permanent director. Schwartz served as the deputy surgeon general during Trump’s first term . But before she can officially take over, the president’s pick will require confirmation by the Senate. IRAN HAS JUST ANNOUNCED THAT THE STRAIT OF IRAN IS FULLY OPEN AND READY FOR FULL PASSAGE. THANK YOU! Continue reading...', 'pending', 'Civic Stewardship (institutional decision-making capacity; legitimacy of governance institutions); tangential System Vitality (leadership transitions at federal agencies)', 'Shrai Popat (now) and Vivian Ho (earlier)', NULL, 'news', false, false, 7.5, 'RGI partially agrees: the surveillance law extension signals continued legislative gridlock on security governance, but a 10-day extension is a tactical delay, not a strategic shift in how intelligence systems operate or are governed. Senior leaders should prepare for repeated surveillance/intelligence policy uncertainty—expect fragmented authority and delayed institutional decision-making to persist as a structural feature of US governance.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (515, 'US Senate votes to repeal Biden-era ban on mining near Minnesota wilderness area', 'https://www.theguardian.com/us-news/2026/apr/17/senate-overturn-biden-era-mining-ban-minnesota', 'The Guardian', 'https://www.theguardian.com/world/rss', 6.7, '{"Policy & Regulation","Climate & Environmental Health"}', 'US Senate votes 50-49 to repeal Biden''s 20-year mining moratorium near Minnesota''s Boundary Waters wilderness area, signaling potential shift in domestic resource extraction policy and environmental regulation.', '2026-04-17 14:56:11+00', '2026-04-17 15:40:06.32802+00', 'Measure passed 50-49 to overturn a 20-year ban on mining near renowned Boundary Waters Canoe Area Wilderness The US Senate narrowly voted on Thursday to overturn a ban on mining near Minnesota’s Boundary Waters Canoe Area Wilderness, an enormous complex of interconnected lakes, rivers and forests that is among the most visited wild areas in the US. The resolution passed 50-49 to repeal a 20-year moratorium imposed by former president Joe Biden’s administration in 2023 on mining across the 225,000 acres in the Superior national forest. Continue reading...', 'pending', 'System Vitality (institutional legitimacy and stakeholder trust around environmental governance); Civic Stewardship (corporate responsibility, environmental policy, democracy/policy reform); tangential Strategic Foresight (commodity markets, supply-chain transitions).', 'Anna Betts', NULL, 'news', false, false, 9.5, 'RGI partially agrees: the Senate action signals real geopolitical/economic pressure on domestic resource security, but the article lacks strategic depth on why this inflection matters now—whether it reflects broader commodity scarcity, supply-chain decoupling from China, or domestic political realignment on extraction policy. Senior leaders must anticipate that resource nationalism and domestic mining revival will reshape ESG compliance, supply-chain strategy, and stakeholder governance for a decade.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (516, 'ICE’s hiring spree led to influx of recruits with questionable qualifications, investigation shows', 'https://www.theguardian.com/us-news/2026/apr/17/ice-immigration-agents-backgrounds', 'The Guardian', 'https://www.theguardian.com/world/rss', 5.7, '{"Policy & Regulation","Leadership & Organizations"}', 'Investigation reveals ICE''s rapid expansion under Trump administration recruited staff with bankruptcy histories, employment gaps, and misconduct allegations, raising institutional governance questions.', '2026-04-17 13:52:03+00', '2026-04-17 15:40:06.330596+00', 'Patchy employment records, bankruptcies and allegations of wrongdoing blemish the records of several new recruits Sign up for the Breaking News US email to get newsletter alerts in your inbox Rapid recruitment and expansion by US Immigration and Customs Enforcement ( ICE ) has led to an influx of employees with questionable qualifications, an investigation has found. The track records of some of the new recruits amid the Trump administration ’s mass deportation agenda stand out – and not in a good way. Continue reading...', 'pending', 'System Vitality (governance/institutional health)', 'Associated Press', NULL, 'news', false, false, 8.5, 'RGI partially agrees: ICE hiring quality failures reflect genuine institutional governance risk, but this article focuses on personnel vetting rather than systemic policy implications for private-sector leadership. Institutions must establish baseline HR controls; boards should audit government contractor and regulated industry hiring standards for similar vulnerabilities.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (517, 'Even OpenAI’s top economist thinks the AI job apocalypse is overstated. Here’s why.', 'https://www.marketwatch.com/story/even-openais-top-economist-thinks-the-ai-job-apocalypse-is-overstated-heres-why-7e920e7a?mod=mw_rss_topstories', 'MarketWatch', 'https://feeds.marketwatch.com/marketwatch/topstories/', 6.4, '{"AI & Artificial Intelligence","Future of Work"}', 'OpenAI economist argues AI job displacement forecasts are overblown based on internal research; MarketWatch reports findings pushing back against ''apocalypse'' narratives around AI labor disruption.', '2026-04-17 12:58:00+00', '2026-04-17 15:40:06.33333+00', 'OpenAI has done an in-depth study at just what AI disruption means for the jobs market, pushing back at some gloomier forecasts.', 'pending', 'System Vitality (organizational workforce resilience, leadership preparation for labor-market transition); Strategic Foresight (weak signals on tech-sector consensus regarding employment disruption timelines)', 'Barbara Kollmeyer', NULL, 'news', false, false, 7.2, 'RGI partially agrees: OpenAI''s internal labor-market research carries institutional weight, but a single company''s optimistic framing on its own technology''s employment impact warrants skepticism given structural incentive misalignment. Senior leaders should commission independent, non-vendor labor-market modeling to stress-test workforce transition timelines and reskilling capacity within their own sectors—OpenAI''s conclusions are a data point, not ground truth.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (518, 'Think the rally is safe? This elite market-timing indicator says a correction is overdue.', 'https://www.marketwatch.com/story/think-the-rally-is-safe-this-elite-market-timing-indicator-says-a-correction-is-overdue-8049c27f?mod=mw_rss_topstories', 'MarketWatch', 'https://feeds.marketwatch.com/marketwatch/topstories/', 5.1, '{}', 'Think the rally is safe? This elite market-timing indicator says a correction is overdue.', '2026-04-17 12:05:00+00', '2026-04-17 15:40:06.336998+00', 'The gold-platinum ratio suggests the stock market is living on borrowed time.', 'pending', 'Multiple', 'Mark Hulbert', NULL, 'news', false, false, 5, NULL);
