INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (622, 'India fails to pass bill to boost women’s representation after delimitation row', 'https://www.theguardian.com/world/2026/apr/17/india-narendra-modi-women-representation-delimitationl', 'The Guardian', 'https://www.theguardian.com/world/rss', 5.7, '{"Global Politics","Policy & Regulation"}', 'Modi government''s failure to pass women''s representation bill after accusations of using it as cover for electoral redistricting signals democratic institutional strain and potential erosion of civic legitimacy in India.', '2026-04-17 17:28:51+00', '2026-04-17 18:54:05.542311+00', 'Opposition accuses Narendra Modi government of using quotas as cover for redrawing electoral map The Indian government has failed to pass a bill to increase female representation in parliament after being accused of using the plan as a guise to redraw the country’s electoral map. It was the first time in 12 years in power that a constitutional amendment proposed by Narendra Modi’s Bharatiya Janata party (BJP) government was not passed by parliament. Continue reading...', 'pending', 'Civic Stewardship (institutional legitimacy, democratic health); System Vitality (trust and institutional credibility)', 'Hannah Ellis-Petersen in Delhi', NULL, 'news', false, false, 9.5, 'RGI partially agrees: the article correctly identifies a governance failure and political strategy conflict, but underweights the deeper systemic implication—the weaponization of representation reform as electoral manipulation fundamentally undermines institutional legitimacy and civic trust, creating cascading risks for democratic institutions. Senior leaders operating in India or managing geopolitical exposure must now assess whether democratic guardrails are eroding faster than previously modeled, and recalibrate stakeholder trust strategies accordingly.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (623, 'Rachel Reeves to raise windfall tax on low-carbon electricity generators', 'https://www.theguardian.com/business/2026/apr/17/rachel-reeves-to-raise-windfall-tax-on-low-carbon-electricity-generators', 'The Guardian', 'https://www.theguardian.com/world/rss', 6.7, '{"Policy & Regulation","Energy & Oil",Macroeconomics}', 'UK Chancellor Rachel Reeves plans to increase windfall taxes on low-carbon electricity generators to manage household energy bills, targeting excess profits from renewable and nuclear assets amid ongoing energy market volatility.', '2026-04-17 17:48:02+00', '2026-04-17 18:54:05.545448+00', 'Chancellor aims to curb rising household bills as she consults on reforms to weaken link between gas and electricity prices Rachel Reeves is poised to raise the government’s windfall tax on low-carbon electricity generators to help to limit UK household energy bills, the Guardian understands. The chancellor is ready to hike the levy introduced in 2022 to target the excess profits made by the owners of older renewable energy and nuclear plants as electricity market prices soared after Russia’s full-scale invasion of Ukraine. Continue reading...', 'pending', 'Civic Stewardship (corporate responsibility, policy legitimacy, institutional trust) and System Vitality (organizational cost pressures on energy operators). Secondary relevance to Strategic Foresight (energy market transition signals).', 'Jillian Ambrose and Nils Pratley', NULL, 'news', false, false, 8.5, 'RGI partially agrees: the windfall tax mechanism addresses a real market distortion (excess profits from low-carbon generators during energy crisis), but the policy signal suggests reactive cost-containment rather than systemic energy market redesign. Senior leaders in energy, infrastructure, and regulated utilities must anticipate similar windfall tax escalation across Europe and prepare capital allocation strategies accordingly.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (624, 'Fed’s Waller turns cautious on rate cuts and worries about a ’lasting increase in inflation’', 'https://www.marketwatch.com/story/feds-waller-turns-cautious-on-rate-cuts-and-warns-of-a-lasting-increase-in-inflation-ad7d7e4d?mod=mw_rss_topstories', 'MarketWatch', 'https://feeds.marketwatch.com/marketwatch/topstories/', 8.4, '{Macroeconomics,Geopolitics,"Policy & Regulation"}', 'Federal Reserve Governor Chris Waller signals potential pause on rate cuts due to oil price surges from Iran tensions and persistent tariff effects, warning of sustained inflation risks that could alter monetary policy trajectory.', '2026-04-17 18:04:00+00', '2026-04-17 18:54:05.549687+00', 'Federal Reserve Governor Chris Waller said the surge in oil prices tied to the Iran war and lingering effects from U.S. tariffs could “lead to a more lasting increase in inflation,” potentially forcing the central bank to eschew further interest-rate cuts.', 'pending', '{"Strategic Foresight","System Vitality"}', 'Jeffry Bartash', NULL, 'news', false, true, 8.2, 'RGI partially agrees: Waller''s inflation concern is material, but the article conflates geopolitical oil shocks with tariff-driven inflation—distinct policy vectors requiring different leadership responses. Senior leaders must now model dual scenarios: stagflationary pressure from supply shocks AND demand-side fiscal drag from trade policy, forcing immediate capital allocation and workforce planning recalibration.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (625, 'Airline and cruise stocks soar, as ‘TACO’ gives way to ‘trust in Trump alone’', 'https://www.marketwatch.com/story/airline-and-cruise-stocks-soar-as-taco-gives-way-to-trust-in-trump-alone-bc142106?mod=mw_rss_topstories', 'MarketWatch', 'https://feeds.marketwatch.com/marketwatch/topstories/', 5.2, '{}', 'Airline and cruise stocks soar, as ‘TACO’ gives way to ‘trust in Trump alone’', '2026-04-17 17:38:00+00', '2026-04-17 18:54:05.554517+00', 'United Airlines and Royal Caribbean shares were leading the S&P 500’s gainers as investors “trust in Trump” to deliver peace.', 'pending', 'Multiple', 'Bill Peters', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (626, 'US lawmakers intensify scrutiny of scientific-publishing practices', 'https://www.nature.com/articles/d41586-026-01251-y', 'Nature', 'https://www.nature.com/nature.rss', 5, '{}', 'US lawmakers intensify scrutiny of scientific-publishing practices', '2026-04-17 00:00:00+00', '2026-04-17 18:54:05.559432+00', 'Nature, Published online: 17 April 2026; doi:10.1038/d41586-026-01251-y A congressional hearing covered the rise of paper mills and the costs of open-access publishing — but there was little agreement on what reform would entail.', 'pending', 'Multiple', 'Max Kozlov', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (627, 'More Workers—and Employers—Are Looking Abroad for Jobs They Can’t Find at Home', 'https://www.inc.com/bruce-crumley/more-workers-and-employers-are-looking-abroad-for-jobs-they-cant-find-at-home/91331845', 'Inc. Magazine', 'https://www.inc.com/rss', 5.4, '{"Future of Work","Supply Chains & Trade"}', 'Cross-border job searches accelerating among both workers and employers, driven by remote work enablement, job scarcity, and lifestyle factors. Inc. survey-based reporting on emerging talent market fragmentation.', '2026-04-17 18:12:02+00', '2026-04-17 18:54:05.562754+00', 'Surveys show job scarcity, lifestyle concerns, and remote work are driving a growing cross‑border search for talent and opportunity.', 'pending', 'System Vitality (organizational operating models, talent strategy, future of work structure) and secondary Strategic Foresight (human capital reallocation as weak signal of structural economic shift).', 'Bruce Crumley', NULL, 'news', false, false, 6.2, 'RGI partially agrees: remote work has enabled cross-border talent mobility, but the article conflates cyclical job-market dynamics with structural shifts in how organizations source talent globally. The strategic signal is real but underdeveloped—what matters is whether this represents a permanent reallocation of human capital and organizational operating models, or temporary labor arbitrage during a transition period. Senior leaders must treat this as a leading indicator of talent geography decoupling from traditional headquarters models and plan workforce strategies accordingly.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (628, 'Goldman Sachs Warns That Losing Your Job to AI Can Hurt Your Earnings for a Decade', 'https://www.inc.com/kit-eaton/goldman-sachs-warns-that-losing-your-job-to-ai-can-hurt-your-earnings-for-a-decade/91332401', 'Inc. Magazine', 'https://www.inc.com/rss', 7.4, '{"AI & Artificial Intelligence","Future of Work","Civic Stewardship"}', 'Goldman Sachs research finds workers displaced by AI experience decade-long earnings suppression versus traditional layoff cohorts, signaling structural labor market risk beyond automation efficiency gains.', '2026-04-17 17:04:54+00', '2026-04-17 18:54:05.567338+00', 'New research suggests workers displaced by AI face lower pay, slower wage growth, and longer recoveries than those laid off for other reasons.', 'pending', 'System Vitality (organizational talent/culture risk); Civic Stewardship (corporate legitimacy and community impact); Strategic Foresight (labor market transition signals)', 'Kit Eaton', NULL, 'news', false, false, 7.2, 'RGI partially agrees: the research signal on AI displacement''s wage scarring is substantive, but Goldman''s framing conflates correlation with causation and underspecifies whether wage loss stems from skill obsolescence, market saturation, or employer discrimination. Senior leaders must recognize that AI-displaced workers face structural reemployment penalties that likely exceed cyclical layoff effects, demanding proactive reskilling infrastructure and transparent transition policies to manage legitimacy risk and talent retention.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (629, 'Stellantis and Microsoft strike a 5-year AI deal covering 100+ initiatives', 'https://qz.com/stellantis-microsoft-ai-deal-azure-cloud-datacenter', 'Quartz', 'https://qz.com/feed', 6.4, '{"AI & Artificial Intelligence","Technology & Digital Innovation"}', 'Stellantis commits to 100+ AI initiatives on Microsoft Azure, cutting datacenter costs 60% by 2029. Signals enterprise cloud migration momentum but unclear if addresses core EV/autonomy competitive positioning.', '2026-04-17 17:10:12+00', '2026-04-17 18:54:05.573525+00', 'The automaker will move to Microsoft''s Azure cloud and cut its datacenter footprint by 60% by 2029 as part of the agreement', 'pending', '{"Strategic Foresight — AI acceleration and enterprise deployment patterns","System Vitality — organizational infrastructure modernization"}', 'Quartz Staff', NULL, 'news', false, false, 7.2, 'RGI partially agrees: this represents meaningful enterprise AI deployment at scale, but the article lacks strategic depth on competitive implications or whether this positions Stellantis for autonomous/EV leadership vs. operational efficiency alone. Senior leaders should monitor whether legacy automakers'' cloud consolidation signals capability gaps in AI-native product development vs. Tesla/Chinese EV competitors.');
