INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (632, 'Netflix stock sinks after a soft earnings forecast as Reed Hastings leaves the board', 'https://qz.com/netflix-stock-falls-q2-forecast-hastings-board-exit-041726', 'Quartz', 'https://qz.com/feed', 5.1, '{}', 'Netflix stock sinks after a soft earnings forecast as Reed Hastings leaves the board', '2026-04-17 12:11:07+00', '2026-04-17 18:54:05.58806+00', 'The streaming giant''s revenue forecasts came in below Wall Street expectations, while co-founder Reed Hastings announced he would leave the board', 'pending', 'Multiple', 'Cris Tolomia', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (383, '6,000 Meters Under the Pacific, Japan Seeks Independence From China on Rare Earths', 'https://www.wired.com/story/under-the-pacific-japan-seeks-independence-from-china-on-rare-earths/', 'Wired', 'https://www.wired.com/feed/rss', 8.5, '{Geopolitics,Strategy}', 'Japan''s rare earth independence threatens China''s supply-chain leverage over advanced manufacturing and defense. Leaders must assess implications for sourcing, geopolitical risk, and competitive positioning in tech/defense sectors.', '2026-04-17 08:30:00+00', '2026-04-17 08:37:27.322681+00', 'Tokyo is succeeding where the rest of the world has failed, reducing its reliance on Beijing for crucial rare earth elements—thanks to an enormous underwater deposit discovered on a remote island.', 'selected', 'Strategic Foresight', 'Lorenzo Lamperti', NULL, 'news', true, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (384, 'Three Questions for Kevin Warsh, Trump’s Fed Pick', 'https://www.nytimes.com/2026/04/17/opinion/warsh-fed-confirmation.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 8.7, '{Governance,Policy,Finance}', 'NYT editorial examines Kevin Warsh''s nomination as Federal Reserve chair, highlighting the critical tension between central bank independence and executive branch pressure—a systemic governance issue affecting monetary policy credibility and market stability.', '2026-04-17 09:00:39+00', '2026-04-17 09:52:57.510384+00', 'Senators must assess whether Mr. Warsh would perform his duties as a public servant, or whether he would serve the interests of the president.', 'selected', 'System Vitality (institutional trust and governance integrity) + Civic Stewardship (democratic institutions and separation of powers)', 'The Editorial Board', NULL, 'news', true, false, 9.5, 'Frames Federal Reserve leadership appointment as a test of institutional independence versus presidential influence.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (455, 'US Eyes More Namibian Uranium Imports as AI Drives Nuclear Push', 'https://www.bloomberg.com/news/articles/2026-04-17/us-eyes-more-namibian-uranium-imports-as-ai-drives-nuclear-push', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 8.7, '{"Energy & Oil",Geopolitics,"AI & Artificial Intelligence"}', 'The US is accelerating uranium procurement from Namibia to secure nuclear fuel supplies amid surging AI energy demands, signaling a major geopolitical and energy strategy shift with implications for global nuclear supply chains and US-Africa relations.', '2026-04-17 15:09:04+00', '2026-04-17 15:40:06.143467+00', 'The US is weighing boosting uranium imports from Namibia, the world’s third-biggest producer, and supporting greater output of the nuclear fuel through its mining companies and government financing, America’s top diplomat in the southern African nation said.', 'selected', '{"Strategic Foresight","Civic Stewardship"}', 'Paul Burkhardt', NULL, 'news', true, true, 9.5, 'RGI agrees: the strategic repositioning of US energy sourcing toward nuclear fuel directly reflects the geopolitical realignment driven by AI infrastructure demands and energy security concerns. Senior leaders must immediately map nuclear supply-chain dependencies and assess how AI-driven energy scarcity reshapes competitive positioning in high-compute sectors.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (691, 'UN warns South Sudan at risk of ‘full-scale famine’ as fighting intensifies', 'https://www.aljazeera.com/news/2026/4/17/un-warns-south-sudan-at-risk-of-full-scale-famine-as-fighting-intensifies?traffic_source=rss', 'Al Jazeera English', 'https://www.aljazeera.com/xml/rss/all.xml', 5, '{}', 'UN warns South Sudan at risk of ‘full-scale famine’ as fighting intensifies', '2026-04-17 19:59:26+00', '2026-04-18 02:02:06.537008+00', 'UN aid chief Tom Fletcher says hunger is tightening its grip amid rising humanitarian needs and intensifying fighting.', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (462, 'Iran Conflict Poses Risk to Global Economy, IMF Members to Say', 'https://www.bloomberg.com/news/articles/2026-04-17/iran-conflict-poses-risk-to-global-economy-imf-members-to-say', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 8.7, '{Geopolitics,Macroeconomics}', 'IMF''s International Monetary and Financial Committee signals that Iran conflict poses ''serious threat to global economy,'' with disproportionate impact on developing nations — a primary institutional warning that reshapes risk assessment across energy, trade, and capital markets.', '2026-04-17 14:12:07+00', '2026-04-17 15:40:06.165748+00', 'The conflict in the Middle East is a major shock that poses a “serious threat to the global economy” and will hit the poorest countries the hardest, according to a statement expected to be released by the Chair of the International Monetary and Financial Committee Friday.', 'selected', '{"Strategic Foresight","System Vitality"}', 'Jorge Valero', NULL, 'news', true, true, 9.5, 'RGI agrees: geopolitical volatility in energy-critical regions directly reshapes macroeconomic forecasts, capital allocation, and institutional risk management — the IMF''s formal governance signal elevates this beyond commentary to systemic warning. Senior leaders must immediately stress-test supply chain, energy, and currency exposure to Middle East conflict escalation and repricing of geopolitical risk premiums.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (470, 'Oil prices plunge on claims Strait of Hormuz is open', 'https://www.axios.com/2026/04/17/hormuz-iran-oil-prices', 'Axios', 'https://api.axios.com/feed/', 8.4, '{Geopolitics,"Energy & Oil","Supply Chains & Trade"}', 'Oil prices dropped 10% after Trump and Iran''s foreign minister announced the Strait of Hormuz—handling 25% of global seaborne oil—is fully open for transit, signaling potential relief from energy supply constraints tied to regional conflict escalation.', '2026-04-17 14:58:12+00', '2026-04-17 15:40:06.189771+00', 'Data: Financial Modeling Prep ; Chart: Ben Geman/Axios Oil prices dropped over 10% Friday after President Trump and Iran''s foreign minister claimed the Strait of Hormuz — the world''s most critical energy shipping lane — is open for transit. Why it matters: The steep selloff signals traders see a real sign that the unprecedented throttling of oil and petroleum product flows could significantly ease. The drop also follows signs of continued progress in ceasefire negotiations. Driving the news: "In line with the ceasefire in Lebanon, the passage for all commercial vessels through Strait of Hormuz is declared completely open for the remaining period of ceasefire," Iranian foreign minister Abbas Araghchi posted on X . He said this would occur "on the coordinated route as already announced by Ports and Maritime Organisation of the Islamic Rep. of Iran." "IRAN HAS JUST ANNOUNCED THAT THE STRAIT OF IRAN IS FULLY OPEN AND READY FOR FULL PASSAGE. THANK YOU!," Trump posted on Truth Social. The big picture: The global benchmark Brent crude is down to $88.90 per barrel, the lowest in over a month. WTI, the main U.S. reference, is at $83.35. U.S. stock futures — already in positive territory before the announcement — moved higher on the news. What we''re watching: It''s unclear how many shippers will feel the claims provide enough certainty to start resuming transit through the narrow waterway, which handles about a fourth of the world''s seaborne oil trade.', 'selected', '{"Strategic Foresight","System Vitality"}', 'Ben Geman', NULL, 'news', false, true, 8.2, 'RGI partially agrees: the article correctly identifies the market signal (10% oil price drop) and geopolitical significance of Strait of Hormuz reopening, but understates the fragility of the claimed agreement and lacks analysis of whether this represents durable de-escalation or tactical positioning. Senior leaders must immediately stress-test supply chain and energy hedging strategies against the high probability this ceasefire announcement proves temporary or conditional.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (471, 'Scoop: U.S. considers $20 billion cash-for-uranium deal with Iran', 'https://www.axios.com/2026/04/17/iran-us-deal-20-billion-frozen-funds-uranium', 'Axios', 'https://api.axios.com/feed/', 9.3, '{Geopolitics,"Policy & Regulation"}', 'U.S. and Iran negotiating $20B frozen-asset release in exchange for uranium stockpile surrender, with Pakistan mediating. Deal framework includes nuclear moratorium terms, third-country uranium transfers, and international monitoring—but significant gaps remain on enrichment timelines and verification enforcement.', '2026-04-17 12:24:37+00', '2026-04-17 15:40:06.199026+00', 'The U.S. and Iran are negotiating over a three-page plan to end the war, with one element under discussion being that the U.S. would release $20 billion in frozen Iranian funds in return for Iran giving up its stockpile of enriched uranium, according to two U.S. officials and two additional sources briefed on the talks. Why it matters: There has been steady progress in the talks this week, though significant gaps remain. A deal on these terms would bring the war to a close, while potentially generating backlash from Iran hawks. President Trump said Thursday that U.S. and Iranian negotiators would likely meet this weekend for a second round of talks to try to seal the deal. The talks are expected to take place in Islamabad, likely on Sunday, according to a source familiar with the mediation efforts. Pakistan is mediating the negotiations, with behind-the-scenes support from Egypt and Turkey. Breaking it down: A top priority for the Trump administration is ensuring Iran can''t access the stockpile of nearly 2,000kg of enriched uranium buried in its underground nuclear facilities, in particular the 450kg enriched to 60% purity. The Iranians, meanwhile, need money. The parties are negotiating over what will happen to the stockpile, and how much of Iran''s assets will be unfrozen. They are also discussing the terms on which Iran could use that money. Zoom in: According to two sources, the U.S was ready in an earlier stage of the negotiations to release $6 billion for Iran to purchase food, medicine and other humanitarian supplies. The Iranians demanded $27 billion. The latest number discussed by the U.S. and Iran is $20 billion, the sources said. One U.S. official said that was a U.S. proposal. The other U.S. official described the cash-for-uranium concept as "one of many discussions." Meanwhile, the U.S. asked Iran to agree to ship all its nuclear material to the U.S., while the Iranians only agreed to "down-blend" it inside Iran. Under a compromise proposal now under discussion, some of the highly enriched uranium would be shipped to a third country, not necessarily the U.S., and some of it would be down-blended in Iran under international monitoring. The intrigue: The three-page memorandum of understanding (MOU) the two sides are negotiating over also includes a "voluntary" moratorium on nuclear enrichment by Iran. The U.S. demanded in the last round of talks that Iran agree to a 20-year moratorium . Iran countered with five years. The mediators are still trying to close the gap. As part of the MOU, Iran would be allowed to have nuclear research reactors for the production of medical isotopes, but would pledge that all of its nuclear facilities would be above ground. The existing underground facilities would remain out of commission. The MOU also deals with the Strait of Hormuz, though the sources said there are still significant gaps on that issue. It''s unclear if the MOU refers to Iran''s ballistic missiles and its support for regional proxies. Isra', 'selected', 'Strategic Foresight (geopolitical volatility, systemic security architecture), Civic Stewardship (legitimacy of state commitments, energy/security policy reform)', 'Barak Ravid', NULL, 'news', true, true, 8.2, 'RGI partially agrees: the reported framework shows pragmatic negotiation structure (asset-for-constraint exchange), but the characterization of ''steady progress'' obscures persistent gaps on enrichment timelines and verification that remain strategically unresolved. Senior leaders must prepare for either breakthrough or prolonged volatility—this deal''s success hinges on Iran''s compliance credibility and Congressional acceptance, both structurally uncertain.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (505, 'Oil prices plunge as Iran says Strait of Hormuz ''open'' during ceasefire', 'https://www.bbc.com/news/articles/ckg045z73z1o?at_medium=RSS&at_campaign=rss', 'BBC News', 'http://feeds.bbci.co.uk/news/rss.xml', 8.7, '{Geopolitics,"Energy & Oil",Macroeconomics}', 'Iran confirms Strait of Hormuz remains open during ceasefire, triggering 10% Brent crude drop and signaling potential Middle East de-escalation with major implications for energy markets and global supply-chain risk.', '2026-04-17 14:54:05+00', '2026-04-17 15:40:06.300057+00', 'Brent crude sinks 10% after Iran says the key waterway is completely open for commercial ships for the rest of the ceasefire.', 'selected', 'Strategic Foresight (geopolitical volatility, market transitions, weak signals of systemic stability); System Vitality (organizational capital allocation and confidence shifts); Civic Stewardship (energy security and global stability).', NULL, NULL, 'news', true, true, 9.5, 'RGI agrees: Iran''s ceasefire announcement and explicit commitment to keep the Strait of Hormuz open materially reduces geopolitical risk premium in energy markets and signals a potential de-escalation in Middle East tensions that reshape capital allocation and supply-chain confidence. Senior leaders must immediately reassess energy hedging strategies, supply-chain resilience assumptions, and geopolitical scenario planning—this ceasefire durability will determine whether this 10% price move reflects a structural shift or a tactical reprieve.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (526, 'Oil falls almost 10% and stock futures rise as Iran opens Strait of Hormuz', 'https://qz.com/oil-prices-fall-iran-strait-hormuz-ceasefire-stocks-041726', 'Quartz', 'https://qz.com/feed', 8.4, '{Geopolitics,"Energy & Oil","Finance & Markets"}', 'Iranian official declares Strait of Hormuz ''completely open'' during Israel-Lebanon ceasefire; oil prices fall ~10%, stock futures rise. Markets interpret as reduced geopolitical risk premium.', '2026-04-17 13:51:00+00', '2026-04-17 15:40:06.358961+00', 'A top Iranian official declared the Strait of Hormuz "completely open" to commercial vessels during the Israel-Lebanon ceasefire', 'selected', '{"Strategic Foresight","System Vitality"}', 'Quartz Staff', NULL, 'news', false, true, 7.2, 'RGI partially agrees: the geopolitical signal is material and markets are correctly pricing reduced regional risk, but the article underweights uncertainty around ceasefire durability and Iran''s strategic intent beyond the strait declaration. Senior leaders in energy, logistics, and capital-intensive industries must immediately model scenario-based supply chain resilience around Hormuz contingencies, as ceasefire fragility could reverse these price signals within weeks.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (535, 'Warsh Hearing Will Test How Far He’ll Push Balance Sheet Reform', 'https://www.bloomberg.com/news/articles/2026-04-17/warsh-hearing-will-test-how-far-he-ll-push-balance-sheet-reform', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 8.7, '{Macroeconomics,"Policy & Regulation"}', 'Kevin Warsh''s Senate confirmation hearing will expose his intent to shrink the Federal Reserve''s balance sheet and reduce market interventionism — signaling a structural shift in monetary policy that will reshape how Fortune 500 leaders model leverage, liquidity buffers, and crisis response assumptions.', '2026-04-17 16:27:26+00', '2026-04-17 16:38:04.712189+00', 'Kevin Warsh will get his first major public platform as Federal Reserve Chair nominee next week to address his longstanding concerns over the central bank’s outsized market footprint.', 'selected', '{"Strategic Foresight","System Vitality"}', 'Alex Harris, Maria Eloisa Capurro', NULL, 'news', true, true, 9.5, 'RGI agrees: Warsh''s Fed Chair nomination represents a material shift in central bank philosophy toward balance sheet constraint, directly affecting monetary policy regime and capital allocation frameworks that shape institutional strategy. Senior leaders must recalibrate risk models, duration assumptions, and capital deployment strategies around a potential tightening bias that constrains liquidity provision during market stress.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (541, 'Trump tells Axios he expects Iran deal "in a day or two"', 'https://www.axios.com/2026/04/17/trump-iran-deal-interview-pakistan-talks', 'Axios', 'https://api.axios.com/feed/', 8.4, '{Geopolitics,"Global Politics","Wars & Crisis"}', 'Trump claims Iran nuclear deal imminent (''day or two''), but multiple U.S. officials report significant gaps remain on critical issues. Negotiations center on $20B frozen Iranian assets, uranium stockpile restrictions, and naval strait access; Israeli government divisions threaten ceasefire viability.', '2026-04-17 16:13:24+00', '2026-04-17 16:38:04.732553+00', 'President Trump told Axios that U.S. and Iranian negotiators will probably meet this weekend, and he expects them to hammer out a final deal to end the war . Reality check: Multiple U.S. officials and other sources briefed on the negotiations have told Axios that while significant progress has been made, and the U.S. and Iran are now closing in on a three-page peace plan, gaps still remain on critical issues. Trump, who has held at least one direct call with an Iranian official in recent days, is clearly feeling optimistic. "The Iranians want to meet. They want to make a deal. I think a meeting will probably take place over the weekend. I think we will get a deal in the next day or two," he said in a brief phone interview. Driving the news: Axios reported on Friday that one element of the deal under discussion would be the U.S. releasing $20 billion in frozen Iranian funds in return for Iran giving up its stockpile of enriched uranium. The plan also involves a moratorium on Iranian enrichment. What they''re saying: Trump said he''s not going to lift the naval blockade which has been imposed on Iran before a deal is reached, and stressed he wants the strait to be open for everybody. Iran announced on Friday that it would open the strait for the remainder of the ceasefire, which expires on April 21, but the details of how that will work remain unclear. The big picture: Trump said the deal will "make Israel safe" and stressed "Israel is going to come out great" at the end of the war. At the same time, he made clear he wants Israeli strikes on Lebanon to end as part of the ceasefire that was announced on Thursday. "Israel has to stop. They can''t continue to blow buildings up. I am not gonna allow it," he said. What to watch: On Friday evening, shortly before the interview, an Israeli drone conducted a strike in southern Lebanon. Some in the Israeli government oppose a deal and want to continue the wars in Iran and in Lebanon, though that likely won''t be possible as long as Trump opposes it.', 'selected', 'Strategic Foresight (geopolitical volatility, weak signal interpretation, long-range pattern recognition on Middle East stability and energy markets); Civic Stewardship (legitimacy of negotiated settlements, institutional credibility of executive messaging)', 'Barak Ravid', NULL, 'news', false, true, 7.2, 'RGI partially agrees: Trump''s direct statement signals genuine negotiation momentum, but the gap between his optimistic timeline (''day or two'') and multiple official sources citing ''significant gaps on critical issues'' suggests either strategic messaging or misalignment between executive confidence and operational reality—a leadership credibility signal worth monitoring. Senior leaders must recognize that geopolitical deal timelines announced by sitting executives often compress months of unresolved complexity into days, requiring independent verification before strategic repositioning around Middle East stability or energy markets.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (542, 'The Strait of Hormuz is opening for business', 'https://www.axios.com/2026/04/17/iran-strait-inflation-oil-stocks', 'Axios', 'https://api.axios.com/feed/', 8.4, '{Geopolitics,"Energy & Oil",Macroeconomics}', 'Iran''s blockade of the Strait of Hormuz—a critical chokepoint for ~20% of global oil supply—appears to have ended following U.S. counterblocade threat and Israel-Lebanon ceasefire, temporarily reducing global recession risk and energy price volatility. However, underlying structural tensions remain unresolved.', '2026-04-17 16:04:01+00', '2026-04-17 16:38:04.738604+00', 'The blockage to energy supplies through the Persian Gulf appears to have ended. If it holds, it takes a massive weight off the world economy. Why it matters: The possibility of a prolonged disruption to the supply of crude oil, liquefied natural gas, fertilizer and other commodities looks to be off the table. The Trump administration''s strategic move from last weekend — matching Iran''s strait blockade for ships that don''t pay a toll with a U.S. blockade — seems to have worked, at least for now. The global economy''s outlook for the remainder of this year heavily depends on the outlook for energy supplies through the strait. Driving the news: Iran''s foreign minister said that in light of a ceasefire between Israel and Lebanon, "the passage for all commercial vessels through the Strait of Hormuz is declared completely open for the remaining period of ceasefire." President Trump said on Truth Social that Israel is "PROHIBITED " from further bombing of Lebanon. He said that the U.S. Naval blockade "WILL REMAIN IN FULL FORCE AND EFFECT AS IT PERTAINS TO IRAN, ONLY, UNTIL SUCH TIME AS OUR TRANSACTION WITH IRAN IS 100% COMPLETE" and that this process "SHOULD GO VERY QUICKLY." State of play: In the initial weeks after the U.S. and Israel decapitated Iranian leadership, Iran''s blockage of the strait worked as a strategic advantage, giving it leverage over the global economy. In effect, Iran was able to exact a toll on friendly countries that were in desperate need of oil. Events of the last week show that two can play that game, with a U.S. threat against ships that pass through the strait threatening to choke off a crucial source of funds for the battered Iranian regime. Both sides'' ability to inflict economic pain on the other led to the apparent de-escalation. What they''re saying: "The US is being very smart about the blockade," Robin Brooks, a senior fellow at the Brookings Institution, wrote Thursday on X . "It dangles prospects of peace to markets, which caps oil prices," he adds. "That defangs Iran''s main negotiating leverage, which is to cause panic and push oil prices higher. The mullahs are getting pushed into a corner." Between the lines: There have been signs for weeks that Trump was looking for an off-ramp from the conflict, a way to declare victory and reduce economic shockwaves. Strategists can debate whether there has been any lasting achievement of U.S. geopolitical goals. But at least the odds of a global economic slowdown look to be reduced. Data: FactSet; Chart: Courtenay Brown/Axios Zoom in: Oil prices plunged, and stock markets around the world soared on the news Friday that the Strait of Hormuz is opening. A deal that reopens the strait could help ease pressure on a Federal Reserve already pinned down by pre-war sticky inflation. The Iran war risked an impossible situation for the Fed: inflation too high to cut rates, despite a softening labor market that might ultimately require looser policy. By the numbers: Stocks were soaring Fri', 'selected', 'Strategic Foresight (geopolitical volatility, market transitions, weak signals of de-escalation vs. durable resolution); Macroeconomic inflection point (energy supply certainty as recession hedge)', 'Neil Irwin', NULL, 'news', false, true, 7.2, 'RGI partially agrees: the article correctly identifies the Strait of Hormuz reopening as economically significant, but conflates tactical negotiation leverage with durable geopolitical resolution—Iran''s structural incentives to disrupt energy flows remain intact regardless of temporary ceasefires. Senior leaders must treat this as a volatility pause, not a structural fix: contingency planning for renewed Persian Gulf disruption should remain a core scenario in 2025 strategic forecasting, with explicit triggers for energy hedging and supply chain repositioning.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (549, 'Ukraine’s long-range strikes prompt new Russian threat against Europe', 'https://www.aljazeera.com/features/2026/4/17/ukraines-long-range-strikes-prompt-new-russian-threat-against-europe?traffic_source=rss', 'Al Jazeera English', 'https://www.aljazeera.com/xml/rss/all.xml', 8.4, '{Geopolitics,"Wars & Crisis","Energy & Oil"}', 'Ukraine escalates drone strikes on Russian oil infrastructure, denying Moscow critical state revenues and signaling a shift toward asymmetric economic warfare as a strategic tool.', '2026-04-17 15:46:03+00', '2026-04-17 16:38:04.762817+00', 'Ukraine has penetrated Russian airspace with unprecedented numbers of drones, denying Russia windfall oil profits.', 'selected', 'Strategic Foresight (weak-signal pattern recognition of energy-focused conflict asymmetry) + Civic Stewardship (state legitimacy tied to revenue capture; implications for corporate energy sector alignment and sanctions efficacy)', NULL, NULL, 'news', false, false, 7.2, 'RGI partially agrees: the article correctly identifies Ukraine''s operational shift toward energy infrastructure targeting, which materially disrupts Russian state revenue and constrains Putin''s war-financing capacity—a genuine strategic development. However, the framing of ''new Russian threat against Europe'' lacks specific substantiation and risks conflating operational retaliation with escalation intent; the causal chain between Ukrainian strikes and European risk requires sharper evidence than this reporting provides. Senior leaders must recognize that energy asymmetry warfare—targeting adversary revenue streams rather than military assets—is now a normalized conflict tactic with cascading implications for energy markets, corporate supply-chain exposure, and NATO alliance cohesion.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (593, 'Trump Says Iran Agrees to Unlimited Suspension of Nuclear Program', 'https://www.bloomberg.com/news/videos/2026-04-17/trump-says-iran-agrees-to-suspend-nuclear-program-video', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 9.7, '{Geopolitics,"Policy & Regulation"}', 'Trump announces Iran has agreed to indefinite nuclear program suspension without compensation—a significant geopolitical claim requiring verification and reshaping US-Iran relations and global nonproliferation strategy.', '2026-04-17 16:55:07+00', '2026-04-17 18:54:05.406252+00', 'President Donald Trump said in a phone interview on Friday that Iran agreed to suspend its nuclear program indefinitely and will not receive any frozen funds from the US in exchange for the move. Tyler Kendall reports on Bloomberg Television. (Source: Bloomberg)', 'selected', '{"Strategic Foresight","Civic Stewardship"}', NULL, NULL, 'news', true, true, 8.5, 'RGI partially agrees: Trump''s claim requires immediate independent verification through IAEA inspection protocols and multilateral diplomatic channels—Bloomberg reports the statement but does not yet confirm Iran''s formal acceptance or technical implementation details. Senior leaders must treat this as a negotiating position, not a settled accord, and prepare contingency strategies for both verified compliance and potential reversal.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (618, 'UK and France to lead defensive mission in Strait of Hormuz', 'https://www.bbc.com/news/articles/c5yjz819vmgo?at_medium=RSS&at_campaign=rss', 'BBC News', 'http://feeds.bbci.co.uk/news/rss.xml', 8.7, '{Geopolitics,"Supply Chains & Trade"}', 'UK and France announce joint defensive mission in Strait of Hormuz; signals European reassertion of security role in critical chokepoint affecting ~30% of global oil transit.', '2026-04-17 18:27:55+00', '2026-04-17 18:54:05.526573+00', 'Sir Keir Starmer has said further details of the plan will come after a meeting in London next week.', 'selected', '{"Strategic Foresight","Civic Stewardship"}', NULL, NULL, 'news', true, true, 9.5, 'RGI partially agrees: the article correctly identifies a significant geopolitical development affecting global energy security and trade routes, but lacks strategic depth on how this mission reshapes U.S.-Europe defense burden-sharing or impacts energy markets long-term. Senior leaders must recalibrate supply chain resilience and geopolitical risk premiums for Middle East operations immediately, as European military commitment signals potential shift in global security architecture.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (706, 'What Bob Weir Taught Me About Leadership and Legacy', 'https://www.inc.com/bob-spoerl/what-bob-weir-taught-me-about-leadership-and-legacy/91332714', 'Inc. Magazine', 'https://www.inc.com/rss', 5, '{}', 'What Bob Weir Taught Me About Leadership and Legacy', '2026-04-17 20:02:59+00', '2026-04-18 02:02:06.573922+00', 'Lately it occurs to me, what a long, strange trip it’s been.', 'pending', 'Multiple', 'Bob Spoerl', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (621, 'Iran foreign minister: strait of Hormuz now ‘completely open’ to commercial vessels', 'https://www.theguardian.com/world/2026/apr/17/strait-of-hormuz-now-open-to-commercial-vessels', 'The Guardian', 'https://www.theguardian.com/world/rss', 8.7, '{Geopolitics,"Energy & Oil","Supply Chains & Trade"}', 'Iran''s foreign minister claims the Strait of Hormuz is now fully open to commercial traffic; Trump claims Iran agreed to suspend nuclear development. Oil prices fell on the announcement, but analysts caution against premature assumptions of stable passage through this critical chokepoint.', '2026-04-17 17:54:14+00', '2026-04-17 18:54:05.539128+00', 'Meanwhile, as new 10-day truce in Lebanon enters its first full day, Trump claims Iran has agreed to suspend its nuclear programme Iran’s foreign minister has said that the strait of Hormuz is now fully open to commercial vessels, reinforcing hopes for an eventual end to the war in the Middle East and sending oil prices tumbling despite analysts’ warnings that there will be no immediate widespread resumption of passage through the vital waterway. In a barrage of social media posts, Donald Trump claimed on Friday that Iran had agreed never to close the strategic waterway again, hailing “A GREAT AND BRILLIANT DAY FOR THE WORLD!” Continue reading...', 'selected', '{"Strategic Foresight","Civic Stewardship"}', 'Jason Burke and William Christou in Beirut', NULL, 'news', true, true, 7.5, 'RGI partially agrees: The Strait of Hormuz reopening signals potential de-escalation in Middle East tensions, but the claim requires verification against Iran''s historical patterns and Trump''s track record on nuclear negotiations. Senior leaders must immediately stress-test supply chain resilience and energy hedging strategies, as geopolitical ceasefire claims have collapsed rapidly in this region before.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (633, 'Trump Frames Iran War as All but Over in Optimistic Social Media Flurry', 'https://www.nytimes.com/2026/04/17/world/middleeast/trump-iran-war-truth-social-posts.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 6.5, '{Geopolitics,"Wars & Crisis"}', 'Trump uses social media to declare Iran conflict ''all but over,'' but Iranian officials dispute claims. Unconfirmed rhetoric carries material weight for business continuity planning and regional risk assessment.', '2026-04-17 23:11:04+00', '2026-04-18 02:02:06.03797+00', 'Iranian officials did not confirm most of Mr. Trump’s claims and disputed several of them.', 'pending', '{"Strategic Foresight","Civic Stewardship"}', 'Ashley Ahn', NULL, 'news', false, true, 8.5, 'RGI partially agrees: Trump''s rhetorical positioning on Iran reflects real geopolitical signaling that affects business confidence and regional stability calculations, but the article''s reliance on unconfirmed claims limits strategic clarity. Senior leaders must treat executive geopolitical rhetoric as a market and security signal regardless of factual verification—it shapes investor behavior, supply chain risk assessment, and institutional decision-making in real time.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (634, 'Prosecutor Withdraws From Trump Team’s Investigation of Ex-CIA Director John O. Brennan', 'https://www.nytimes.com/2026/04/17/us/justice-dept-trump-investigation-cia-brennan.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 5, '{}', 'Prosecutor Withdraws From Trump Team’s Investigation of Ex-CIA Director John O. Brennan', '2026-04-17 20:55:56+00', '2026-04-18 02:02:06.275212+00', 'A career Justice Department lawyer, Maria Medetis Long, in Miami is said to have raised concerns about whether the evidence justified moving forward with a bid to prosecute John O. Brennan.', 'pending', 'Multiple', 'Charlie Savage, Alan Feuer and Glenn Thrush', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (635, 'Federal Appeals Court Opens Door to Moving Trans Inmates Under Trump Gender Order', 'https://www.nytimes.com/2026/04/17/us/politics/transgender-prisoners-appeals-court.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 4.5, '{"Policy & Regulation"}', 'Federal appeals court ruling on transgender inmate transfers under Trump administration policy; affects 17 individuals in correctional system.', '2026-04-17 20:22:14+00', '2026-04-18 02:02:06.278449+00', 'A three-judge panel gave a group of 17 transgender women a few weeks to seek further recourse in court before their transfer to men’s facilities could take effect.', 'pending', 'Civic Stewardship (marginally) — relates to institutional policy and governance, but lacks systemic or market-level implications for organizational leaders.', 'Mattathias Schwartz', NULL, 'news', false, false, 8.5, 'RGI notes this item falls outside the core strategic lens — limited implications for senior leadership.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (636, 'DHS Expands Deportation Fleet With High-End Jets', 'https://www.nytimes.com/2026/04/17/us/politics/homeland-security-gulfstream.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 4.5, '{"Policy & Regulation"}', 'DHS acquires five additional aircraft (including two Gulfstream jets) to double its deportation fleet capacity, based on contract documents and interviews.', '2026-04-17 22:46:05+00', '2026-04-18 02:02:06.280748+00', 'The contract for five planes doubles the Department of Homeland Security’s fleet of jets to expel immigrants, and includes two Gulfstream planes, according to documents and interviews.', 'pending', 'Civic Stewardship (marginal) — touches immigration enforcement policy but lacks systemic leadership, organizational, or institutional implications for the RGI audience.', 'Madeleine Ngo', NULL, 'news', false, false, 9.5, 'RGI notes this item falls outside the core strategic lens — limited implications for senior leadership.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (639, 'Cerebras, an A.I. Chip Maker, Files to Go Public as Tech Offerings Ramp Up', 'https://www.nytimes.com/2026/04/17/technology/cerebras-public-offering-ai.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 5.5, '{"AI & Artificial Intelligence","Finance & Markets"}', 'Cerebras, a specialized AI chip maker, filed for IPO alongside SpaceX, Anthropic, and OpenAI, signaling a wave of tech public offerings and potential investor appetite for AI infrastructure plays.', '2026-04-17 22:03:45+00', '2026-04-18 02:02:06.289436+00', 'The Silicon Valley chip maker filed a prospectus just as SpaceX, Anthropic and OpenAI prepared for their own listings, in what is shaping up to be a wave of enormous initial public offerings.', 'pending', 'Strategic Foresight (AI acceleration, capital concentration in compute layer); Finance & Markets (capital reallocation signals)', 'Cade Metz', NULL, 'news', false, false, 9.5, 'RGI partially agrees: Cerebras''s IPO filing signals genuine AI infrastructure consolidation and capital reallocation toward compute-layer companies, but the article conflates market timing with strategic significance—IPO waves are cyclical, not necessarily indicative of AI''s real competitive inflection. Senior leaders must distinguish between liquidity events and actual shifts in AI competitive advantage; the real question is whether Cerebras''s chip architecture materially displaces incumbent GPU/AI infrastructure, not whether it goes public.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (640, 'Japan’s Cherry Blossom Database, 1,200 Years Old, Has a New Keeper', 'https://www.nytimes.com/2026/04/17/climate/japan-cherry-blossom-database-scientist.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 4.5, '{"Climate & Environmental Health"}', 'NYT reports on Japan''s 1,200-year cherry blossom phenological dataset, a climate proxy record, and the succession challenge for its steward. While scientifically significant as a long-term climate indicator, the article is primarily a human-interest/institutional succession story without systemic implications for corporate or civic leadership.', '2026-04-17 20:55:27+00', '2026-04-18 02:02:06.292391+00', 'The remarkable catalog of dates is one of the longest-running records of climate change. Its creator died, setting off a search for a successor.', 'pending', 'Marginal relevance to Strategic Foresight (climate signals), but presented as local institutional narrative rather than actionable geopolitical or market signal.', 'Hiroko Tabuchi', NULL, 'news', false, false, 9.5, 'RGI notes this item falls outside the core strategic lens — limited implications for senior leadership.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (641, 'Western States Need Water. San Diego Has Extra. Will They Make A Deal?', 'https://www.nytimes.com/2026/04/17/climate/how-pacific-ocean-water-could-help-the-colorado-river-crisis.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 5.5, '{"Climate & Environmental Health","Supply Chains & Trade"}', 'San Diego County is marketing desalinated seawater to drought-stressed Western states, testing whether bilateral water deals can ease regional scarcity amid structural supply shortfalls.', '2026-04-17 22:05:15+00', '2026-04-18 02:02:06.295373+00', 'San Diego County is shopping a surplus of desalinated seawater to Western states that are facing increasingly urgent drought and short supplies.', 'pending', 'Civic Stewardship (water as shared resource governance); Strategic Foresight (climate-driven resource scarcity signals)', 'Scott Dance', NULL, 'news', false, false, 8.5, 'RGI partially agrees: San Diego''s desalination surplus represents a localized supply solution, but the article lacks strategic analysis of whether market-based water trading can systematically address the West''s structural water deficit driven by climate, agriculture, and policy failure. Senior leaders should recognize that voluntary surplus-sharing between states masks the absence of regional water governance architecture—a critical vulnerability as drought intensifies.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (642, 'Starmer’s Credibility Just Took Another Body Blow Over the Mandelson Scandal', 'https://www.nytimes.com/2026/04/17/world/europe/starmer-credibility-mandelson-epstein-scandal.html', 'New York Times', 'https://rss.nytimes.com/services/xml/rss/nyt/HomePage.xml', 4.5, '{"Global Politics"}', 'UK PM Keir Starmer faces credibility damage over lack of awareness regarding Peter Mandelson''s appointment and Epstein connections, raising questions about his control over government operations.', '2026-04-17 18:41:34+00', '2026-04-18 02:02:06.298311+00', 'Prime Minister Keir Starmer appears to have been kept in the dark repeatedly over Peter Mandelson, the Jeffrey Epstein associate — fueling an image of weakness.', 'pending', 'Tangential to System Vitality (leadership credibility erosion), but primarily a domestic political personality narrative rather than systemic governance signal.', 'Michael D. Shear', NULL, 'news', false, false, 8.5, 'RGI notes this item falls outside the core strategic lens — limited implications for senior leadership.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (643, 'Australian Minister Says Fuel Reserves Up, More Shipments on Way', 'https://www.bloomberg.com/news/articles/2026-04-18/australian-minister-says-fuel-reserves-up-more-shipments-on-way', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 4.5, '{"Energy & Oil"}', 'Australian Energy Minister Chris Bowen reports fuel reserves increased and additional shipments are arriving, addressing short-term supply concerns in an import-dependent market.', '2026-04-18 01:20:53+00', '2026-04-18 02:02:06.301231+00', 'Australia’s fuel reserves rose in the past week and more is on the way, Energy Minister Chris Bowen said, easing concern of shortages in the import-reliant country.', 'pending', 'None — routine commodity/supply update without systemic market implications or leadership relevance.', 'Peter Vercoe', NULL, 'news', false, false, 8.5, 'RGI notes this item falls outside the core strategic lens — limited implications for senior leadership.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (644, 'Fermi Shares Plunge After Announcing Departure of CEO', 'https://www.bloomberg.com/news/articles/2026-04-18/fermi-shares-plunge-after-announcing-departure-of-ceo', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 4.5, '{"AI & Artificial Intelligence"}', 'CEO departure at Fermi, a developer of a major AI campus project in Texas, triggered a 31% stock decline. While the company operates in the strategically important AI infrastructure space, the event is primarily a single-firm governance incident rather than a systemic market shift or leadership breakthrough with broad implications.', '2026-04-18 00:14:32+00', '2026-04-18 02:02:06.303503+00', 'Fermi shares fell as much as 31% in post-market trading after the developer behind a massive planned AI campus in Texas announced the immediate departure of co-founder and Chief Executive Officer Toby Neugebauer.', 'pending', 'Marginal to System Vitality (leadership continuity at single firm); minimal relevance to Strategic Foresight or Civic Stewardship.', 'Mark Chediak', NULL, 'news', false, false, 8.5, 'RGI notes this item falls outside the core strategic lens — limited implications for senior leadership.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (646, 'Geothermal Power Firm Fervo Energy Files for IPO', 'https://www.bloomberg.com/news/articles/2026-04-17/geothermal-power-firm-fervo-files-for-initial-public-offering', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 5.5, '{"Climate & Environmental Health","Finance & Markets"}', 'Advanced geothermal startup Fervo Energy files for IPO while disclosing operating losses ahead of Utah project launch, signaling investor appetite for next-generation baseload clean power.', '2026-04-17 22:09:27+00', '2026-04-18 02:02:06.309433+00', 'Fervo Energy Co. filed for an initial public offering, disclosing wider losses as it plans to start generating power from its first geothermal project in Utah later this year.', 'pending', 'System Vitality (organizational capital formation); Strategic Foresight (energy transition weak signal); Civic Stewardship (decarbonization pathway)', 'Anthony Hughes', NULL, 'news', false, false, 9.5, 'RGI partially agrees: Fervo''s IPO filing signals genuine market validation for advanced geothermal as a baseload decarbonization technology, but a single company''s capital raise—even with losses disclosed—does not constitute a systemic energy transition inflection point. Senior leaders should monitor whether Fervo''s Utah project achieves commercial power generation and grid stability at scale; if successful, it reshapes long-term energy infrastructure investment and climate risk modeling for capital-intensive sectors.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (647, 'Blue Owl Co-CEOs’ Personal Loans No Longer Backed by Firm Shares', 'https://www.bloomberg.com/news/articles/2026-04-17/blue-owl-co-ceos-personal-loans-no-longer-backed-by-firm-shares', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 5, '{}', 'Blue Owl Co-CEOs’ Personal Loans No Longer Backed by Firm Shares', '2026-04-17 22:21:32+00', '2026-04-18 02:02:06.312399+00', 'Blue Owl Capital Inc. Co-Chief Executive Officers Doug Ostrover and Marc Lipschultz have revised the terms of personal loans to remove the company’s shares as collateral, after turmoil in the private credit market hammered the stock’s value in recent months.', 'pending', 'Multiple', 'Davide Scigliuzzo', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (648, 'Rosner on Credit Markets Amid Geopolitical Tension', 'https://www.bloomberg.com/news/videos/2026-04-17/rosner-on-credit-markets-amid-geopolitical-tension-video', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 6.5, '{"Finance & Markets",Geopolitics}', 'Goldman Sachs MSFI head discusses credit market resilience and yield attractiveness despite geopolitical headwinds, signaling tight spreads may mask underlying volatility risk.', '2026-04-17 22:01:40+00', '2026-04-18 02:02:06.314896+00', 'Lindsay Rosner, Head of Multi Sector Fixed Income at Goldman Sachs Asset Management, discuss the current state of credit markets amid geopolitical tensions and private credit challenges. Rosner highlights that while credit spreads remain tight, the all-in yield remains attractive to investors. She speaks with Katie Greifeld on “Real Yield.” (Source: Bloomberg)', 'pending', '{"Strategic Foresight"}', NULL, NULL, 'news', false, true, 8.5, 'RGI partially agrees: Rosner correctly identifies credit spread compression as a market signal, but the analysis lacks systemic depth on how geopolitical volatility reshapes capital allocation and institutional risk frameworks—which are core leadership concerns. Senior leaders must recognize that tight spreads amid geopolitical tension signal potential mispricing of tail risk and should stress-test portfolio and funding assumptions accordingly.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (651, 'Biotech Odyssey, Medical Device Firm Mobia File for US IPOs', 'https://www.bloomberg.com/news/articles/2026-04-17/autoimmune-inflammatory-focused-biotech-odyssey-files-for-ipo', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 4.5, '{"Finance & Markets"}', 'Two biotech/medical device firms (Odyssey, Mobia) file for US IPOs amid renewed investor appetite for healthcare stocks. Standard capital markets activity with no systemic signal.', '2026-04-17 20:52:04+00', '2026-04-18 02:02:06.322681+00', 'Healthcare companies are lining up to go public with a drug developer and medical device company joining a pool of peers seeking to advance public listing plans amid robust investor demand for biotech stocks.', 'pending', 'None — this is routine market activity without strategic foresight, system vitality, or civic stewardship implications.', 'Bailey Lipschultz, Anthony Hughes', NULL, 'news', false, false, 8.5, 'RGI notes this item falls outside the core strategic lens — limited implications for senior leadership.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (652, 'Live Nation Inks $742 Million of Private Debt Tied to Venues', 'https://www.bloomberg.com/news/articles/2026-04-17/live-nation-inks-742-million-of-private-debt-tied-to-venues', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 5, '{}', 'Live Nation Inks $742 Million of Private Debt Tied to Venues', '2026-04-17 21:28:14+00', '2026-04-18 02:02:06.32477+00', 'Live Nation Entertainment Inc. has borrowed about €630 million ($742 million) in the private debt market to help finance its global investment in concert venues, people with knowledge of the matter said.', 'pending', 'Multiple', 'Emily Graffeo, Silas Brown', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (653, 'IMF, World Bank Navigate Economic Fallout From Iran War', 'https://www.bloomberg.com/news/videos/2026-04-17/imf-world-bank-navigate-economic-fallout-from-iran-war-video', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 6.5, '{Geopolitics,Macroeconomics}', 'IMF and World Bank convene amid concerns that Iran conflict could trigger a new economic downturn; Bloomberg Economics hosts discuss geopolitical risk to global financial stability.', '2026-04-17 21:08:53+00', '2026-04-18 02:02:06.326948+00', 'With the world facing a potential new economic crisis, the mood at this week’s IMF-World Bank meetings is decidedly dour. Bloomberg Economics’ Stephanie Flanders and Shawn Donnan join David Gura to discuss on the Big Take podcast. (Source: Bloomberg)', 'pending', '{"Strategic Foresight","Civic Stewardship"}', NULL, NULL, 'news', false, false, 8.5, 'RGI partially agrees: the article correctly identifies geopolitical volatility as an economic risk factor, but lacks substantive analysis of specific transmission mechanisms, policy responses, or strategic implications for institutional leadership. Senior leaders must immediately model Iran conflict scenarios across energy markets, supply chains, and capital allocation — not treat this as ambient economic uncertainty.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (654, 'AI Chipmaker Cerebras Systems Files Publicly for US IPO', 'https://www.bloomberg.com/news/articles/2026-04-17/ai-chipmaker-cerebras-systems-files-publicly-again-for-us-ipo', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 6.5, '{"AI & Artificial Intelligence","Finance & Markets"}', 'Cerebras Systems, a developer of large-scale AI chips and data center systems, has filed for a US IPO after a previous withdrawal, signaling market appetite for specialized AI infrastructure beyond traditional GPU makers.', '2026-04-17 20:33:11+00', '2026-04-18 02:02:06.329794+00', 'Cerebras Systems Inc., an artificial intelligence chipmaker and data center operator, filed publicly for an initial public offering months after withdrawing a previous attempt to list.', 'pending', 'Strategic Foresight', 'Carmen Reinicke', NULL, 'news', false, false, 8.5, 'RGI partially agrees: Cerebras''s IPO filing signals continued institutional confidence in specialized AI infrastructure, but the company remains pre-profitability with unproven commercial scale—making this a market validation signal rather than proof of transformative business model. Senior leaders should recognize that AI infrastructure competition is shifting from compute generalists (NVIDIA) toward specialized wafer and data center providers, requiring portfolio reassessment of enterprise AI cost structures.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (655, 'NYC’s Second-Home Tax Unites Mamdani, Hochul', 'https://www.bloomberg.com/news/videos/2026-04-17/nyc-s-second-home-tax-unites-mamdani-hochul-video', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 5, '{}', 'NYC’s Second-Home Tax Unites Mamdani, Hochul', '2026-04-17 20:09:57+00', '2026-04-18 02:02:06.332695+00', 'Bloomberg''s Nacha Cattan joins Katie Greifeld on "Bloomberg Real Yield." Governor Kathy Hochul and New York City Mayor Zohran Mamdani have finally found a tax that they agree on. Getting everyone else on board stands to be more complicated. Mamdani has been an eager proponent of taxing wealthier New Yorkers to close a projected $5.4 billion two-year gap in the city’s budget and to fund a slew of social programs. (Source: Bloomberg)', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (656, 'Belgium Gets Cut by Moody’s in Reproof at Failure to Cut Debt', 'https://www.bloomberg.com/news/articles/2026-04-17/belgium-gets-cut-by-moody-s-in-reproof-at-failure-to-cut-debt', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 6.5, '{Macroeconomics,"Policy & Regulation"}', 'Moody''s downgraded Belgium''s sovereign debt rating, citing persistent high budget deficits and slow fiscal consolidation. The move underscores widening eurozone fiscal stress.', '2026-04-17 20:47:35+00', '2026-04-18 02:02:06.335999+00', 'Belgium was lowered one step by Moody’s, underscoring how the struggle to cut one of the biggest budget deficits in Europe is besmirching the country’s status as a borrower.', 'pending', 'System Vitality (institutional credibility); Civic Stewardship (fiscal legitimacy)', 'Max Ramsay', NULL, 'news', false, true, 9.5, 'RGI partially agrees: Moody''s downgrade reflects genuine structural fiscal risk, but the article treats a rating action as primary news rather than a lagging indicator of systemic imbalance already priced into markets. Senior leaders should monitor whether eurozone debt-servicing cascades accelerate if fiscal consolidation across major EU economies stalls—this signals broader questions about currency union sustainability and cross-border capital flows.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (659, 'Private Credit Dispersion Creates Opportunity: Cocke', 'https://www.bloomberg.com/news/videos/2026-04-17/private-credit-dispersion-creates-opportunity-cocke-video', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 6.5, '{"Finance & Markets","Strategic Foresight"}', 'Private credit managers face redemption surge driven by loan quality concerns and borrower exposure to AI disruption. Market dislocation signals systemic stress in alternative asset valuations.', '2026-04-17 20:32:53+00', '2026-04-18 02:02:06.343538+00', 'John Cocke, deputy CIO for credit at Corbin Capital Partners, joins Katie Greifeld on "Bloomberg Real Yield." Private credit funds run by some of the biggest managers are contending with a surge in redemption requests amid concerns about loan quality and exposure to borrowers vulnerable to AI disruption. (Source: Bloomberg)', 'pending', 'System Vitality (institutional resilience of alternative finance); Strategic Foresight (weak signal of AI''s impact on non-tech-native businesses; market stress cascades)', NULL, NULL, 'news', false, false, 8.5, 'RGI partially agrees: the article correctly identifies a systemic stress point in private credit markets (redemption pressure + AI-driven borrower vulnerability), but frames this as opportunity rather than interrogating the deeper institutional resilience question. Senior leaders must recognize that private credit redemption waves signal broader confidence erosion in opaque asset classes—a material governance and fiduciary risk.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (660, 'Wall Street Rushes to Price Out War Damage as Stocks Hit Records', 'https://www.bloomberg.com/news/articles/2026-04-17/wall-street-rushes-to-price-out-war-damage-as-stocks-hit-records', 'Bloomberg', 'https://feeds.bloomberg.com/markets/news.rss', 6.5, '{Geopolitics,"Finance & Markets"}', 'Wall Street is pricing in a swift resolution to US-Iran tensions based on recent market moves, driving equities to records and oil lower. However, the article lacks clarity on what specific developments triggered this repricing or whether fundamental tensions have actually shifted.', '2026-04-17 20:22:48+00', '2026-04-18 02:02:06.345807+00', 'Traders spent this week betting that the US conflict with Iran is all but over &mdash; driving stocks to records, dumping the dollar and pushing oil to around $90 a barrel.', 'pending', 'Strategic Foresight (weak signal detection on trader positioning); Civic Stewardship (geopolitical stability affects business legitimacy)', 'Ruth Carson, Winnie Hsu, Alice Atkins', NULL, 'news', false, false, 8.5, 'RGI partially agrees: market repricing around geopolitical de-escalation is a legitimate signal, but this article conflates trader sentiment with actual strategic resolution—Iran tensions remain structurally unresolved. Senior leaders must distinguish between market momentum and underlying geopolitical risk; positioning for peace without hedging for renewed escalation is a classic capital allocation error.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (668, 'AI needs a reality check', 'https://www.fastcompany.com/91529003/ai-needs-a-reality-check', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 6.2, '{"AI & Artificial Intelligence","Policy & Regulation"}', 'Fast Company opinion piece argues that most AI healthcare companies make bold claims without delivering approved treatments or diagnostics, and calls for industry to close the gap between model training and clinical validation—using examples from Isomorphic, Lila, Anthropic, Recursion, and the author''s own company Owkin.', '2026-04-17 18:46:00+00', '2026-04-18 02:02:06.482211+00', 'AI companies love to make bold claims about healthcare. Alphabet’s Isomorphic tells us that “frontier AI can unlock deeper scientific insights, faster breakthroughs, and life-changing medicines.” Lila confidently markets its AI as a tool for &#8220;faster discovery for every field where breakthrough science matters.&#8221; And they’re spending as though they believe the hype. Anthropic recently acquired stealth startup Coefficient Bio for $400 million. But there&#8217;s only one true test of any healthcare AI: Did it work in humans? Did it create a medicine that saved someone&#8217;s life? And bluntly, most companies have not achieved that. Let’s look at the number of treatments brought to market. Isomorphic? None. Lila? The same. Marketing claims in AI rarely survive contact with reality. That&#8217;s because making real progress in healthcare is hard. To test a new treatment, you need to take it through a Phase 3 clinical trial. That&#8217;s typically 10 years and $2 billion. To test a diagnostic, you need to demonstrate clinical benefit, pass a rigorous third-party test, and build a full quality management system—before your product is even permitted into the clinic. To uncover and prove new human biology? That could take decades of scientific experimentation. CLOSE THE GAP So what do we need to do? The industry needs to close the gap between where AI models are trained and where medicine actually happens. That hard graft is what the best AI companies in the field are doing. Companies like Insilico Medicine and Recursion are advancing AI-discovered assets through clinical trials. At Owkin, we&#8217;ve taken OKN4395, our oncology drug, into the Phase 1a clinical INVOKE trial. Beyond that, we&#8217;ve trained our AI on real patient data for years and brought MSIntuit CRC through Europe’s CE mark into pathology practice. This is hard work, but bringing your AI to patients has a big upside: It forces your AI to be better. From our experience, we&#8217;ve had to tackle unexpected, knotty problems. When we were first bringing diagnostic AI to the clinic, we realized that the models wouldn&#8217;t generalize well across population changes or scanner setups. We had to develop simple but robust methods to adapt our models to the vagaries of individual locations and technologies. IMPROVE THE FEEDBACK LOOP IN REAL TIME We think that this “reality check”—testing our models’ results with real patients—is so important, that we’ve built it into the structure of our INVOKE trial. In a traditional trial, the design looks only at the essential indicators of trial success and the interim results would decide whether the trial progresses. That’s it. But unlike a traditional trial, we&#8217;re using ongoing data from our patient participants to improve our AI. Where our AI&#8217;s predictions about patients’ responses have missed the mark, we have retrained it on the real data to improve its performance. It&#8217;s a positive feedback loop: The more information we', 'pending', 'Strategic Foresight (weak signal on AI hype cycles and capital allocation inefficiency) + System Vitality (organizational integrity and credibility risk for AI firms making unvalidated claims)', 'Thomas Clozel', NULL, 'news', false, false, 7.2, 'RGI partially agrees: the article correctly identifies that AI healthcare claims often outpace clinical validation, a critical reality check for leaders investing in or evaluating AI-driven biotech—but conflates marketing hype with genuine technological limitation rather than acknowledging that some frontier AI approaches may ultimately deliver despite current gap. Leaders must distinguish between companies gaming narratives and those genuinely advancing assets through clinical rigor; the former deserves skepticism, the latter deserves capital and patience.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (669, 'Oil prices tank and stocks climb after Iran reopens the Strait of Hormuz', 'https://www.fastcompany.com/91528952/oil-prices-tank-and-stocks-climb-after-iran-reopens-the-strait-of-hormuz', 'Fast Company', 'https://www.fastcompany.com/latest/rss', 7.2, '{Geopolitics,"Finance & Markets","Energy & Oil"}', 'Iran reopens Strait of Hormuz for commercial shipping amid ceasefire signals; oil prices drop 10-12%, U.S. stocks surge 1.5-2.3%. Market rally reflects reduced geopolitical risk premium, but sustainability remains uncertain pending formal war resolution.', '2026-04-17 18:26:52+00', '2026-04-18 02:02:06.484365+00', 'Oil prices dropped more than 10% Friday, and U.S. stocks raced toward&nbsp; another record &nbsp;after&nbsp; Iran said the Strait of Hormuz is open &nbsp;again for commercial tankers carrying oil from the Persian Gulf to customers worldwide. The S&P 500 leaped 1.5% as Wall Street rallied to the finish of a third straight week of big gains, its longest streak since Halloween. A freer flow of oil would take pressure off prices not only for gasoline but also&nbsp; for groceries and all kinds of other products &nbsp;that get moved by vehicles. It could even ultimately help people pay less on credit-card interest or mortgage bills. The Dow Jones Industrial Average climbed 1,130 points, or 2.3%, as of 12:52 p.m. Eastern time, while the Nasdaq composite was 1.7% higher The U.S. stock market has jumped more than 12% since hitting&nbsp; a bottom in late March &nbsp;on hopes the United States and Iran can avoid a worst-case scenario for the global economy despite&nbsp; their war . Friday’s reopening of the&nbsp; Strait of Hormuz , which may only be temporary, is the clearest signal yet for optimism, and&nbsp; President Donald Trump &nbsp;said late Thursday that the war “should be ending pretty soon.” The price for a barrel of benchmark U.S. crude plunged immediately after Iran’s foreign minister, Abbas Araghchi, posted on X that the passage for all commercial vessels through the strait “is declared completely open” as a ceasefire appears to be holding in Lebanon. He said it would stay open for the remaining period of the ceasefire, and U.S. oil tumbled 12.2% to $83.18 per barrel. Brent crude, the international standard, dropped 10.4% to $89.01 per barrel. To be sure, it remains above its $70 price from before the war, indicating some caution is still embedded in financial markets. Several times since the war began,&nbsp; optimism &nbsp;on Wall Street has&nbsp; quickly swung &nbsp;to doubt about a possible end to the fighting. That in turn has caused vicious and sudden swings of prices for everything from stocks to bonds to oil. Minutes after the Iranian foreign minister’s announcement of the reopening of the Strait of Hormuz, Trump said on his social media network that the&nbsp; U.S. Navy’s blockade of Iranian ports &nbsp;remains “in full force” until both sides reach a deal on the war. He, though, also said that “should go very quickly in that most of the points are already negotiated” and emphasized it by using all capital letters. Companies with big fuel bills soared to some of Wall Street’s biggest gains following the easing of oil prices. United Airlines surged 9.2%. On Thursday, the head of the International Energy Agency had said that&nbsp; Europe has “maybe six weeks or so” of remaining jet fuel supplies . Operators of cruise ships, which guzzle fuel, also steamed higher. Norwegian Cruise Line jumped 8.1%, and Royal Caribbean Group gained 10.3%. Housing and auto-related companies also got some relief from the drop in oil prices. With less threat of', 'pending', 'Strategic Foresight (geopolitical volatility, weak signals of escalation/de-escalation); System Vitality (organizational supply chain exposure, energy cost inflation pressures on operations)', 'Associated Press', NULL, 'news', false, true, 7.2, 'RGI partially agrees: the Strait of Hormuz reopening signals genuine geopolitical de-escalation with material market consequences, but the article conflates temporary tactical moves with strategic resolution—Iran''s announcement may be posturing rather than durable policy shift. Senior leaders must treat commodity price volatility as a risk management signal, not a ceasefire confirmation, and stress-test supply chain resilience against rapid reversal.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (670, 'OpenAI Executive Kevin Weil Is Leaving the Company', 'https://www.wired.com/story/openai-executive-kevin-weil-is-leaving-the-company/', 'Wired', 'https://www.wired.com/feed/rss', 5, '{}', 'OpenAI Executive Kevin Weil Is Leaving the Company', '2026-04-17 19:56:42+00', '2026-04-18 02:02:06.486892+00', 'The former Instagram VP is departing the ChatGPT-maker, which is folding the AI science application he led into Codex.', 'pending', 'Multiple', 'Maxwell Zeff', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (671, 'Sam Altman’s project World looks to scale its human verification empire. First stop: Tinder.', 'https://techcrunch.com/2026/04/17/sam-altmans-project-world-looks-to-scale-its-human-verification-empire-first-stop-tinder/', 'TechCrunch', 'https://techcrunch.com/feed/', 5, '{}', 'Sam Altman’s project World looks to scale its human verification empire. First stop: Tinder.', '2026-04-17 22:34:02+00', '2026-04-18 02:02:06.489346+00', 'World, which has raised eyebrows (but also a lot of interest) with its Orb-centered anonymous verification project, is looking to expand its influence via a bevy of new partnerships.', 'pending', 'Multiple', 'Lucas Ropek', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (673, 'Sources: Cursor in talks to raise $2B+ at $50B valuation as enterprise growth surges', 'https://techcrunch.com/2026/04/17/sources-cursor-in-talks-to-raise-2b-at-50b-valuation-as-enterprise-growth-surges/', 'TechCrunch', 'https://techcrunch.com/feed/', 4.5, '{"Technology & Digital Innovation"}', 'AI coding platform Cursor reportedly in fundraising discussions at $50B valuation, led by a16z and Thrive Capital, citing enterprise adoption growth.', '2026-04-17 19:17:26+00', '2026-04-18 02:02:06.494469+00', 'Returning backers a16z and Thrive are expected to lead the round.', 'pending', 'Weak alignment. While AI acceleration is a core RGI discipline, this is a single company fundraising announcement without systemic market signal, governance implication, or leadership operational impact.', 'Marina Temkin', NULL, 'news', false, false, 6.5, 'RGI notes this item falls outside the core strategic lens — limited implications for senior leadership.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (674, 'OpenAI’s former Sora boss is leaving', 'https://www.theverge.com/ai-artificial-intelligence/914463/openai-sora-bill-peebles-kevin-weil-leaving-departing', 'The Verge', 'https://www.theverge.com/rss/index.xml', 5, '{}', 'OpenAI’s former Sora boss is leaving', '2026-04-17 21:13:25+00', '2026-04-18 02:02:06.49683+00', 'Last month, OpenAI gave up on its Sora video generation tool, and on Friday, the Sora team''s leader, Bill Peebles, announced that he is leaving the company. OpenAI has been shifting its priorities as part of an effort to avoid "side quests," and Peebles'' departure is just one of many recent changes as the company [&#8230;]', 'pending', 'Multiple', 'Jay Peters', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (675, 'Anthropic’s new cybersecurity model could get it back in the government’s good graces', 'https://www.theverge.com/ai-artificial-intelligence/914229/tides-turning-anthropic-trump-administration-cybersecurity-mythos-preview', 'The Verge', 'https://www.theverge.com/rss/index.xml', 5.2, '{"AI & Artificial Intelligence",Geopolitics,"Policy & Regulation"}', 'Anthropic launches Claude Mythos Preview, a cybersecurity-focused AI model, amid extended tensions with Trump administration over the company''s perceived political alignment. The move signals vendor repositioning in response to geopolitical and regulatory pressure on AI firms.', '2026-04-17 20:14:21+00', '2026-04-18 02:02:06.499266+00', 'The Trump administration has spent nearly two months fighting with AI company Anthropic. It''s dubbed the company a "RADICAL LEFT, WOKE COMPANY" full of "Leftwing nut jobs" and a menace to national security. But some of the ice may reportedly be melting between the two, thanks to Anthropic''s buzzy new cybersecurity-focused model: Claude Mythos Preview. [&#8230;]', 'pending', 'Strategic Foresight (AI vendor fragmentation, geopolitical sorting of tech markets); Policy & Regulation (AI firm-government relations).', 'Hayden Field', NULL, 'news', false, false, 6.2, 'RGI partially agrees: Anthropic''s pivot toward government-relevant cybersecurity capabilities reflects genuine market-demand signaling and geopolitical pressure on AI firms, but the headline overstates the strategic significance of a single model release as a political reconciliation tool. Senior leaders should recognize that AI vendors will increasingly segment products by buyer class (defense, commercial, enterprise) and that political friction with AI firms creates market fragmentation risks for organizations dependent on multi-vendor ecosystems.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (676, 'US-sanctioned currency exchange says $15 million heist done by "unfriendly states"', 'https://arstechnica.com/security/2026/04/russia-friendly-exchange-says-western-special-service-behind-15-million-cyberattack/', 'Ars Technica', 'https://feeds.arstechnica.com/arstechnica/index', 5, '{}', 'US-sanctioned currency exchange says $15 million heist done by "unfriendly states"', '2026-04-17 21:28:35+00', '2026-04-18 02:02:06.501504+00', 'Grinex says needed hacking resources "available exclusively to ... unfriendly states."', 'pending', 'Multiple', 'Dan Goodin', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (678, 'Ukraine Has a Plan to Build Back Better', 'https://foreignpolicy.com/2026/04/17/ukraine-green-reconstruction-renewable-energy-build-back-better/', 'Foreign Policy', 'https://foreignpolicy.com/feed/', 6.5, '{Geopolitics,"Policy & Regulation"}', 'Ukraine is framing post-war reconstruction around environmental, social, and geopolitical sustainability principles—signaling how conflict-affected nations are now anchoring recovery to institutional legitimacy and long-term systemic resilience rather than pure restoration.', '2026-04-17 21:16:01+00', '2026-04-18 02:02:06.506421+00', 'The war-torn country wants to reconstruct in a way that is environmentally, socially, and geopolitically more sustainable.', 'pending', '{"Strategic Foresight","Civic Stewardship"}', 'Diana Kruzman', NULL, 'news', false, false, 7.5, 'RGI partially agrees: Ukraine''s reconstruction planning does signal systemic institutional resilience and forward-thinking governance under existential pressure, but the article''s headline oversells specificity—''a plan'' suggests concrete strategy when details appear limited to directional intent. Senior leaders should recognize that post-conflict reconstruction increasingly incorporates ESG and geopolitical positioning as legitimacy markers, not merely humanitarian objectives; this will reshape how institutional leaders approach crisis recovery and stakeholder trust in the next decade.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (679, 'Iran Says Strait of Hormuz Is ‘Completely Open’', 'https://foreignpolicy.com/2026/04/17/strait-hormuz-completely-open-iran-trump-us-blockade-oil/', 'Foreign Policy', 'https://foreignpolicy.com/feed/', 6.5, '{Geopolitics,"Supply Chains & Trade","Energy & Oil"}', 'Iran claims the Strait of Hormuz remains fully operational, but the strategic waterway''s actual accessibility remains unclear and potentially subject to Iranian conditions—signaling continued geopolitical friction over one of the world''s most critical chokepoints for global energy and trade.', '2026-04-17 20:08:57+00', '2026-04-18 02:02:06.509458+00', 'But it’s unclear whether the strategic waterway is really open without conditions.', 'pending', 'Strategic Foresight (geopolitical volatility and systemic market risk); Supply chain and energy price stability for multinational operations.', 'Alexandra Sharp', NULL, 'news', false, false, 7.5, 'RGI partially agrees: Iran''s assertion of unobstructed Strait of Hormuz access reflects strategic messaging rather than ground truth—the waterway''s operational status remains contingent on geopolitical tensions and Iranian leverage calculations. Senior leaders must treat Strait passage as a conditional asset, not a given, and model supply chain and energy price scenarios around periodic constraint risk.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (680, 'Order Without Order', 'https://foreignpolicy.com/2026/04/17/order-hierarchy-medieval-chaos-power-security/', 'Foreign Policy', 'https://foreignpolicy.com/feed/', 6.5, '{Geopolitics,"Global Politics"}', 'Foreign Policy essay arguing that the post-Cold War obsession with defining a global order obscures a messier reality of fragmented authority, decentralized power, and institutional complexity resembling medieval rather than modern systems.', '2026-04-17 19:30:20+00', '2026-04-18 02:02:06.511829+00', 'Our fixation with defining the emerging global order hides the true complexity of our neo-medieval moment.', 'pending', '{"Strategic Foresight","Civic Stewardship"}', 'Parag Khanna', NULL, 'news', false, false, 7.5, 'RGI partially agrees: the article correctly identifies fragmentation in global governance structures, but its neo-medieval framing risks obscuring the concrete power asymmetries and AI-driven state competition that will actually shape institutional behavior. Senior leaders must move beyond order-disorder binaries and build resilience strategies for operating within multipolar zones of competing authority and reduced predictability.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (681, 'The FBI Director Is MIA', 'https://www.theatlantic.com/politics/2026/04/kash-patel-fbi-director-drinking-absences/686839/?utm_source=feed', 'The Atlantic', 'https://www.theatlantic.com/feed/all/', 5, '{}', 'The FBI Director Is MIA', '2026-04-17 22:20:00+00', '2026-04-18 02:02:06.513787+00', 'Kash Patel has alarmed colleagues with episodes of excessive drinking and unexplained absences.', 'pending', 'Multiple', 'Sarah Fitzpatrick', NULL, 'news', false, false, 5, NULL);
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (684, 'Iran war live: Tehran says Trump made ‘false’ claims, amid peace talks', 'https://www.aljazeera.com/news/liveblog/2026/4/18/iran-war-live-tehran-says-president-trump-made-false-claims-amid-talks?traffic_source=rss', 'Al Jazeera English', 'https://www.aljazeera.com/xml/rss/all.xml', 6.2, '{Geopolitics,"Wars & Crisis"}', 'Iran disputes Trump statements during active Israel-Lebanon ceasefire and ongoing peace negotiations. Tens of thousands displaced by Israeli operations in Lebanon begin returning home on day one of truce.', '2026-04-18 00:00:00+00', '2026-04-18 02:02:06.521849+00', 'Tens of thousands of people forcibly displaced by Israeli attacks on Lebanon use first day of ceasefire to return home.', 'pending', 'Strategic Foresight (geopolitical volatility, regional escalation risk, long-term stability signals); Civic Stewardship (humanitarian displacement, regional legitimacy, institutional response)', NULL, NULL, 'news', false, false, 7.2, 'RGI partially agrees: The article captures real geopolitical volatility and displacement dynamics, but frames this primarily as daily news coverage rather than as a systemic signal about escalation risk, regional destabilization, or implications for global supply chains and institutional strategy. Senior leaders need the underlying *pattern* (Iran-Israel-US triangulation, ceasefire fragility, refugee/humanitarian cascade effects on neighboring economies), not the daily claim-counterclaim cycle.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (685, 'Pressure mounts on Peru’s election authorities amid presidential race delay', 'https://www.aljazeera.com/news/2026/4/17/pressure-mounts-on-perus-election-authorities-amid-presidential-race-delay?traffic_source=rss', 'Al Jazeera English', 'https://www.aljazeera.com/xml/rss/all.xml', 5, '{}', 'Pressure mounts on Peru’s election authorities amid presidential race delay', '2026-04-17 22:47:21+00', '2026-04-18 02:02:06.523579+00', 'The vote count continues to determine who will join conservative Keiko Fujimori in Peru&#039;s presidential run-off in June.', 'pending', 'Multiple', NULL, NULL, 'news', false, false, 5, NULL);
