INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (692, 'US Congress extends controversial surveillance power under FISA for 10 days', 'https://www.aljazeera.com/news/2026/4/17/us-congress-temporarily-extends-controversial-surveillance-power-under-fisa?traffic_source=rss', 'Al Jazeera English', 'https://www.aljazeera.com/xml/rss/all.xml', 6.2, '{"Policy & Regulation","Global Politics"}', 'US Congress extended contested FISA surveillance authority for 10 days, deferring resolution of warrantless data collection powers that directly implicate corporate compliance obligations, employee privacy protocols, and organizational risk exposure.', '2026-04-17 19:20:08+00', '2026-04-18 02:02:06.540033+00', 'The measure has long been criticised for allowing US intelligence agencies to collect citizen data without a warrant.', 'pending', 'System Vitality (organizational governance & compliance architecture); Civic Stewardship (legitimacy of data practices & democratic accountability)', NULL, NULL, 'news', false, false, 7.2, 'RGI partially agrees: the article correctly identifies FISA reauthorization as institutionally significant, but undersells the governance implications for corporate compliance, data stewardship, and organizational liability that senior leaders must operationalize. This 10-day extension signals continued policy instability—leaders must prepare for either legislative codification or emergency sunset within weeks, both of which reshape data governance frameworks.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (694, 'Shipping firms seek clarifications before crossing Hormuz', 'https://www.aljazeera.com/economy/2026/4/17/shipping-firms-seek-clarifications-before-crossing-hormuz?traffic_source=rss', 'Al Jazeera English', 'https://www.aljazeera.com/xml/rss/all.xml', 6.2, '{Geopolitics,"Supply Chains & Trade"}', 'Shipping companies are requesting clarity on mine presence and Iranian conditions before transiting the Strait of Hormuz, signaling elevated caution in a critical chokepoint for 21% of global oil trade.', '2026-04-17 18:35:10+00', '2026-04-18 02:02:06.545371+00', 'Shipping companies said several things had to be clarified, including the presence of mines, Iranian conditions.', 'pending', '{"Strategic Foresight","System Vitality"}', NULL, NULL, 'news', false, false, 7.2, 'RGI partially agrees: the Hormuz shipping uncertainty reflects genuine geopolitical risk to global trade flows, though this report lacks specificity on concrete operational impacts or clarifications sought. Senior leaders in energy, shipping, and supply chain sectors must immediately stress-test contingency routing and insurance models against sustained Hormuz volatility.');
