INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (697, 'Mortgage rates show signs of falling after Iran war peak', 'https://www.bbc.com/news/articles/cwyx2q86lgpo?at_medium=RSS&at_campaign=rss', 'BBC News', 'http://feeds.bbci.co.uk/news/rss.xml', 6.5, '{Geopolitics,Macroeconomics}', 'Mortgage rate declines following reported Iran war de-escalation suggest markets are repricing geopolitical risk downward. Article lacks clarity on whether this reflects durable policy shift or temporary market relief.', '2026-04-17 23:33:10+00', '2026-04-18 02:02:06.552294+00', 'Major lenders make rate reductions as markets take some heart from a possible truce in the Iran war.', 'pending', 'Strategic Foresight (weak signal on geopolitical volatility calming), Macroeconomics (rate trajectory and risk-off positioning)', NULL, NULL, 'news', false, false, 8.5, 'RGI partially agrees: mortgage rate movements do signal broader geopolitical risk de-escalation and market sentiment shifts, but this article lacks the strategic depth needed to assess whether the Iran truce signals a durable shift in risk premiums or a temporary tactical reprieve. Senior leaders should monitor whether this geopolitical relief translates into sustained capital reallocation away from defensive positions — a genuine inflection point would reshape investment timing and M&A strategies across sectors.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (698, 'Orbán''s era was over in a flash and Hungary''s next PM is a man in a hurry', 'https://www.bbc.com/news/articles/c4g40npz37lo?at_medium=RSS&at_campaign=rss', 'BBC News', 'http://feeds.bbci.co.uk/news/rss.xml', 6.5, '{Geopolitics,"Global Politics"}', 'Hungary''s Péter Magyar and Tisza party win landslide, positioning rapid power transition from Orbán; potential implications for EU institutional dynamics and NATO alignment remain to be defined.', '2026-04-17 23:02:14+00', '2026-04-18 02:02:06.554245+00', 'Péter Magyar and his Tisza party are wasting no time preparing for the transfer of power after their dramatic landslide victory.', 'pending', 'Civic Stewardship (institutional legitimacy, democratic reform signal); Strategic Foresight (geopolitical realignment in Central Europe)', NULL, NULL, 'news', false, false, 8.5, 'RGI partially agrees: Magyar''s electoral mandate signals potential institutional reform in a NATO/EU member state, but the article lacks specifics on governance architecture changes or systemic implications for Western institutional alignment. Senior leaders must monitor whether Magyar''s transition reshapes EU policy coordination on Ukraine, industrial policy, or democratic institutions—currently unclear from this reporting.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (699, 'AI minister Kendall says she doesn''t use AI at work', 'https://www.bbc.com/news/articles/cd0rmzjd720o?at_medium=RSS&at_campaign=rss', 'BBC News', 'http://feeds.bbci.co.uk/news/rss.xml', 4.5, '{"AI & Artificial Intelligence","Policy & Regulation"}', 'UK Science Secretary announces £500m AI investment fund while admitting personal non-use of AI tools — raising questions about leadership credibility and institutional AI literacy at policy level.', '2026-04-17 17:08:16+00', '2026-04-18 02:02:06.557647+00', 'The Science, Innovation and Technology Secretary this week unveiled a £500m fund to boost British AI firms.', 'pending', 'System Vitality (leadership credibility gap); Strategic Foresight (UK AI competitive positioning)', NULL, NULL, 'news', false, false, 9.5, 'RGI partially agrees: the hypocrisy signal is real and reflects broader leadership credibility gaps on AI adoption, but the article conflates personal non-use with institutional AI strategy capacity. The critical forward signal is that UK tech policy credibility rests on demonstrated competency, not rhetorical commitment — leaders must align personal practice with institutional AI governance mandates.');
INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (700, 'Air Canada temporarily suspends some flights to New York and other locations', 'https://www.theguardian.com/world/2026/apr/17/air-canada-suspending-flights-fuel-prices', 'The Guardian', 'https://www.theguardian.com/world/rss', 6.5, '{Geopolitics,"Supply Chains & Trade",Macroeconomics}', 'Air Canada suspends NYC routes citing elevated aviation fuel costs driven by Iran-Israel tensions; broader implications for airline profitability, supply chain resilience, and inflation pressure remain underexplored.', '2026-04-17 20:57:11+00', '2026-04-18 02:02:06.55999+00', 'Spirit Airlines reportedly seeks emergency US government funding as war against Iran keeps aviation fuel costs high Sign up for the Breaking News US email to get newsletter alerts in your inbox Air Canada has announced a temporary suspension of flights from Toronto and Montreal to New York ’s John F Kennedy airport, citing rising fuel prices. The move comes amid growing concerns that airlines worldwide may scale back services as aviation fuel costs climb in the wake of the US and Israel’s ongoing war with Iran, which entered a fragile ceasefire earlier in April. Although Iran announced on Friday that the strait of Hormuz had reopened, helping ease oil prices, fuel costs remain significantly elevated after weeks of disruption. Continue reading...', 'pending', 'Strategic Foresight (weak signal: geopolitical volatility translating to operational constraint); System Vitality (operational stress on labor/capacity); Macroeconomic inflection point (cost-push pressure on margins and service availability)', 'Maya Yang', NULL, 'news', false, false, 7.5, 'RGI partially agrees: the article correctly identifies a real geopolitical