INSERT INTO public.articles (id, headline, url, source_name, source_url, relevancy_score, topic_tags, teaser_summary, published_at, scraped_at, content, status, discipline_alignment, author, author_type, platform, is_emerging_signal, is_primary_signal, authenticity_score, viewpoint) VALUES (701, 'Starmer was left in dark about Mandelson’s vetting by two other top civil servants', 'https://www.theguardian.com/politics/2026/apr/17/keir-starmer-kept-in-dark-peter-mandelson-vetting-two-top-civil-servants', 'The Guardian', 'https://www.theguardian.com/world/rss', 5, '{}', 'Starmer was left in dark about Mandelson’s vetting by two other top civil servants', '2026-04-17 17:40:30+00', '2026-04-18 02:02:06.56219+00', 'Exclusive: Officials have spent weeks debating whether or not to release highly sensitive information about the affair Keir Starmer was left in the dark about sensitive information relating to Peter Mandelson’s security vetting by two other top civil servants, including the head of the civil service, the Guardian can reveal. The prime minister said on Friday that it was “unforgivable” and “staggering” that senior officials did not tell him that Mandelson failed a security vetting process weeks before he took up his role as ambassador to Washington. Continue reading...', 'pending', 'Multiple', 'Paul Lewis, Henry Dyer and Pippa Crerar', NULL, 'news', false, false, 5, NULL);
